                let w = kernel.gwe.system_metric(crate::ce::gwe::SM_CXSCREEN);
                let h = kernel.gwe.system_metric(crate::ce::gwe::SM_CYSCREEN);
                let _ = memory.write_u32(rect_ptr, 0);
