fn file_notification_prefix_fit(
    records: &[crate::ce::object::FileChangeRecord],
    _buffer: u32,
    buffer_len: usize,
) -> (usize, usize) {
    let mut fit_count = 0usize;
    let mut returned = 0usize;
    for record in records {
        let record_len = encoded_file_notification_record_len(record);
        if returned
            .checked_add(record_len)
            .is_none_or(|needed| needed > buffer_len)
        {
            break;
        }
        returned += record_len;
        fit_count += 1;
    }
    (fit_count, returned)
}

fn encoded_file_notification_len(records: &[crate::ce::object::FileChangeRecord]) -> usize {
    records
        .iter()
        .map(encoded_file_notification_record_len)
        .sum()
}

fn encoded_file_notification_record_len(record: &crate::ce::object::FileChangeRecord) -> usize {
    let name_len = record.path.encode_utf16().count() * 2;
    align_usize_to_u32(12usize + name_len + 2)
}

fn encode_file_notification_record(
    record: &crate::ce::object::FileChangeRecord,
    next_offset: u32,
) -> Vec<u8> {
    let mut name = Vec::new();
    for unit in record.path.encode_utf16() {
        name.extend_from_slice(&unit.to_le_bytes());
    }
    let aligned_len = encoded_file_notification_record_len(record);
    let record_len = 12usize + name.len() + 2;
    let mut out = Vec::with_capacity(aligned_len);
    out.extend_from_slice(&next_offset.to_le_bytes());
    out.extend_from_slice(&record.action.to_le_bytes());
    out.extend_from_slice(&(name.len() as u32).to_le_bytes());
    out.extend_from_slice(&name);
    out.extend_from_slice(&0u16.to_le_bytes());
    out.resize(out.len() + aligned_len.saturating_sub(record_len), 0);
    out
}

fn align_usize_to_u32(value: usize) -> usize {
    (value + 3) & !3
}

fn message_box_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    mut framebuffer: Option<&mut dyn Framebuffer>,
    context: &CoredllRawContext,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let state = match framebuffer {
        Some(ref mut framebuffer) => message_box_w_prepare(
            kernel,
            memory,
            Some(&mut **framebuffer),
            Some(context),
            thread_id,
            args,
        ),
        None => message_box_w_prepare(kernel, memory, None, Some(context), thread_id, args),
    };
    let state = match state {
        Err(result) => return result,
        Ok(state) => state,
    };
    let (result, used_default_fallback) = match state.try_queued_result(kernel, thread_id) {
        Some(result) => (result, false),
        None => {
            message_box_drain_generated_paints(kernel, thread_id);
            (state.default_result(), true)
        }
    };
    state.teardown(kernel, thread_id, result, framebuffer);
    if used_default_fallback {
        message_box_drain_generated_paints(kernel, thread_id);
    }
    kernel.threads.set_last_error(thread_id, 0);
    result
}

/// Validate args, disable owner, create the dialog window, and optionally render.
/// Returns `Err(result)` on invalid args (caller should set V0 and return immediately).
/// Returns `Ok(state)` with the live dialog ready for the modal loop.
pub(crate) fn message_box_w_prepare<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    framebuffer: Option<&mut dyn Framebuffer>,
    context: Option<&CoredllRawContext>,
    thread_id: u32,
    args: &[u32],
) -> std::result::Result<MessageBoxModalState, u32> {
    let owner_hwnd = raw_arg(args, 0);
    if owner_hwnd != 0 && !kernel.gwe.is_window(owner_hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return Err(0);
    }
    let text_ptr = raw_arg(args, 1);
    let caption_ptr = raw_arg(args, 2);
    let Some(text) = read_message_box_string(memory, text_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return Err(0);
    };
    let Some(caption) = read_message_box_string(memory, caption_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return Err(0);
    };
    let style = raw_arg(args, 3);
    let Some(selection) = message_box_selection(style) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return Err(0);
    };
    let owner_was_enabled = if owner_hwnd == 0 {
        None
    } else {
        Some(kernel.gwe.is_window_enabled(owner_hwnd))
    };
    tracing::debug!(
        target: "ce.gwe",
        hwnd = format_args!("0x{:08x}", owner_hwnd),
        text = %text,
        caption = %caption,
        style = format_args!("0x{:08x}", style),
        result = selection.result,
        "MessageBoxW"
    );
    if owner_was_enabled.is_some() {
        let _ = kernel.enable_window(owner_hwnd, false);
    }
    let visible_caption = "";
    let visible_text = "";
    let window_state = create_message_box_window(
        kernel,
        thread_id,
        owner_hwnd,
        visible_caption,
        visible_text,
        style,
        &selection,
    );
    if style & MB_SETFOREGROUND != 0 {
        let _ = kernel.gwe.set_active_window(Some(window_state.dialog_hwnd));
    }
    // CE's dialog manager focuses the default button when the box appears, so the
    // initial keyboard target is the button Enter/Space will activate.
    if let Some(default_button) = window_state
        .button_hwnds
        .get(selection.default_button_index)
        .copied()
    {
        let _ = kernel.set_focus(Some(default_button));
    }
    let (rendered, backing_store) = if let Some(framebuffer) = framebuffer {
        let layout = message_box_layout_for_framebuffer(
            kernel,
            framebuffer,
            owner_hwnd,
            visible_caption,
            visible_text,
            &selection,
        );
        let backing_store = capture_framebuffer_rect(framebuffer, layout.dialog);
        render_message_box_framebuffer_layout(
            kernel,
            framebuffer,
            &layout,
            visible_caption,
            visible_text,
            &selection,
        );
        (true, backing_store)
    } else {
        (false, None)
    };
    Ok(MessageBoxModalState {
        window_state,
        selection,
        owner_hwnd,
        owner_was_enabled,
        caller_pc: context.and_then(|context| context.caller_pc),
        trap_pc: context.and_then(|context| context.trap_pc),
        caller_module: context.and_then(|context| context.caller_module.clone()),
        text,
        caption,
        style,
        rendered,
        backing_store,
    })
}

/// Carries live dialog state during a modal `MessageBoxW` wait.
#[derive(Debug, Clone)]
#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
pub(crate) struct MessageBoxModalState {
    window_state: MessageBoxWindowState,
    selection: MessageBoxSelection,
    owner_hwnd: u32,
    owner_was_enabled: Option<bool>,
    caller_pc: Option<u32>,
    trap_pc: Option<u32>,
    caller_module: Option<String>,
    text: String,
    caption: String,
    style: u32,
    rendered: bool,
    backing_store: Option<FramebufferBackingStore>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct FramebufferBackingStore {
    rect: Rect,
    row_stride: usize,
    pixels: Vec<u8>,
}

#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
impl MessageBoxModalState {
    pub(crate) fn dialog_hwnd(&self) -> u32 {
        self.window_state.dialog_hwnd
    }

    pub(crate) fn default_result(&self) -> u32 {
        self.selection.result
    }

    pub(crate) fn restore_framebuffer(&self, framebuffer: &mut dyn Framebuffer) {
        if let Some(backing_store) = self.backing_store.as_ref() {
            restore_framebuffer_rect(framebuffer, backing_store);
        }
    }

    /// Drain any already-queued modal messages; returns `Some(result)` if the dialog
    /// was dismissed, `None` if more input is still needed.
    pub(crate) fn try_queued_result(&self, kernel: &mut CeKernel, thread_id: u32) -> Option<u32> {
        if let Some(result) =
            kernel.take_modal_dialog_result(thread_id, self.window_state.dialog_hwnd)
        {
            return self.selection.buttons.contains(&result).then_some(result);
        }
        if let Some(result) = kernel.gwe.dialog_result(self.window_state.dialog_hwnd) {
            return self.selection.buttons.contains(&result).then_some(result);
        }
        message_box_modal_input_result(kernel, thread_id, &self.window_state, &self.selection)
    }

    /// End the dialog, destroy its window, re-enable the owner, and record to shell.
    pub(crate) fn teardown(
        self,
        kernel: &mut CeKernel,
        thread_id: u32,
        result: u32,
        mut framebuffer: Option<&mut dyn Framebuffer>,
    ) {
        let dialog_was_active = kernel
            .gwe
            .active_window_is_within(self.window_state.dialog_hwnd);
        if let (Some(framebuffer), Some(backing_store)) =
            (framebuffer.as_deref_mut(), self.backing_store.as_ref())
        {
            restore_framebuffer_rect(framebuffer, backing_store);
        }
        let _ = kernel.end_dialog(thread_id, self.window_state.dialog_hwnd, result);
        let _ = kernel.destroy_window_with_reason(self.window_state.dialog_hwnd, "MessageBoxW");
        if let Some(was_enabled) = self.owner_was_enabled {
            let _ = kernel.enable_window(self.owner_hwnd, was_enabled);
        }
        if let (Some(framebuffer), Some(backing_store)) =
            (framebuffer.as_deref_mut(), self.backing_store.as_ref())
        {
            restore_framebuffer_rect(framebuffer, backing_store);
        }
        kernel.shell.record_message_box(MessageBoxRecord {
            thread_id,
            owner_hwnd: self.owner_hwnd,
            dialog_hwnd: self.window_state.dialog_hwnd,
            text_hwnd: self.window_state.text_hwnd,
            caller_pc: self.caller_pc,
            trap_pc: self.trap_pc,
            caller_module: self.caller_module,
            text: self.text,
            caption: self.caption,
            style: self.style,
            buttons: self.selection.buttons,
            button_hwnds: self.window_state.button_hwnds,
            button_layout: self.selection.button_layout,
            default_button_index: self.selection.default_button_index,
            icon: self.selection.icon,
            result,
            owner_was_enabled: self.owner_was_enabled,
            rendered: self.rendered,
            dialog_was_active,
            dialog_ex_style: self.window_state.dialog_ex_style,
        });
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) struct MessageBoxWindowState {
    pub(crate) dialog_hwnd: u32,
    pub(crate) text_hwnd: u32,
    pub(crate) button_hwnds: Vec<u32>,
    pub(crate) dialog_ex_style: u32,
}

#[derive(Debug, Clone)]
struct MessageBoxLayout {
    dialog: Rect,
    caption: Rect,
    caption_text: Rect,
    icon_outer: Option<Rect>,
    icon_inner: Option<Rect>,
    text_background: Rect,
    text: Rect,
    text_child: Rect,
    button_children: Vec<Rect>,
    button_screens: Vec<Rect>,
}

fn message_box_layout(
    kernel: &CeKernel,
    owner_hwnd: u32,
    caption: &str,
    text: &str,
    selection: &MessageBoxSelection,
) -> MessageBoxLayout {
    message_box_layout_in_bounds(
        kernel,
        owner_hwnd,
        caption,
        text,
        selection,
        kernel.gwe.desktop_rect(),
    )
}

fn message_box_layout_for_framebuffer(
    kernel: &CeKernel,
    framebuffer: &dyn Framebuffer,
    owner_hwnd: u32,
    caption: &str,
    text: &str,
    selection: &MessageBoxSelection,
) -> MessageBoxLayout {
    let info = framebuffer.info();
    let bounds = Rect::from_origin_size(0, 0, info.width as i32, info.height as i32);
    message_box_layout_in_bounds(kernel, owner_hwnd, caption, text, selection, bounds)
}

fn message_box_layout_in_bounds(
    kernel: &CeKernel,
    owner_hwnd: u32,
    caption: &str,
    text: &str,
    selection: &MessageBoxSelection,
    desktop: Rect,
) -> MessageBoxLayout {
    let frame_x = kernel
        .gwe
        .system_metric(crate::ce::gwe::SM_CXDLGFRAME)
        .max(1);
    let frame_y = kernel
        .gwe
        .system_metric(crate::ce::gwe::SM_CYDLGFRAME)
        .max(1);
    let caption_height = kernel
        .gwe
        .system_metric(crate::ce::gwe::SM_CYCAPTION)
        .max(frame_y * 4);
    let icon_width = kernel
        .gwe
        .system_metric(crate::ce::gwe::SM_CXSMICON)
        .max(frame_x * 4);
    let icon_height = kernel
        .gwe
        .system_metric(crate::ce::gwe::SM_CYSMICON)
        .max(frame_y * 4);
    let margin_x = frame_x * 4;
    let margin_y = frame_y * 4;
    let gap_x = frame_x * 3;
    let gap_y = frame_y * 3;
    let max_dialog_width = (desktop.width() - margin_x * 2).max(margin_x * 8);
    let max_text_width = (max_dialog_width - margin_x * 2 - icon_width - gap_x).max(margin_x * 6);

    let (caption_width, caption_height_text) = measure_message_box_text(caption, max_text_width);
    let (text_width, text_height) = measure_message_box_text(text, max_text_width);
    let text_background_width = text_width.max(frame_x * 30) + frame_x * 2;
    let text_background_height = text_height.max(caption_height_text) + frame_y * 2;

    let button_gap = gap_x;
    let button_sizes: Vec<(i32, i32)> = selection
        .button_layout
        .iter()
        .map(|button| {
            let (label_width, label_height) =
                measure_message_box_text(message_box_button_title(button.label), max_text_width);
            (
                (label_width + frame_x * 8).max(frame_x * 18),
                (label_height + frame_y * 3).max(caption_height - frame_y),
            )
        })
        .collect();
    let buttons_width = button_sizes.iter().map(|(width, _)| *width).sum::<i32>()
        + button_gap * (button_sizes.len().saturating_sub(1) as i32);
    let button_height = button_sizes
        .iter()
        .map(|(_, height)| *height)
        .max()
        .unwrap_or(caption_height - frame_y);

    let content_width = icon_width + gap_x + text_background_width;
    let dialog_width = (margin_x * 2)
        .saturating_add(
            content_width
                .max(buttons_width)
                .max(caption_width + margin_x),
        )
        .min(max_dialog_width)
        .max(margin_x * 12);
    let dialog_height = caption_height
        + margin_y
        + text_background_height
        + gap_y
        + button_height
        + margin_y
        + frame_y;

    let owner_or_desktop = (owner_hwnd != 0)
        .then(|| kernel.gwe.get_window_rect(owner_hwnd))
        .flatten()
        .filter(|rect| rect.width() > 0 && rect.height() > 0)
        .unwrap_or(desktop);
    let left = (owner_or_desktop.left + (owner_or_desktop.width() - dialog_width) / 2).clamp(
        desktop.left,
        (desktop.right - dialog_width).max(desktop.left),
    );
    let top = (owner_or_desktop.top + (owner_or_desktop.height() - dialog_height) / 2).clamp(
        desktop.top,
        (desktop.bottom - dialog_height).max(desktop.top),
    );
    let dialog = Rect::from_origin_size(left, top, dialog_width, dialog_height);

    let caption = Rect::from_origin_size(
        dialog.left + frame_x,
        dialog.top + frame_y,
        dialog.width() - frame_x * 2,
        caption_height,
    );
    let caption_text = Rect::from_origin_size(
        caption.left + frame_x * 2,
        caption.top + frame_y,
        caption.width() - frame_x * 4,
        caption.height() - frame_y * 2,
    );
    let content_top = caption.bottom + margin_y;
    let icon_outer = selection.icon.map(|_| {
        Rect::from_origin_size(dialog.left + margin_x, content_top, icon_width, icon_height)
    });
    let icon_inner = icon_outer.map(|rect| {
        Rect::from_origin_size(
            rect.left + frame_x,
            rect.top + frame_y,
            (rect.width() - frame_x * 2).max(1),
            (rect.height() - frame_y * 2).max(1),
        )
    });
    let text_background = Rect::from_origin_size(
        dialog.left + margin_x + icon_width + gap_x,
        content_top,
        dialog.width() - margin_x * 2 - icon_width - gap_x,
        text_background_height,
    );
    let text_rect = Rect::from_origin_size(
        text_background.left + frame_x,
        text_background.top + frame_y,
        text_background.width() - frame_x * 2,
        text_background.height() - frame_y * 2,
    );

    let buttons_top = text_background.bottom + gap_y;
    let mut next_button_left = dialog.left + (dialog.width() - buttons_width) / 2;
    let button_screens: Vec<Rect> = button_sizes
        .into_iter()
        .map(|(width, height)| {
            let rect = Rect::from_origin_size(next_button_left, buttons_top, width, height);
            next_button_left += width + button_gap;
            rect
        })
        .collect();
    let button_children = button_screens
        .iter()
        .map(|rect| rect.offset(-dialog.left, -dialog.top))
        .collect();

    MessageBoxLayout {
        dialog,
        caption,
        caption_text,
        icon_outer,
        icon_inner,
        text_background,
        text: text_rect,
        text_child: text_rect.offset(-dialog.left, -dialog.top),
        button_children,
        button_screens,
    }
}

fn create_message_box_window(
    kernel: &mut CeKernel,
    thread_id: u32,
    owner_hwnd: u32,
    caption: &str,
    text: &str,
    style: u32,
    selection: &MessageBoxSelection,
) -> MessageBoxWindowState {
    let owner = (owner_hwnd != 0).then_some(owner_hwnd);
    let layout = message_box_layout(kernel, owner_hwnd, caption, text, selection);
    let dialog_ex_style = if style & MB_TOPMOST != 0 {
        WS_EX_TOPMOST
    } else {
        0
    };
    let dialog = kernel.create_window_ex_w_with_parent_owner_and_rect(
        thread_id,
        "Dialog",
        caption,
        None,
        owner,
        0,
        WS_POPUP | WS_VISIBLE,
        dialog_ex_style,
        layout.dialog,
    );
    let text_hwnd = kernel.create_window_ex_w_with_rect(
        thread_id,
        "Static",
        text,
        Some(dialog),
        0,
        WS_CHILD | WS_VISIBLE,
        0,
        layout.text_child,
    );
    let button_hwnds = selection
        .button_layout
        .iter()
        .enumerate()
        .map(|(index, button)| {
            let button_style = if index == selection.default_button_index {
                BS_DEFPUSHBUTTON
            } else {
                BS_PUSHBUTTON
            };
            let style = WS_CHILD | WS_VISIBLE | WS_TABSTOP | button_style;
            kernel.create_window_ex_w_with_rect(
                thread_id,
                "Button",
                message_box_button_title(button.label),
                Some(dialog),
                button.id,
                style,
                0,
                layout.button_children[index],
            )
        })
        .collect();
    MessageBoxWindowState {
        dialog_hwnd: dialog,
        text_hwnd,
        button_hwnds,
        dialog_ex_style,
    }
}

fn message_box_modal_input_result(
    kernel: &mut CeKernel,
    thread_id: u32,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
) -> Option<u32> {
    const MAX_DRAINED_SENT_MESSAGES: usize = 64;
    for _ in 0..MAX_DRAINED_SENT_MESSAGES {
        let Some(message) = kernel.take_ready_sent_message_w_filtered(thread_id, None, 0, 0) else {
            break;
        };
        if message_box_message_targets_window(window_state, message.hwnd)
            && let Some(result) =
                message_box_message_result(kernel, window_state, selection, &message)
        {
            let _ = kernel.complete_active_sent_message(thread_id, result);
            return Some(result);
        }
        kernel.dispatch_message_w_for_thread(thread_id, message);
    }

    let modal_message_min = crate::ce::gwe::WM_PAINT;
    while let Some(message) = kernel.peek_message_w_filtered(
        thread_id,
        None,
        modal_message_min,
        crate::ce::gwe::WM_LBUTTONUP,
        PeekFlags::REMOVE,
    ) {
        if message_box_message_targets_window(window_state, message.hwnd) {
            if let Some(result) =
                message_box_message_result(kernel, window_state, selection, &message)
            {
                let _ = kernel.complete_active_sent_message(thread_id, result);
                return Some(result);
            }
            if message.msg == crate::ce::gwe::WM_PAINT {
                kernel.dispatch_message_w_for_thread(thread_id, message);
            } else {
                message_box_handle_navigation(kernel, window_state, &message);
            }
        } else {
            kernel.dispatch_message_w_for_thread(thread_id, message);
        }
    }
    None
}

fn message_box_drain_generated_paints(kernel: &mut CeKernel, thread_id: u32) {
    const MAX_DRAINED_PAINTS: usize = 64;
    for _ in 0..MAX_DRAINED_PAINTS {
        let Some(message) = kernel.gwe.peek_message_filtered(
            thread_id,
            None,
            crate::ce::gwe::WM_PAINT,
            crate::ce::gwe::WM_PAINT,
            PeekFlags::REMOVE,
        ) else {
            break;
        };
        kernel.dispatch_message_w_for_thread(thread_id, message);
    }
}

fn message_box_message_targets_window(window_state: &MessageBoxWindowState, hwnd: u32) -> bool {
    hwnd == window_state.dialog_hwnd
        || hwnd == window_state.text_hwnd
        || window_state.button_hwnds.contains(&hwnd)
}

fn message_box_message_result(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
    message: &Message,
) -> Option<u32> {
    const VK_RETURN: u32 = 0x0d;
    const VK_ESCAPE: u32 = 0x1b;
    const VK_SPACE: u32 = 0x20;

    match message.msg {
        crate::ce::gwe::WM_COMMAND => {
            let command = message.wparam & 0xffff;
            selection.buttons.contains(&command).then_some(command)
        }
        crate::ce::gwe::WM_CLOSE => Some(message_box_cancel_or_default_result(
            kernel,
            window_state,
            selection,
        )),
        crate::ce::gwe::WM_SYSCOMMAND if (message.wparam & 0xfff0) == crate::ce::gwe::SC_CLOSE => {
            Some(message_box_cancel_or_default_result(
                kernel,
                window_state,
                selection,
            ))
        }
        crate::ce::gwe::WM_KEYDOWN if message.wparam == VK_RETURN => {
            Some(message_box_return_command(kernel, window_state, selection))
        }
        crate::ce::gwe::WM_CHAR if message.wparam == VK_RETURN => {
            Some(message_box_return_command(kernel, window_state, selection))
        }
        // Space activates the focused button, matching the CE dialog manager
        // (`DLGC_BUTTON` controls treat space like a click).
        crate::ce::gwe::WM_KEYDOWN if message.wparam == VK_SPACE => {
            message_box_focused_button_command(kernel, window_state, selection)
        }
        crate::ce::gwe::WM_KEYDOWN if message.wparam == VK_ESCAPE => Some(
            message_box_cancel_or_default_result(kernel, window_state, selection),
        ),
        crate::ce::gwe::WM_CHAR if message.wparam == VK_ESCAPE => Some(
            message_box_cancel_or_default_result(kernel, window_state, selection),
        ),
        // Mnemonic accelerator: pressing a letter matching a button's &-marked character
        // activates that button. CE dialog manager handles WM_CHAR in its modal pump.
        crate::ce::gwe::WM_CHAR | crate::ce::gwe::WM_SYSCHAR => {
            let ch = char::from_u32(message.wparam)?;
            ch.is_ascii_alphabetic().then(|| {
                let ch_lower = ch.to_ascii_lowercase();
                selection
                    .button_layout
                    .iter()
                    .find(|button| message_box_button_mnemonic(button.label) == ch_lower)
                    .map(|button| button.id)
            })?
        }
        crate::ce::gwe::WM_LBUTTONDOWN => None,
        crate::ce::gwe::WM_LBUTTONUP => {
            if let Some(command) =
                message_box_direct_button_command(kernel, window_state, selection, message.hwnd)
            {
                return Some(command);
            }
            if message.hwnd == window_state.dialog_hwnd {
                return message_box_dialog_click_command(
                    kernel,
                    window_state,
                    selection,
                    message.lparam,
                );
            }
            None
        }
        _ => None,
    }
}

/// Resolves the command Enter should pick: the focused pushbutton when one of the
/// box's buttons holds focus, otherwise the dialog's current default button.
fn message_box_return_command(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
) -> u32 {
    let source = kernel
        .gwe
        .get_focus()
        .filter(|hwnd| message_box_message_targets_window(window_state, *hwnd))
        .unwrap_or(window_state.dialog_hwnd);
    let (command, _) =
        kernel
            .gwe
            .dialog_return_command(window_state.dialog_hwnd, source, selection.result);
    command
}

/// Resolves the command Space should pick: only fires when a box button is focused.
fn message_box_focused_button_command(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
) -> Option<u32> {
    let focus = kernel.gwe.get_focus()?;
    message_box_direct_button_command(kernel, window_state, selection, focus)
}

/// Moves focus between the box's buttons for Tab/Shift+Tab and arrow keys, matching
/// the CE dialog manager so a following Enter/Space activates the navigated button.
fn message_box_handle_navigation(
    kernel: &mut CeKernel,
    window_state: &MessageBoxWindowState,
    message: &Message,
) {
    const VK_TAB: u32 = 0x09;
    const VK_LEFT: u32 = 0x25;
    const VK_UP: u32 = 0x26;
    const VK_RIGHT: u32 = 0x27;
    const VK_DOWN: u32 = 0x28;

    if message.msg != crate::ce::gwe::WM_KEYDOWN {
        return;
    }
    let previous = match message.wparam {
        VK_TAB => kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000 != 0,
        VK_LEFT | VK_UP => true,
        VK_RIGHT | VK_DOWN => false,
        _ => return,
    };
    let current = kernel
        .gwe
        .get_focus()
        .filter(|hwnd| message_box_message_targets_window(window_state, *hwnd))
        .unwrap_or(window_state.dialog_hwnd);
    if let Some(next) =
        kernel
            .gwe
            .get_next_dlg_tab_item(window_state.dialog_hwnd, current, previous)
    {
        let _ = kernel.set_focus(Some(next));
    }
}

fn message_box_direct_button_command(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
    hwnd: u32,
) -> Option<u32> {
    window_state
        .button_hwnds
        .contains(&hwnd)
        .then(|| kernel.gwe.get_dlg_ctrl_id(hwnd))
        .flatten()
        .filter(|id| selection.buttons.contains(id))
}

fn message_box_dialog_click_command(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
    lparam: u32,
) -> Option<u32> {
    let point = message_box_lparam_point(lparam);
    let screen_point = kernel
        .gwe
        .client_to_screen(window_state.dialog_hwnd, point)?;
    window_state
        .button_hwnds
        .iter()
        .copied()
        .find(|hwnd| {
            kernel
                .gwe
                .get_window_rect(*hwnd)
                .is_some_and(|rect| rect.contains_point(screen_point))
        })
        .and_then(|hwnd| message_box_direct_button_command(kernel, window_state, selection, hwnd))
}

fn message_box_lparam_point(lparam: u32) -> Point {
    Point {
        x: (lparam & 0xffff) as i16 as i32,
        y: ((lparam >> 16) & 0xffff) as i16 as i32,
    }
}

fn message_box_cancel_or_default_result(
    kernel: &CeKernel,
    window_state: &MessageBoxWindowState,
    selection: &MessageBoxSelection,
) -> u32 {
    const IDCANCEL: u32 = 2;
    if selection.buttons.contains(&IDCANCEL) {
        let (command, _) = kernel
            .gwe
            .dialog_cancel_command(window_state.dialog_hwnd, IDCANCEL);
        command
    } else {
        selection.result
    }
}

fn render_message_box_framebuffer_layout(
    kernel: &CeKernel,
    framebuffer: &mut dyn Framebuffer,
    layout: &MessageBoxLayout,
    caption: &str,
    text: &str,
    selection: &MessageBoxSelection,
) {
    let frame_x = kernel
        .gwe
        .system_metric(crate::ce::gwe::SM_CXDLGFRAME)
        .max(1);
    let frame_y = kernel
        .gwe
        .system_metric(crate::ce::gwe::SM_CYDLGFRAME)
        .max(1);
    fill_framebuffer_screen_rect(framebuffer, layout.dialog, rgb(0x00, 0x00, 0x00));
    fill_framebuffer_screen_rect(
        framebuffer,
        Rect::from_origin_size(
            layout.dialog.left + frame_x,
            layout.dialog.top + frame_y,
            layout.dialog.width() - frame_x * 2,
            layout.dialog.height() - frame_y * 2,
        ),
        rgb(0xc0, 0xc0, 0xc0),
    );
    fill_framebuffer_screen_rect(framebuffer, layout.caption, rgb(0x00, 0x00, 0x80));
    render_framebuffer_text(
        framebuffer,
        layout.caption_text,
        caption,
        rgb(0xff, 0xff, 0xff),
    );

    if let Some(icon) = selection.icon {
        let color = match icon {
            MessageBoxIcon::Hand => rgb(0xc0, 0x00, 0x00),
            MessageBoxIcon::Question => rgb(0x00, 0x40, 0xff),
            MessageBoxIcon::Exclamation => rgb(0xff, 0xc0, 0x00),
            MessageBoxIcon::Asterisk => rgb(0x00, 0x80, 0x40),
        };
        if let Some(icon_outer) = layout.icon_outer {
            fill_framebuffer_screen_rect(framebuffer, icon_outer, rgb(0xff, 0xff, 0xff));
        }
        if let Some(icon_inner) = layout.icon_inner {
            fill_framebuffer_screen_rect(framebuffer, icon_inner, color);
        }
    }

    fill_framebuffer_screen_rect(framebuffer, layout.text_background, rgb(0xff, 0xff, 0xff));
    render_framebuffer_text(framebuffer, layout.text, text, rgb(0x00, 0x00, 0x00));

    for (index, button) in selection.button_layout.iter().enumerate() {
        let Some(button_rect) = layout.button_screens.get(index).copied() else {
            continue;
        };
        fill_framebuffer_screen_rect(framebuffer, button_rect, rgb(0x00, 0x00, 0x00));
        fill_framebuffer_screen_rect(
            framebuffer,
            Rect::from_origin_size(
                button_rect.left + 1,
                button_rect.top + 1,
                button_rect.width() - 2,
                button_rect.height() - 2,
            ),
            rgb(0xd8, 0xd8, 0xd8),
        );
        if index == selection.default_button_index {
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(
                    button_rect.left + 3,
                    button_rect.top + 3,
                    button_rect.width() - 6,
                    1,
                ),
                rgb(0x00, 0x00, 0x00),
            );
            fill_framebuffer_screen_rect(
                framebuffer,
                Rect::from_origin_size(
                    button_rect.left + 3,
                    button_rect.bottom - 4,
                    button_rect.width() - 6,
                    1,
                ),
                rgb(0x00, 0x00, 0x00),
            );
        }
        render_framebuffer_text(
            framebuffer,
            Rect::from_origin_size(
                button_rect.left + 7,
                button_rect.top + 4,
                button_rect.width() - 14,
                button_rect.height() - 8,
            ),
            message_box_button_title(button.label),
            rgb(0x00, 0x00, 0x00),
        );
    }
}

fn render_framebuffer_text(framebuffer: &mut dyn Framebuffer, rect: Rect, text: &str, color: u32) {
    #[cfg(windows)]
    {
        if render_framebuffer_text_with_gdi(framebuffer, rect, text, color) {
            return;
        }
    }

    render_framebuffer_text_marks(framebuffer, rect, text, color);
}

fn measure_message_box_text(text: &str, max_width: i32) -> (i32, i32) {
    #[cfg(windows)]
    {
        if let Some(measured) = measure_message_box_text_with_gdi(text, max_width) {
            return measured;
        }
    }

    measure_message_box_text_fallback(text, max_width)
}

#[cfg(windows)]
fn measure_message_box_text_with_gdi(text: &str, max_width: i32) -> Option<(i32, i32)> {
    use std::ptr::null_mut;

    use windows::Win32::{
        Foundation::RECT,
        Graphics::Gdi::{
            DEFAULT_GUI_FONT, DRAW_TEXT_FORMAT, DeleteDC, DrawTextW as GdiDrawTextW,
            GetStockObject, HDC, SelectObject,
        },
    };

    let hdc = unsafe { windows::Win32::Graphics::Gdi::CreateCompatibleDC(HDC(null_mut())) };
    if hdc.0.is_null() {
        return None;
    }
    let font = unsafe { GetStockObject(DEFAULT_GUI_FONT) };
    let old_font = if !font.0.is_null() {
        unsafe { SelectObject(hdc, font) }
    } else {
        windows::Win32::Graphics::Gdi::HGDIOBJ(null_mut())
    };

    let mut text_wide: Vec<u16> = text.encode_utf16().collect();
    if text_wide.is_empty() {
        text_wide.push(' ' as u16);
    }
    let mut rect = RECT {
        left: 0,
        top: 0,
        right: max_width.max(1),
        bottom: 0,
    };
    let height = unsafe {
        GdiDrawTextW(
            hdc,
            text_wide.as_mut_slice(),
            &mut rect,
            DRAW_TEXT_FORMAT(DT_LEFT | DT_TOP | DT_WORDBREAK | DT_NOPREFIX | DT_CALCRECT),
        )
    };

    unsafe {
        if !old_font.0.is_null() {
            let _ = SelectObject(hdc, old_font);
        }
        let _ = DeleteDC(hdc);
    }

    (height > 0).then_some((
        (rect.right - rect.left).max(1),
        (rect.bottom - rect.top).max(1),
    ))
}

fn measure_message_box_text_fallback(text: &str, max_width: i32) -> (i32, i32) {
    let cell_height = 16;
    let max_width = max_width.max(1);
    let mut line_width = 0;
    let mut widest = 0;
    let mut lines = 1;
    for ch in text.chars() {
        if ch == '\r' {
            continue;
        }
        if ch == '\n' {
            widest = widest.max(line_width);
            line_width = 0;
            lines += 1;
            continue;
        }
        let char_width = if ch.is_ascii() { 7 } else { 14 };
        if line_width > 0 && line_width + char_width > max_width {
            widest = widest.max(line_width);
            line_width = 0;
            lines += 1;
        }
        line_width += char_width;
    }
    widest = widest.max(line_width).max(1).min(max_width);
    (widest, lines * cell_height)
}

#[cfg(windows)]
fn render_framebuffer_text_with_gdi(
    framebuffer: &mut dyn Framebuffer,
    rect: Rect,
    text: &str,
    color: u32,
) -> bool {
    use std::{ffi::c_void, ptr::null_mut};

    use windows::Win32::{
        Foundation::{COLORREF, RECT},
        Graphics::Gdi::{
            BI_RGB, BITMAPINFO, BITMAPINFOHEADER, CreateCompatibleDC, CreateDIBSection,
            DEFAULT_GUI_FONT, DIB_RGB_COLORS, DRAW_TEXT_FORMAT, DeleteDC, DeleteObject,
            DrawTextW as GdiDrawTextW, GetStockObject, HDC, HGDIOBJ, SelectObject, SetBkMode,
            SetTextColor, TRANSPARENT,
        },
    };

    if text.is_empty() {
        return true;
    }

    let info = framebuffer.info();
    let left = rect.left.max(0).min(info.width as i32);
    let top = rect.top.max(0).min(info.height as i32);
    let right = rect.right.max(0).min(info.width as i32);
    let bottom = rect.bottom.max(0).min(info.height as i32);
    if right <= left || bottom <= top {
        return true;
    }

    let width = right - left;
    let height = bottom - top;
    let bmi = BITMAPINFO {
        bmiHeader: BITMAPINFOHEADER {
            biSize: std::mem::size_of::<BITMAPINFOHEADER>() as u32,
            biWidth: width,
            biHeight: -height,
            biPlanes: 1,
            biBitCount: 32,
            biCompression: BI_RGB.0,
            ..Default::default()
        },
        ..Default::default()
    };

    let mut bits: *mut c_void = null_mut();
    let hdc = unsafe { CreateCompatibleDC(HDC(null_mut())) };
    if hdc.0.is_null() {
        return false;
    }

    let Ok(bitmap) = (unsafe { CreateDIBSection(hdc, &bmi, DIB_RGB_COLORS, &mut bits, None, 0) })
    else {
        unsafe {
            let _ = DeleteDC(hdc);
        }
        return false;
    };
    if bitmap.0.is_null() || bits.is_null() {
        unsafe {
            let _ = DeleteDC(hdc);
        }
        return false;
    }

    let font = unsafe { GetStockObject(DEFAULT_GUI_FONT) };

    let old_bitmap = unsafe { SelectObject(hdc, HGDIOBJ(bitmap.0)) };
    let old_font = if !font.0.is_null() {
        unsafe { SelectObject(hdc, font) }
    } else {
        HGDIOBJ(null_mut())
    };

    unsafe {
        let _ = SetBkMode(hdc, TRANSPARENT);
        let _ = SetTextColor(hdc, COLORREF(0x00ff_ffff));
    }

    let mut text_wide: Vec<u16> = text.encode_utf16().collect();
    let mut text_rect = RECT {
        left: 0,
        top: 0,
        right: width,
        bottom: height,
    };
    let draw_flags = DT_LEFT | DT_TOP | DT_WORDBREAK | DT_NOPREFIX;
    unsafe {
        let _ = GdiDrawTextW(
            hdc,
            text_wide.as_mut_slice(),
            &mut text_rect,
            DRAW_TEXT_FORMAT(draw_flags),
        );
    }

    let source =
        unsafe { std::slice::from_raw_parts(bits.cast::<u8>(), (width * height * 4) as usize) };
    let target_pixel = pixel_bytes_for_colorref(info.format, color);
    let bytes_per_pixel = info.format.bytes_per_pixel();
    let mut dirty = false;
    {
        let pixels = framebuffer.pixels_mut();
        for y in 0..height as usize {
            for x in 0..width as usize {
                let source_offset = y * width as usize * 4 + x * 4;
                let blue = source[source_offset] as u16;
                let green = source[source_offset + 1] as u16;
                let red = source[source_offset + 2] as u16;
                if red + green + blue <= 8 {
                    continue;
                }
                let target_offset =
                    (top as usize + y) * info.stride + (left as usize + x) * bytes_per_pixel;
                pixels[target_offset..target_offset + bytes_per_pixel]
                    .copy_from_slice(&target_pixel[..bytes_per_pixel]);
                dirty = true;
            }
        }
    }

    unsafe {
        if !old_font.0.is_null() {
            let _ = SelectObject(hdc, old_font);
        }
        if !old_bitmap.0.is_null() {
            let _ = SelectObject(hdc, old_bitmap);
        }
        let _ = DeleteObject(HGDIOBJ(bitmap.0));
        let _ = DeleteDC(hdc);
    }

    if dirty {
        framebuffer.mark_dirty(FramebufferRect::new(
            left as u32,
            top as u32,
            (right - left) as u32,
            (bottom - top) as u32,
        ));
    }
    true
}

fn render_framebuffer_text_marks(
    framebuffer: &mut dyn Framebuffer,
    rect: Rect,
    text: &str,
    color: u32,
) {
    let mut x = rect.left;
    let mut y = rect.top;
    let max_right = rect.right;
    let max_bottom = rect.bottom;
    for ch in text.chars().take(96) {
        if ch == '\r' {
            continue;
        }
        if ch == '\n' || x + 4 > max_right {
            x = rect.left;
            y += 6;
            if ch == '\n' {
                continue;
            }
        }
        if y + 5 > max_bottom {
            break;
        }
        if !ch.is_whitespace() {
            fill_framebuffer_screen_rect(framebuffer, Rect::from_origin_size(x, y, 3, 5), color);
        }
        x += 4;
    }
}

fn message_box_button_title(label: MessageBoxButtonLabel) -> &'static str {
    match label {
        MessageBoxButtonLabel::Ok => "OK",
        MessageBoxButtonLabel::Cancel => "Cancel",
        // CE ownerdrawlib (odlib.rc ALS_Button_Abort) displays "Quit", not "Abort"
        MessageBoxButtonLabel::Abort => "Quit",
        MessageBoxButtonLabel::Retry => "Retry",
        MessageBoxButtonLabel::Ignore => "Ignore",
        MessageBoxButtonLabel::Yes => "Yes",
        MessageBoxButtonLabel::No => "No",
        MessageBoxButtonLabel::YesAll => "Yes to All",
    }
}

/// Returns the CE ownerdrawlib mnemonic character for each standard button label
/// (extracted from odlib.rc `&`-markers: e.g. "&OK"→'o', "Y&es to All"→'e').
fn message_box_button_mnemonic(label: MessageBoxButtonLabel) -> char {
    match label {
        MessageBoxButtonLabel::Ok => 'o',
        MessageBoxButtonLabel::Cancel => 'c',
        // CE ownerdrawlib displays "&Quit", mnemonic is 'q'
        MessageBoxButtonLabel::Abort => 'q',
        MessageBoxButtonLabel::Retry => 'r',
        MessageBoxButtonLabel::Ignore => 'i',
        MessageBoxButtonLabel::Yes => 'y',
        MessageBoxButtonLabel::No => 'n',
        // CE ownerdrawlib: "Y&es to All" → mnemonic is 'e'
        MessageBoxButtonLabel::YesAll => 'e',
    }
}

fn read_message_box_string<M: CoredllGuestMemory>(memory: &M, ptr: u32) -> Option<String> {
    if ptr == 0 {
        Some(String::new())
    } else {
        read_guest_wide_arg(memory, ptr)
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub(crate) struct MessageBoxSelection {
    pub(crate) buttons: Vec<u32>,
    pub(crate) button_layout: Vec<MessageBoxButton>,
    pub(crate) default_button_index: usize,
    pub(crate) icon: Option<MessageBoxIcon>,
    pub(crate) result: u32,
}

fn message_box_selection(style: u32) -> Option<MessageBoxSelection> {
    const MB_TYPEMASK: u32 = 0x0000_000f;
    const MB_DEFMASK: u32 = 0x0000_0300;
    const MB_ICONMASK: u32 = 0x0000_00f0;
    const MB_OK: u32 = 0x0000_0000;
    const MB_OKCANCEL: u32 = 0x0000_0001;
    const MB_ABORTRETRYIGNORE: u32 = 0x0000_0002;
    const MB_YESNOCANCEL: u32 = 0x0000_0003;
    const MB_YESNO: u32 = 0x0000_0004;
    const MB_RETRYCANCEL: u32 = 0x0000_0005;
    const MB_YESALL: u32 = 0x0000_0006;
    const MB_CANCEL: u32 = 0x0000_0007;
    const MB_DEFBUTTON1: u32 = 0x0000_0000;
    const MB_DEFBUTTON2: u32 = 0x0000_0100;
    const MB_DEFBUTTON3: u32 = 0x0000_0200;
    const MB_DEFBUTTON4: u32 = 0x0000_0300;
    const MB_ICONHAND: u32 = 0x0000_0010;
    const MB_ICONQUESTION: u32 = 0x0000_0020;
    const MB_ICONEXCLAMATION: u32 = 0x0000_0030;
    const MB_ICONASTERISK: u32 = 0x0000_0040;
    const MB_SETFOREGROUND: u32 = 0x0001_0000;
    const MB_TOPMOST: u32 = 0x0004_0000;
    const MB_RTLREADING: u32 = 0x0010_0000;
    const IDOK: u32 = 1;
    const IDCANCEL: u32 = 2;
    const IDABORT: u32 = 3;
    const IDRETRY: u32 = 4;
    const IDIGNORE: u32 = 5;
    const IDYES: u32 = 6;
    const IDNO: u32 = 7;

    let supported_mask =
        MB_TYPEMASK | MB_DEFMASK | MB_ICONMASK | MB_SETFOREGROUND | MB_TOPMOST | MB_RTLREADING;
    if style & !supported_mask != 0 {
        return None;
    }

    let button_layout: Vec<MessageBoxButton> = match style & MB_TYPEMASK {
        MB_OK => vec![message_box_button(
            IDOK,
            MessageBoxButtonLabel::Ok,
            MessageBoxButtonSlot::Center,
        )],
        MB_OKCANCEL => vec![
            message_box_button(IDOK, MessageBoxButtonLabel::Ok, MessageBoxButtonSlot::Left),
            message_box_button(
                IDCANCEL,
                MessageBoxButtonLabel::Cancel,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_ABORTRETRYIGNORE => vec![
            message_box_button(
                IDABORT,
                MessageBoxButtonLabel::Abort,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(
                IDRETRY,
                MessageBoxButtonLabel::Retry,
                MessageBoxButtonSlot::Center,
            ),
            message_box_button(
                IDIGNORE,
                MessageBoxButtonLabel::Ignore,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_YESNOCANCEL => vec![
            message_box_button(
                IDYES,
                MessageBoxButtonLabel::Yes,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(
                IDNO,
                MessageBoxButtonLabel::No,
                MessageBoxButtonSlot::Center,
            ),
            message_box_button(
                IDCANCEL,
                MessageBoxButtonLabel::Cancel,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_YESNO => vec![
            message_box_button(
                IDYES,
                MessageBoxButtonLabel::Yes,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(IDNO, MessageBoxButtonLabel::No, MessageBoxButtonSlot::Right),
        ],
        MB_RETRYCANCEL => vec![
            message_box_button(
                IDRETRY,
                MessageBoxButtonLabel::Retry,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(
                IDCANCEL,
                MessageBoxButtonLabel::Cancel,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_YESALL => vec![
            message_box_button(
                IDYES,
                MessageBoxButtonLabel::Yes,
                MessageBoxButtonSlot::Left,
            ),
            message_box_button(
                IDNO,
                MessageBoxButtonLabel::No,
                MessageBoxButtonSlot::Center,
            ),
            message_box_button(
                IDCANCEL,
                MessageBoxButtonLabel::YesAll,
                MessageBoxButtonSlot::Right,
            ),
        ],
        MB_CANCEL => vec![message_box_button(
            IDCANCEL,
            MessageBoxButtonLabel::Cancel,
            MessageBoxButtonSlot::Center,
        )],
        _ => return None,
    };
    let buttons: Vec<u32> = button_layout.iter().map(|button| button.id).collect();
    let requested_index = match style & MB_DEFMASK {
        MB_DEFBUTTON1 => 0,
        MB_DEFBUTTON2 => 1,
        MB_DEFBUTTON3 => 2,
        MB_DEFBUTTON4 => 3,
        _ => 0,
    };
    let default_button_index = if requested_index < button_layout.len() {
        requested_index
    } else {
        0
    };
    let icon = match style & MB_ICONMASK {
        0 => None,
        MB_ICONHAND => Some(MessageBoxIcon::Hand),
        MB_ICONQUESTION => Some(MessageBoxIcon::Question),
        MB_ICONEXCLAMATION => Some(MessageBoxIcon::Exclamation),
        MB_ICONASTERISK => Some(MessageBoxIcon::Asterisk),
        _ => return None,
    };
    let result = buttons[default_button_index];
    Some(MessageBoxSelection {
        buttons,
        button_layout,
        default_button_index,
        icon,
        result,
    })
}

fn message_box_button(
    id: u32,
    label: MessageBoxButtonLabel,
    slot: MessageBoxButtonSlot,
) -> MessageBoxButton {
    MessageBoxButton { id, label, slot }
}

