fn get_clipboard_data_raw(kernel: &mut CeKernel, thread_id: u32, format: u32) -> u32 {
    if format == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    if kernel.gwe.clipboard_delayed_render_owner(format).is_some() {
        request_delayed_clipboard_render(kernel, format);
    }
    match kernel.gwe.get_clipboard_data(format) {
        Some(handle) => {
            kernel.threads.set_last_error(thread_id, 0);
            handle
        }
        None => {
            if !kernel.gwe.clipboard_is_open() {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_ACCESS_DENIED);
            } else {
                kernel.threads.set_last_error(thread_id, 0);
            }
            0
        }
    }
}

#[cfg(feature = "unicorn")]
pub(crate) fn request_delayed_clipboard_render_pub(kernel: &mut CeKernel, format: u32) -> bool {
    request_delayed_clipboard_render(kernel, format)
}

fn request_delayed_clipboard_render(kernel: &mut CeKernel, format: u32) -> bool {
    let Some(owner) = kernel.gwe.begin_clipboard_render(format) else {
        return false;
    };
    let Some((target_thread, _)) = kernel.gwe.window_thread_process_id(owner) else {
        return false;
    };
    let message = Message::new(
        owner,
        crate::ce::gwe::WM_RENDERFORMAT,
        format,
        0,
        kernel.timers.tick_count(),
    );
    if kernel.gwe.queue_sent_message_for_window(owner, message) {
        kernel.queue_message_wake_candidates(target_thread);
        true
    } else {
        false
    }
}

fn get_clipboard_data_alloc_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    format: u32,
) -> u32 {
    if format == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    if kernel.gwe.clipboard_delayed_render_owner(format).is_some() {
        request_delayed_clipboard_render(kernel, format);
    }
    let Some(source) = kernel.gwe.get_clipboard_data(format) else {
        if !kernel.gwe.clipboard_is_open() {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_ACCESS_DENIED);
        } else {
            kernel.threads.set_last_error(thread_id, 0);
        }
        return 0;
    };
    if source == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    let Some(size) = kernel.memory.local_size(source) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(copy) = kernel.memory.local_alloc(0, size) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    if size != 0 {
        let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, source, size) else {
            let _ = kernel.memory.local_free(copy);
            return 0;
        };
        if !write_guest_bytes(kernel, memory, thread_id, copy, &bytes) {
            let _ = kernel.memory.local_free(copy);
            return 0;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    copy
}

fn get_priority_clipboard_format_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> i32 {
    let formats_ptr = raw_arg(args, 0);
    let count = raw_arg(args, 1);
    if formats_ptr == 0 || count == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return -1;
    }
    let mut formats = Vec::with_capacity(count as usize);
    for index in 0..count {
        let Some(format) = read_guest_u32(
            kernel,
            memory,
            thread_id,
            formats_ptr.wrapping_add(index.wrapping_mul(4)),
        ) else {
            return -1;
        };
        formats.push(format);
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel.gwe.get_priority_clipboard_format(&formats)
}

