fn create_accelerator_table_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    lp_accel: u32,
    c_entries: u32,
) -> u32 {
    if lp_accel == 0 || c_entries == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    // CE ACCEL: fVirt(1) + impl_pad(1) + key(2) + cmd(2) + pad(2) = 8 bytes
    let byte_count = c_entries.saturating_mul(8);
    let Some(data) = read_guest_bytes(kernel, memory, thread_id, lp_accel, byte_count) else {
        return 0;
    };
    let entries: Vec<AcceleratorEntry> = data
        .chunks_exact(8)
        .map(|chunk| AcceleratorEntry {
            flags: chunk[0],
            key: u16::from_le_bytes([chunk[2], chunk[3]]),
            command: u16::from_le_bytes([chunk[4], chunk[5]]),
        })
        .collect();
    if entries.is_empty() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    let module = kernel.process_module_base();
    kernel
        .resources
        .create_accelerator(module, ResourceId::Integer(0), None, entries)
}

fn load_accelerators_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    module: u32,
    name: u32,
) -> u32 {
    let module = normalized_module(kernel, module);
    let name = ResourceId::from_guest_arg(name);
    let Some(resource_handle) = kernel.resources.find_resource(
        module,
        name.clone(),
        ResourceId::Integer(RT_ACCELERATOR as u16),
    ) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_RESOURCE_NAME_NOT_FOUND);
        return 0;
    };
    let data = kernel
        .resources
        .load_resource(resource_handle)
        .zip(kernel.resources.sizeof_resource(resource_handle))
        .and_then(|(data_ptr, size)| read_guest_bytes(kernel, memory, thread_id, data_ptr, size))
        .unwrap_or_default();
    let entries = parse_accelerator_entries(&data);
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .create_accelerator(module, name, Some(resource_handle), entries)
}

fn destroy_accelerator_table_raw(kernel: &mut CeKernel, thread_id: u32, accel: u32) -> bool {
    if !kernel.resources.delete_accelerator(accel) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn translate_accelerator_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    hwnd: u32,
    accel: u32,
    msg_ptr: u32,
) -> u32 {
    let Some(accel_table) = kernel.resources.accelerator(accel).cloned() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(message) = read_guest_message(kernel, memory, thread_id, msg_ptr) else {
        return 0;
    };
    let is_char_msg = matches!(
        message.msg,
        crate::ce::gwe::WM_CHAR | crate::ce::gwe::WM_SYSCHAR
    );
    if !matches!(
        message.msg,
        crate::ce::gwe::WM_KEYDOWN
            | crate::ce::gwe::WM_SYSKEYDOWN
            | crate::ce::gwe::WM_CHAR
            | crate::ce::gwe::WM_SYSCHAR
    ) {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    let Some(entry) = accel_table.entries.iter().find(|entry| {
        accelerator_entry_matches_with_char_msg(kernel, &message, entry, is_char_msg)
    }) else {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    };
    let target = if hwnd != 0 { hwnd } else { message.hwnd };
    if target == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    // CE TranslateAcceleratorW uses SendMessage (not PostMessage) so WM_COMMAND is delivered
    // via the sent-message queue, which GetMessage/PeekMessage services before posted messages.
    let time_ms = kernel.timers.tick_count();
    let wm_command = crate::ce::gwe::Message::new(
        target,
        crate::ce::gwe::WM_COMMAND,
        (u32::from(entry.command) & 0xffff) | (1 << 16), // HIWORD=1: accelerator notification
        0,
        time_ms,
    );
    if let Some((target_thread, _)) = kernel.gwe.window_thread_process_id(target) {
        if kernel.gwe.queue_sent_message_for_window(target, wm_command) {
            kernel.queue_message_wake_candidates(target_thread);
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    1
}

fn accelerator_entry_matches_with_char_msg(
    kernel: &CeKernel,
    message: &Message,
    entry: &AcceleratorEntry,
    is_char_msg: bool,
) -> bool {
    let key = message.wparam as u16;
    let shift = kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000 != 0;
    let control = kernel.gwe.get_key_state(crate::ce::gwe::VK_CONTROL) & 0x8000 != 0;
    let caps = kernel.gwe.get_key_state(crate::ce::gwe::VK_CAPITAL) & 0x0001 != 0;
    let alt = (kernel.gwe.get_key_state(crate::ce::gwe::VK_MENU) & 0x8000 != 0)
        || matches!(
            message.msg,
            crate::ce::gwe::WM_SYSKEYDOWN | crate::ce::gwe::WM_SYSCHAR
        );
    let matches_key = if entry.flags & ACCEL_FVIRTKEY != 0 {
        // FVIRTKEY entries only match WM_KEYDOWN/WM_SYSKEYDOWN, not WM_CHAR/WM_SYSCHAR.
        if is_char_msg {
            return false;
        }
        entry.key == key
    } else {
        // Character entries: for WM_CHAR/WM_SYSCHAR, wparam is the char directly.
        // For WM_KEYDOWN, translate the VK via the active keyboard layout.
        let char_key = if is_char_msg {
            key
        } else {
            let layout = kernel.gwe.keyboard_layout();
            let layout_lang = layout & 0xFFFF;
            if matches!(layout_lang, 0x040C | 0x0407 | 0x040A | 0x0C0A) {
                let (ch, _) = translate_vk_for_western_layout(layout, message.wparam, shift, caps);
                if ch != 0 {
                    ch as u16
                } else {
                    translate_virtual_key_to_char(kernel, message.wparam) as u16
                }
            } else {
                translate_virtual_key_to_char(kernel, message.wparam) as u16
            }
        };
        char_key != 0 && ascii_accel_key(entry.key) == ascii_accel_key(char_key)
    };
    if !matches_key {
        return false;
    }
    (entry.flags & ACCEL_FSHIFT != 0) == shift
        && (entry.flags & ACCEL_FCONTROL != 0) == control
        && (entry.flags & ACCEL_FALT != 0) == alt
}

fn ascii_accel_key(key: u16) -> u16 {
    if (u16::from(b'a')..=u16::from(b'z')).contains(&key) {
        key - u16::from(b'a') + u16::from(b'A')
    } else {
        key
    }
}

fn parse_accelerator_entries(bytes: &[u8]) -> Vec<AcceleratorEntry> {
    let mut entries = Vec::new();
    for chunk in bytes.chunks_exact(8) {
        let flags_word = u16::from_le_bytes([chunk[0], chunk[1]]);
        let key = u16::from_le_bytes([chunk[2], chunk[3]]);
        let command = u16::from_le_bytes([chunk[4], chunk[5]]);
        let flags = flags_word as u8;
        entries.push(AcceleratorEntry {
            flags,
            key,
            command,
        });
        if flags_word & 0x0080 != 0 {
            break;
        }
    }
    entries
}

fn normalized_module(kernel: &CeKernel, module: u32) -> u32 {
    if module == 0 {
        kernel.process_module_base()
    } else {
        module
    }
}

fn load_bitmap_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    module: u32,
    name: u32,
) -> u32 {
    load_bitmap_resource(kernel, memory, thread_id, module, name)
}

fn load_image_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let module = raw_arg(args, 0);
    let name = raw_arg(args, 1);
    let image_type = raw_arg(args, 2);
    let flags = raw_arg(args, 5);

    if image_type == IMAGE_CURSOR {
        return load_cursor_w_raw(kernel, thread_id, module, name);
    }
    if image_type == IMAGE_ICON {
        return load_icon_w_raw(kernel, thread_id, module, name);
    }
    if image_type != IMAGE_BITMAP {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }

    if flags & LR_LOADFROMFILE != 0 {
        return load_bitmap_file(kernel, memory, thread_id, name);
    }

    load_bitmap_resource(kernel, memory, thread_id, module, name)
}

fn load_cursor_w_raw(kernel: &mut CeKernel, thread_id: u32, module: u32, name: u32) -> u32 {
    load_stock_or_resource_image(
        kernel,
        thread_id,
        module,
        name,
        RT_GROUP_CURSOR as u16,
        0x000b_0000,
    )
}

// GetIconInfo(hIcon, piconinfo) — fills ICONINFO struct for the given icon handle.
fn get_icon_info_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hicon = raw_arg(args, 0);
    let piconinfo = raw_arg(args, 1);
    if hicon == 0 || piconinfo == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    // ICONINFO: fIcon(4) + xHotspot(4) + yHotspot(4) + hbmMask(4) + hbmColor(4) = 20 bytes.
    // Treat all icon handles as icons (fIcon=1), hotspot at 0,0, bitmaps as NULL.
    write_guest_u32(kernel, memory, thread_id, piconinfo, 1); // fIcon
    write_guest_u32(kernel, memory, thread_id, piconinfo + 4, 0); // xHotspot
    write_guest_u32(kernel, memory, thread_id, piconinfo + 8, 0); // yHotspot
    write_guest_u32(kernel, memory, thread_id, piconinfo + 12, 0); // hbmMask
    write_guest_u32(kernel, memory, thread_id, piconinfo + 16, 0); // hbmColor
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn load_icon_w_raw(kernel: &mut CeKernel, thread_id: u32, module: u32, name: u32) -> u32 {
    load_stock_or_resource_image(
        kernel,
        thread_id,
        module,
        name,
        RT_GROUP_ICON as u16,
        0x000b_8000,
    )
}

fn create_icon_indirect_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    icon_info_ptr: u32,
) -> u32 {
    if icon_info_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(is_icon) = read_guest_u32(kernel, memory, thread_id, icon_info_ptr) else {
        return 0;
    };
    let Some(x_hotspot) = read_guest_u32(kernel, memory, thread_id, icon_info_ptr + 4) else {
        return 0;
    };
    let Some(y_hotspot) = read_guest_u32(kernel, memory, thread_id, icon_info_ptr + 8) else {
        return 0;
    };
    let Some(mask_bitmap) = read_guest_u32(kernel, memory, thread_id, icon_info_ptr + 12) else {
        return 0;
    };
    let Some(color_bitmap) = read_guest_u32(kernel, memory, thread_id, icon_info_ptr + 16) else {
        return 0;
    };
    let Some((mask_bitmap, owns_mask_bitmap)) =
        clone_bitmap_for_icon(kernel, memory, thread_id, mask_bitmap)
    else {
        return 0;
    };
    let Some((color_bitmap, owns_color_bitmap)) =
        clone_bitmap_for_icon(kernel, memory, thread_id, color_bitmap)
    else {
        if owns_mask_bitmap {
            delete_owned_bitmap(kernel, mask_bitmap);
        }
        return 0;
    };
    match kernel.resources.create_icon_with_bitmap_ownership(
        is_icon != 0,
        x_hotspot,
        y_hotspot,
        mask_bitmap,
        color_bitmap,
        owns_mask_bitmap,
        owns_color_bitmap,
    ) {
        Some(icon) => {
            kernel.threads.set_last_error(thread_id, 0);
            icon
        }
        None => {
            if owns_mask_bitmap {
                delete_owned_bitmap(kernel, mask_bitmap);
            }
            if owns_color_bitmap {
                delete_owned_bitmap(kernel, color_bitmap);
            }
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            0
        }
    }
}

fn clone_bitmap_for_icon<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bitmap: u32,
) -> Option<(u32, bool)> {
    if bitmap == 0 {
        return Some((0, false));
    }
    let source = kernel.resources.bitmap(bitmap)?.clone();
    if source.bits_ptr == 0 {
        return Some((bitmap, false));
    }
    let bytes = read_bitmap_object_bytes(memory, &source)?;
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, bytes.len() as u32)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return None;
    };
    if !write_guest_bytes(kernel, memory, thread_id, bits_ptr, &bytes) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return None;
    }
    let height = if source.top_down {
        -source.height
    } else {
        source.height
    };
    let clone = kernel.resources.create_owned_bitmap_with_masks(
        source.width,
        height,
        source.planes,
        source.bits_pixel,
        bits_ptr,
        source.rgb_masks,
    );
    if let Some(clone_bitmap) = kernel.resources.bitmap_mut(clone) {
        clone_bitmap.color_table = source.color_table;
        clone_bitmap.alpha_mask = source.alpha_mask;
    }
    Some((clone, true))
}

fn kern_extract_icons_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let file_ptr = raw_arg(args, 0);
    let icon_index = raw_i32_arg(args, 1);
    let large_out = raw_arg(args, 2);
    let small_out = raw_arg(args, 3);
    let Some(path) = read_guest_wide_arg(memory, file_ptr).map(|path| path.replace('/', "\\"))
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if icon_index < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_RESOURCE_NAME_NOT_FOUND);
        return 0;
    }
    let Ok((large, small)) = kern_extract_icon_resource_bytes(kernel, &path, icon_index as u32)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_RESOURCE_NAME_NOT_FOUND);
        return 0;
    };

    let mut extracted = 0;
    if large_out != 0 {
        let Some(ptr) = copy_resource_bytes_to_guest_heap(kernel, memory, thread_id, &large) else {
            return extracted;
        };
        if !write_guest_u32(kernel, memory, thread_id, large_out, ptr) {
            let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, ptr);
            return 0;
        }
        extracted += 1;
    }
    if small_out != 0 {
        let Some(ptr) = copy_resource_bytes_to_guest_heap(kernel, memory, thread_id, &small) else {
            return extracted;
        };
        if !write_guest_u32(kernel, memory, thread_id, small_out, ptr) {
            let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, ptr);
            return 0;
        }
        extracted += 1;
    }
    if extracted == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_RESOURCE_NAME_NOT_FOUND);
    } else {
        kernel.threads.set_last_error(thread_id, 0);
    }
    extracted
}

fn kern_extract_icon_resource_bytes(
    kernel: &mut CeKernel,
    path: &str,
    icon_index: u32,
) -> std::result::Result<(Vec<u8>, Vec<u8>), PeIconExtractError> {
    use crate::pe::PeImage;

    let bytes = kernel
        .read_guest_file(path)
        .map_err(|_| PeIconExtractError::Unavailable)?;
    let pe = PeImage::parse_bytes(path, &bytes).map_err(|_| PeIconExtractError::Unavailable)?;
    let resources = pe
        .resource_data_entries()
        .map_err(|_| PeIconExtractError::Malformed)?;
    let group = pe_icon_group_resources(&resources)
        .into_iter()
        .find(|resource| resource.name_string.is_none() && resource.name == icon_index)
        .ok_or(PeIconExtractError::Unavailable)?;
    let entries = pe_icon_group_entries(&pe, &bytes, group)?;
    let large_id = entries.first().ok_or(PeIconExtractError::Malformed)?.id;
    let small_id = entries.get(1).unwrap_or(&entries[0]).id;
    let large = pe_icon_resource_bytes_by_id(&pe, &bytes, &resources, large_id)?;
    let small = if small_id == large_id {
        large.clone()
    } else {
        pe_icon_resource_bytes_by_id(&pe, &bytes, &resources, small_id)?
    };
    Ok((large, small))
}

fn copy_resource_bytes_to_guest_heap<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bytes: &[u8],
) -> Option<u32> {
    let size = u32::try_from(bytes.len()).ok()?;
    let Some(ptr) = kernel
        .memory
        .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, size)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return None;
    };
    if !write_guest_bytes(kernel, memory, thread_id, ptr, bytes) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, ptr);
        return None;
    }
    Some(ptr)
}

fn extract_icon_ex_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let file_ptr = raw_arg(args, 0);
    let icon_index = raw_i32_arg(args, 1);
    let large_out = raw_arg(args, 2);
    let small_out = raw_arg(args, 3);
    let icon_count = raw_arg(args, 4);
    let Some(path) = read_guest_wide_arg(memory, file_ptr).map(|path| path.replace('/', "\\"))
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Ok(attributes) = kernel.file_attributes_w(&path) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_FILE_NOT_FOUND);
        return 0;
    };
    let is_pe = is_executable_shell_path(&path) || path.to_ascii_lowercase().ends_with(".dll");
    if icon_index == -1 {
        kernel.threads.set_last_error(thread_id, 0);
        return if is_pe {
            pe_icon_group_count(kernel, &path).unwrap_or(1)
        } else {
            1
        };
    }
    if icon_index < 0 || icon_count == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    let mut extracted = 0;
    for slot in 0..icon_count {
        let current_index = (icon_index as u32).saturating_add(slot);
        let icons = match extract_shell_icons_for_index(
            kernel,
            memory,
            thread_id,
            &path,
            attributes.attributes,
            is_pe,
            current_index,
        ) {
            Ok(Some(icons)) => icons,
            Ok(None) => break,
            Err(error) => {
                kernel.threads.set_last_error(thread_id, error);
                return extracted;
            }
        };
        let offset = slot.saturating_mul(4);
        if large_out != 0
            && !write_guest_u32(
                kernel,
                memory,
                thread_id,
                large_out.wrapping_add(offset),
                icons.large,
            )
        {
            return 0;
        }
        if small_out != 0
            && !write_guest_u32(
                kernel,
                memory,
                thread_id,
                small_out.wrapping_add(offset),
                icons.small,
            )
        {
            return 0;
        }
        extracted += 1;
    }
    kernel.threads.set_last_error(thread_id, 0);
    extracted
}

#[derive(Debug, Clone, Copy)]
struct ExtractedShellIcons {
    large: u32,
    small: u32,
}

impl ExtractedShellIcons {
    fn same(icon: u32) -> Self {
        Self {
            large: icon,
            small: icon,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PeIconExtractError {
    Unavailable,
    Malformed,
}

fn extract_shell_icons_for_index<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    path: &str,
    attributes: u32,
    is_pe: bool,
    icon_index: u32,
) -> std::result::Result<Option<ExtractedShellIcons>, u32> {
    if is_pe {
        match extract_pe_icons(kernel, memory, thread_id, path, icon_index) {
            Ok(icons) => Ok(Some(icons)),
            Err(PeIconExtractError::Unavailable) if icon_index == 0 => {
                let class = shell_file_class(kernel, path, attributes);
                Ok(Some(ExtractedShellIcons::same(
                    shell_file_icon(kernel, path, attributes, &class).handle,
                )))
            }
            Err(PeIconExtractError::Unavailable) => Ok(None),
            Err(PeIconExtractError::Malformed) => Err(ERROR_RESOURCE_NAME_NOT_FOUND),
        }
    } else if icon_index == 0 {
        let class = shell_file_class(kernel, path, attributes);
        Ok(Some(ExtractedShellIcons::same(
            shell_file_icon(kernel, path, attributes, &class).handle,
        )))
    } else {
        Ok(None)
    }
}

fn pe_icon_group_count(kernel: &mut CeKernel, path: &str) -> Option<u32> {
    use crate::pe::PeImage;

    let bytes = kernel.read_guest_file(path).ok()?;
    let pe = PeImage::parse_bytes(path, &bytes).ok()?;
    let resources = pe.resource_data_entries().ok()?;

    Some(pe_icon_group_resources(&resources).len() as u32)
}

fn pe_icon_group_resources(
    resources: &[crate::pe::PeResourceData],
) -> Vec<&crate::pe::PeResourceData> {
    const RT_GROUP_ICON: u32 = 14;

    resources
        .iter()
        .filter(|resource| resource.kind == RT_GROUP_ICON)
        .collect()
}

#[derive(Debug, Clone, Copy)]
struct PeIconGroupEntry {
    width: i32,
    height: i32,
    bit_count: i32,
    id: u16,
}

fn pe_icon_group_entries(
    pe: &crate::pe::PeImage,
    bytes: &[u8],
    group: &crate::pe::PeResourceData,
) -> std::result::Result<Vec<PeIconGroupEntry>, PeIconExtractError> {
    let group_offset = pe
        .rva_to_file_offset(group.data_rva)
        .ok_or(PeIconExtractError::Malformed)?;
    let group_end = group_offset
        .checked_add(group.size as usize)
        .ok_or(PeIconExtractError::Malformed)?;
    let group_bytes = bytes
        .get(group_offset..group_end)
        .ok_or(PeIconExtractError::Malformed)?;

    if group_bytes.len() < 6 {
        return Err(PeIconExtractError::Malformed);
    }
    let reserved = read_le_u16(group_bytes, 0).ok_or(PeIconExtractError::Malformed)?;
    let resource_type = read_le_u16(group_bytes, 2).ok_or(PeIconExtractError::Malformed)?;
    let icon_count = read_le_u16(group_bytes, 4).ok_or(PeIconExtractError::Malformed)? as usize;
    if reserved != 0 || resource_type != 1 || icon_count == 0 {
        return Err(PeIconExtractError::Malformed);
    }
    let group_table_len = 6usize
        .checked_add(
            icon_count
                .checked_mul(14)
                .ok_or(PeIconExtractError::Malformed)?,
        )
        .ok_or(PeIconExtractError::Malformed)?;
    if group_bytes.len() < group_table_len {
        return Err(PeIconExtractError::Malformed);
    }

    let mut entries = Vec::with_capacity(icon_count);
    for index in 0..icon_count {
        let entry_off = 6 + index * 14;
        let entry = group_bytes
            .get(entry_off..entry_off + 14)
            .ok_or(PeIconExtractError::Malformed)?;
        entries.push(PeIconGroupEntry {
            width: pe_icon_directory_dimension(entry[0]),
            height: pe_icon_directory_dimension(entry[1]),
            bit_count: read_le_u16(entry, 6).ok_or(PeIconExtractError::Malformed)? as i32,
            id: read_le_u16(entry, 12).ok_or(PeIconExtractError::Malformed)?,
        });
    }
    Ok(entries)
}

fn extract_pe_icons<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    path: &str,
    icon_index: u32,
) -> std::result::Result<ExtractedShellIcons, PeIconExtractError> {
    use crate::pe::PeImage;

    let bytes = kernel
        .read_guest_file(path)
        .map_err(|_| PeIconExtractError::Unavailable)?;
    let pe = PeImage::parse_bytes(path, &bytes).map_err(|_| PeIconExtractError::Unavailable)?;
    let resources = pe
        .resource_data_entries()
        .map_err(|_| PeIconExtractError::Malformed)?;

    // Find the icon group at icon_index. The public ExtractIconExW path uses
    // zero-based group enumeration; CE KernExtractIcons then resolves the
    // selected group through RT_GROUP_ICON/MAKEINTRESOURCE.
    let groups = pe_icon_group_resources(&resources);
    let group = groups
        .get(icon_index as usize)
        .copied()
        .or_else(|| {
            ((icon_index as usize) > groups.len()).then(|| {
                groups
                    .iter()
                    .copied()
                    .find(|resource| resource.name_string.is_none() && resource.name == icon_index)
            })?
        })
        .ok_or(PeIconExtractError::Unavailable)?;

    let entries = pe_icon_group_entries(&pe, &bytes, group)?;
    let large_id = select_pe_icon_group_entry(&entries, 32)
        .ok_or(PeIconExtractError::Malformed)?
        .id;
    let small_id = select_pe_icon_group_entry(&entries, 16)
        .ok_or(PeIconExtractError::Malformed)?
        .id;
    let large =
        extract_pe_icon_by_id(kernel, memory, thread_id, &pe, &bytes, &resources, large_id)?;
    let small = if small_id == large_id {
        large
    } else {
        extract_pe_icon_by_id(kernel, memory, thread_id, &pe, &bytes, &resources, small_id)?
    };

    Ok(ExtractedShellIcons { large, small })
}

fn pe_icon_directory_dimension(value: u8) -> i32 {
    if value == 0 { 256 } else { value as i32 }
}

fn select_pe_icon_group_entry(
    entries: &[PeIconGroupEntry],
    target: i32,
) -> Option<PeIconGroupEntry> {
    entries.iter().copied().max_by_key(|entry| {
        let exact_size = entry.width == target && entry.height == target;
        let size_score = if exact_size {
            10_000
        } else {
            entry.width.max(entry.height)
        };
        size_score * 1_000 + entry.bit_count
    })
}

fn pe_icon_resource_bytes_by_id(
    pe: &crate::pe::PeImage,
    bytes: &[u8],
    resources: &[crate::pe::PeResourceData],
    icon_id: u16,
) -> std::result::Result<Vec<u8>, PeIconExtractError> {
    const RT_ICON: u32 = 3;

    let icon_entry = resources
        .iter()
        .find(|r| r.kind == RT_ICON && r.name == icon_id as u32)
        .ok_or(PeIconExtractError::Malformed)?;
    let icon_offset = pe
        .rva_to_file_offset(icon_entry.data_rva)
        .ok_or(PeIconExtractError::Malformed)?;
    let icon_end = icon_offset
        .checked_add(icon_entry.size as usize)
        .ok_or(PeIconExtractError::Malformed)?;
    bytes
        .get(icon_offset..icon_end)
        .map(|icon_bytes| icon_bytes.to_vec())
        .ok_or(PeIconExtractError::Malformed)
}

fn extract_pe_icon_by_id<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    pe: &crate::pe::PeImage,
    bytes: &[u8],
    resources: &[crate::pe::PeResourceData],
    icon_id: u16,
) -> std::result::Result<u32, PeIconExtractError> {
    const RT_ICON: u32 = 3;

    // Find matching RT_ICON entry
    let icon_entry = resources
        .iter()
        .find(|r| r.kind == RT_ICON && r.name == icon_id as u32)
        .ok_or(PeIconExtractError::Malformed)?;
    let icon_offset = pe
        .rva_to_file_offset(icon_entry.data_rva)
        .ok_or(PeIconExtractError::Malformed)?;
    let icon_end = icon_offset
        .checked_add(icon_entry.size as usize)
        .ok_or(PeIconExtractError::Malformed)?;
    let icon_bytes = bytes
        .get(icon_offset..icon_end)
        .ok_or(PeIconExtractError::Malformed)?;

    // RT_ICON data is a DIB - BITMAPINFOHEADER + color table + XOR mask + AND mask
    // The height in the header is 2*h (XOR + AND masks stacked), fix it for color bitmap
    if icon_bytes.len() < 40 {
        return Err(PeIconExtractError::Malformed);
    }
    let actual_width = read_le_i32(icon_bytes, 4).ok_or(PeIconExtractError::Malformed)?;
    let dib_height = read_le_u32(icon_bytes, 8).ok_or(PeIconExtractError::Malformed)?;
    let actual_height = (dib_height / 2) as i32;
    let bpp = read_le_u16(icon_bytes, 14).ok_or(PeIconExtractError::Malformed)?;
    let compression = read_le_u32(icon_bytes, 16).unwrap_or(0);
    if actual_width <= 0 || actual_height <= 0 || dib_height % 2 != 0 || bpp == 0 {
        return Err(PeIconExtractError::Malformed);
    }

    // Create a copy of the icon DIB with corrected height for the color bitmap
    let mut color_dib: Vec<u8> = icon_bytes.to_vec();
    color_dib
        .get_mut(8..12)
        .ok_or(PeIconExtractError::Malformed)?
        .copy_from_slice(&(actual_height as u32).to_le_bytes());

    let color_bitmap = create_bitmap_from_dib_bytes(kernel, memory, thread_id, &color_dib);
    if color_bitmap == 0 {
        return Err(PeIconExtractError::Malformed);
    }

    // Extract AND mask (1bpp, follows XOR pixels in RT_ICON data)
    // Only BI_RGB and BI_BITFIELDS icons have AND masks
    let mask_bitmap = pe_icon_and_mask_bitmap(
        kernel,
        memory,
        thread_id,
        icon_bytes,
        actual_width,
        actual_height,
        bpp,
        compression,
    );

    kernel
        .resources
        .create_icon_with_bitmap_ownership(
            true,
            0,
            0,
            mask_bitmap,
            color_bitmap,
            mask_bitmap != 0,
            color_bitmap != 0,
        )
        .ok_or(PeIconExtractError::Malformed)
}

fn pe_icon_and_mask_bitmap<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    icon_bytes: &[u8],
    width: i32,
    height: i32,
    bpp: u16,
    compression: u32,
) -> u32 {
    pe_icon_and_mask_bitmap_inner(
        kernel,
        memory,
        thread_id,
        icon_bytes,
        width,
        height,
        bpp,
        compression,
    )
    .unwrap_or(0)
}

fn pe_icon_and_mask_bitmap_inner<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    icon_bytes: &[u8],
    width: i32,
    height: i32,
    bpp: u16,
    compression: u32,
) -> Option<u32> {
    const BI_BITFIELDS: u32 = 3;
    let header_size = 40usize;
    // BI_BITFIELDS adds 12 bytes of RGB masks between header and pixel data
    let bitfields_bytes: usize = if compression == BI_BITFIELDS { 12 } else { 0 };
    let color_entries: usize = if bpp <= 8 { 1 << bpp } else { 0 };
    let used_entries = read_le_u32(icon_bytes, 32).map(|n| n as usize).unwrap_or(0);
    let actual_color_entries = if used_entries > 0 && used_entries < color_entries {
        used_entries
    } else {
        color_entries
    };
    let color_table_bytes = actual_color_entries * 4;
    let xor_stride = ((width as usize)
        .checked_mul(bpp as usize)?
        .checked_add(31)?
        / 32)
        * 4;
    let xor_size = xor_stride.checked_mul(height as usize)?;
    let and_stride = ((width as usize).checked_add(31)? / 32) * 4;
    let and_size = and_stride.checked_mul(height as usize)?;
    let and_offset = header_size
        .checked_add(bitfields_bytes)?
        .checked_add(color_table_bytes)?
        .checked_add(xor_size)?;
    let and_end = and_offset.checked_add(and_size)?;

    let and_bytes = icon_bytes.get(and_offset..and_end)?;

    // Build a 1bpp BITMAPINFOHEADER DIB for the AND mask.
    // Color table: index 0 = black (opaque), index 1 = white (transparent).
    let mut mask_dib: Vec<u8> = Vec::with_capacity(40 + 8 + and_size);
    mask_dib.extend_from_slice(&40u32.to_le_bytes());
    mask_dib.extend_from_slice(&width.to_le_bytes());
    mask_dib.extend_from_slice(&height.to_le_bytes());
    mask_dib.extend_from_slice(&1u16.to_le_bytes());
    mask_dib.extend_from_slice(&1u16.to_le_bytes());
    mask_dib.extend_from_slice(&0u32.to_le_bytes()); // BI_RGB
    mask_dib.extend_from_slice(&0u32.to_le_bytes()); // biSizeImage
    mask_dib.extend_from_slice(&0u32.to_le_bytes()); // biXPelsPerMeter
    mask_dib.extend_from_slice(&0u32.to_le_bytes()); // biYPelsPerMeter
    mask_dib.extend_from_slice(&2u32.to_le_bytes()); // biClrUsed
    mask_dib.extend_from_slice(&0u32.to_le_bytes()); // biClrImportant
    mask_dib.extend_from_slice(&[0x00, 0x00, 0x00, 0x00]); // index 0 = black (opaque)
    mask_dib.extend_from_slice(&[0xFF, 0xFF, 0xFF, 0x00]); // index 1 = white (transparent)
    mask_dib.extend_from_slice(and_bytes);

    let handle = create_bitmap_from_dib_bytes(kernel, memory, thread_id, &mask_dib);
    (handle != 0).then_some(handle)
}

fn destroy_icon_raw(kernel: &mut CeKernel, thread_id: u32, icon: u32) -> bool {
    if let Some(object) = kernel.resources.icon(icon).cloned() {
        if object.is_icon {
            let _ = kernel.resources.delete_icon(icon);
            let mut bitmaps = BTreeSet::new();
            if object.owns_mask_bitmap && object.mask_bitmap != 0 {
                bitmaps.insert(object.mask_bitmap);
            }
            if object.owns_color_bitmap && object.color_bitmap != 0 {
                bitmaps.insert(object.color_bitmap);
            }
            for bitmap in bitmaps {
                delete_owned_bitmap(kernel, bitmap);
            }
            kernel.threads.set_last_error(thread_id, 0);
            return true;
        }
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    if !is_icon_handle(kernel, icon) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn draw_icon_ex_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let x = raw_i32_arg(args, 1);
    let y = raw_i32_arg(args, 2);
    let icon = raw_arg(args, 3);
    let width = raw_i32_arg(args, 4);
    let height = raw_i32_arg(args, 5);
    let draw_flags = raw_arg(args, 8);
    if !is_valid_hdc(kernel, hdc) || !is_icon_handle(kernel, icon) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    // Icons created via CreateIconIndirect / ExtractIconEx have a bitmap-backed IconObject
    if let Some(icon_obj) = kernel.resources.icon(icon) {
        const DI_MASK: u32 = 0x0001;
        const DI_IMAGE: u32 = 0x0002;
        const DI_NORMAL: u32 = DI_MASK | DI_IMAGE;

        let color_bitmap = icon_obj.color_bitmap;
        let mask_bitmap = icon_obj.mask_bitmap;
        let effective_flags = if draw_flags & DI_NORMAL == 0 {
            DI_NORMAL
        } else {
            draw_flags & DI_NORMAL
        };
        let mask_only = effective_flags == DI_MASK;
        let source_bitmap = if mask_only {
            mask_bitmap
        } else if color_bitmap != 0 {
            color_bitmap
        } else {
            mask_bitmap
        };
        let (source_width, source_height) = kernel
            .resources
            .bitmap(source_bitmap)
            .map(|bitmap| (bitmap.width.abs().max(1), bitmap.height.abs().max(1)))
            .unwrap_or((width, height));
        let width = if width > 0 {
            width
        } else if width == 0 {
            source_width
        } else {
            32
        };
        let height = if height > 0 {
            height
        } else if height == 0 {
            source_height
        } else {
            32
        };
        if width <= 0 || height <= 0 {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return false;
        }
        let image = crate::ce::resource::ImageListImage {
            bitmap: source_bitmap,
            mask: if effective_flags == DI_NORMAL && color_bitmap != 0 && !mask_only {
                mask_bitmap
            } else {
                0
            },
            icon: 0,
            source_x: 0,
            source_y: 0,
            transparent_color: None,
        };
        if let Some(fb) = framebuffer {
            render_image_list_bitmap_entry_framebuffer(
                kernel,
                memory,
                fb,
                hdc,
                x,
                y,
                width,
                height,
                source_width,
                source_height,
                &image,
                None,
                None,
                None,
            );
        } else {
            render_image_list_bitmap_entry_hdc(
                kernel,
                memory,
                hdc,
                x,
                y,
                width,
                height,
                source_width,
                source_height,
                &image,
                None,
                None,
                None,
            );
        }
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }
    let width = if width > 0 { width } else { 32 };
    let height = if height > 0 { height } else { 32 };
    if width <= 0 || height <= 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let flags = ((icon >> SHELL_ICON_OVERLAY_SHIFT) & 0x0f) << 8;
    let draw = ImageListDraw {
        image_list: SHELL_SYSTEM_IMAGE_LIST_HANDLE,
        index: (icon & 0xffff) as i32,
        hdc,
        x,
        y,
        width,
        height,
        flags,
        overlay_image: None,
        rgb_fg: CLR_DEFAULT,
        rgb_bk: CLR_NONE,
        x_bitmap: 0,
        y_bitmap: 0,
        rop: SRCCOPY,
    };
    if !render_image_list_draw_bitmap(kernel, memory, draw) {
        render_image_list_draw_framebuffer(kernel, memory, framebuffer, draw);
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn is_icon_handle(kernel: &CeKernel, icon: u32) -> bool {
    if icon == 0 {
        return false;
    }
    if let Some(entry) = kernel.resources.resource_entry(icon) {
        return entry.kind == ResourceId::Integer(RT_GROUP_ICON as u16);
    }
    if kernel
        .resources
        .icon(icon)
        .is_some_and(|object| object.is_icon)
    {
        return true;
    }
    let without_overlay = icon & 0x00ff_ffff;
    without_overlay & 0xffff_0000 == 0x000b_0000 && without_overlay & 0x0000_ffff >= 0x8000
}

fn image_list_create_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> u32 {
    let width = raw_i32_arg(args, 0);
    let height = raw_i32_arg(args, 1);
    let flags = raw_arg(args, 2);
    let initial = raw_i32_arg(args, 3);
    let grow = raw_i32_arg(args, 4);
    match kernel
        .resources
        .create_image_list(width, height, flags, initial, grow)
    {
        Some(handle) => {
            kernel.threads.set_last_error(thread_id, 0);
            handle
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            0
        }
    }
}

fn image_list_destroy_raw(kernel: &mut CeKernel, thread_id: u32, handle: u32) -> bool {
    if is_shell_system_image_list_handle(handle) {
        // CE shell code tears down shared SHGetFileInfo system HIMAGELISTs during shutdown.
        // The emulator's fixed synthetic handles stay reusable, but the release succeeds.
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }

    let owned_bitmaps = image_list_owned_bitmap_handles(kernel, handle);
    if kernel.resources.destroy_image_list(handle) {
        for bitmap in owned_bitmaps {
            delete_owned_bitmap(kernel, bitmap);
        }
        kernel.threads.set_last_error(thread_id, 0);
        true
    } else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        false
    }
}

fn image_list_owned_bitmap_handles(kernel: &CeKernel, handle: u32) -> Vec<u32> {
    let Some(list) = kernel.resources.image_list(handle) else {
        return Vec::new();
    };
    let mut seen = BTreeSet::new();
    let mut owned = Vec::new();
    for image in &list.images {
        for bitmap in [image.bitmap, image.mask] {
            if bitmap != 0
                && seen.insert(bitmap)
                && kernel
                    .resources
                    .bitmap(bitmap)
                    .is_some_and(|object| object.bits_owned)
            {
                owned.push(bitmap);
            }
        }
    }
    owned
}

fn image_list_load_image_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let module = raw_arg(args, 0);
    let name = raw_arg(args, 1);
    let requested_cx = raw_i32_arg(args, 2);
    let grow = raw_i32_arg(args, 3);
    let mask = raw_arg(args, 4);
    let image_type = raw_arg(args, 5);
    let flags = raw_arg(args, 6);
    if image_type != IMAGE_BITMAP {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let bitmap = load_image_w_raw(
        kernel,
        memory,
        thread_id,
        &[module, name, IMAGE_BITMAP, 0, 0, flags],
    );
    if bitmap == 0 {
        return 0;
    }
    let Some(bitmap_info) = kernel.resources.bitmap(bitmap).cloned() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let height = bitmap_info.height.max(1);
    let width = if requested_cx > 0 {
        requested_cx
    } else if requested_cx == 0 {
        height
    } else {
        requested_cx
    };
    const ILC_MASK: u32 = 0x0001;
    const ILC_COLORMASK: u32 = 0x00fe;
    let mut image_list_flags = 0;
    if mask != CLR_NONE {
        image_list_flags |= ILC_MASK;
    }
    image_list_flags |= u32::from(bitmap_info.bits_pixel) & ILC_COLORMASK;
    let Some(list) = kernel
        .resources
        .create_image_list(width, height, image_list_flags, 1, grow)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let added = if mask == CLR_NONE {
        kernel.resources.add_image_list_image(list, bitmap, 0)
    } else {
        let mask = image_list_add_masked_color(kernel, memory, mask, bitmap);
        let Some(mask_bitmap) =
            create_image_list_mask_bitmap(kernel, memory, thread_id, bitmap, mask)
        else {
            kernel.resources.destroy_image_list(list);
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        let added =
            kernel
                .resources
                .add_masked_image_list_image_with_mask(list, bitmap, mask_bitmap, mask);
        if added.is_none() {
            delete_owned_bitmap(kernel, mask_bitmap);
        }
        added
    };
    if added.is_none() {
        kernel.resources.destroy_image_list(list);
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    list
}

fn image_list_add_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> i32 {
    let handle = raw_arg(args, 0);
    let bitmap = raw_arg(args, 1);
    let mask = raw_arg(args, 2);
    let Some(bitmap) = clone_bitmap_for_image_list(kernel, memory, thread_id, bitmap) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return -1;
    };
    let Some(mask) = clone_optional_bitmap_for_image_list(kernel, memory, thread_id, mask) else {
        delete_owned_bitmap(kernel, bitmap);
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return -1;
    };
    match kernel.resources.add_image_list_image(handle, bitmap, mask) {
        Some(index) => {
            kernel.threads.set_last_error(thread_id, 0);
            index
        }
        None => {
            delete_owned_bitmap(kernel, bitmap);
            delete_owned_bitmap(kernel, mask);
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            -1
        }
    }
}

fn image_list_add_masked_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> i32 {
    let handle = raw_arg(args, 0);
    let bitmap = raw_arg(args, 1);
    let transparent_color = raw_arg(args, 2);
    let Some(bitmap) = clone_bitmap_for_image_list(kernel, memory, thread_id, bitmap) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return -1;
    };
    let transparent_color = image_list_add_masked_color(kernel, memory, transparent_color, bitmap);
    let Some(mask) =
        create_image_list_mask_bitmap(kernel, memory, thread_id, bitmap, transparent_color)
    else {
        delete_owned_bitmap(kernel, bitmap);
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return -1;
    };
    match kernel.resources.add_masked_image_list_image_with_mask(
        handle,
        bitmap,
        mask,
        transparent_color,
    ) {
        Some(index) => {
            kernel.threads.set_last_error(thread_id, 0);
            index
        }
        None => {
            delete_owned_bitmap(kernel, bitmap);
            delete_owned_bitmap(kernel, mask);
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            -1
        }
    }
}

fn image_list_add_masked_color<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &M,
    transparent_color: u32,
    bitmap: u32,
) -> u32 {
    if transparent_color != CLR_DEFAULT {
        return transparent_color;
    }
    let Some(bitmap) = kernel.resources.bitmap(bitmap) else {
        return transparent_color;
    };
    let Some(bytes) = read_bitmap_object_bytes(memory, bitmap) else {
        return transparent_color;
    };
    match bitmap_pixel_rgb(bitmap, &bytes, 0, 0) {
        Some(rgb) => colorref_from_rgb(rgb),
        None => transparent_color,
    }
}

fn create_image_list_mask_bitmap<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bitmap: u32,
    transparent_color: u32,
) -> Option<u32> {
    if transparent_color == CLR_NONE {
        return Some(0);
    }
    let source = kernel.resources.bitmap(bitmap).cloned()?;
    let source_bytes = read_bitmap_object_bytes(memory, &source)?;
    let bits_per_row = source.width.unsigned_abs() as u64;
    let width_bytes = (((bits_per_row + 31) / 32) * 4).min(i32::MAX as u64) as u32;
    let byte_count = width_bytes.checked_mul(source.height as u32)?;
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return None;
    };
    let zeroes = vec![0; byte_count as usize];
    if !write_guest_bytes(kernel, memory, thread_id, bits_ptr, &zeroes) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return None;
    }
    let mask = kernel
        .resources
        .create_owned_bitmap(source.width, source.height, 1, 1, bits_ptr);
    if let Some(mask_bitmap) = kernel.resources.bitmap_mut(mask) {
        mask_bitmap.color_table = vec![[0, 0, 0, 0], [0xff, 0xff, 0xff, 0]];
    }
    let transparent_rgb = colorref_rgb(transparent_color);
    let mask_bitmap = kernel.resources.bitmap(mask).cloned()?;
    for y in 0..source.height {
        for x in 0..source.width {
            if bitmap_pixel_rgb(&source, &source_bytes, x, y) == Some(transparent_rgb) {
                let _ = write_bitmap_pixel_rgb(memory, &mask_bitmap, x, y, [0xff, 0xff, 0xff]);
                let _ = write_bitmap_pixel_rgb(memory, &source, x, y, [0, 0, 0]);
            }
        }
    }
    Some(mask)
}

fn image_list_replace_icon_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> i32 {
    let handle = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let icon = raw_arg(args, 2);
    let old_owned_bitmaps = image_list_owned_bitmap_handles(kernel, handle);
    if let Some(icon_obj) = kernel.resources.icon(icon).cloned() {
        let Some((bitmap, mask)) =
            snapshot_icon_for_image_list(kernel, memory, thread_id, handle, &icon_obj)
        else {
            return -1;
        };
        let result = if index < 0 {
            kernel
                .resources
                .add_masked_image_list_image_with_mask(handle, bitmap, mask, CLR_NONE)
                .map(|index| index >= 0)
        } else {
            kernel
                .resources
                .replace_image_list_image(handle, index, bitmap, mask)
        };
        match result {
            Some(true) => {
                delete_unreferenced_image_list_owned_bitmaps(kernel, handle, old_owned_bitmaps);
                kernel.threads.set_last_error(thread_id, 0);
                return if index < 0 {
                    kernel
                        .resources
                        .image_list_count(handle)
                        .and_then(|count| i32::try_from(count).ok())
                        .map(|count| count - 1)
                        .unwrap_or(-1)
                } else {
                    index
                };
            }
            Some(false) | None => {
                delete_owned_bitmap(kernel, bitmap);
                delete_owned_bitmap(kernel, mask);
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                return -1;
            }
        }
    }
    match kernel
        .resources
        .replace_image_list_icon(handle, index, icon)
    {
        Some(index) => {
            delete_unreferenced_image_list_owned_bitmaps(kernel, handle, old_owned_bitmaps);
            kernel.threads.set_last_error(thread_id, 0);
            index
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            -1
        }
    }
}

fn snapshot_icon_for_image_list<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    handle: u32,
    icon: &IconObject,
) -> Option<(u32, u32)> {
    const ILC_MASK: u32 = 0x0001;
    let list = kernel.resources.image_list(handle)?;
    if list.width <= 0 || list.height <= 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    let width = list.width;
    let height = list.height;
    let has_list_mask = list.flags & ILC_MASK != 0;
    let background = if list.bk_color == CLR_NONE || list.bk_color == CLR_DEFAULT {
        [0, 0, 0]
    } else {
        colorref_rgb(list.bk_color)
    };
    let source_color = kernel.resources.bitmap(icon.color_bitmap).cloned();
    let source_mask = kernel.resources.bitmap(icon.mask_bitmap).cloned();
    if source_color.is_none() && source_mask.is_none() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    let bitmap = create_blank_owned_bitmap(kernel, memory, thread_id, width, height, 32)?;
    let bitmap_obj = kernel.resources.bitmap(bitmap).cloned()?;
    for y in 0..height {
        for x in 0..width {
            let _ = write_bitmap_pixel_rgb(memory, &bitmap_obj, x, y, background);
        }
    }

    let color_bytes = source_color
        .as_ref()
        .and_then(|bitmap| read_bitmap_object_bytes(memory, bitmap));
    let mask_bytes = source_mask
        .as_ref()
        .and_then(|bitmap| read_bitmap_object_bytes(memory, bitmap));
    if let Some(source) = source_color.as_ref() {
        let copy_width = width.min(source.width.abs());
        let copy_height = height.min(source.height);
        for y in 0..copy_height {
            for x in 0..copy_width {
                let transparent = source_mask
                    .as_ref()
                    .zip(mask_bytes.as_ref())
                    .and_then(|(mask, bytes)| bitmap_pixel_rgb(mask, bytes, x, y))
                    .is_some_and(|rgb| rgb != [0, 0, 0]);
                if transparent {
                    continue;
                }
                if let Some(rgb) = color_bytes
                    .as_ref()
                    .and_then(|bytes| bitmap_pixel_rgb(source, bytes, x, y))
                {
                    let _ = write_bitmap_pixel_rgb(memory, &bitmap_obj, x, y, rgb);
                }
            }
        }
    }

    let mask = if has_list_mask {
        let mask = create_blank_owned_bitmap(kernel, memory, thread_id, width, height, 1)?;
        if let Some(mask_obj) = kernel.resources.bitmap_mut(mask) {
            mask_obj.color_table = vec![[0, 0, 0, 0], [0xff, 0xff, 0xff, 0]];
        }
        let mask_obj = kernel.resources.bitmap(mask).cloned()?;
        if let Some(source) = source_mask.as_ref() {
            let copy_width = width.min(source.width.abs());
            let copy_height = height.min(source.height);
            for y in 0..copy_height {
                for x in 0..copy_width {
                    if let Some(rgb) = mask_bytes
                        .as_ref()
                        .and_then(|bytes| bitmap_pixel_rgb(source, bytes, x, y))
                    {
                        let _ = write_bitmap_pixel_rgb(memory, &mask_obj, x, y, rgb);
                    }
                }
            }
        }
        mask
    } else {
        0
    };
    Some((bitmap, mask))
}

fn create_blank_owned_bitmap<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    width: i32,
    height: i32,
    bits_pixel: u16,
) -> Option<u32> {
    let bits_per_row = (width.unsigned_abs() as u64).checked_mul(u64::from(bits_pixel))?;
    let width_bytes = (((bits_per_row + 31) / 32) * 4).min(i32::MAX as u64) as u32;
    let byte_count = width_bytes.checked_mul(height.unsigned_abs())?;
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return None;
    };
    let zeroes = vec![0; byte_count as usize];
    if !write_guest_bytes(kernel, memory, thread_id, bits_ptr, &zeroes) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return None;
    }
    Some(
        kernel
            .resources
            .create_owned_bitmap(width, height, 1, bits_pixel, bits_ptr),
    )
}

fn image_list_replace_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let handle = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let bitmap = raw_arg(args, 2);
    let mask = raw_arg(args, 3);
    if index < 0 || bitmap == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(bitmap) = clone_bitmap_for_image_list(kernel, memory, thread_id, bitmap) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    let Some(mask) = clone_optional_bitmap_for_image_list(kernel, memory, thread_id, mask) else {
        delete_owned_bitmap(kernel, bitmap);
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    let old_owned_bitmaps = image_list_owned_bitmap_handles(kernel, handle);
    match kernel
        .resources
        .replace_image_list_image(handle, index, bitmap, mask)
    {
        Some(true) => {
            delete_unreferenced_image_list_owned_bitmaps(kernel, handle, old_owned_bitmaps);
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        Some(false) => {
            delete_owned_bitmap(kernel, bitmap);
            delete_owned_bitmap(kernel, mask);
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
        None => {
            delete_owned_bitmap(kernel, bitmap);
            delete_owned_bitmap(kernel, mask);
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn delete_unreferenced_image_list_owned_bitmaps(
    kernel: &mut CeKernel,
    handle: u32,
    candidates: Vec<u32>,
) {
    if candidates.is_empty() {
        return;
    }
    let referenced = image_list_bitmap_handle_set(kernel, handle);
    for bitmap in candidates {
        if !referenced.contains(&bitmap)
            && kernel
                .resources
                .bitmap(bitmap)
                .is_some_and(|object| object.bits_owned)
        {
            delete_owned_bitmap(kernel, bitmap);
        }
    }
}

fn image_list_bitmap_handle_set(kernel: &CeKernel, handle: u32) -> BTreeSet<u32> {
    let Some(list) = kernel.resources.image_list(handle) else {
        return BTreeSet::new();
    };
    list.images
        .iter()
        .flat_map(|image| [image.bitmap, image.mask])
        .filter(|handle| *handle != 0)
        .collect()
}

fn clone_optional_bitmap_for_image_list<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bitmap: u32,
) -> Option<u32> {
    if bitmap == 0 {
        Some(0)
    } else {
        clone_bitmap_for_image_list(kernel, memory, thread_id, bitmap)
    }
}

fn clone_bitmap_for_image_list<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bitmap: u32,
) -> Option<u32> {
    let Some(source) = kernel.resources.bitmap(bitmap).cloned() else {
        return Some(bitmap);
    };
    if source.bits_ptr == 0 {
        return Some(bitmap);
    }
    let bytes = read_bitmap_object_bytes(memory, &source)?;
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, bytes.len() as u32)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return None;
    };
    if !write_guest_bytes(kernel, memory, thread_id, bits_ptr, &bytes) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return None;
    }
    let height = if source.top_down {
        -source.height
    } else {
        source.height
    };
    let clone = kernel.resources.create_owned_bitmap_with_masks(
        source.width,
        height,
        source.planes,
        source.bits_pixel,
        bits_ptr,
        source.rgb_masks,
    );
    if let Some(clone_bitmap) = kernel.resources.bitmap_mut(clone) {
        clone_bitmap.color_table = source.color_table;
        clone_bitmap.alpha_mask = source.alpha_mask;
    }
    Some(clone)
}

fn image_list_remove_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let handle = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let old_owned_bitmaps = image_list_owned_bitmap_handles(kernel, handle);
    match kernel.resources.remove_image_list_image(handle, index) {
        Some(true) => {
            delete_unreferenced_image_list_owned_bitmaps(kernel, handle, old_owned_bitmaps);
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        Some(false) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

