fn image_list_get_count_raw(kernel: &mut CeKernel, thread_id: u32, handle: u32) -> u32 {
    if is_shell_system_image_list_handle(handle) {
        kernel.threads.set_last_error(thread_id, 0);
        return SHELL_SYSTEM_IMAGE_LIST_COUNT;
    }
    match kernel.resources.image_list_count(handle) {
        Some(count) => {
            kernel.threads.set_last_error(thread_id, 0);
            count as u32
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            0
        }
    }
}

fn image_list_get_icon_size_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let handle = raw_arg(args, 0);
    let cx_ptr = raw_arg(args, 1);
    let cy_ptr = raw_arg(args, 2);
    if cx_ptr == 0 || cy_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let size = if let Some(size) = shell_system_image_list_size(handle) {
        Some(size)
    } else {
        kernel
            .resources
            .image_list(handle)
            .map(|list| (list.width, list.height))
    };
    let Some((cx, cy)) = size else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    if !write_guest_i32(kernel, memory, thread_id, cx_ptr, cx)
        || !write_guest_i32(kernel, memory, thread_id, cy_ptr, cy)
    {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn image_list_get_icon_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let handle = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let flags = raw_arg(args, 2);
    if is_shell_system_image_list_handle(handle) {
        if index < 0 || index as u32 >= SHELL_SYSTEM_IMAGE_LIST_COUNT {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return shell_icon_handle_with_flags(index, flags);
    }
    let Some(list) = kernel.resources.image_list(handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(image) = (index >= 0)
        .then(|| list.images.get(index as usize))
        .flatten()
        .cloned()
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if image.bitmap != 0 && kernel.resources.bitmap(image.bitmap).is_some() {
        let width = list.width;
        let height = list.height;
        if let Some(icon) = create_icon_from_image_list_bitmap_entry(
            kernel, memory, thread_id, handle, index, flags, width, height,
        ) {
            kernel.threads.set_last_error(thread_id, 0);
            return icon;
        }
        if kernel.threads.get_last_error(thread_id) == 0 {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        }
        return 0;
    }
    match kernel.resources.image_list_icon(handle, index, 0, flags) {
        Some(icon) if icon != 0 => {
            kernel.threads.set_last_error(thread_id, 0);
            icon
        }
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            0
        }
    }
}

fn create_icon_from_image_list_bitmap_entry<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    handle: u32,
    index: i32,
    flags: u32,
    width: i32,
    height: i32,
) -> Option<u32> {
    const ILD_MASK: u32 = 0x0010;
    const ILD_TRANSPARENT: u32 = 0x0001;
    if width <= 0 || height <= 0 {
        return None;
    }
    let color_bitmap = create_owned_zeroed_bitmap(kernel, memory, thread_id, width, height, 32)?;
    let mask_bitmap = match create_owned_zeroed_bitmap(kernel, memory, thread_id, width, height, 1)
    {
        Some(bitmap) => bitmap,
        None => {
            delete_owned_bitmap(kernel, color_bitmap);
            return None;
        }
    };
    if let Some(mask) = kernel.resources.bitmap_mut(mask_bitmap) {
        mask.color_table = vec![[0x00, 0x00, 0x00, 0x00], [0xff, 0xff, 0xff, 0x00]];
    }

    let hdc = kernel.resources.create_compatible_dc();
    let _ = kernel.resources.select_object(hdc, mask_bitmap);
    let mask_draw = ImageListDraw {
        image_list: handle,
        index,
        hdc,
        x: 0,
        y: 0,
        width,
        height,
        x_bitmap: 0,
        y_bitmap: 0,
        rgb_bk: CLR_DEFAULT,
        rgb_fg: CLR_DEFAULT,
        flags: ILD_MASK | flags,
        rop: 0,
        overlay_image: None,
    };
    let mask_ok = render_image_list_draw_bitmap(kernel, memory, mask_draw);

    let _ = kernel.resources.select_object(hdc, color_bitmap);
    let color_draw = ImageListDraw {
        flags: ILD_TRANSPARENT | flags,
        ..mask_draw
    };
    let color_ok = render_image_list_draw_bitmap(kernel, memory, color_draw);
    let _ = kernel.resources.delete_dc(hdc);

    if !mask_ok || !color_ok {
        delete_owned_bitmap(kernel, mask_bitmap);
        delete_owned_bitmap(kernel, color_bitmap);
        return None;
    }
    match kernel.resources.create_icon_with_bitmap_ownership(
        true,
        0,
        0,
        mask_bitmap,
        color_bitmap,
        true,
        true,
    ) {
        Some(icon) => Some(icon),
        None => {
            delete_owned_bitmap(kernel, mask_bitmap);
            delete_owned_bitmap(kernel, color_bitmap);
            None
        }
    }
}

fn create_owned_zeroed_bitmap<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    width: i32,
    height: i32,
    bits_pixel: u16,
) -> Option<u32> {
    let byte_count = bitmap_byte_count(width, height, bits_pixel)?;
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return None;
    };
    let zeroes = vec![0; byte_count as usize];
    if !write_guest_bytes(kernel, memory, thread_id, bits_ptr, &zeroes) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return None;
    }
    Some(
        kernel
            .resources
            .create_owned_bitmap(width, height, 1, bits_pixel, bits_ptr),
    )
}

fn image_list_get_image_info_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let handle = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let info_ptr = raw_arg(args, 2);
    if info_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let info = if let Some((width, height)) = shell_system_image_list_size(handle) {
        if index < 0 || index as u32 >= SHELL_SYSTEM_IMAGE_LIST_COUNT {
            None
        } else {
            let left = index.saturating_mul(width);
            Some((
                shell_system_image_bitmap_handle(index),
                0,
                left,
                0,
                left.saturating_add(width),
                height,
            ))
        }
    } else {
        kernel.resources.image_list_info(handle, index).map(|info| {
            (
                info.bitmap,
                info.mask,
                info.left,
                info.top,
                info.right,
                info.bottom,
            )
        })
    };
    let Some((bitmap, mask, left, top, right, bottom)) = info else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    if !write_guest_u32(kernel, memory, thread_id, info_ptr, bitmap)
        || !write_guest_u32(kernel, memory, thread_id, info_ptr.wrapping_add(4), mask)
        || !write_guest_u32(kernel, memory, thread_id, info_ptr.wrapping_add(8), 0)
        || !write_guest_u32(kernel, memory, thread_id, info_ptr.wrapping_add(12), 0)
        || !write_guest_i32(kernel, memory, thread_id, info_ptr.wrapping_add(16), left)
        || !write_guest_i32(kernel, memory, thread_id, info_ptr.wrapping_add(20), top)
        || !write_guest_i32(kernel, memory, thread_id, info_ptr.wrapping_add(24), right)
        || !write_guest_i32(kernel, memory, thread_id, info_ptr.wrapping_add(28), bottom)
    {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn image_list_set_bk_color_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let handle = raw_arg(args, 0);
    let color = raw_arg(args, 1);
    if is_shell_system_image_list_handle(handle) {
        kernel.threads.set_last_error(thread_id, 0);
        return CLR_NONE;
    }
    match kernel.resources.set_image_list_bk_color(handle, color) {
        Some(previous) => {
            if previous != color {
                reset_image_list_bitmap_bk_color(kernel, memory, handle, color);
            }
            kernel.threads.set_last_error(thread_id, 0);
            previous
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            CLR_NONE
        }
    }
}

fn reset_image_list_bitmap_bk_color<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    handle: u32,
    color: u32,
) {
    const ILC_MASK: u32 = 0x0001;
    const ILC_VIRTUAL: u32 = 0x8000;
    let Some(list) = kernel.resources.image_list(handle) else {
        return;
    };
    if list.flags & ILC_MASK == 0 || list.flags & ILC_VIRTUAL != 0 {
        return;
    }
    let fill = if color == CLR_NONE || color == 0 {
        [0, 0, 0]
    } else if color == 0x00ff_ffff {
        [0xff, 0xff, 0xff]
    } else {
        colorref_rgb(color)
    };
    for image in &list.images {
        let Some((bitmap_handle, mask_handle)) = image_list_image_bitmap_handles(kernel, image)
        else {
            continue;
        };
        if mask_handle == 0 {
            continue;
        }
        let Some(bitmap) = kernel.resources.bitmap(bitmap_handle).cloned() else {
            continue;
        };
        let Some(mask) = kernel.resources.bitmap(mask_handle).cloned() else {
            continue;
        };
        for row in 0..list.height {
            let y = image.source_y.saturating_add(row);
            for col in 0..list.width {
                let x = image.source_x.saturating_add(col);
                if mask_bitmap_pixel_on(memory, &mask, x, y) == Some(true) {
                    let _ = write_bitmap_pixel_rgb(memory, &bitmap, x, y, fill);
                }
            }
        }
    }
}

fn image_list_get_bk_color_raw(kernel: &mut CeKernel, thread_id: u32, handle: u32) -> u32 {
    if is_shell_system_image_list_handle(handle) {
        kernel.threads.set_last_error(thread_id, 0);
        return CLR_NONE;
    }
    match kernel.resources.image_list(handle) {
        Some(list) => {
            kernel.threads.set_last_error(thread_id, 0);
            list.bk_color
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            CLR_NONE
        }
    }
}

fn image_list_draw_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let handle = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let hdc = raw_arg(args, 2);
    let x = raw_i32_arg(args, 3);
    let y = raw_i32_arg(args, 4);
    let flags = raw_arg(args, 5);
    let (width, height) = if let Some(size) = shell_system_image_list_size(handle) {
        size
    } else if let Some(list) = kernel.resources.image_list(handle) {
        (list.width, list.height)
    } else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let draw = normalize_image_list_draw(
        kernel,
        ImageListDraw {
            image_list: handle,
            index,
            hdc,
            x,
            y,
            width,
            height,
            flags,
            overlay_image: None,
            rgb_fg: CLR_DEFAULT,
            rgb_bk: CLR_DEFAULT,
            x_bitmap: 0,
            y_bitmap: 0,
            rop: SRCCOPY,
        },
    );
    let rendered = record_image_list_draw(kernel, thread_id, draw);
    if rendered {
        record_image_list_draw_dispperf(kernel, draw);
        if !render_image_list_draw_bitmap(kernel, memory, draw) {
            render_image_list_draw_framebuffer(kernel, memory, framebuffer, draw);
        }
    }
    rendered
}

fn image_list_draw_ex_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let handle = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let hdc = raw_arg(args, 2);
    let x = raw_i32_arg(args, 3);
    let y = raw_i32_arg(args, 4);
    let width = raw_i32_arg(args, 5);
    let height = raw_i32_arg(args, 6);
    let rgb_bk = raw_arg(args, 7);
    let rgb_fg = raw_arg(args, 8);
    let raw_flags = raw_arg(args, 9);
    if !is_shell_system_image_list_handle(handle) && kernel.resources.image_list(handle).is_none() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    let draw = normalize_image_list_draw(
        kernel,
        ImageListDraw {
            image_list: handle,
            index,
            hdc,
            x,
            y,
            width,
            height,
            flags: raw_flags,
            overlay_image: None,
            rgb_fg,
            rgb_bk,
            x_bitmap: 0,
            y_bitmap: 0,
            rop: SRCCOPY,
        },
    );
    let rendered = record_image_list_draw(kernel, thread_id, draw);
    if rendered {
        record_image_list_draw_dispperf(kernel, draw);
        if !render_image_list_draw_bitmap(kernel, memory, draw) {
            render_image_list_draw_framebuffer(kernel, memory, framebuffer, draw);
        }
    }
    rendered
}

fn image_list_draw_indirect_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    draw_ptr: u32,
) -> bool {
    if draw_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(size) = read_guest_u32(kernel, memory, thread_id, draw_ptr) else {
        return false;
    };
    const IMAGELISTDRAWPARAMS_SIZE: u32 = 56;
    if size != IMAGELISTDRAWPARAMS_SIZE {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(handle) = read_guest_u32(kernel, memory, thread_id, draw_ptr.wrapping_add(4)) else {
        return false;
    };
    let Some(index) = read_guest_i32(kernel, memory, thread_id, draw_ptr.wrapping_add(8)) else {
        return false;
    };
    let Some(hdc) = read_guest_u32(kernel, memory, thread_id, draw_ptr.wrapping_add(12)) else {
        return false;
    };
    let Some(x) = read_guest_i32(kernel, memory, thread_id, draw_ptr.wrapping_add(16)) else {
        return false;
    };
    let Some(y) = read_guest_i32(kernel, memory, thread_id, draw_ptr.wrapping_add(20)) else {
        return false;
    };
    let Some(width) = read_guest_i32(kernel, memory, thread_id, draw_ptr.wrapping_add(24)) else {
        return false;
    };
    let Some(height) = read_guest_i32(kernel, memory, thread_id, draw_ptr.wrapping_add(28)) else {
        return false;
    };
    // IMAGELISTDRAWPARAMS layout (all 4-byte fields):
    //  @0  cbSize, @4 himl, @8 i, @12 hdcDst, @16 x, @20 y, @24 cx, @28 cy
    //  @32 xBitmap, @36 yBitmap, @40 rgbBk, @44 rgbFg, @48 fStyle, @52 dwRop
    // xBitmap/yBitmap are added to the image source rect per CE imagelist.cpp DrawIndirect.
    let x_bitmap =
        read_guest_i32(kernel, memory, thread_id, draw_ptr.wrapping_add(32)).unwrap_or(0);
    let y_bitmap =
        read_guest_i32(kernel, memory, thread_id, draw_ptr.wrapping_add(36)).unwrap_or(0);
    let rgb_bk =
        read_guest_u32(kernel, memory, thread_id, draw_ptr.wrapping_add(40)).unwrap_or(CLR_NONE);
    let rgb_fg =
        read_guest_u32(kernel, memory, thread_id, draw_ptr.wrapping_add(44)).unwrap_or(CLR_DEFAULT);
    let raw_flags =
        read_guest_u32(kernel, memory, thread_id, draw_ptr.wrapping_add(48)).unwrap_or(0);
    let rop = read_guest_u32(kernel, memory, thread_id, draw_ptr.wrapping_add(52)).unwrap_or(0);
    let draw = normalize_image_list_draw(
        kernel,
        ImageListDraw {
            image_list: handle,
            index,
            hdc,
            x,
            y,
            width,
            height,
            flags: raw_flags,
            overlay_image: None,
            rgb_fg,
            rgb_bk,
            x_bitmap,
            y_bitmap,
            rop,
        },
    );
    let rendered = record_image_list_draw(kernel, thread_id, draw);
    if rendered {
        record_image_list_draw_dispperf(kernel, draw);
        let visible_params = image_list_draw_indirect_visible_params(kernel, draw);
        if !write_image_list_draw_indirect_normalized_params(
            kernel,
            memory,
            thread_id,
            draw_ptr,
            visible_params,
        ) {
            return false;
        }
        if !render_image_list_draw_bitmap(kernel, memory, draw) {
            render_image_list_draw_framebuffer(kernel, memory, framebuffer, draw);
        }
    }
    rendered
}

fn image_list_draw_indirect_visible_params(
    kernel: &CeKernel,
    draw: ImageListDraw,
) -> ImageListDraw {
    const ILD_MASK: u32 = 0x0010;
    const ILD_TRANSPARENT: u32 = 0x0001;
    const ILD_OVERLAYMASK: u32 = 0x0000_0f00;

    if draw.flags & ILD_OVERLAYMASK == 0 {
        return draw;
    }
    let Some(list) = kernel.resources.image_list(draw.image_list) else {
        return draw;
    };
    let Some(overlay) = image_list_overlay_record(list, draw) else {
        return draw;
    };
    ImageListDraw {
        index: overlay.image_index,
        x: draw.x.saturating_add(overlay.x),
        y: draw.y.saturating_add(overlay.y),
        width: overlay.width,
        height: overlay.height,
        flags: (draw.flags & ILD_MASK) | ILD_TRANSPARENT | overlay.flags,
        ..draw
    }
}

fn write_image_list_draw_indirect_normalized_params<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    draw_ptr: u32,
    draw: ImageListDraw,
) -> bool {
    write_guest_u32(
        kernel,
        memory,
        thread_id,
        draw_ptr.wrapping_add(8),
        draw.index as u32,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        draw_ptr.wrapping_add(16),
        draw.x as u32,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        draw_ptr.wrapping_add(20),
        draw.y as u32,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        draw_ptr.wrapping_add(24),
        draw.width as u32,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        draw_ptr.wrapping_add(28),
        draw.height as u32,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        draw_ptr.wrapping_add(40),
        draw.rgb_bk,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        draw_ptr.wrapping_add(48),
        draw.flags,
    )
}

fn normalize_image_list_draw(kernel: &CeKernel, mut draw: ImageListDraw) -> ImageListDraw {
    const ILD_TRANSPARENT: u32 = 0x0001;
    const ILD_BLENDMASK: u32 = 0x000e;
    let (default_width, default_height, bk_color) =
        if let Some((width, height)) = shell_system_image_list_size(draw.image_list) {
            (width, height, CLR_NONE)
        } else if let Some(list) = kernel.resources.image_list(draw.image_list) {
            (list.width, list.height, list.bk_color)
        } else {
            (draw.width, draw.height, CLR_NONE)
        };
    if draw.rgb_bk == CLR_DEFAULT {
        draw.rgb_bk = bk_color;
    }
    if draw.rgb_bk == CLR_NONE {
        draw.flags |= ILD_TRANSPARENT;
    }
    if draw.rgb_fg == CLR_NONE && draw.flags & ILD_BLENDMASK != 0 {
        draw.flags |= ILD_TRANSPARENT;
    }
    if draw.width == 0 {
        draw.width = default_width.saturating_sub(draw.x_bitmap);
    }
    if draw.height == 0 {
        draw.height = default_height.saturating_sub(draw.y_bitmap);
    }
    draw
}

fn render_image_list_draw_framebuffer<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &M,
    framebuffer: Option<&mut dyn Framebuffer>,
    draw: ImageListDraw,
) {
    let Some(framebuffer) = framebuffer else {
        return;
    };
    let (default_width, default_height) =
        if let Some(size) = shell_system_image_list_size(draw.image_list) {
            size
        } else if let Some(list) = kernel.resources.image_list(draw.image_list) {
            (list.width, list.height)
        } else {
            return;
        };
    let width = if draw.width > 0 {
        draw.width
    } else {
        default_width
    };
    let height = if draw.height > 0 {
        draw.height
    } else {
        default_height
    };
    if width <= 0 || height <= 0 {
        return;
    }
    if render_image_list_bitmap_framebuffer(kernel, memory, &mut *framebuffer, draw, width, height)
    {
        return;
    }
    let Some(pseudo) = pseudo_image_list_draw(draw, width, height) else {
        return;
    };
    fill_framebuffer_rect_for_hdc(
        kernel,
        framebuffer,
        draw.hdc,
        pseudo.border,
        pseudo.border_color,
    );
    if let Some(body) = pseudo.body {
        fill_framebuffer_rect_for_hdc(kernel, framebuffer, draw.hdc, body.rect, body.color);
    }
    if let Some(overlay) = pseudo.overlay_outer {
        fill_framebuffer_rect_for_hdc(kernel, framebuffer, draw.hdc, overlay.rect, overlay.color);
    }
    if let Some(overlay) = pseudo.overlay_inner {
        fill_framebuffer_rect_for_hdc(kernel, framebuffer, draw.hdc, overlay.rect, overlay.color);
    }
}

fn render_image_list_draw_bitmap<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    draw: ImageListDraw,
) -> bool {
    if !kernel.resources.is_memory_dc(draw.hdc) {
        return false;
    }
    let (default_width, default_height) =
        if let Some(size) = shell_system_image_list_size(draw.image_list) {
            size
        } else if let Some(list) = kernel.resources.image_list(draw.image_list) {
            (list.width, list.height)
        } else {
            return true;
        };
    let width = if draw.width > 0 {
        draw.width
    } else {
        default_width
    };
    let height = if draw.height > 0 {
        draw.height
    } else {
        default_height
    };
    if width <= 0 || height <= 0 {
        return true;
    }
    if render_image_list_bitmap_hdc(kernel, memory, draw, width, height) {
        return true;
    }
    let Some(pseudo) = pseudo_image_list_draw(draw, width, height) else {
        return true;
    };
    let _ = fill_bitmap_rect_for_hdc(
        kernel,
        memory,
        draw.hdc,
        pseudo.border,
        BrushPaint::Solid(pseudo.border_color),
    );
    if let Some(body) = pseudo.body {
        let _ = fill_bitmap_rect_for_hdc(
            kernel,
            memory,
            draw.hdc,
            body.rect,
            BrushPaint::Solid(body.color),
        );
    }
    if let Some(overlay) = pseudo.overlay_outer {
        let _ = fill_bitmap_rect_for_hdc(
            kernel,
            memory,
            draw.hdc,
            overlay.rect,
            BrushPaint::Solid(overlay.color),
        );
    }
    if let Some(overlay) = pseudo.overlay_inner {
        let _ = fill_bitmap_rect_for_hdc(
            kernel,
            memory,
            draw.hdc,
            overlay.rect,
            BrushPaint::Solid(overlay.color),
        );
    }
    true
}

#[derive(Debug, Clone, Copy)]
struct PseudoImageListFill {
    rect: Rect,
    color: u32,
}

#[derive(Debug, Clone, Copy)]
struct PseudoImageListDraw {
    border: Rect,
    border_color: u32,
    body: Option<PseudoImageListFill>,
    overlay_outer: Option<PseudoImageListFill>,
    overlay_inner: Option<PseudoImageListFill>,
}

fn pseudo_image_list_draw(
    draw: ImageListDraw,
    width: i32,
    height: i32,
) -> Option<PseudoImageListDraw> {
    if width <= 0 || height <= 0 {
        return None;
    }
    let mut pseudo = PseudoImageListDraw {
        border: Rect::from_origin_size(draw.x, draw.y, width, height),
        border_color: rgb(0x00, 0x00, 0x00),
        body: None,
        overlay_outer: None,
        overlay_inner: None,
    };
    if width <= 2 || height <= 2 {
        return Some(pseudo);
    }
    let seed = draw
        .index
        .max(0)
        .unsigned_abs()
        .wrapping_mul(37)
        .wrapping_add(draw.image_list.rotate_left(5));
    let body = rgb(
        0x40 + (seed & 0x7f),
        0x50 + ((seed >> 4) & 0x7f),
        0x60 + ((seed >> 8) & 0x7f),
    );
    pseudo.body = Some(PseudoImageListFill {
        rect: Rect::from_origin_size(draw.x + 1, draw.y + 1, width - 2, height - 2),
        color: body,
    });
    let overlay = draw
        .overlay_image
        .map(|overlay| overlay.saturating_add(1) as u32)
        .unwrap_or((draw.flags >> 8) & 0x0f);
    let overlay = if (1..=4).contains(&overlay) {
        overlay
    } else {
        0
    };
    if overlay != 0 && width >= 6 && height >= 6 {
        pseudo.overlay_outer = Some(PseudoImageListFill {
            rect: Rect::from_origin_size(draw.x + width - 5, draw.y + height - 5, 4, 4),
            color: rgb(0xff, 0xff, 0xff),
        });
        pseudo.overlay_inner = Some(PseudoImageListFill {
            rect: Rect::from_origin_size(draw.x + width - 4, draw.y + height - 4, 2, 2),
            color: rgb(0x00, 0x80, 0x00),
        });
    }
    Some(pseudo)
}

fn render_image_list_bitmap_framebuffer<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &M,
    framebuffer: &mut dyn Framebuffer,
    draw: ImageListDraw,
    width: i32,
    height: i32,
) -> bool {
    const ILD_MASK: u32 = 0x0010;
    const ILD_IMAGE: u32 = 0x0020;

    if is_shell_system_image_list_handle(draw.image_list) || draw.index < 0 {
        return false;
    }
    let Some(list) = kernel.resources.image_list(draw.image_list) else {
        return false;
    };
    let Some(image) = list.images.get(draw.index as usize) else {
        return false;
    };
    let draw_flags = draw.flags & 0x00ff;
    const ILD_TRANSPARENT: u32 = 0x0001;
    let rop = image_list_draw_rop(draw_flags, draw.rop);
    // Apply ILD draw flags to the effective image: ILD_MASK draws only the mask
    // bitmap; ILD_IMAGE suppresses mask and transparent-color transparency.
    // Also apply xBitmap/yBitmap source offsets from DrawIndirect.
    let mask_only = draw_flags & ILD_MASK != 0 && image.mask != 0;
    let effective_image = if mask_only {
        crate::ce::resource::ImageListImage {
            bitmap: image.mask,
            mask: 0,
            source_x: image.source_x + draw.x_bitmap,
            source_y: image.source_y + draw.y_bitmap,
            ..image.clone()
        }
    } else if draw_flags & ILD_IMAGE != 0 {
        crate::ce::resource::ImageListImage {
            mask: 0,
            transparent_color: None,
            source_x: image.source_x + draw.x_bitmap,
            source_y: image.source_y + draw.y_bitmap,
            ..image.clone()
        }
    } else {
        crate::ce::resource::ImageListImage {
            source_x: image.source_x + draw.x_bitmap,
            source_y: image.source_y + draw.y_bitmap,
            ..image.clone()
        }
    };
    // When ILD_TRANSPARENT is not set and a background color is specified, CE fills
    // the transparent areas with rgb_bk (via ROP_PatMask on the mask + SRCCOPY).
    // We approximate this by pre-filling the dest rect with rgb_bk so that pixels
    // not overwritten by the image (transparent) show the background color.
    if draw_flags & ILD_TRANSPARENT == 0 && draw.rgb_bk != CLR_NONE {
        let dest_rect = Rect::from_origin_size(draw.x, draw.y, width, height);
        fill_framebuffer_rect_for_hdc(kernel, framebuffer, draw.hdc, dest_rect, draw.rgb_bk);
    }
    let src_width = list.width.max(1);
    let src_height = list.height.max(1);
    let blend = ild_blend_mode(draw_flags, draw.rgb_fg, mask_only);
    let image_color_table =
        (!mask_only && !list.color_table.is_empty()).then_some(list.color_table.as_slice());
    if !render_image_list_bitmap_entry_framebuffer(
        kernel,
        memory,
        framebuffer,
        draw.hdc,
        draw.x,
        draw.y,
        width,
        height,
        src_width,
        src_height,
        &effective_image,
        image_color_table,
        blend,
        rop,
    ) {
        return false;
    }

    let overlay_record = image_list_overlay_record(list, draw);
    if let Some(overlay_record) = overlay_record
        && let Some(overlay) = list.images.get(overlay_record.image_index as usize)
    {
        let mut overlay = overlay.clone();
        overlay.source_x = overlay.source_x.saturating_add(overlay_record.x);
        overlay.source_y = overlay.source_y.saturating_add(overlay_record.y);
        if draw_flags & ILD_MASK != 0 {
            if overlay.mask == 0 {
                return true;
            }
            overlay.bitmap = overlay.mask;
            overlay.mask = 0;
            overlay.transparent_color = None;
        } else if overlay_record.flags & ILD_IMAGE != 0 {
            overlay.mask = 0;
            overlay.transparent_color = None;
        }
        let overlay_color_table = (draw_flags & ILD_MASK == 0 && !list.color_table.is_empty())
            .then_some(list.color_table.as_slice());
        let _ = render_image_list_bitmap_entry_framebuffer(
            kernel,
            memory,
            framebuffer,
            draw.hdc,
            draw.x.saturating_add(overlay_record.x),
            draw.y.saturating_add(overlay_record.y),
            overlay_record.width,
            overlay_record.height,
            overlay_record.width.max(1),
            overlay_record.height.max(1),
            &overlay,
            overlay_color_table,
            None, // overlay not blended
            None,
        );
    }
    true
}

fn render_image_list_bitmap_hdc<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    draw: ImageListDraw,
    width: i32,
    height: i32,
) -> bool {
    const ILD_MASK: u32 = 0x0010;
    const ILD_IMAGE: u32 = 0x0020;

    if is_shell_system_image_list_handle(draw.image_list) || draw.index < 0 {
        return false;
    }
    let Some(list) = kernel.resources.image_list(draw.image_list) else {
        return false;
    };
    let Some(image) = list.images.get(draw.index as usize) else {
        return false;
    };
    let draw_flags = draw.flags & 0x00ff;
    const ILD_TRANSPARENT: u32 = 0x0001;
    let rop = image_list_draw_rop(draw_flags, draw.rop);
    // Apply ILD draw flags and xBitmap/yBitmap source offsets from DrawIndirect.
    let mask_only = draw_flags & ILD_MASK != 0 && image.mask != 0;
    let effective_image = if mask_only {
        crate::ce::resource::ImageListImage {
            bitmap: image.mask,
            mask: 0,
            source_x: image.source_x + draw.x_bitmap,
            source_y: image.source_y + draw.y_bitmap,
            ..image.clone()
        }
    } else if draw_flags & ILD_IMAGE != 0 {
        crate::ce::resource::ImageListImage {
            mask: 0,
            transparent_color: None,
            source_x: image.source_x + draw.x_bitmap,
            source_y: image.source_y + draw.y_bitmap,
            ..image.clone()
        }
    } else {
        crate::ce::resource::ImageListImage {
            source_x: image.source_x + draw.x_bitmap,
            source_y: image.source_y + draw.y_bitmap,
            ..image.clone()
        }
    };
    // Pre-fill dest rect with rgb_bk so transparent pixels show the background color.
    if draw_flags & ILD_TRANSPARENT == 0 && draw.rgb_bk != CLR_NONE {
        let dest_rect = Rect::from_origin_size(draw.x, draw.y, width, height);
        let _ = fill_bitmap_rect_for_hdc(
            kernel,
            memory,
            draw.hdc,
            dest_rect,
            BrushPaint::Solid(draw.rgb_bk),
        );
    }
    let src_width = list.width.max(1);
    let src_height = list.height.max(1);
    let blend = ild_blend_mode(draw_flags, draw.rgb_fg, mask_only);
    let image_color_table =
        (!mask_only && !list.color_table.is_empty()).then_some(list.color_table.as_slice());
    if !render_image_list_bitmap_entry_hdc(
        kernel,
        memory,
        draw.hdc,
        draw.x,
        draw.y,
        width,
        height,
        src_width,
        src_height,
        &effective_image,
        image_color_table,
        blend,
        rop,
    ) {
        return false;
    }

    let overlay_record = image_list_overlay_record(list, draw);
    if let Some(overlay_record) = overlay_record
        && let Some(overlay) = list.images.get(overlay_record.image_index as usize)
    {
        let mut overlay = overlay.clone();
        overlay.source_x = overlay.source_x.saturating_add(overlay_record.x);
        overlay.source_y = overlay.source_y.saturating_add(overlay_record.y);
        if draw_flags & ILD_MASK != 0 {
            if overlay.mask == 0 {
                return true;
            }
            overlay.bitmap = overlay.mask;
            overlay.mask = 0;
            overlay.transparent_color = None;
        } else if overlay_record.flags & ILD_IMAGE != 0 {
            overlay.mask = 0;
            overlay.transparent_color = None;
        }
        let overlay_color_table = (draw_flags & ILD_MASK == 0 && !list.color_table.is_empty())
            .then_some(list.color_table.as_slice());
        let _ = render_image_list_bitmap_entry_hdc(
            kernel,
            memory,
            draw.hdc,
            draw.x.saturating_add(overlay_record.x),
            draw.y.saturating_add(overlay_record.y),
            overlay_record.width,
            overlay_record.height,
            overlay_record.width.max(1),
            overlay_record.height.max(1),
            &overlay,
            overlay_color_table,
            None, // overlay not blended
            None,
        );
    }
    true
}

fn image_list_overlay_record(
    list: &crate::ce::resource::ImageListObject,
    draw: ImageListDraw,
) -> Option<crate::ce::resource::ImageListOverlay> {
    draw.overlay_image
        .map(|image_index| crate::ce::resource::ImageListOverlay {
            image_index,
            x: 0,
            y: 0,
            width: list.width,
            height: list.height,
            flags: 0,
        })
        .or_else(|| {
            let overlay = (draw.flags & 0x0000_0f00) >> 8;
            if overlay == 0 {
                None
            } else {
                list.overlays.get(&overlay).copied()
            }
        })
}

fn render_image_list_bitmap_entry_framebuffer<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &M,
    framebuffer: &mut dyn Framebuffer,
    hdc: u32,
    dst_x: i32,
    dst_y: i32,
    dst_width: i32,
    dst_height: i32,
    src_width: i32,
    src_height: i32,
    image: &crate::ce::resource::ImageListImage,
    image_color_table: Option<&[[u8; 4]]>,
    blend: Option<ImageListBlend>,
    rop: Option<u32>,
) -> bool {
    // Resolve the bitmap: prefer image.bitmap, fall back to icon color_bitmap.
    let (bitmap_handle, mask_handle) = if image.bitmap != 0 {
        (image.bitmap, image.mask)
    } else if image.icon != 0 {
        let Some(icon) = kernel.resources.icon(image.icon) else {
            return false;
        };
        if icon.color_bitmap == 0 {
            return false;
        }
        (icon.color_bitmap, icon.mask_bitmap)
    } else {
        return false;
    };
    let Some(bitmap) = kernel.resources.bitmap(bitmap_handle) else {
        return false;
    };
    let Some(bitmap_bytes) = read_bitmap_object_bytes(memory, bitmap) else {
        return false;
    };
    let effective_mask = if image.bitmap != 0 {
        image.mask
    } else {
        mask_handle
    };
    let mask_bitmap_bytes = if effective_mask != 0 {
        kernel
            .resources
            .bitmap(effective_mask)
            .and_then(|mask| read_bitmap_object_bytes(memory, mask).map(|bytes| (mask, bytes)))
    } else {
        None
    };
    draw_bitmap_bytes_to_framebuffer(
        kernel,
        framebuffer,
        hdc,
        dst_x,
        dst_y,
        dst_width,
        dst_height,
        image.source_x,
        image.source_y,
        src_width,
        src_height,
        bitmap,
        &bitmap_bytes,
        image_color_table,
        mask_bitmap_bytes
            .as_ref()
            .map(|(mask, bytes)| (*mask, bytes.as_slice())),
        image.transparent_color.map(colorref_rgb),
        blend,
        None,
        rop,
    );
    true
}

fn render_image_list_bitmap_entry_hdc<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    hdc: u32,
    dst_x: i32,
    dst_y: i32,
    dst_width: i32,
    dst_height: i32,
    src_width: i32,
    src_height: i32,
    image: &crate::ce::resource::ImageListImage,
    image_color_table: Option<&[[u8; 4]]>,
    blend: Option<ImageListBlend>,
    rop: Option<u32>,
) -> bool {
    let (bitmap_handle, mask_handle) = if image.bitmap != 0 {
        (image.bitmap, image.mask)
    } else if image.icon != 0 {
        let Some(icon) = kernel.resources.icon(image.icon) else {
            return false;
        };
        if icon.color_bitmap == 0 {
            return false;
        }
        (icon.color_bitmap, icon.mask_bitmap)
    } else {
        return false;
    };
    let Some(src_bitmap) = kernel.resources.bitmap(bitmap_handle) else {
        return false;
    };
    let Some(src_bytes) = read_bitmap_object_bytes(memory, src_bitmap) else {
        return false;
    };
    let effective_mask = if image.bitmap != 0 {
        image.mask
    } else {
        mask_handle
    };
    let mask_bitmap_bytes = if effective_mask != 0 {
        kernel
            .resources
            .bitmap(effective_mask)
            .and_then(|mask| read_bitmap_object_bytes(memory, mask).map(|bytes| (mask, bytes)))
    } else {
        None
    };
    let Some(dst_bitmap) = selected_bitmap_object(kernel, hdc) else {
        return true;
    };
    let dst_rect = blt_destination_rect(dst_x, dst_y, dst_width, dst_height);
    for clip in hdc_clip_rects(kernel, hdc, dst_rect, dst_bitmap.width, dst_bitmap.height) {
        draw_bitmap_bytes_to_bitmap(
            memory,
            &dst_bitmap,
            dst_x,
            dst_y,
            dst_width,
            dst_height,
            image.source_x,
            image.source_y,
            src_width,
            src_height,
            src_bitmap,
            &src_bytes,
            image_color_table,
            mask_bitmap_bytes
                .as_ref()
                .map(|(mask, bytes)| (*mask, bytes.as_slice())),
            image.transparent_color.map(colorref_rgb),
            blend,
            None,
            rop,
            clip,
        );
    }
    true
}

fn read_bitmap_object_bytes<M: CoredllGuestMemory>(
    memory: &M,
    bitmap: &crate::ce::resource::BitmapObject,
) -> Option<Vec<u8>> {
    if bitmap.bits_ptr == 0 || bitmap.width <= 0 || bitmap.height <= 0 || bitmap.width_bytes <= 0 {
        return None;
    }
    let byte_count = bitmap.width_bytes.saturating_mul(bitmap.height) as u32;
    let mut bytes = vec![0; byte_count as usize];
    memory.read_bytes(bitmap.bits_ptr, &mut bytes).ok()?;
    Some(bytes)
}

fn image_list_copy_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let dst_handle = raw_arg(args, 0);
    let dst_index = raw_i32_arg(args, 1);
    let src_handle = raw_arg(args, 2);
    let src_index = raw_i32_arg(args, 3);
    let flags = raw_arg(args, 4);
    match kernel
        .resources
        .copy_image_list_image(dst_handle, dst_index, src_handle, src_index, flags)
    {
        Some(true) => {
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        Some(false) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn image_list_copy_dither_image_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) {
    let dst_handle = raw_arg(args, 0);
    let dst_index = raw_i32_arg(args, 1) & 0xffff;
    let x = raw_i32_arg(args, 2);
    let y = raw_i32_arg(args, 3);
    let src_handle = raw_arg(args, 4);
    let src_index = raw_i32_arg(args, 5);
    let flags = raw_arg(args, 6);
    match kernel
        .resources
        .copy_dither_image_list_image(dst_handle, dst_index, x, y, src_handle, src_index, flags)
    {
        Some(true) => {
            copy_dither_image_list_bitmap_pixels(
                kernel, memory, dst_handle, dst_index, x, y, src_handle, src_index,
            );
            kernel.threads.set_last_error(thread_id, 0);
        }
        Some(false) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        }
    }
}

fn copy_dither_image_list_bitmap_pixels<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    dst_handle: u32,
    dst_index: i32,
    x: i32,
    y: i32,
    src_handle: u32,
    src_index: i32,
) {
    let Some(dst_list) = kernel.resources.image_list(dst_handle) else {
        return;
    };
    let Some(src_list) = kernel.resources.image_list(src_handle) else {
        return;
    };
    let Some(dst_image) = dst_list.images.get(dst_index as usize).cloned() else {
        return;
    };
    let Some(src_image) = src_list.images.get(src_index as usize).cloned() else {
        return;
    };
    let Some((dst_bitmap_handle, dst_mask_handle)) =
        image_list_image_bitmap_handles(kernel, &dst_image)
    else {
        return;
    };
    let Some((src_bitmap_handle, src_mask_handle)) =
        image_list_image_bitmap_handles(kernel, &src_image)
    else {
        return;
    };

    copy_image_list_bitmap_pixels(
        kernel,
        memory,
        dst_bitmap_handle,
        dst_image.source_x.saturating_add(x),
        dst_image.source_y.saturating_add(y),
        src_bitmap_handle,
        src_image.source_x,
        src_image.source_y,
        src_list.width,
        src_list.height,
    );

    if dst_mask_handle != 0 && src_mask_handle != 0 {
        copy_dither_image_list_mask_pixels(
            kernel,
            memory,
            dst_mask_handle,
            dst_image.source_x.saturating_add(x),
            dst_image.source_y.saturating_add(y),
            src_mask_handle,
            src_image.source_x,
            src_image.source_y,
            src_list.width,
            src_list.height,
        );
    }
}

fn copy_dither_image_list_mask_pixels<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    dst_mask_handle: u32,
    dst_x: i32,
    dst_y: i32,
    src_mask_handle: u32,
    src_x: i32,
    src_y: i32,
    width: i32,
    height: i32,
) {
    if width <= 0 || height <= 0 {
        return;
    }
    let Some(dst_mask) = kernel.resources.bitmap(dst_mask_handle).cloned() else {
        return;
    };
    let Some(src_mask) = kernel.resources.bitmap(src_mask_handle) else {
        return;
    };
    for row in 0..height {
        let dy = dst_y.saturating_add(row);
        let sy = src_y.saturating_add(row);
        if dy < 0 || dy >= dst_mask.height || sy < 0 || sy >= src_mask.height {
            continue;
        }
        for col in 0..width {
            let dx = dst_x.saturating_add(col);
            let sx = src_x.saturating_add(col);
            if dx < 0 || dx >= dst_mask.width || sx < 0 || sx >= src_mask.width {
                continue;
            }
            let Some(dst_on) = mask_bitmap_pixel_on(memory, &dst_mask, dx, dy) else {
                continue;
            };
            let Some(src_on) = mask_bitmap_pixel_on(memory, src_mask, sx, sy) else {
                continue;
            };
            let blended = dst_on && (src_on || ce_image_list_dither_mask_on(col, row));
            let rgb = if blended {
                [0xff, 0xff, 0xff]
            } else {
                [0x00, 0x00, 0x00]
            };
            let _ = write_bitmap_pixel_rgb(memory, &dst_mask, dx, dy, rgb);
        }
    }
}

fn mask_bitmap_pixel_on<M: CoredllGuestMemory>(
    memory: &M,
    bitmap: &crate::ce::resource::BitmapObject,
    x: i32,
    y: i32,
) -> Option<bool> {
    bitmap_pixel_rgb_from_memory(memory, bitmap, x, y).map(|rgb| rgb != [0, 0, 0])
}

fn ce_image_list_dither_mask_on(x: i32, y: i32) -> bool {
    ((x ^ y) & 1) == 0
}

fn image_list_image_bitmap_handles(
    kernel: &CeKernel,
    image: &crate::ce::resource::ImageListImage,
) -> Option<(u32, u32)> {
    if image.bitmap != 0 {
        return Some((image.bitmap, image.mask));
    }
    if image.icon == 0 {
        return None;
    }
    let icon = kernel.resources.icon(image.icon)?;
    (icon.color_bitmap != 0).then_some((icon.color_bitmap, icon.mask_bitmap))
}

fn copy_image_list_bitmap_pixels<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    dst_bitmap_handle: u32,
    dst_x: i32,
    dst_y: i32,
    src_bitmap_handle: u32,
    src_x: i32,
    src_y: i32,
    width: i32,
    height: i32,
) {
    if width <= 0 || height <= 0 {
        return;
    }
    let Some(dst_bitmap) = kernel.resources.bitmap(dst_bitmap_handle).cloned() else {
        return;
    };
    let Some(src_bitmap) = kernel.resources.bitmap(src_bitmap_handle) else {
        return;
    };
    let Some(src_bytes) = read_bitmap_object_bytes(memory, src_bitmap) else {
        return;
    };
    let clip = Rect {
        left: 0,
        top: 0,
        right: dst_bitmap.width,
        bottom: dst_bitmap.height,
    };
    draw_bitmap_bytes_to_bitmap(
        memory,
        &dst_bitmap,
        dst_x,
        dst_y,
        width,
        height,
        src_x,
        src_y,
        width,
        height,
        src_bitmap,
        &src_bytes,
        None,
        None,
        None,
        None,
        None,
        None,
        clip,
    );
}

