fn image_list_get_drag_image_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let point_ptr = raw_arg(args, 0);
    let hotspot_ptr = raw_arg(args, 1);
    let Some(drag) = kernel.resources.image_list_drag() else {
        let (x, y) = kernel.resources.image_list_drag_position();
        let (hotspot_x, hotspot_y) = kernel.resources.image_list_drag_hotspot();
        if point_ptr != 0
            && !write_guest_point(kernel, memory, thread_id, point_ptr, Point { x, y })
        {
            return 0;
        }
        if hotspot_ptr != 0
            && !write_guest_point(
                kernel,
                memory,
                thread_id,
                hotspot_ptr,
                Point {
                    x: hotspot_x,
                    y: hotspot_y,
                },
            )
        {
            return 0;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    };
    if point_ptr != 0
        && !write_guest_point(
            kernel,
            memory,
            thread_id,
            point_ptr,
            Point {
                x: drag.x,
                y: drag.y,
            },
        )
    {
        return 0;
    }
    if hotspot_ptr != 0
        && !write_guest_point(
            kernel,
            memory,
            thread_id,
            hotspot_ptr,
            Point {
                x: drag.hotspot_x,
                y: drag.hotspot_y,
            },
        )
    {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    drag.image_list
}

fn image_list_duplicate_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    handle: u32,
) -> u32 {
    if is_shell_system_image_list_handle(handle) {
        ensure_shell_system_image_list(kernel, handle);
    }
    let Some(source) = kernel.resources.image_list(handle).cloned() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some((images, cloned_bitmaps)) =
        clone_image_list_images_for_duplicate(kernel, memory, thread_id, &source.images)
    else {
        if kernel.threads.get_last_error(thread_id) == 0 {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        }
        return 0;
    };
    match kernel
        .resources
        .duplicate_image_list_with_images(handle, images)
    {
        Some(duplicate) => {
            kernel.threads.set_last_error(thread_id, 0);
            duplicate
        }
        None => {
            for bitmap in cloned_bitmaps {
                delete_owned_bitmap(kernel, bitmap);
            }
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            0
        }
    }
}

fn clone_image_list_images_for_duplicate<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    images: &[crate::ce::resource::ImageListImage],
) -> Option<(Vec<crate::ce::resource::ImageListImage>, Vec<u32>)> {
    let mut cloned_images = Vec::with_capacity(images.len());
    let mut cloned_bitmaps = Vec::new();
    for image in images {
        let Some((bitmap, bitmap_cloned)) =
            clone_bitmap_for_image_list_duplicate(kernel, memory, thread_id, image.bitmap)
        else {
            for bitmap in cloned_bitmaps {
                delete_owned_bitmap(kernel, bitmap);
            }
            return None;
        };
        if bitmap_cloned {
            cloned_bitmaps.push(bitmap);
        }
        let Some((mask, mask_cloned)) =
            clone_bitmap_for_image_list_duplicate(kernel, memory, thread_id, image.mask)
        else {
            for bitmap in cloned_bitmaps {
                delete_owned_bitmap(kernel, bitmap);
            }
            return None;
        };
        if mask_cloned {
            cloned_bitmaps.push(mask);
        }
        cloned_images.push(crate::ce::resource::ImageListImage {
            bitmap,
            mask,
            icon: image.icon,
            transparent_color: image.transparent_color,
            source_x: image.source_x,
            source_y: image.source_y,
        });
    }
    Some((cloned_images, cloned_bitmaps))
}

fn clone_bitmap_for_image_list_duplicate<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bitmap: u32,
) -> Option<(u32, bool)> {
    if bitmap == 0 {
        return Some((0, false));
    }
    let Some(source) = kernel.resources.bitmap(bitmap) else {
        return Some((bitmap, false));
    };
    if source.bits_ptr == 0 {
        return Some((bitmap, false));
    }
    clone_bitmap_for_image_list(kernel, memory, thread_id, bitmap).map(|clone| (clone, true))
}

fn image_list_set_overlay_image_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let handle = raw_arg(args, 0);
    let image_index = raw_i32_arg(args, 1);
    let overlay = raw_i32_arg(args, 2);
    let unchanged = image_list_overlay_matches(kernel, handle, image_index, overlay);
    if unchanged {
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }
    match kernel
        .resources
        .set_image_list_overlay(handle, image_index, overlay)
    {
        Some(true) => {
            refine_image_list_overlay_bounds(kernel, memory, handle, image_index, overlay);
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        Some(false) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn image_list_overlay_matches(
    kernel: &CeKernel,
    handle: u32,
    image_index: i32,
    overlay: i32,
) -> bool {
    const ILC_MASK: u32 = 0x0001;
    const NUM_OVERLAY_IMAGES: i32 = 4;
    if image_index < 0 || !(1..=NUM_OVERLAY_IMAGES).contains(&overlay) {
        return false;
    }
    let Some(list) = kernel.resources.image_list(handle) else {
        return false;
    };
    list.flags & ILC_MASK != 0
        && list.images.get(image_index as usize).is_some()
        && list
            .overlays
            .get(&(overlay as u32))
            .is_some_and(|record| record.image_index == image_index)
}

fn refine_image_list_overlay_bounds<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    handle: u32,
    image_index: i32,
    overlay: i32,
) {
    const ILD_IMAGE: u32 = 0x0020;
    let Some(list) = kernel.resources.image_list(handle) else {
        return;
    };
    let Some(image) = list.images.get(image_index as usize) else {
        return;
    };
    let list_width = list.width.max(0);
    let list_height = list.height.max(0);
    let source_x = image.source_x;
    let source_y = image.source_y;
    let mask_handle = image.mask;
    if mask_handle == 0 {
        let _ = kernel.resources.set_image_list_overlay_bounds(
            handle,
            overlay,
            0,
            0,
            list_width,
            list_height,
            ILD_IMAGE,
        );
        return;
    }
    let Some(mask) = kernel.resources.bitmap(mask_handle) else {
        return;
    };
    let Some(mask_bytes) = read_bitmap_object_bytes(memory, mask) else {
        return;
    };
    let mut left = i32::MAX;
    let mut top = i32::MAX;
    let mut right = 0;
    let mut bottom = 0;
    for y in 0..list_height {
        for x in 0..list_width {
            if bitmap_pixel_rgb(mask, &mask_bytes, source_x + x, source_y + y) == Some([0, 0, 0]) {
                left = left.min(x);
                top = top.min(y);
                right = right.max(x.saturating_add(1));
                bottom = bottom.max(y.saturating_add(1));
            }
        }
    }
    if left == i32::MAX {
        left = 0;
        top = 0;
    }
    let mut flags = 0;
    if right > left && bottom > top {
        let mut rectangular = true;
        'rows: for y in top..bottom {
            for x in left..right {
                if bitmap_pixel_rgb(mask, &mask_bytes, source_x + x, source_y + y)
                    != Some([0, 0, 0])
                {
                    rectangular = false;
                    break 'rows;
                }
            }
        }
        if rectangular {
            flags = ILD_IMAGE;
        }
    }
    let _ = kernel.resources.set_image_list_overlay_bounds(
        handle,
        overlay,
        left,
        top,
        right.saturating_sub(left),
        bottom.saturating_sub(top),
        flags,
    );
}

fn record_image_list_draw(kernel: &mut CeKernel, thread_id: u32, draw: ImageListDraw) -> bool {
    if draw.hdc == 0 || draw.index < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    if is_shell_system_image_list_handle(draw.image_list) {
        if draw.index as u32 >= SHELL_SYSTEM_IMAGE_LIST_COUNT {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return false;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }
    match kernel.resources.record_image_list_draw(draw) {
        Some(true) => {
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        Some(false) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            false
        }
    }
}

fn record_image_list_draw_dispperf(kernel: &mut CeKernel, draw: ImageListDraw) {
    let draw_flags = draw.flags & 0x00ff;
    if let Some(rop) = image_list_draw_rop(draw_flags, draw.rop) {
        kernel.record_display_perf_gpe(rop, false, false);
    }
}

fn shell_system_image_bitmap_handle(index: i32) -> u32 {
    0x000b_d000 | ((index as u32) & 0x0fff)
}

fn load_stock_or_resource_image(
    kernel: &mut CeKernel,
    thread_id: u32,
    module: u32,
    name: u32,
    resource_kind: u16,
    stock_base: u32,
) -> u32 {
    if module == 0 && name <= u16::MAX as u32 {
        kernel.threads.set_last_error(thread_id, 0);
        return stock_base | name;
    }

    let module = normalized_module(kernel, module);
    let name = ResourceId::from_guest_arg(name);
    let Some(resource_handle) =
        kernel
            .resources
            .find_resource(module, name, ResourceId::Integer(resource_kind))
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_RESOURCE_NAME_NOT_FOUND);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    resource_handle
}

fn load_bitmap_resource<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    module: u32,
    name: u32,
) -> u32 {
    let module = if module == 0 {
        kernel.process_module_base()
    } else {
        module
    };
    let Some(resource_handle) = kernel.resources.find_resource(
        module,
        ResourceId::from_guest_arg(name),
        ResourceId::Integer(RT_BITMAP as u16),
    ) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_RESOURCE_NAME_NOT_FOUND);
        return 0;
    };
    let Some(data_ptr) = kernel.resources.load_resource(resource_handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(size) = kernel.resources.sizeof_resource(resource_handle) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, data_ptr, size) else {
        return 0;
    };
    create_bitmap_from_dib_bytes(kernel, memory, thread_id, &bytes)
}

fn load_bitmap_file<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    name_ptr: u32,
) -> u32 {
    let Some(path) = read_guest_wide_arg(memory, name_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Ok(bytes) = kernel.read_guest_file(&path) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_FILE_NOT_FOUND);
        return 0;
    };
    create_bitmap_from_file_bytes(kernel, memory, thread_id, &bytes)
}

fn create_bitmap_from_file_bytes<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bytes: &[u8],
) -> u32 {
    if bytes.len() < 14 || &bytes[0..2] != b"BM" {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bits_offset) = read_le_u32(bytes, 10) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if bytes.len() <= 14 || bits_offset < 14 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let dib = &bytes[14..];
    let Some(header) = parse_dib_header(dib) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if header.width == 0 || header.height == 0 || header.planes != 1 || header.bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(byte_count) = bitmap_byte_count(header.width, header.height, header.bits_pixel) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let bits_offset = bits_offset as usize;
    let byte_count_usize = byte_count as usize;
    if bits_offset
        .checked_add(byte_count_usize)
        .map_or(true, |end| end > bytes.len())
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    if !write_guest_bytes(
        kernel,
        memory,
        thread_id,
        bits_ptr,
        &bytes[bits_offset..bits_offset + byte_count_usize],
    ) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel.resources.create_readonly_owned_bitmap(
        header.width,
        header.height,
        header.planes,
        header.bits_pixel,
        bits_ptr,
    )
}

fn create_bitmap_from_dib_bytes<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bytes: &[u8],
) -> u32 {
    create_bitmap_from_dib_bytes_with_color_usage(kernel, memory, thread_id, bytes, DIB_RGB_COLORS)
}

fn create_bitmap_from_dib_bytes_with_color_usage<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    bytes: &[u8],
    color_usage: u32,
) -> u32 {
    let Some(header) = parse_dib_header(bytes) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if header.width == 0 || header.height == 0 || header.planes != 1 || header.bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(header_size) = read_le_u32(bytes, 0) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let compression = if header_size >= 40 {
        let Some(compression) = read_le_u32(bytes, 16) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        compression
    } else {
        BI_RGB
    };
    let Some(rgb_masks) =
        dib_rgb_masks_from_bytes(bytes, header_size, compression, header.bits_pixel)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(alpha_mask) =
        dib_alpha_mask_from_bytes(bytes, header_size, compression, header.bits_pixel)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let color_table = read_dib_color_table_from_bytes(
        bytes,
        header_size,
        compression,
        header.bits_pixel,
        color_usage,
    );
    let Some(bits_offset) = dib_bits_offset(
        bytes,
        header_size,
        compression,
        header.bits_pixel,
        color_usage,
    ) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(byte_count) = bitmap_byte_count(header.width, header.height, header.bits_pixel) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let byte_count_usize = byte_count as usize;
    if bits_offset
        .checked_add(byte_count_usize)
        .map_or(true, |end| end > bytes.len())
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    if !write_guest_bytes(
        kernel,
        memory,
        thread_id,
        bits_ptr,
        &bytes[bits_offset..bits_offset + byte_count_usize],
    ) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    let bitmap = kernel.resources.create_readonly_owned_bitmap_with_masks(
        header.width,
        header.height,
        header.planes,
        header.bits_pixel,
        bits_ptr,
        rgb_masks,
    );
    if !color_table.is_empty()
        && let Some(object) = kernel.resources.bitmap_mut(bitmap)
    {
        object.color_table = color_table;
    }
    if let Some(object) = kernel.resources.bitmap_mut(bitmap) {
        object.alpha_mask = alpha_mask;
    }
    bitmap
}

fn packed_dib_byte_count_from_guest<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    packed_dib: u32,
    color_usage: u32,
) -> Option<usize> {
    let header_size = read_guest_u32(kernel, memory, thread_id, packed_dib)?;
    if !(12..=124).contains(&header_size) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    let header_bytes = read_guest_bytes(kernel, memory, thread_id, packed_dib, header_size)?;
    let Some(header) = parse_dib_header(&header_bytes) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    };
    if header.width == 0 || header.height == 0 || header.planes != 1 || header.bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    let compression = if header_size >= 40 {
        read_le_u32(&header_bytes, 16)?
    } else {
        BI_RGB
    };
    let bits_offset = dib_bits_offset(
        &header_bytes,
        header_size,
        compression,
        header.bits_pixel,
        color_usage,
    )?;
    let byte_count = bitmap_byte_count(header.width, header.height, header.bits_pixel)? as usize;
    bits_offset.checked_add(byte_count)
}

fn create_bitmap_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    width: i32,
    height: i32,
    planes: u16,
    bits_pixel: u16,
    bits_ptr: u32,
) -> u32 {
    if width <= 0 || height == 0 || planes == 0 || bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .create_bitmap(width, height, planes, bits_pixel, bits_ptr)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct DibHeader {
    width: i32,
    height: i32,
    planes: u16,
    bits_pixel: u16,
}

fn parse_dib_header(bytes: &[u8]) -> Option<DibHeader> {
    let header_size = read_le_u32(bytes, 0)?;
    match header_size {
        12 => Some(DibHeader {
            width: read_le_u16(bytes, 4)? as i32,
            height: read_le_u16(bytes, 6)? as i32,
            planes: read_le_u16(bytes, 8)?,
            bits_pixel: read_le_u16(bytes, 10)?,
        }),
        40..=124 => Some(DibHeader {
            width: read_le_i32(bytes, 4)?,
            height: read_le_i32(bytes, 8)?,
            planes: read_le_u16(bytes, 12)?,
            bits_pixel: read_le_u16(bytes, 14)?,
        }),
        _ => None,
    }
}

fn bitmap_byte_count(width: i32, height: i32, bits_pixel: u16) -> Option<u32> {
    if width == 0 || height == 0 || bits_pixel == 0 {
        return None;
    }
    let width = u64::from(width.unsigned_abs());
    let height = u64::from(height.unsigned_abs());
    let bits_per_row = width.checked_mul(u64::from(bits_pixel))?;
    let row_bytes = bits_per_row
        .checked_add(31)?
        .checked_div(32)?
        .checked_mul(4)?;
    let bytes = row_bytes.checked_mul(height)?;
    (bytes <= u64::from(u32::MAX)).then_some(bytes as u32)
}

fn is_supported_dib_bit_depth(bits_pixel: u16) -> bool {
    matches!(bits_pixel, 1 | 2 | 4 | 8 | 16 | 24 | 32)
}

fn dib_bits_offset(
    bytes: &[u8],
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
    color_usage: u32,
) -> Option<usize> {
    let header_size = header_size as usize;
    if bytes.len() < header_size {
        return None;
    }
    let mask_bytes = match compression {
        BI_BITFIELDS if header_size == 40 => 12usize,
        BI_ALPHABITFIELDS if header_size == 40 => 16usize,
        _ => 0,
    };
    let color_entries = dib_color_entry_count(bytes, header_size as u32, bits_pixel)?;
    let color_entry_bytes = if color_usage == DIB_PAL_COLORS {
        2usize
    } else if header_size == 12 {
        3usize
    } else {
        4usize
    };
    header_size
        .checked_add(mask_bytes)?
        .checked_add(color_entries.checked_mul(color_entry_bytes)?)
}

fn dib_color_entry_count(bytes: &[u8], header_size: u32, bits_pixel: u16) -> Option<usize> {
    if !matches!(bits_pixel, 1 | 2 | 4 | 8) {
        return Some(0);
    }
    let max_entries = 1usize.checked_shl(u32::from(bits_pixel))?;
    if header_size >= 40 {
        let used_entries = read_le_u32(bytes, 32)
            .and_then(|count| (count != 0).then_some(count as usize))
            .unwrap_or(max_entries)
            .min(max_entries);
        Some(used_entries)
    } else {
        Some(max_entries)
    }
}

fn dib_rgb_masks_from_bytes(
    bytes: &[u8],
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
) -> Option<Option<[u32; 3]>> {
    match compression {
        BI_RGB => Some(None),
        BI_BITFIELDS if bits_pixel == 24 => Some(None),
        BI_BITFIELDS if matches!(bits_pixel, 16 | 32) => {
            let mask_offset = if header_size >= 52 {
                40usize
            } else {
                header_size as usize
            };
            let mask_bytes = bytes.get(mask_offset..mask_offset.checked_add(12)?)?;
            Some(Some([
                read_le_u32(mask_bytes, 0)?,
                read_le_u32(mask_bytes, 4)?,
                read_le_u32(mask_bytes, 8)?,
            ]))
        }
        BI_ALPHABITFIELDS if matches!(bits_pixel, 16 | 32) => {
            let mask_offset = if header_size >= 56 {
                40usize
            } else {
                header_size as usize
            };
            let mask_bytes = bytes.get(mask_offset..mask_offset.checked_add(16)?)?;
            Some(Some([
                read_le_u32(mask_bytes, 0)?,
                read_le_u32(mask_bytes, 4)?,
                read_le_u32(mask_bytes, 8)?,
            ]))
        }
        _ => None,
    }
}

fn dib_alpha_mask_from_bytes(
    bytes: &[u8],
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
) -> Option<Option<u32>> {
    if compression != BI_ALPHABITFIELDS || !matches!(bits_pixel, 16 | 32) {
        return Some(None);
    }
    let mask_offset = if header_size >= 56 {
        40usize
    } else {
        header_size as usize
    };
    let mask_bytes = bytes.get(mask_offset..mask_offset.checked_add(16)?)?;
    Some(Some(read_le_u32(mask_bytes, 12)?))
}

fn read_dib_color_table_from_bytes(
    bytes: &[u8],
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
    color_usage: u32,
) -> Vec<[u8; 4]> {
    let Some(used_entries) = dib_color_entry_count(bytes, header_size, bits_pixel) else {
        return Vec::new();
    };
    if used_entries == 0 {
        return Vec::new();
    }
    if color_usage == DIB_PAL_COLORS {
        return read_dib_palette_index_table_from_bytes(bytes, header_size, used_entries)
            .unwrap_or_else(|| default_indexed_color_table(bits_pixel));
    }
    let table_offset = if header_size == 12 {
        12usize
    } else if compression == BI_BITFIELDS && header_size == 40 {
        52usize
    } else if compression == BI_ALPHABITFIELDS && header_size == 40 {
        56usize
    } else {
        header_size as usize
    };
    let bytes_per_entry = if header_size == 12 { 3usize } else { 4 };
    let Some(table_bytes) = used_entries.checked_mul(bytes_per_entry) else {
        return default_indexed_color_table(bits_pixel);
    };
    let Some(table) = bytes.get(table_offset..table_offset.saturating_add(table_bytes)) else {
        return default_indexed_color_table(bits_pixel);
    };
    let mut entries = Vec::with_capacity(used_entries);
    for entry in table.chunks_exact(bytes_per_entry) {
        entries.push([
            entry[0],
            entry[1],
            entry[2],
            if bytes_per_entry == 4 { entry[3] } else { 0 },
        ]);
    }
    entries
}

fn read_dib_palette_index_table_from_bytes(
    bytes: &[u8],
    header_size: u32,
    used_entries: usize,
) -> Option<Vec<[u8; 4]>> {
    let table_offset = header_size as usize;
    let table_bytes = used_entries.checked_mul(2)?;
    let table = bytes.get(table_offset..table_offset.checked_add(table_bytes)?)?;
    let mut entries = Vec::with_capacity(used_entries);
    for entry in table.chunks_exact(2) {
        let palette_index = u16::from_le_bytes([entry[0], entry[1]]);
        let value = palette_index.min(u16::from(u8::MAX)) as u8;
        entries.push([value, value, value, 0]);
    }
    Some(entries)
}

fn dib_rgb_masks<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    info_ptr: u32,
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
) -> Option<Option<[u32; 3]>> {
    match compression {
        BI_RGB => Some(None),
        BI_BITFIELDS if bits_pixel == 24 => Some(None),
        BI_BITFIELDS if matches!(bits_pixel, 16 | 32) => {
            let mask_bytes = if header_size >= 52 {
                read_guest_bytes(kernel, memory, thread_id, info_ptr.wrapping_add(40), 12)?
            } else {
                read_guest_bytes(
                    kernel,
                    memory,
                    thread_id,
                    info_ptr.wrapping_add(header_size),
                    12,
                )?
            };
            Some(Some([
                read_le_u32(&mask_bytes, 0)?,
                read_le_u32(&mask_bytes, 4)?,
                read_le_u32(&mask_bytes, 8)?,
            ]))
        }
        BI_ALPHABITFIELDS if matches!(bits_pixel, 16 | 32) => {
            let mask_bytes = if header_size >= 56 {
                read_guest_bytes(kernel, memory, thread_id, info_ptr.wrapping_add(40), 16)?
            } else {
                read_guest_bytes(
                    kernel,
                    memory,
                    thread_id,
                    info_ptr.wrapping_add(header_size),
                    16,
                )?
            };
            Some(Some([
                read_le_u32(&mask_bytes, 0)?,
                read_le_u32(&mask_bytes, 4)?,
                read_le_u32(&mask_bytes, 8)?,
            ]))
        }
        _ => None,
    }
}

fn dib_alpha_mask<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    info_ptr: u32,
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
) -> Option<Option<u32>> {
    if compression != BI_ALPHABITFIELDS || !matches!(bits_pixel, 16 | 32) {
        return Some(None);
    }
    let mask_bytes = if header_size >= 56 {
        read_guest_bytes(kernel, memory, thread_id, info_ptr.wrapping_add(40), 16)?
    } else {
        read_guest_bytes(
            kernel,
            memory,
            thread_id,
            info_ptr.wrapping_add(header_size),
            16,
        )?
    };
    Some(Some(read_le_u32(&mask_bytes, 12)?))
}

fn read_dib_color_table<M: CoredllGuestMemory>(
    memory: &M,
    info_ptr: u32,
    header_size: u32,
    compression: u32,
    bits_pixel: u16,
    color_usage: u32,
) -> Vec<[u8; 4]> {
    if !matches!(bits_pixel, 1 | 2 | 4 | 8) {
        return Vec::new();
    }
    let max_entries = 1usize << bits_pixel;
    let used_entries = if header_size >= 40 {
        memory
            .read_u32(info_ptr.wrapping_add(32))
            .ok()
            .and_then(|count| (count != 0).then_some(count as usize))
            .unwrap_or(max_entries)
            .min(max_entries)
    } else {
        max_entries
    };
    if used_entries == 0 {
        return Vec::new();
    }
    if color_usage == DIB_PAL_COLORS {
        return read_dib_palette_index_table(memory, info_ptr, header_size, used_entries)
            .unwrap_or_else(|| default_indexed_color_table(bits_pixel));
    }
    let table_ptr = if header_size == 12 {
        info_ptr.wrapping_add(12)
    } else if compression == BI_BITFIELDS && header_size == 40 {
        info_ptr.wrapping_add(52)
    } else if compression == BI_ALPHABITFIELDS && header_size == 40 {
        info_ptr.wrapping_add(56)
    } else {
        info_ptr.wrapping_add(header_size)
    };
    let bytes_per_entry = if header_size == 12 { 3 } else { 4 };
    let mut table = Vec::with_capacity(used_entries);
    for index in 0..used_entries {
        let entry_ptr = table_ptr.wrapping_add((index * bytes_per_entry) as u32);
        let blue = match memory.read_u8(entry_ptr) {
            Ok(value) => value,
            Err(_) => return default_indexed_color_table(bits_pixel),
        };
        let green = match memory.read_u8(entry_ptr.wrapping_add(1)) {
            Ok(value) => value,
            Err(_) => return default_indexed_color_table(bits_pixel),
        };
        let red = match memory.read_u8(entry_ptr.wrapping_add(2)) {
            Ok(value) => value,
            Err(_) => return default_indexed_color_table(bits_pixel),
        };
        let reserved = if bytes_per_entry == 4 {
            match memory.read_u8(entry_ptr.wrapping_add(3)) {
                Ok(value) => value,
                Err(_) => return default_indexed_color_table(bits_pixel),
            }
        } else {
            0
        };
        table.push([blue, green, red, reserved]);
    }
    table
}

fn read_dib_palette_index_table<M: CoredllGuestMemory>(
    memory: &M,
    info_ptr: u32,
    header_size: u32,
    used_entries: usize,
) -> Option<Vec<[u8; 4]>> {
    let table_ptr = info_ptr.wrapping_add(header_size);
    let mut table = Vec::with_capacity(used_entries);
    for index in 0..used_entries {
        let entry_ptr = table_ptr.wrapping_add((index * 2) as u32);
        let palette_index = u16::from_le_bytes([
            memory.read_u8(entry_ptr).ok()?,
            memory.read_u8(entry_ptr.wrapping_add(1)).ok()?,
        ]);
        let value = palette_index.min(u16::from(u8::MAX)) as u8;
        table.push([value, value, value, 0]);
    }
    Some(table)
}

fn default_indexed_color_table(bits_pixel: u16) -> Vec<[u8; 4]> {
    let entries = 1usize << bits_pixel;
    if bits_pixel == 1 {
        return vec![[0, 0, 0, 0], [0xff, 0xff, 0xff, 0]];
    }
    let divisor = entries.saturating_sub(1).max(1) as u16;
    (0..entries)
        .map(|index| {
            let value = ((index as u16 * 255) / divisor) as u8;
            [value, value, value, 0]
        })
        .collect()
}

fn get_object_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    handle: u32,
    byte_count: i32,
    out_ptr: u32,
) -> u32 {
    // BITMAP: bmType(i32)+bmWidth(i32)+bmHeight(i32)+bmWidthBytes(i32)+bmPlanes(u16)+bmBitsPixel(u16)+bmBits(u32)
    const BITMAP_SIZE: u32 = 24;
    // DIBSECTION: BITMAP + BITMAPINFOHEADER + RGB bitfields[3] + section handle + offset
    const DIBSECTION_SIZE: u32 = 84;
    // LOGPEN: lopnStyle(u32)+lopnWidth.x(i32)+lopnWidth.y(i32)+lopnColor(u32)
    const LOGPEN_SIZE: u32 = 16;
    // LOGBRUSH: lbStyle(u32)+lbColor(u32)+lbHatch(i32)
    const LOGBRUSH_SIZE: u32 = 12;
    // LOGFONTW: 5*i32 + 8*u8 + lfFaceName[32]*u16
    const LOGFONTW_SIZE: u32 = 92;
    // HPALETTE -> WORD count of entries
    const PALETTE_SIZE: u32 = 2;

    // gdi_object_kind returns &'static str — no borrow held after this line
    let kind = kernel.resources.gdi_object_kind(handle);
    let required: u32 = match kind {
        "bitmap" => BITMAP_SIZE,
        "pen" => LOGPEN_SIZE,
        "brush" => LOGBRUSH_SIZE,
        "font" => LOGFONTW_SIZE,
        "palette" => PALETTE_SIZE,
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        }
    };

    // CE spec: out_ptr == 0 → return required buffer size without writing
    if out_ptr == 0 {
        return required;
    }
    if byte_count < required as i32 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INSUFFICIENT_BUFFER);
        return 0;
    }

    let bytes: Vec<u8> = match kind {
        "bitmap" => {
            let Some(bmp) = kernel.resources.bitmap(handle).cloned() else {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                return 0;
            };
            let mut b = bitmap_object_bytes(&bmp);
            if bmp.dib_section && byte_count >= DIBSECTION_SIZE as i32 {
                b.extend_from_slice(&40u32.to_le_bytes()); // biSize
                b.extend_from_slice(&bmp.width.to_le_bytes());
                let dib_height = if bmp.top_down {
                    -bmp.height
                } else {
                    bmp.height
                };
                b.extend_from_slice(&dib_height.to_le_bytes());
                b.extend_from_slice(&bmp.planes.to_le_bytes());
                b.extend_from_slice(&bmp.bits_pixel.to_le_bytes());
                let compression = if bmp.alpha_mask.is_some() {
                    BI_ALPHABITFIELDS
                } else if bmp.rgb_masks.is_some() {
                    BI_BITFIELDS
                } else {
                    BI_RGB
                };
                b.extend_from_slice(&compression.to_le_bytes());
                let size_image = (bmp.width_bytes.max(0) as u32).saturating_mul(bmp.height as u32);
                b.extend_from_slice(&size_image.to_le_bytes());
                b.extend_from_slice(&0i32.to_le_bytes()); // biXPelsPerMeter
                b.extend_from_slice(&0i32.to_le_bytes()); // biYPelsPerMeter
                b.extend_from_slice(&(bmp.color_table.len() as u32).to_le_bytes());
                b.extend_from_slice(&0u32.to_le_bytes()); // biClrImportant
                for mask in bmp.rgb_masks.unwrap_or([0, 0, 0]) {
                    b.extend_from_slice(&mask.to_le_bytes());
                }
                b.extend_from_slice(&bmp.section_handle.to_le_bytes()); // dshSection
                b.extend_from_slice(&bmp.section_offset.to_le_bytes()); // dsOffset
            }
            b
        }
        "pen" => {
            let (style, width, color) = if let Some(pen) = kernel.resources.pen(handle).cloned() {
                (pen.style, pen.width, pen.color)
            } else {
                // Stock pen: derive from handle index
                match handle & 0xff {
                    6 => (0u32, 1i32, 0x00ff_ffff_u32), // WHITE_PEN: PS_SOLID, w=1, white
                    7 => (0u32, 1i32, 0u32),            // BLACK_PEN: PS_SOLID, w=1, black
                    8 => (5u32, 0i32, 0u32),            // NULL_PEN: PS_NULL, w=0
                    _ => (0u32, 1i32, 0u32),            // DC_PEN and unknown: PS_SOLID, black
                }
            };
            let mut b = Vec::with_capacity(LOGPEN_SIZE as usize);
            b.extend_from_slice(&style.to_le_bytes());
            b.extend_from_slice(&width.to_le_bytes()); // lopnWidth.x
            b.extend_from_slice(&0i32.to_le_bytes()); // lopnWidth.y (ignored by CE)
            b.extend_from_slice(&color.to_le_bytes());
            b
        }
        "brush" => {
            let (style, color, hatch) = if let Some(brush) = kernel.resources.brush(handle).cloned()
            {
                if let Some(bmp) = brush.pattern_bitmap {
                    (3u32, 0u32, bmp as i32) // BS_PATTERN
                } else {
                    (0u32, brush.color, 0i32) // BS_SOLID
                }
            } else {
                // Stock brush: derive from handle index
                match handle & 0xff {
                    0 => (0u32, 0x00ff_ffff_u32, 0i32), // WHITE_BRUSH
                    1 => (0u32, 0x00c0_c0c0_u32, 0i32), // LTGRAY_BRUSH
                    2 => (0u32, 0x0080_8080_u32, 0i32), // GRAY_BRUSH
                    3 => (0u32, 0x0040_4040_u32, 0i32), // DKGRAY_BRUSH
                    4 => (0u32, 0u32, 0i32),            // BLACK_BRUSH
                    5 => (1u32, 0u32, 0i32),            // NULL_BRUSH: BS_HOLLOW
                    _ => (0u32, 0u32, 0i32),            // DC_BRUSH and unknown: solid black
                }
            };
            let mut b = Vec::with_capacity(LOGBRUSH_SIZE as usize);
            b.extend_from_slice(&style.to_le_bytes());
            b.extend_from_slice(&color.to_le_bytes());
            b.extend_from_slice(&hatch.to_le_bytes());
            b
        }
        "font" => {
            let (
                height,
                width,
                escapement,
                orientation,
                weight,
                italic,
                underline,
                strikeout,
                charset,
                out_precision,
                clip_precision,
                quality,
                pitch_family,
                face,
            ) = if let Some(font) = kernel.resources.font(handle).cloned() {
                (
                    font.height,
                    font.width,
                    font.escapement,
                    font.orientation,
                    font.weight,
                    font.italic as u8,
                    font.underline as u8,
                    font.strikeout as u8,
                    font.charset,
                    font.out_precision,
                    font.clip_precision,
                    font.quality,
                    font.pitch_and_family,
                    font.face_name,
                )
            } else {
                // SYSTEM_FONT stock object — CE default system font
                (
                    -12i32,
                    0i32,
                    0i32,
                    0i32,
                    400i32,
                    0u8,
                    0u8,
                    0u8,
                    0u8,
                    0u8,
                    0u8,
                    0u8,
                    0u8,
                    "System".to_string(),
                )
            };
            let mut b = Vec::with_capacity(LOGFONTW_SIZE as usize);
            b.extend_from_slice(&height.to_le_bytes());
            b.extend_from_slice(&width.to_le_bytes());
            b.extend_from_slice(&escapement.to_le_bytes());
            b.extend_from_slice(&orientation.to_le_bytes());
            b.extend_from_slice(&weight.to_le_bytes());
            b.push(italic);
            b.push(underline);
            b.push(strikeout);
            b.push(charset);
            b.push(out_precision);
            b.push(clip_precision);
            b.push(quality);
            b.push(pitch_family);
            // lfFaceName[LF_FACESIZE=32]: null-terminated UTF-16LE, 64 bytes
            let mut face_bytes = [0u8; 64];
            for (i, ch) in face.encode_utf16().take(31).enumerate() {
                face_bytes[i * 2] = ch as u8;
                face_bytes[i * 2 + 1] = (ch >> 8) as u8;
            }
            b.extend_from_slice(&face_bytes);
            b
        }
        "palette" => {
            let Some(count) = palette_entry_count(kernel, handle) else {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                return 0;
            };
            count.to_le_bytes().to_vec()
        }
        _ => unreachable!(),
    };

    let ok = write_guest_bytes(kernel, memory, thread_id, out_ptr, &bytes);
    if ok {
        kernel.threads.set_last_error(thread_id, 0);
        bytes.len() as u32
    } else {
        0
    }
}

fn bitmap_object_bytes(bitmap: &crate::ce::resource::BitmapObject) -> Vec<u8> {
    let mut bytes = Vec::with_capacity(24);
    bytes.extend_from_slice(&0i32.to_le_bytes()); // bmType
    bytes.extend_from_slice(&bitmap.width.to_le_bytes());
    bytes.extend_from_slice(&bitmap.height.to_le_bytes());
    bytes.extend_from_slice(&bitmap.width_bytes.to_le_bytes());
    bytes.extend_from_slice(&bitmap.planes.to_le_bytes());
    bytes.extend_from_slice(&bitmap.bits_pixel.to_le_bytes());
    bytes.extend_from_slice(&bitmap.bits_ptr.to_le_bytes());
    bytes
}

fn delete_object_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    handle: u32,
) -> bool {
    if handle == 0 {
        return false;
    }
    if is_stock_delete_noop(handle) {
        return true;
    }
    let bitmap = kernel.resources.bitmap(handle).cloned();
    let owned_pattern_bitmap = kernel
        .resources
        .brush(handle)
        .and_then(|brush| brush.owns_pattern_bitmap.then_some(brush.pattern_bitmap))
        .flatten();
    let removed = kernel.resources.delete_gdi_object(handle);
    if removed
        && let Some(bitmap) = bitmap
        && bitmap.bits_owned
        && bitmap.bits_ptr != 0
    {
        if bitmap.section_handle != 0 {
            if let Some((file_id, view, bytes)) = commit_file_mapping_view_from_guest(
                kernel,
                memory,
                thread_id,
                bitmap.bits_ptr,
                None,
            ) && let Some(file_id) = file_id
            {
                let _ = kernel.write_file_at(file_id, view.offset as usize, &bytes);
            }
            let _ = kernel.handles.remove_file_mapping_view(bitmap.bits_ptr);
        }
        let _ = kernel
            .memory
            .heap_free(PROCESS_HEAP_HANDLE, 0, bitmap.bits_ptr);
    }
    if removed && let Some(pattern_bitmap) = owned_pattern_bitmap {
        delete_owned_bitmap(kernel, pattern_bitmap);
    }
    removed
}

fn is_stock_delete_noop(handle: u32) -> bool {
    const STOCK_DELETE_NOOP_INDEXES: &[u32] = &[0, 1, 2, 3, 4, 5, 6, 7, 8, 13, 15, 18, 19, 32, 33];
    STOCK_DELETE_NOOP_INDEXES
        .iter()
        .any(|index| stock_object_handle(*index) == Some(handle))
}

fn delete_owned_bitmap(kernel: &mut CeKernel, handle: u32) {
    if handle == 0 {
        return;
    }
    let bitmap = kernel.resources.bitmap(handle).cloned();
    if kernel.resources.delete_bitmap(handle)
        && let Some(bitmap) = bitmap
        && bitmap.bits_owned
        && bitmap.bits_ptr != 0
    {
        let _ = kernel
            .memory
            .heap_free(PROCESS_HEAP_HANDLE, 0, bitmap.bits_ptr);
    }
}

fn read_le_u16(bytes: &[u8], offset: usize) -> Option<u16> {
    Some(u16::from_le_bytes([
        *bytes.get(offset)?,
        *bytes.get(offset + 1)?,
    ]))
}

fn read_le_u32(bytes: &[u8], offset: usize) -> Option<u32> {
    Some(u32::from_le_bytes([
        *bytes.get(offset)?,
        *bytes.get(offset + 1)?,
        *bytes.get(offset + 2)?,
        *bytes.get(offset + 3)?,
    ]))
}

fn read_le_i32(bytes: &[u8], offset: usize) -> Option<i32> {
    read_le_u32(bytes, offset).map(|value| value as i32)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum WindowRectKind {
    Window,
    Client,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PointMapKind {
    ClientToScreen,
    ScreenToClient,
}

fn write_window_rect<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hwnd: u32,
    rect_ptr: u32,
    kind: WindowRectKind,
) -> bool {
    let rect = match kind {
        WindowRectKind::Window => kernel.gwe.get_window_rect(hwnd),
        WindowRectKind::Client => kernel.gwe.get_client_rect(hwnd),
    };
    let Some(rect) = rect else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    write_guest_rect(kernel, memory, thread_id, rect_ptr, rect)
}

// Strsafe helpers.

// Read up to max_chars wide chars from guest memory (not including null terminator).
fn read_guest_wcs_bounded<M: CoredllGuestMemory>(memory: &M, ptr: u32, max_chars: u32) -> Vec<u16> {
    let mut v = Vec::new();
    for i in 0..max_chars {
        match memory.read_u16(ptr + i * 2) {
            Ok(0) => break,
            Ok(c) => v.push(c),
            Err(_) => break,
        }
    }
    v
}

// Read up to max_bytes bytes from guest memory (stops at NUL or limit).
fn read_guest_bytes_bounded<M: CoredllGuestMemory>(
    memory: &M,
    ptr: u32,
    max_bytes: u32,
) -> Vec<u8> {
    let mut v = Vec::new();
    for i in 0..max_bytes {
        match memory.read_u8(ptr + i) {
            Ok(0) => break,
            Ok(c) => v.push(c),
            Err(_) => break,
        }
    }
    v
}

// Write wide string to guest memory, NUL-terminate within cap_chars characters.
// Returns true if the whole string fit.
fn write_guest_wcs<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    dst: u32,
    src: &[u16],
    cap_chars: u32,
) -> bool {
    if cap_chars == 0 {
        return false;
    }
    let copy = src.len().min((cap_chars - 1) as usize);
    for (i, &ch) in src[..copy].iter().enumerate() {
        if !write_guest_u16(kernel, memory, thread_id, dst + i as u32 * 2, ch) {
            return false;
        }
    }
    write_guest_u16(kernel, memory, thread_id, dst + copy as u32 * 2, 0);
    copy == src.len()
}

// Write ANSI string to guest memory, NUL-terminate within cap_bytes.
fn strsafe_write_bytes<M: CoredllGuestMemory>(
    _kernel: &mut CeKernel,
    memory: &mut M,
    _thread_id: u32,
    dst: u32,
    src: &[u8],
    cap_bytes: u32,
) -> bool {
    if cap_bytes == 0 {
        return false;
    }
    let copy = src.len().min((cap_bytes - 1) as usize);
    for (i, &b) in src[..copy].iter().enumerate() {
        if memory.write_u8(dst + i as u32, b).is_err() {
            return false;
        }
    }
    let _ = memory.write_u8(dst + copy as u32, 0);
    copy == src.len()
}

fn strsafe_copy_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
    _is_cb: bool,
) -> u32 {
    let dst = raw_arg(args, 0);
    let cap = raw_arg(args, 1); // chars or bytes depending on Cch vs Cb
    let src_ptr = raw_arg(args, 2);
    if dst == 0 || cap == 0 {
        return STRSAFE_E_INVALID_PARAMETER;
    }
    let cap_chars = if _is_cb { cap / 2 } else { cap };
    let src = read_guest_wcs_bounded(memory, src_ptr, 0x8000);
    if write_guest_wcs(kernel, memory, thread_id, dst, &src, cap_chars) {
        0 // S_OK
    } else {
        STRSAFE_E_INSUFFICIENT_BUFFER
    }
}

fn strsafe_copy_ex_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
    _is_cb: bool,
) -> u32 {
    // StringCchCopyExW(pszDest, cchDest, pszSrc, ppszDestEnd, pcchRemaining, dwFlags)
    let dst = raw_arg(args, 0);
    let cap = raw_arg(args, 1);
    let src_ptr = raw_arg(args, 2);
    let pp_end = raw_arg(args, 3);
    let p_rem = raw_arg(args, 4);
    // dwFlags at args[5] — ignored in emulation
    if dst == 0 || cap == 0 {
        return STRSAFE_E_INVALID_PARAMETER;
    }
    let cap_chars = if _is_cb { cap / 2 } else { cap };
    let src = read_guest_wcs_bounded(memory, src_ptr, 0x8000);
    let ok = write_guest_wcs(kernel, memory, thread_id, dst, &src, cap_chars);
    let written = src.len().min((cap_chars - 1) as usize);
    let end_ptr = dst + written as u32 * 2;
    let rem = cap_chars.saturating_sub(written as u32 + 1);
    if pp_end != 0 {
        write_guest_u32(kernel, memory, thread_id, pp_end, end_ptr);
    }
    if p_rem != 0 {
        write_guest_u32(kernel, memory, thread_id, p_rem, rem);
    }
    if ok { 0 } else { STRSAFE_E_INSUFFICIENT_BUFFER }
}

fn strsafe_copy_n_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
    _ex: bool,
) -> u32 {
    // StringCchCopyNW(pszDest, cchDest, pszSrc, cchSrc) — copy at most cchSrc chars.
    let dst = raw_arg(args, 0);
    let cap = raw_arg(args, 1);
    let src_ptr = raw_arg(args, 2);
    let src_limit = raw_arg(args, 3);
    if dst == 0 || cap == 0 {
        return STRSAFE_E_INVALID_PARAMETER;
    }
    let src = read_guest_wcs_bounded(memory, src_ptr, src_limit);
    if write_guest_wcs(kernel, memory, thread_id, dst, &src, cap) {
        0
    } else {
        STRSAFE_E_INSUFFICIENT_BUFFER
    }
}

fn strsafe_cat_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
    _ex: bool,
) -> u32 {
    let dst = raw_arg(args, 0);
    let cap = raw_arg(args, 1);
    let src_ptr = raw_arg(args, 2);
    if dst == 0 || cap == 0 {
        return STRSAFE_E_INVALID_PARAMETER;
    }
    // Find current length of dst.
    let dst_len = read_guest_wcs_bounded(memory, dst, cap).len() as u32;
    let rem_chars = cap.saturating_sub(dst_len);
    let src = read_guest_wcs_bounded(memory, src_ptr, 0x8000);
    if write_guest_wcs(
        kernel,
        memory,
        thread_id,
        dst + dst_len * 2,
        &src,
        rem_chars,
    ) {
        0
    } else {
        STRSAFE_E_INSUFFICIENT_BUFFER
    }
}

