fn enum_windows_raw(kernel: &mut CeKernel, thread_id: u32, _callback: u32, _lparam: u32) -> bool {
    // EnumWindows requires invoking a guest callback, which needs Unicorn.
    // In raw dispatch (non-Unicorn) record the attempt and return TRUE (empty enumeration).
    kernel.threads.set_last_error(thread_id, 0);
    true
}

// DPA (Dynamic Pointer Array) helpers.
// CE DPA struct layout (20 bytes at HDPA):
//   +0  cpItems   i32 — current item count
//   +4  pp        u32 — guest pointer to item array (array of u32 pointers)
//   +8  hheap     u32 — heap handle used for allocations
//   +12 cpCapacity i32 — allocated capacity in items
//   +16 cpGrow    i32 — grow increment

const DPA_SIZE: u32 = 20;
const DPA_OFFSET_CP_ITEMS: u32 = 0;
const DPA_OFFSET_PP: u32 = 4;
const DPA_OFFSET_HHEAP: u32 = 8;
const DPA_OFFSET_CP_CAPACITY: u32 = 12;
const DPA_OFFSET_CP_GROW: u32 = 16;

fn dpa_create_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let cp_grow = raw_i32_arg(args, 0).max(1);
    let heap = kernel.memory.get_process_heap();
    let Some(hdpa) = kernel.memory.heap_alloc(heap, 0, DPA_SIZE) else {
        kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
        return 0;
    };
    let _ = memory.write_u32(hdpa + DPA_OFFSET_CP_ITEMS, 0);
    let _ = memory.write_u32(hdpa + DPA_OFFSET_PP, 0);
    let _ = memory.write_u32(hdpa + DPA_OFFSET_HHEAP, heap);
    let _ = memory.write_u32(hdpa + DPA_OFFSET_CP_CAPACITY, 0);
    let _ = memory.write_u32(hdpa + DPA_OFFSET_CP_GROW, cp_grow as u32);
    kernel.threads.set_last_error(thread_id, 0);
    hdpa
}

fn dpa_destroy_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdpa: u32,
) -> bool {
    if hdpa == 0 {
        return false;
    }
    let Ok(heap) = memory.read_u32(hdpa + DPA_OFFSET_HHEAP) else {
        return false;
    };
    let Ok(pp) = memory.read_u32(hdpa + DPA_OFFSET_PP) else {
        return false;
    };
    if pp != 0 {
        let _ = kernel.memory.heap_free(heap, 0, pp);
    }
    let _ = kernel.memory.heap_free(heap, 0, hdpa);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn dpa_callback_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
    destroy: bool,
) -> u32 {
    let hdpa = raw_arg(args, 0);
    let callback = raw_arg(args, 1);
    if callback != 0 {
        // Guest callbacks require the Unicorn callout path.
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_SUPPORTED);
        return 0;
    }
    if destroy {
        let _ = dpa_destroy_raw(kernel, memory, thread_id, hdpa);
    } else {
        kernel.threads.set_last_error(thread_id, 0);
    }
    0
}

fn dpa_ensure_capacity<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    hdpa: u32,
    needed: u32,
) -> bool {
    let Ok(heap) = memory.read_u32(hdpa + DPA_OFFSET_HHEAP) else {
        return false;
    };
    let Ok(capacity) = memory.read_u32(hdpa + DPA_OFFSET_CP_CAPACITY) else {
        return false;
    };
    let Ok(cp_grow) = memory.read_u32(hdpa + DPA_OFFSET_CP_GROW) else {
        return false;
    };
    if capacity >= needed {
        return true;
    }
    let new_capacity = ((needed + cp_grow - 1) / cp_grow) * cp_grow;
    let Some(byte_count) = new_capacity.checked_mul(4) else {
        return false;
    };
    let Ok(pp) = memory.read_u32(hdpa + DPA_OFFSET_PP) else {
        return false;
    };
    let Some(new_pp) = kernel.memory.heap_alloc(heap, 0, byte_count) else {
        return false;
    };
    if pp != 0 {
        // Copy existing items to new array.
        if let Ok(cap_u32) = memory.read_u32(hdpa + DPA_OFFSET_CP_CAPACITY) {
            for i in 0..cap_u32 {
                if let Ok(val) = memory.read_u32(pp + i * 4) {
                    let _ = memory.write_u32(new_pp + i * 4, val);
                }
            }
        }
        let _ = kernel.memory.heap_free(heap, 0, pp);
    }
    let _ = memory.write_u32(hdpa + DPA_OFFSET_PP, new_pp);
    let _ = memory.write_u32(hdpa + DPA_OFFSET_CP_CAPACITY, new_capacity);
    true
}

fn dpa_grow_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdpa = raw_arg(args, 0);
    let count = raw_i32_arg(args, 1);
    if hdpa == 0 || count < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    if dpa_ensure_capacity(kernel, memory, hdpa, count as u32) {
        kernel.threads.set_last_error(thread_id, 0);
        true
    } else {
        kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
        false
    }
}

fn dpa_insert_ptr_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hdpa = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let p = raw_arg(args, 2);
    if hdpa == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0xffff_ffff; // DA_ERR = -1 as u32
    }
    let Ok(cp_items) = memory.read_u32(hdpa + DPA_OFFSET_CP_ITEMS) else {
        return 0xffff_ffff;
    };
    let insert_at = if index < 0 || index as u32 >= cp_items {
        cp_items // append
    } else {
        index as u32
    };
    if !dpa_ensure_capacity(kernel, memory, hdpa, cp_items + 1) {
        kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
        return 0xffff_ffff;
    }
    let Ok(pp) = memory.read_u32(hdpa + DPA_OFFSET_PP) else {
        return 0xffff_ffff;
    };
    // Shift elements after insert_at up by one slot.
    let mut i = cp_items;
    while i > insert_at {
        if let Ok(val) = memory.read_u32(pp + (i - 1) * 4) {
            let _ = memory.write_u32(pp + i * 4, val);
        }
        i -= 1;
    }
    let _ = memory.write_u32(pp + insert_at * 4, p);
    let _ = memory.write_u32(hdpa + DPA_OFFSET_CP_ITEMS, cp_items + 1);
    kernel.threads.set_last_error(thread_id, 0);
    insert_at
}

fn dpa_get_ptr_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    hdpa: u32,
    index: i32,
) -> u32 {
    if hdpa == 0 || index < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Ok(cp_items) = memory.read_u32(hdpa + DPA_OFFSET_CP_ITEMS) else {
        return 0;
    };
    if (index as u32) >= cp_items {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_INDEX);
        return 0;
    }
    let Ok(pp) = memory.read_u32(hdpa + DPA_OFFSET_PP) else {
        return 0;
    };
    memory.read_u32(pp + (index as u32) * 4).unwrap_or(0)
}

fn dpa_set_ptr_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdpa = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let p = raw_arg(args, 2);
    if hdpa == 0 || index < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Ok(cp_items) = memory.read_u32(hdpa + DPA_OFFSET_CP_ITEMS) else {
        return false;
    };
    if (index as u32) >= cp_items {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_INDEX);
        return false;
    }
    let Ok(pp) = memory.read_u32(hdpa + DPA_OFFSET_PP) else {
        return false;
    };
    let _ = memory.write_u32(pp + (index as u32) * 4, p);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn dpa_delete_ptr_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdpa: u32,
    index: i32,
) -> u32 {
    if hdpa == 0 || index < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Ok(cp_items) = memory.read_u32(hdpa + DPA_OFFSET_CP_ITEMS) else {
        return 0;
    };
    let idx = index as u32;
    if idx >= cp_items {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_INDEX);
        return 0;
    }
    let Ok(pp) = memory.read_u32(hdpa + DPA_OFFSET_PP) else {
        return 0;
    };
    let old = memory.read_u32(pp + idx * 4).unwrap_or(0);
    // Shift elements down.
    for i in idx..(cp_items - 1) {
        if let Ok(val) = memory.read_u32(pp + (i + 1) * 4) {
            let _ = memory.write_u32(pp + i * 4, val);
        }
    }
    let _ = memory.write_u32(hdpa + DPA_OFFSET_CP_ITEMS, cp_items - 1);
    kernel.threads.set_last_error(thread_id, 0);
    old
}

fn dpa_delete_all_ptrs_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdpa: u32,
) -> bool {
    if hdpa == 0 {
        return false;
    }
    let _ = memory.write_u32(hdpa + DPA_OFFSET_CP_ITEMS, 0);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn dpa_get_ptr_index_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    hdpa: u32,
    p: u32,
) -> u32 {
    if hdpa == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0xffff_ffff;
    }
    let Ok(cp_items) = memory.read_u32(hdpa + DPA_OFFSET_CP_ITEMS) else {
        return 0xffff_ffff;
    };
    let Ok(pp) = memory.read_u32(hdpa + DPA_OFFSET_PP) else {
        return 0xffff_ffff;
    };
    for i in 0..cp_items {
        if memory.read_u32(pp + i * 4).ok() == Some(p) {
            kernel.threads.set_last_error(thread_id, 0);
            return i;
        }
    }
    0xffff_ffff // DA_ERR = -1 — not found
}

fn dpa_clone_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hdpa = raw_arg(args, 0);
    let hdpa_new = raw_arg(args, 1);
    if hdpa == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Ok(src_cp_items) = memory.read_u32(hdpa + DPA_OFFSET_CP_ITEMS) else {
        return 0;
    };
    let Ok(src_pp) = memory.read_u32(hdpa + DPA_OFFSET_PP) else {
        return 0;
    };
    let Ok(src_cp_grow) = memory.read_u32(hdpa + DPA_OFFSET_CP_GROW) else {
        return 0;
    };
    let dest = if hdpa_new != 0 {
        hdpa_new
    } else {
        let heap = kernel.memory.get_process_heap();
        let Some(h) = kernel.memory.heap_alloc(heap, 0, DPA_SIZE) else {
            kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
            return 0;
        };
        let _ = memory.write_u32(h + DPA_OFFSET_CP_ITEMS, 0);
        let _ = memory.write_u32(h + DPA_OFFSET_PP, 0);
        let _ = memory.write_u32(h + DPA_OFFSET_HHEAP, heap);
        let _ = memory.write_u32(h + DPA_OFFSET_CP_CAPACITY, 0);
        let _ = memory.write_u32(h + DPA_OFFSET_CP_GROW, src_cp_grow);
        h
    };
    if src_cp_items > 0 {
        if !dpa_ensure_capacity(kernel, memory, dest, src_cp_items) {
            kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
            return 0;
        }
        let Ok(dest_pp) = memory.read_u32(dest + DPA_OFFSET_PP) else {
            return 0;
        };
        for i in 0..src_cp_items {
            if let Ok(val) = memory.read_u32(src_pp + i * 4) {
                let _ = memory.write_u32(dest_pp + i * 4, val);
            }
        }
    }
    let _ = memory.write_u32(dest + DPA_OFFSET_CP_ITEMS, src_cp_items);
    kernel.threads.set_last_error(thread_id, 0);
    dest
}

// DSA (Dynamic Structure Array) helpers.
// CE DSA struct layout (24 bytes at HDSA):
//   +0  cpItems   u32 — item count
//   +4  pData     u32 — pointer to item data (cpCapacity * cbItem bytes)
//   +8  hheap     u32 — heap handle
//   +12 cpCapacity u32 — allocated capacity in items
//   +16 cpGrow    u32 — grow increment
//   +20 cbItem    u32 — bytes per item

const DSA_SIZE: u32 = 24;
const DSA_OFFSET_CP_ITEMS: u32 = 0;
const DSA_OFFSET_PDATA: u32 = 4;
const DSA_OFFSET_HHEAP: u32 = 8;
const DSA_OFFSET_CP_CAPACITY: u32 = 12;
const DSA_OFFSET_CP_GROW: u32 = 16;
const DSA_OFFSET_CB_ITEM: u32 = 20;

fn dsa_create_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let cb_item = raw_arg(args, 0);
    let cp_grow = raw_arg(args, 1).max(1);
    if cb_item == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let heap = kernel.memory.get_process_heap();
    let Some(hdsa) = kernel.memory.heap_alloc(heap, 0, DSA_SIZE) else {
        kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
        return 0;
    };
    let _ = memory.write_u32(hdsa + DSA_OFFSET_CP_ITEMS, 0);
    let _ = memory.write_u32(hdsa + DSA_OFFSET_PDATA, 0);
    let _ = memory.write_u32(hdsa + DSA_OFFSET_HHEAP, heap);
    let _ = memory.write_u32(hdsa + DSA_OFFSET_CP_CAPACITY, 0);
    let _ = memory.write_u32(hdsa + DSA_OFFSET_CP_GROW, cp_grow);
    let _ = memory.write_u32(hdsa + DSA_OFFSET_CB_ITEM, cb_item);
    kernel.threads.set_last_error(thread_id, 0);
    hdsa
}

fn dsa_destroy_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdsa: u32,
) -> bool {
    if hdsa == 0 {
        return false;
    }
    let Ok(heap) = memory.read_u32(hdsa + DSA_OFFSET_HHEAP) else {
        return false;
    };
    let Ok(pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return false;
    };
    if pdata != 0 {
        let _ = kernel.memory.heap_free(heap, 0, pdata);
    }
    let _ = kernel.memory.heap_free(heap, 0, hdsa);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn dsa_callback_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
    destroy: bool,
) -> u32 {
    let hdsa = raw_arg(args, 0);
    let callback = raw_arg(args, 1);
    if callback != 0 {
        // Guest callbacks require the Unicorn callout path.
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_SUPPORTED);
        return 0;
    }
    if destroy {
        let _ = dsa_destroy_raw(kernel, memory, thread_id, hdsa);
    } else {
        kernel.threads.set_last_error(thread_id, 0);
    }
    0
}

fn dsa_ensure_capacity<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    hdsa: u32,
    needed: u32,
) -> bool {
    let Ok(heap) = memory.read_u32(hdsa + DSA_OFFSET_HHEAP) else {
        return false;
    };
    let Ok(capacity) = memory.read_u32(hdsa + DSA_OFFSET_CP_CAPACITY) else {
        return false;
    };
    if capacity >= needed {
        return true;
    }
    let Ok(cp_grow) = memory.read_u32(hdsa + DSA_OFFSET_CP_GROW) else {
        return false;
    };
    let Ok(cb_item) = memory.read_u32(hdsa + DSA_OFFSET_CB_ITEM) else {
        return false;
    };
    let new_capacity = ((needed + cp_grow - 1) / cp_grow) * cp_grow;
    let Some(byte_count) = new_capacity.checked_mul(cb_item) else {
        return false;
    };
    let Some(new_pdata) = kernel.memory.heap_alloc(heap, 0, byte_count) else {
        return false;
    };
    let Ok(old_pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return false;
    };
    if old_pdata != 0 {
        // Copy existing data.
        for i in 0..(capacity * cb_item) {
            if let Ok(b) = memory.read_u8(old_pdata + i) {
                let _ = memory.write_u8(new_pdata + i, b);
            }
        }
        let _ = kernel.memory.heap_free(heap, 0, old_pdata);
    }
    let _ = memory.write_u32(hdsa + DSA_OFFSET_PDATA, new_pdata);
    let _ = memory.write_u32(hdsa + DSA_OFFSET_CP_CAPACITY, new_capacity);
    true
}

fn dsa_grow_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdsa = raw_arg(args, 0);
    let count = raw_i32_arg(args, 1);
    if hdsa == 0 || count < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    if dsa_ensure_capacity(kernel, memory, hdsa, count as u32) {
        kernel.threads.set_last_error(thread_id, 0);
        true
    } else {
        kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
        false
    }
}

fn dsa_insert_item_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hdsa = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let p_item = raw_arg(args, 2);
    if hdsa == 0 || p_item == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0xffff_ffff;
    }
    let Ok(cp_items) = memory.read_u32(hdsa + DSA_OFFSET_CP_ITEMS) else {
        return 0xffff_ffff;
    };
    let Ok(cb_item) = memory.read_u32(hdsa + DSA_OFFSET_CB_ITEM) else {
        return 0xffff_ffff;
    };
    let insert_at = if index < 0 || index as u32 >= cp_items {
        cp_items
    } else {
        index as u32
    };
    if !dsa_ensure_capacity(kernel, memory, hdsa, cp_items + 1) {
        kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
        return 0xffff_ffff;
    }
    let Ok(pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return 0xffff_ffff;
    };
    // Shift items above insert_at up by cb_item bytes.
    let mut i = cp_items;
    while i > insert_at {
        for b in 0..cb_item {
            if let Ok(val) = memory.read_u8(pdata + (i - 1) * cb_item + b) {
                let _ = memory.write_u8(pdata + i * cb_item + b, val);
            }
        }
        i -= 1;
    }
    // Copy new item.
    for b in 0..cb_item {
        if let Ok(val) = memory.read_u8(p_item + b) {
            let _ = memory.write_u8(pdata + insert_at * cb_item + b, val);
        }
    }
    let _ = memory.write_u32(hdsa + DSA_OFFSET_CP_ITEMS, cp_items + 1);
    kernel.threads.set_last_error(thread_id, 0);
    insert_at
}

fn dsa_get_item_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdsa = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let p_dest = raw_arg(args, 2);
    if hdsa == 0 || index < 0 || p_dest == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Ok(cp_items) = memory.read_u32(hdsa + DSA_OFFSET_CP_ITEMS) else {
        return false;
    };
    if (index as u32) >= cp_items {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_INDEX);
        return false;
    }
    let Ok(cb_item) = memory.read_u32(hdsa + DSA_OFFSET_CB_ITEM) else {
        return false;
    };
    let Ok(pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return false;
    };
    for b in 0..cb_item {
        if let Ok(val) = memory.read_u8(pdata + (index as u32) * cb_item + b) {
            let _ = memory.write_u8(p_dest + b, val);
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn dsa_get_item_ptr_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    hdsa: u32,
    index: i32,
) -> u32 {
    if hdsa == 0 || index < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Ok(cp_items) = memory.read_u32(hdsa + DSA_OFFSET_CP_ITEMS) else {
        return 0;
    };
    if (index as u32) >= cp_items {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_INDEX);
        return 0;
    }
    let Ok(cb_item) = memory.read_u32(hdsa + DSA_OFFSET_CB_ITEM) else {
        return 0;
    };
    let Ok(pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return 0;
    };
    pdata + (index as u32) * cb_item
}

fn dsa_set_item_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdsa = raw_arg(args, 0);
    let index = raw_i32_arg(args, 1);
    let p_item = raw_arg(args, 2);
    if hdsa == 0 || index < 0 || p_item == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Ok(cp_items) = memory.read_u32(hdsa + DSA_OFFSET_CP_ITEMS) else {
        return false;
    };
    if (index as u32) >= cp_items {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_INDEX);
        return false;
    }
    let Ok(cb_item) = memory.read_u32(hdsa + DSA_OFFSET_CB_ITEM) else {
        return false;
    };
    let Ok(pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return false;
    };
    for b in 0..cb_item {
        if let Ok(val) = memory.read_u8(p_item + b) {
            let _ = memory.write_u8(pdata + (index as u32) * cb_item + b, val);
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn dsa_delete_item_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdsa: u32,
    index: i32,
) -> bool {
    if hdsa == 0 || index < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Ok(cp_items) = memory.read_u32(hdsa + DSA_OFFSET_CP_ITEMS) else {
        return false;
    };
    let idx = index as u32;
    if idx >= cp_items {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_INDEX);
        return false;
    }
    let Ok(cb_item) = memory.read_u32(hdsa + DSA_OFFSET_CB_ITEM) else {
        return false;
    };
    let Ok(pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return false;
    };
    for i in idx..(cp_items - 1) {
        for b in 0..cb_item {
            if let Ok(val) = memory.read_u8(pdata + (i + 1) * cb_item + b) {
                let _ = memory.write_u8(pdata + i * cb_item + b, val);
            }
        }
    }
    let _ = memory.write_u32(hdsa + DSA_OFFSET_CP_ITEMS, cp_items - 1);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn dsa_clone_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hdsa = raw_arg(args, 0);
    let hdsa_new = raw_arg(args, 1);
    if hdsa == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Ok(src_cp_items) = memory.read_u32(hdsa + DSA_OFFSET_CP_ITEMS) else {
        return 0;
    };
    let Ok(src_pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return 0;
    };
    let Ok(src_cp_grow) = memory.read_u32(hdsa + DSA_OFFSET_CP_GROW) else {
        return 0;
    };
    let Ok(src_cb_item) = memory.read_u32(hdsa + DSA_OFFSET_CB_ITEM) else {
        return 0;
    };
    let dest = if hdsa_new != 0 {
        hdsa_new
    } else {
        let heap = kernel.memory.get_process_heap();
        let Some(h) = kernel.memory.heap_alloc(heap, 0, DSA_SIZE) else {
            kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
            return 0;
        };
        let _ = memory.write_u32(h + DSA_OFFSET_CP_ITEMS, 0);
        let _ = memory.write_u32(h + DSA_OFFSET_PDATA, 0);
        let _ = memory.write_u32(h + DSA_OFFSET_HHEAP, heap);
        let _ = memory.write_u32(h + DSA_OFFSET_CP_CAPACITY, 0);
        let _ = memory.write_u32(h + DSA_OFFSET_CP_GROW, src_cp_grow);
        let _ = memory.write_u32(h + DSA_OFFSET_CB_ITEM, src_cb_item);
        h
    };
    if src_cp_items > 0 {
        if !dsa_ensure_capacity(kernel, memory, dest, src_cp_items) {
            kernel.threads.set_last_error(thread_id, ERROR_OUTOFMEMORY);
            return 0;
        }
        let Ok(dest_pdata) = memory.read_u32(dest + DSA_OFFSET_PDATA) else {
            return 0;
        };
        for i in 0..(src_cp_items * src_cb_item) {
            if let Ok(b) = memory.read_u8(src_pdata + i) {
                let _ = memory.write_u8(dest_pdata + i, b);
            }
        }
    }
    let _ = memory.write_u32(dest + DSA_OFFSET_CP_ITEMS, src_cp_items);
    kernel.threads.set_last_error(thread_id, 0);
    dest
}

fn dsa_set_range_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdsa = raw_arg(args, 0);
    let i_start = raw_i32_arg(args, 1);
    let c_items = raw_i32_arg(args, 2);
    let pv = raw_arg(args, 3);
    if hdsa == 0 || i_start < 0 || c_items <= 0 || pv == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let i_start = i_start as u32;
    let c_items = c_items as u32;
    let Ok(cp_items) = memory.read_u32(hdsa + DSA_OFFSET_CP_ITEMS) else {
        return false;
    };
    let Ok(cb_item) = memory.read_u32(hdsa + DSA_OFFSET_CB_ITEM) else {
        return false;
    };
    if i_start.saturating_add(c_items) > cp_items {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Ok(pdata) = memory.read_u32(hdsa + DSA_OFFSET_PDATA) else {
        return false;
    };
    // Copy the single cb_item-sized value at pv into each slot in the range.
    for item in 0..c_items {
        for b in 0..cb_item {
            if let Ok(byte) = memory.read_u8(pv + b) {
                let _ = memory.write_u8(pdata + (i_start + item) * cb_item + b, byte);
            }
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_window_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32, cmd: u32) -> u32 {
    if !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    if cmd > crate::ce::gwe::GW_CHILD {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    kernel.gwe.get_window(hwnd, cmd).unwrap_or(0)
}

fn set_parent_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32, parent: u32) -> u32 {
    let parent = (parent != 0).then_some(parent);
    if !kernel.gwe.is_window(hwnd) || parent.is_some_and(|parent| !kernel.gwe.is_window(parent)) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    if parent.is_some_and(|parent| parent == hwnd || kernel.gwe.is_child(hwnd, parent)) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let previous = kernel.set_parent(hwnd, parent).flatten().unwrap_or(0);
    kernel.threads.set_last_error(thread_id, 0);
    previous
}

fn show_window_raw(
    kernel: &mut CeKernel,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    const SW_HIDE: u32 = 0;
    const SW_SHOWNOACTIVATE: u32 = 4;
    const SW_SHOWMINNOACTIVE: u32 = 7;
    const SW_SHOWNA: u32 = 8;
    let hwnd = raw_arg(args, 0);
    let cmd = raw_arg(args, 1);
    let visible = cmd != SW_HIDE;
    let activate = visible && !matches!(cmd, SW_SHOWNOACTIVATE | SW_SHOWMINNOACTIVE | SW_SHOWNA);
    if visible && !kernel.gwe.is_window_visible(hwnd) {
        if let Some(framebuffer) = framebuffer.as_deref() {
            let _ = kernel.capture_window_backing_store(hwnd, framebuffer);
        }
    }
    let previous = kernel.show_window_with_framebuffer(hwnd, visible, activate, framebuffer);
    kernel.record_window_lifecycle_trace(
        "show_window_cmd",
        thread_id,
        Some(hwnd),
        Some(u32::from(previous)),
        Some(format!(
            "cmd={cmd}/visible={visible}/activate={activate}/module={}/process_show_cmd={}",
            kernel.process_module_path(),
            kernel.process_show_cmd()
        )),
    );
    previous
}

fn set_foreground_window_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32) -> bool {
    if hwnd == 0 || !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    let _ = kernel.activate_window(Some(hwnd));
    let _ = kernel.set_focus(Some(hwnd));
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn set_active_window_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32) -> u32 {
    if hwnd != 0 && !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    let previous = kernel.gwe.get_active_window().unwrap_or(0);
    let _ = kernel.activate_window((hwnd != 0).then_some(hwnd));
    kernel.threads.set_last_error(thread_id, 0);
    previous
}

fn set_focus_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32) -> Option<u32> {
    if hwnd != 0 && !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return None;
    }
    let previous = kernel.set_focus((hwnd != 0).then_some(hwnd));
    kernel.threads.set_last_error(thread_id, 0);
    previous
}

fn set_keyboard_target_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32) -> u32 {
    if hwnd != 0 && !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    let previous = kernel
        .set_keyboard_target(thread_id, (hwnd != 0).then_some(hwnd))
        .unwrap_or(0);
    kernel.threads.set_last_error(thread_id, 0);
    previous
}

fn get_keyboard_layout_list_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let capacity = raw_i32_arg(args, 0);
    let list_ptr = raw_arg(args, 1);
    let layouts = kernel.gwe.keyboard_layout_list();
    if capacity <= 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return layouts.len() as u32;
    }
    if list_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let count = layouts.len().min(capacity as usize);
    for (index, hkl) in layouts.iter().copied().take(count).enumerate() {
        if !write_guest_u32(
            kernel,
            memory,
            thread_id,
            list_ptr.wrapping_add((index as u32) * 4),
            hkl,
        ) {
            return 0;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    count as u32
}

fn get_keyboard_layout_name_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    buffer: u32,
) -> bool {
    let name = kernel.gwe.keyboard_layout_name().to_owned();
    if write_wide_result(kernel, memory, thread_id, buffer, 9, &name) == 0 {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn load_keyboard_layout_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    const KLF_ACTIVATE: u32 = 0x0000_0001;
    const KLF_SETFORPROCESS: u32 = 0x0000_0100;
    const VALID_FLAGS: u32 = KLF_ACTIVATE | KLF_SETFORPROCESS;

    let Some(name) = read_guest_wide_arg(memory, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let flags = raw_arg(args, 1);
    if flags & !VALID_FLAGS != 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let activate = flags & KLF_ACTIVATE != 0;
    let previous = kernel.gwe.keyboard_layout();
    let Some(hkl) = kernel.gwe.load_keyboard_layout_from_name(&name, activate) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    if activate && previous != hkl {
        post_input_lang_change(kernel, thread_id, hkl);
    }
    hkl
}

fn activate_keyboard_layout_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> u32 {
    const KLF_ACTIVATE: u32 = 0x0000_0001;
    const KLF_SETFORPROCESS: u32 = 0x0000_0100;
    const VALID_FLAGS: u32 = KLF_ACTIVATE | KLF_SETFORPROCESS;

    let hkl = raw_arg(args, 0);
    let flags = raw_arg(args, 1);
    if flags & !VALID_FLAGS != 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    match kernel.gwe.activate_keyboard_layout(hkl) {
        Some(previous) => {
            kernel.threads.set_last_error(thread_id, 0);
            post_input_lang_change(kernel, thread_id, kernel.gwe.keyboard_layout());
            previous
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            0
        }
    }
}

fn post_input_lang_change(kernel: &mut CeKernel, thread_id: u32, hkl: u32) {
    if let Some(focus) = kernel.gwe.get_focus() {
        const DEFAULT_CHARSET: u32 = 1;
        kernel.post_message_w_for_thread(
            thread_id,
            focus,
            crate::ce::gwe::WM_INPUTLANGCHANGE,
            DEFAULT_CHARSET,
            hkl,
        );
    }
}

fn imm_get_property_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> u32 {
    const IGP_GETIMEVERSION: u32 = 0xffff_fffc;
    const IGP_PROPERTY: u32 = 0x0000_0004;
    const IGP_CONVERSION: u32 = 0x0000_0008;
    const IGP_SENTENCE: u32 = 0x0000_000c;
    const IGP_UI: u32 = 0x0000_0010;
    const IGP_SETCOMPSTR: u32 = 0x0000_0014;
    const IGP_SELECT: u32 = 0x0000_0018;
    const IGP_PRIVATEDATASIZE: u32 = 0x0000_001c;

    const IMEVER_0400: u32 = 0x0004_0000;
    const IME_PROP_KBD_CHAR_FIRST: u32 = 0x0000_0002;
    const IME_PROP_AT_CARET: u32 = 0x0001_0000;
    const IME_PROP_UNICODE: u32 = 0x0008_0000;
    const IME_CMODE_LANGUAGE: u32 = 0x0000_0003;
    const IME_CMODE_FULLSHAPE: u32 = 0x0000_0008;
    const IME_CMODE_ROMAN: u32 = 0x0000_0010;
    const IME_CMODE_CHARCODE: u32 = 0x0000_0020;
    const UI_CAP_2700: u32 = 0x0000_0001;
    const SELECT_CAP_CONVERSION: u32 = 0x0000_0001;

    let hkl = raw_arg(args, 0);
    let index = raw_arg(args, 1);
    kernel.threads.set_last_error(thread_id, 0);
    if !kernel.gwe.is_ime_layout(hkl) {
        return 0;
    }

    match index {
        IGP_GETIMEVERSION => IMEVER_0400,
        IGP_PROPERTY => IME_PROP_KBD_CHAR_FIRST | IME_PROP_AT_CARET | IME_PROP_UNICODE,
        IGP_CONVERSION => {
            IME_CMODE_LANGUAGE | IME_CMODE_FULLSHAPE | IME_CMODE_ROMAN | IME_CMODE_CHARCODE
        }
        IGP_SENTENCE => 0,
        IGP_UI => UI_CAP_2700,
        IGP_SETCOMPSTR => 0,
        IGP_SELECT => SELECT_CAP_CONVERSION,
        IGP_PRIVATEDATASIZE => 4,
        _ => 0,
    }
}

const TESTIME_FAKEWORD_NOUN: u32 = 0x8000_0000;
const TESTIME_FAKEWORD_VERB: u32 = 0x8000_0001;

fn is_testime_register_word_style(style: u32) -> bool {
    matches!(style, TESTIME_FAKEWORD_NOUN | TESTIME_FAKEWORD_VERB)
}

fn imm_get_register_word_style_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hkl = raw_arg(args, 0);
    let count = raw_arg(args, 1);
    let buffer = raw_arg(args, 2);
    kernel.threads.set_last_error(thread_id, 0);
    if !kernel.gwe.is_ime_layout(hkl) {
        return 0;
    }
    if count == 0 || buffer == 0 {
        return 2;
    }
    if !write_testime_stylebuf_w(
        kernel,
        memory,
        thread_id,
        buffer,
        TESTIME_FAKEWORD_NOUN,
        "NOUN",
    ) {
        return 0;
    }
    if count > 1
        && !write_testime_stylebuf_w(
            kernel,
            memory,
            thread_id,
            buffer + TESTIME_STYLEBUFW_SIZE,
            TESTIME_FAKEWORD_VERB,
            "VERB",
        )
    {
        return 0;
    }
    0
}

const TESTIME_STYLEBUFW_SIZE: u32 = 4 + 32 * 2;

fn write_testime_stylebuf_w<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    buffer: u32,
    style: u32,
    description: &str,
) -> bool {
    write_guest_u32(kernel, memory, thread_id, buffer, style)
        && write_guest_wide_fixed(kernel, memory, thread_id, buffer + 4, description, 32)
}

fn imm_register_word_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hkl = raw_arg(args, 0);
    let reading_ptr = raw_arg(args, 1);
    let style = raw_arg(args, 2);
    let word_ptr = raw_arg(args, 3);
    if !kernel.gwe.is_ime_layout(hkl)
        || !is_testime_register_word_style(style)
        || reading_ptr == 0
        || word_ptr == 0
    {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }
    let Some(reading) = read_guest_wide_z_bounded(kernel, memory, thread_id, reading_ptr, 256)
    else {
        return false;
    };
    let Some(word) = read_guest_wide_z_bounded(kernel, memory, thread_id, word_ptr, 256) else {
        return false;
    };
    kernel.gwe.register_ime_word(reading, style, word);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_unregister_word_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hkl = raw_arg(args, 0);
    let reading_ptr = raw_arg(args, 1);
    let style = raw_arg(args, 2);
    let word_ptr = raw_arg(args, 3);
    if !kernel.gwe.is_ime_layout(hkl)
        || !is_testime_register_word_style(style)
        || reading_ptr == 0
        || word_ptr == 0
    {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }
    let Some(reading) = read_guest_wide_z_bounded(kernel, memory, thread_id, reading_ptr, 256)
    else {
        return false;
    };
    let Some(word) = read_guest_wide_z_bounded(kernel, memory, thread_id, word_ptr, 256) else {
        return false;
    };
    kernel.gwe.unregister_ime_word(&reading, &word);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_enum_register_word_w_raw(kernel: &mut CeKernel, thread_id: u32, hkl: u32) -> u32 {
    kernel.threads.set_last_error(thread_id, 0);
    if !kernel.gwe.is_ime_layout(hkl) {
        return 0;
    }
    // The TESTIME implementation is callback-driven.  Raw dispatch cannot enter
    // guest code, so the Unicorn import hook performs real enumeration.
    0
}

fn imm_get_conversion_list_w_raw(kernel: &mut CeKernel, thread_id: u32) -> u32 {
    // TESTIME's ImeConversionList is a stub that returns no candidate bytes for
    // GCL_CONVERSION, GCL_REVERSECONVERSION, and GCL_REVERSE_LENGTH alike.
    kernel.threads.set_last_error(thread_id, 0);
    0
}

fn imm_escape_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    const IME_ESC_QUERY_SUPPORT: u32 = 0x0003;

    let hkl = raw_arg(args, 0);
    let subfunc = raw_arg(args, 2);
    let data = raw_arg(args, 3);
    kernel.threads.set_last_error(thread_id, 0);
    if !kernel.gwe.is_ime_layout(hkl) || subfunc != IME_ESC_QUERY_SUPPORT || data == 0 {
        return 0;
    }
    u32::from(
        read_guest_u32(kernel, memory, thread_id, data)
            .is_some_and(|requested| requested == IME_ESC_QUERY_SUPPORT),
    )
}

fn default_ime_wnd_get_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32) -> u32 {
    // CE keeps a per-thread default IME window. The emulator does not create
    // hidden IME windows yet, so use the active focus window as the observable
    // message target proxy and fall back to a valid caller HWND.
    let ime_hwnd = kernel
        .gwe
        .get_focus()
        .filter(|focus| kernel.gwe.is_window(*focus))
        .or_else(|| (hwnd != 0 && kernel.gwe.is_window(hwnd)).then_some(hwnd))
        .unwrap_or(0);
    kernel.threads.set_last_error(thread_id, 0);
    ime_hwnd
}

fn imm_is_ui_message_w_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let hwnd = raw_arg(args, 0);
    let msg = raw_arg(args, 1);
    let wparam = raw_arg(args, 2);
    let lparam = raw_arg(args, 3);

    if !is_ime_ui_message(msg) {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }

    let target = if hwnd != 0 {
        kernel.gwe.is_window(hwnd).then_some(hwnd).unwrap_or(0)
    } else {
        default_ime_wnd_get_raw(kernel, thread_id, 0)
    };
    if target == 0 || kernel.send_message_w(target, msg, wparam, lparam).is_none() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }

    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn is_ime_ui_message(msg: u32) -> bool {
    const WM_IME_SETCONTEXT: u32 = 0x0281;
    const WM_IME_CONTROL: u32 = 0x0283;
    const WM_IME_COMPOSITIONFULL: u32 = 0x0284;
    const WM_IME_SELECT: u32 = 0x0285;
    matches!(
        msg,
        WM_IME_SETCONTEXT
            | crate::ce::gwe::WM_IME_NOTIFY
            | WM_IME_CONTROL
            | WM_IME_COMPOSITIONFULL
            | WM_IME_SELECT
            | crate::ce::gwe::WM_IME_CHAR
            | crate::ce::gwe::WM_IME_STARTCOMPOSITION
            | crate::ce::gwe::WM_IME_ENDCOMPOSITION
            | crate::ce::gwe::WM_IME_COMPOSITION
    )
}

fn imm_get_hot_key_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let modifiers_ptr = raw_arg(args, 1);
    let vkey_ptr = raw_arg(args, 2);
    let hkl_ptr = raw_arg(args, 3);
    if !write_optional_u32(kernel, memory, thread_id, modifiers_ptr, 0)
        || !write_optional_u32(kernel, memory, thread_id, vkey_ptr, 0)
        || !write_optional_u32(kernel, memory, thread_id, hkl_ptr, 0)
    {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    false
}

fn imm_get_context_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32) -> u32 {
    if hwnd == 0 || !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    let himc = kernel.gwe.get_ime_context(hwnd).unwrap_or(0);
    kernel.threads.set_last_error(thread_id, 0);
    himc
}

fn imm_destroy_context_raw(kernel: &mut CeKernel, thread_id: u32, himc: u32) -> bool {
    let ok = kernel.gwe.destroy_ime_context(himc);
    kernel
        .threads
        .set_last_error(thread_id, if ok { 0 } else { ERROR_INVALID_HANDLE });
    ok
}

fn imm_release_context_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let hwnd = raw_arg(args, 0);
    let himc = raw_arg(args, 1);
    let ok = hwnd != 0 && himc != 0 && kernel.gwe.release_ime_context(hwnd, himc);
    kernel
        .threads
        .set_last_error(thread_id, if ok { 0 } else { ERROR_INVALID_HANDLE });
    ok
}

fn imm_associate_context_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> u32 {
    match kernel
        .gwe
        .associate_ime_context(raw_arg(args, 0), raw_arg(args, 1))
    {
        Some(previous) => {
            kernel.threads.set_last_error(thread_id, 0);
            previous
        }
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            0
        }
    }
}

const CE_COMPOSITIONSTRING_SIZE: u32 = 25 * 4;
const CE_CANDIDATEINFO_SIZE: u32 = 4 + 4 + 32 * 4 + 4 + 4;
const CE_INPUTCONTEXT_SIZE: u32 = 356;
const INPUTCONTEXT_HWND_OFFSET: u32 = 0;
const INPUTCONTEXT_OPEN_OFFSET: u32 = 4;
const INPUTCONTEXT_STATUS_POS_OFFSET: u32 = 16;
const INPUTCONTEXT_CONVERSION_OFFSET: u32 = 32;
const INPUTCONTEXT_SENTENCE_OFFSET: u32 = 36;
const INPUTCONTEXT_LOGFONT_OFFSET: u32 = 40;
const INPUTCONTEXT_COMP_FORM_OFFSET: u32 = 132;
const INPUTCONTEXT_CAND_FORM_OFFSET: u32 = 160;
const INPUTCONTEXT_COMP_STR_OFFSET: u32 = 288;
const INPUTCONTEXT_CAND_INFO_OFFSET: u32 = 292;
const INPUTCONTEXT_GUIDE_LINE_OFFSET: u32 = 296;
const INPUTCONTEXT_PRIVATE_OFFSET: u32 = 300;
const INPUTCONTEXT_NUM_MSG_BUF_OFFSET: u32 = 304;
const INPUTCONTEXT_MSG_BUF_OFFSET: u32 = 308;
const INPUTCONTEXT_REFCOUNT_OFFSET: u32 = 344;

fn imm_create_imcc_raw(kernel: &mut CeKernel, thread_id: u32, size: u32) -> u32 {
    let Some(handle) = kernel
        .memory
        .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, size)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    kernel
        .gwe
        .register_ime_component(handle, crate::ce::gwe::ImeComponentKind::Generic, size);
    kernel.threads.set_last_error(thread_id, 0);
    handle
}

fn imm_destroy_imcc_raw(kernel: &mut CeKernel, thread_id: u32, himcc: u32) -> bool {
    if himcc == 0 || kernel.gwe.ime_component(himcc).is_none() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    let ok = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, himcc);
    if ok {
        kernel.gwe.unregister_ime_component(himcc);
    }
    kernel
        .threads
        .set_last_error(thread_id, if ok { 0 } else { ERROR_INVALID_HANDLE });
    ok
}

fn allocate_ime_component(
    kernel: &mut CeKernel,
    thread_id: u32,
    kind: crate::ce::gwe::ImeComponentKind,
    size: u32,
) -> Option<u32> {
    let handle = kernel
        .memory
        .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, size)?;
    kernel.gwe.register_ime_component(handle, kind, size);
    kernel.threads.set_last_error(thread_id, 0);
    Some(handle)
}

fn ensure_ime_context_guest_buffers(kernel: &mut CeKernel, thread_id: u32, himc: u32) -> bool {
    let (needs_input, needs_comp, needs_cand) = {
        let Some(context) = kernel.gwe.ime_context(himc) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return false;
        };
        (
            context.input_context_ptr == 0,
            context.h_comp_str == 0,
            context.h_cand_info == 0,
        )
    };

    let input_ptr = if needs_input {
        Some(
            match kernel.memory.heap_alloc(
                PROCESS_HEAP_HANDLE,
                HEAP_ZERO_MEMORY,
                CE_INPUTCONTEXT_SIZE,
            ) {
                Some(ptr) => ptr,
                None => {
                    kernel
                        .threads
                        .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
                    return false;
                }
            },
        )
    } else {
        None
    };
    let comp_handle = if needs_comp {
        match allocate_ime_component(
            kernel,
            thread_id,
            crate::ce::gwe::ImeComponentKind::CompositionString,
            CE_COMPOSITIONSTRING_SIZE,
        ) {
            Some(handle) => Some(handle),
            None => {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
                return false;
            }
        }
    } else {
        None
    };
    let cand_handle = if needs_cand {
        match allocate_ime_component(
            kernel,
            thread_id,
            crate::ce::gwe::ImeComponentKind::CandidateInfo,
            CE_CANDIDATEINFO_SIZE,
        ) {
            Some(handle) => Some(handle),
            None => {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
                return false;
            }
        }
    } else {
        None
    };

    let Some(context) = kernel.gwe.ime_context_mut(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    if let Some(ptr) = input_ptr {
        context.input_context_ptr = ptr;
    }
    if let Some(handle) = comp_handle {
        context.h_comp_str = handle;
    }
    if let Some(handle) = cand_handle {
        context.h_cand_info = handle;
    }
    true
}

fn imm_lock_imc_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let himc = raw_arg(args, 0);
    if himc == 0 || kernel.gwe.ime_context(himc).is_none() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    if !ensure_ime_context_guest_buffers(kernel, thread_id, himc)
        || !serialize_ime_components(kernel, memory, thread_id, himc)
        || !serialize_input_context(kernel, memory, thread_id, himc)
    {
        return 0;
    }
    let Some(context) = kernel.gwe.ime_context_mut(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    context.lock_count = context.lock_count.saturating_add(1);
    let ptr = context.input_context_ptr;
    kernel.threads.set_last_error(thread_id, 0);
    ptr
}

fn imm_unlock_imc_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let himc = raw_arg(args, 0);
    let ptr = match kernel.gwe.ime_context(himc) {
        Some(context) if context.input_context_ptr != 0 => context.input_context_ptr,
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return false;
        }
    };
    let h_comp_str = read_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_COMP_STR_OFFSET),
    )
    .unwrap_or(0);
    let h_cand_info = read_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_CAND_INFO_OFFSET),
    )
    .unwrap_or(0);
    let h_guide_line = read_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_GUIDE_LINE_OFFSET),
    )
    .unwrap_or(0);
    let Some(context) = kernel.gwe.ime_context_mut(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    context.h_comp_str = h_comp_str;
    context.h_cand_info = h_cand_info;
    context.h_guide_line = h_guide_line;
    context.lock_count = context.lock_count.saturating_sub(1);
    for (handle, kind) in [
        (
            h_comp_str,
            crate::ce::gwe::ImeComponentKind::CompositionString,
        ),
        (h_cand_info, crate::ce::gwe::ImeComponentKind::CandidateInfo),
        (h_guide_line, crate::ce::gwe::ImeComponentKind::GuideLine),
    ] {
        if handle != 0 {
            let size = kernel
                .gwe
                .ime_component(handle)
                .map(|component| component.size)
                .or_else(|| kernel.memory.heap_size(PROCESS_HEAP_HANDLE, 0, handle))
                .unwrap_or(0);
            kernel.gwe.register_ime_component(handle, kind, size);
        }
    }
    deserialize_ime_components(kernel, memory, thread_id, himc, h_comp_str, h_cand_info);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_get_imc_lock_count_raw(kernel: &mut CeKernel, thread_id: u32, himc: u32) -> u32 {
    let Some(context) = kernel.gwe.ime_context(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    context.lock_count
}

fn imm_lock_imcc_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let himcc = raw_arg(args, 0);
    let Some(component) = kernel.gwe.ime_component(himcc).copied() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let ok = match component.kind {
        crate::ce::gwe::ImeComponentKind::CompositionString => {
            serialize_composition_component_by_handle(kernel, memory, thread_id, himcc)
        }
        crate::ce::gwe::ImeComponentKind::CandidateInfo => {
            serialize_candidate_info_component_by_handle(kernel, memory, thread_id, himcc)
        }
        _ => true,
    };
    if !ok {
        return 0;
    }
    let Some(component) = kernel.gwe.ime_component_mut(himcc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    component.lock_count = component.lock_count.saturating_add(1);
    kernel.threads.set_last_error(thread_id, 0);
    himcc
}

fn imm_unlock_imcc_raw(kernel: &mut CeKernel, thread_id: u32, himcc: u32) -> bool {
    let Some(component) = kernel.gwe.ime_component_mut(himcc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    component.lock_count = component.lock_count.saturating_sub(1);
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_get_imcc_lock_count_raw(kernel: &mut CeKernel, thread_id: u32, himcc: u32) -> u32 {
    let Some(component) = kernel.gwe.ime_component(himcc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    component.lock_count
}

fn imm_get_imcc_size_raw(kernel: &mut CeKernel, thread_id: u32, himcc: u32) -> u32 {
    let Some(component) = kernel.gwe.ime_component(himcc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    component.size
}

fn imm_resize_imcc_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let himcc = raw_arg(args, 0);
    let size = raw_arg(args, 1);
    if himcc == 0 {
        return imm_create_imcc_raw(kernel, thread_id, size);
    }
    let Some(component) = kernel.gwe.ime_component(himcc).copied() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let old_size = component.size;
    let old_bytes = if old_size > 0 {
        read_guest_bytes(kernel, memory, thread_id, himcc, old_size)
    } else {
        None
    };
    let Some(new_handle) =
        kernel
            .memory
            .heap_re_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, himcc, size)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    if let Some(bytes) = old_bytes.as_deref() {
        let copy = bytes.len().min(size as usize);
        if copy > 0 && !write_guest_bytes(kernel, memory, thread_id, new_handle, &bytes[..copy]) {
            return 0;
        }
    }
    kernel
        .gwe
        .register_ime_component(new_handle, component.kind, size);
    if new_handle != himcc {
        kernel.gwe.unregister_ime_component(himcc);
    }
    kernel.threads.set_last_error(thread_id, 0);
    new_handle
}

fn serialize_ime_components<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    himc: u32,
) -> bool {
    serialize_composition_component(kernel, memory, thread_id, himc)
        && serialize_candidate_info_component(kernel, memory, thread_id, himc)
}

fn serialize_composition_component_by_handle<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    himcc: u32,
) -> bool {
    let himc = kernel
        .gwe
        .ime_contexts_iter()
        .find_map(|(himc, context)| (context.h_comp_str == himcc).then_some(himc));
    himc.is_none_or(|himc| serialize_composition_component(kernel, memory, thread_id, himc))
}

fn serialize_candidate_info_component_by_handle<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    himcc: u32,
) -> bool {
    let himc = kernel
        .gwe
        .ime_contexts_iter()
        .find_map(|(himc, context)| (context.h_cand_info == himcc).then_some(himc));
    himc.is_none_or(|himc| serialize_candidate_info_component(kernel, memory, thread_id, himc))
}

fn serialize_composition_component<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    himc: u32,
) -> bool {
    let (handle, composition) = match kernel.gwe.ime_context(himc) {
        Some(context) if context.h_comp_str != 0 => {
            (context.h_comp_str, context.composition_string.clone())
        }
        _ => return true,
    };
    let bytes = serialized_composition_string_w(&composition);
    kernel.gwe.register_ime_component(
        handle,
        crate::ce::gwe::ImeComponentKind::CompositionString,
        bytes.len() as u32,
    );
    write_guest_bytes(kernel, memory, thread_id, handle, &bytes)
}

fn serialize_candidate_info_component<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    himc: u32,
) -> bool {
    let (handle, lists) = match kernel.gwe.ime_context(himc) {
        Some(context) if context.h_cand_info != 0 => {
            (context.h_cand_info, context.candidate_lists.clone())
        }
        _ => return true,
    };
    let bytes = serialized_candidate_info_w(&lists);
    kernel.gwe.register_ime_component(
        handle,
        crate::ce::gwe::ImeComponentKind::CandidateInfo,
        bytes.len() as u32,
    );
    write_guest_bytes(kernel, memory, thread_id, handle, &bytes)
}

fn serialized_composition_string_w(composition: &[u16]) -> Vec<u8> {
    let string_bytes = composition.len() * 2;
    let total_size = CE_COMPOSITIONSTRING_SIZE as usize + string_bytes;
    let mut bytes = vec![0u8; total_size];
    write_le_u32_at(&mut bytes, 0, total_size as u32);
    if !composition.is_empty() {
        write_le_u32_at(&mut bytes, 44, string_bytes as u32);
        write_le_u32_at(&mut bytes, 48, CE_COMPOSITIONSTRING_SIZE);
        for (index, unit) in composition.iter().copied().enumerate() {
            let offset = CE_COMPOSITIONSTRING_SIZE as usize + index * 2;
            bytes[offset..offset + 2].copy_from_slice(&unit.to_le_bytes());
        }
    }
    bytes
}

fn serialized_candidate_info_w(
    lists: &[Option<crate::ce::gwe::ImeCandidateListState>; 4],
) -> Vec<u8> {
    let mut payloads = Vec::new();
    let mut offsets = [0u32; 32];
    let mut count = 0u32;
    for (index, list) in lists.iter().enumerate() {
        let Some(list) = list.as_ref().filter(|list| !list.candidates.is_empty()) else {
            continue;
        };
        count = count.max(index as u32 + 1);
        offsets[index] = (CE_CANDIDATEINFO_SIZE as usize + payloads.len()) as u32;
        payloads.extend_from_slice(&serialized_candidate_list_w(list));
        while payloads.len() % 4 != 0 {
            payloads.push(0);
        }
    }
    let total_size = CE_CANDIDATEINFO_SIZE as usize + payloads.len();
    let mut bytes = vec![0u8; CE_CANDIDATEINFO_SIZE as usize];
    write_le_u32_at(&mut bytes, 0, total_size as u32);
    write_le_u32_at(&mut bytes, 4, count);
    for (index, offset) in offsets.iter().copied().enumerate() {
        write_le_u32_at(&mut bytes, 8 + index * 4, offset);
    }
    bytes.extend_from_slice(&payloads);
    bytes
}

fn write_le_u32_at(bytes: &mut [u8], offset: usize, value: u32) {
    bytes[offset..offset + 4].copy_from_slice(&value.to_le_bytes());
}

fn serialize_input_context<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    himc: u32,
) -> bool {
    let Some(context) = kernel.gwe.ime_context(himc).cloned() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let ptr = context.input_context_ptr;
    if ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    let hwnd = context.hwnd.unwrap_or(0);
    let mut ok = write_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_HWND_OFFSET),
        hwnd,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_OPEN_OFFSET),
        u32::from(context.open),
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_STATUS_POS_OFFSET),
        context.status_window_pos.x as u32,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_STATUS_POS_OFFSET + 4),
        context.status_window_pos.y as u32,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_CONVERSION_OFFSET),
        context.conversion_status,
    ) && write_guest_u32(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_SENTENCE_OFFSET),
        context.sentence_status,
    ) && write_guest_bytes(
        kernel,
        memory,
        thread_id,
        ptr.wrapping_add(INPUTCONTEXT_LOGFONT_OFFSET),
        &context.composition_font,
    );
    ok = ok
        && write_guest_composition_form(
            kernel,
            memory,
            thread_id,
            ptr.wrapping_add(INPUTCONTEXT_COMP_FORM_OFFSET),
            context.composition_form,
        );
    for (index, form) in context.candidate_forms.iter().copied().enumerate() {
        ok = ok
            && write_guest_candidate_form(
                kernel,
                memory,
                thread_id,
                ptr.wrapping_add(INPUTCONTEXT_CAND_FORM_OFFSET + (index as u32) * 32),
                form,
            );
    }
    ok =
        ok && write_guest_u32(
            kernel,
            memory,
            thread_id,
            ptr.wrapping_add(INPUTCONTEXT_COMP_STR_OFFSET),
            context.h_comp_str,
        ) && write_guest_u32(
            kernel,
            memory,
            thread_id,
            ptr.wrapping_add(INPUTCONTEXT_CAND_INFO_OFFSET),
            context.h_cand_info,
        ) && write_guest_u32(
            kernel,
            memory,
            thread_id,
            ptr.wrapping_add(INPUTCONTEXT_GUIDE_LINE_OFFSET),
            context.h_guide_line,
        ) && write_guest_u32(
            kernel,
            memory,
            thread_id,
            ptr.wrapping_add(INPUTCONTEXT_PRIVATE_OFFSET),
            context.h_private,
        ) && write_guest_u32(
            kernel,
            memory,
            thread_id,
            ptr.wrapping_add(INPUTCONTEXT_NUM_MSG_BUF_OFFSET),
            0,
        ) && write_guest_u32(
            kernel,
            memory,
            thread_id,
            ptr.wrapping_add(INPUTCONTEXT_MSG_BUF_OFFSET),
            context.h_msg_buf,
        ) && write_guest_u32(
            kernel,
            memory,
            thread_id,
            ptr.wrapping_add(INPUTCONTEXT_REFCOUNT_OFFSET),
            context.lock_count.saturating_add(1),
        );
    ok
}

fn resolve_imm_status_context(kernel: &mut CeKernel, himc: u32) -> Option<u32> {
    if himc != 0 {
        return kernel.gwe.ime_context(himc).is_some().then_some(himc);
    }
    let hwnd = kernel.gwe.get_foreground_keyboard_target()?;
    kernel.gwe.get_ime_context(hwnd)
}

fn imm_get_open_status_raw(kernel: &mut CeKernel, thread_id: u32, himc: u32) -> bool {
    let Some(himc) = resolve_imm_status_context(kernel, himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let Some(context) = kernel.gwe.ime_context(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    kernel.threads.set_last_error(thread_id, 0);
    context.open
}

fn imm_set_open_status_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let open = raw_arg(args, 1) != 0;
    if !kernel.gwe.set_ime_open_status(himc, open) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    let hwnd = kernel
        .gwe
        .ime_context(himc)
        .and_then(|c| c.hwnd)
        .unwrap_or(0);
    if hwnd != 0 {
        let _ = kernel.post_message_w_for_thread(
            thread_id,
            hwnd,
            crate::ce::gwe::WM_IME_NOTIFY,
            crate::ce::gwe::IMN_SETOPENSTATUS,
            0,
        );
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_get_conversion_status_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let (conversion_status, sentence_status) = {
        let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return false;
        };
        let Some(context) = kernel.gwe.ime_context(himc) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return false;
        };
        (context.conversion_status, context.sentence_status)
    };
    let conversion_ptr = raw_arg(args, 1);
    let sentence_ptr = raw_arg(args, 2);
    if conversion_ptr != 0
        && !write_guest_u32(kernel, memory, thread_id, conversion_ptr, conversion_status)
    {
        return false;
    }
    if sentence_ptr != 0
        && !write_guest_u32(kernel, memory, thread_id, sentence_ptr, sentence_status)
    {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_set_conversion_status_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let ok = kernel
        .gwe
        .set_ime_conversion_status(himc, raw_arg(args, 1), raw_arg(args, 2));
    kernel
        .threads
        .set_last_error(thread_id, if ok { 0 } else { ERROR_INVALID_HANDLE });
    ok
}

fn imm_get_composition_string_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return u32::MAX;
    };
    let dw_index = raw_arg(args, 1);
    let lp_buf = raw_arg(args, 2);
    let dw_buf_len = raw_arg(args, 3);
    let wchars: Vec<u16> = {
        let Some(ctx) = kernel.gwe.ime_context(himc) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return u32::MAX;
        };
        match dw_index {
            crate::ce::gwe::GCS_COMPSTR => ctx.composition_string.clone(),
            _ => {
                kernel.threads.set_last_error(thread_id, 0);
                return 0;
            }
        }
    };
    let byte_len = (wchars.len() * 2) as u32;
    if lp_buf == 0 || dw_buf_len == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return byte_len;
    }
    let copy_len = (dw_buf_len / 2).min(wchars.len() as u32) as usize;
    let mut ok = true;
    for (i, &wch) in wchars[..copy_len].iter().enumerate() {
        if !write_guest_u16(kernel, memory, thread_id, lp_buf + (i * 2) as u32, wch) {
            ok = false;
            break;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    if ok { byte_len } else { 0 }
}

fn imm_set_composition_string_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let himc = raw_arg(args, 0);
    let dw_index = raw_arg(args, 1);
    let lp_comp = raw_arg(args, 2);
    let dw_comp_len = raw_arg(args, 3);
    // Only SCS_SETSTR (GCS_COMPREADSTR|GCS_COMPSTR = 0x09) is handled here.
    const SCS_SETSTR: u32 = 0x0009;
    if dw_index != SCS_SETSTR {
        kernel.threads.set_last_error(thread_id, 0);
        return true; // unsupported index: silently succeed
    }
    let Some(himc) = resolve_imm_status_context(kernel, himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let composition: Vec<u16> = if lp_comp != 0 && dw_comp_len >= 2 {
        let byte_count = dw_comp_len & !1; // round down to even
        read_guest_bytes(kernel, memory, thread_id, lp_comp, byte_count)
            .unwrap_or_default()
            .chunks_exact(2)
            .map(|b| u16::from_le_bytes([b[0], b[1]]))
            .collect()
    } else {
        Vec::new()
    };
    let lp_flags = if composition.is_empty() {
        crate::ce::gwe::GCS_COMPSTR // empty composition clears
    } else {
        crate::ce::gwe::GCS_COMPSTR
    };
    let testime_candidates = kernel
        .gwe
        .is_ime_layout(kernel.gwe.keyboard_layout())
        .then(|| testime_candidates_for_reading(kernel, &composition))
        .flatten();
    if let Some(hwnd) = kernel.gwe.set_ime_composition_string(himc, composition) {
        refresh_testime_candidate_list(kernel, thread_id, himc, testime_candidates);
        // Notify the target window that the composition string changed.
        let _ = kernel.send_message_w(hwnd, crate::ce::gwe::WM_IME_COMPOSITION, 0, lp_flags);
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn testime_candidates_for_reading(kernel: &CeKernel, reading: &[u16]) -> Option<Vec<String>> {
    const TESTIME_MAX_CANDIDATE_STRINGS: usize = 32;

    let reading_text = String::from_utf16_lossy(reading);
    let mut candidates = Vec::new();
    if let [unit] = reading {
        if let Some(ch) = char::from_u32(*unit as u32).filter(|ch| ch.is_ascii_alphabetic()) {
            let toggled = if ch.is_ascii_uppercase() {
                ch.to_ascii_lowercase()
            } else {
                ch.to_ascii_uppercase()
            };
            candidates.push(ch.to_string());
            candidates.push(toggled.to_string());
        }
    }
    candidates.extend(testime_private_profile_candidates(kernel, &reading_text));
    candidates.extend(kernel.gwe.ime_registered_words_for_reading(&reading_text));
    if candidates.len() > TESTIME_MAX_CANDIDATE_STRINGS {
        return None;
    }
    (!candidates.is_empty()).then_some(candidates)
}

fn testime_private_profile_candidates(kernel: &CeKernel, reading: &str) -> Vec<String> {
    if !kernel
        .gwe
        .testime_registered_word_reading_is_visible(reading)
    {
        return Vec::new();
    }
    kernel
        .registry
        .enum_values(&format!(
            r"HKLM\SOFTWARE\Microsoft\testime\Windows\testime.DIC\{reading}"
        ))
        .unwrap_or_default()
        .into_iter()
        .map(|(name, value)| value.as_str().unwrap_or(&name).to_owned())
        .collect()
}

fn refresh_testime_candidate_list(
    kernel: &mut CeKernel,
    thread_id: u32,
    himc: u32,
    candidates: Option<Vec<String>>,
) {
    const IMN_CHANGECANDIDATE: u32 = 0x0003;
    const IMN_CLOSECANDIDATE: u32 = 0x0004;
    const IMN_OPENCANDIDATE: u32 = 0x0005;
    const CANDIDATE_INDEX: usize = 0;
    const CANDIDATE_MASK: u32 = 1;
    const TESTIME_MAX_CANDIDATE_PAGE_SIZE: u32 = 9;

    let (hwnd, had_candidates) = kernel
        .gwe
        .ime_context(himc)
        .map(|context| {
            (
                context.hwnd.unwrap_or(0),
                context
                    .candidate_lists
                    .get(CANDIDATE_INDEX)
                    .and_then(|slot| slot.as_ref())
                    .is_some_and(|list| !list.candidates.is_empty()),
            )
        })
        .unwrap_or((0, false));

    if let Some(candidates) = candidates.filter(|candidates| !candidates.is_empty()) {
        let page_size = (candidates.len() as u32).min(TESTIME_MAX_CANDIDATE_PAGE_SIZE);
        if kernel.gwe.set_ime_candidate_list(
            himc,
            CANDIDATE_INDEX,
            crate::ce::gwe::ImeCandidateListState {
                style: crate::ce::gwe::IME_CAND_READ,
                selection: 0,
                page_start: 0,
                page_size,
                candidates,
            },
        ) && hwnd != 0
        {
            if !had_candidates {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_NOTIFY,
                    IMN_OPENCANDIDATE,
                    CANDIDATE_MASK,
                );
            }
            let _ = kernel.post_message_w_for_thread(
                thread_id,
                hwnd,
                crate::ce::gwe::WM_IME_NOTIFY,
                IMN_CHANGECANDIDATE,
                CANDIDATE_MASK,
            );
        }
        return;
    }

    let cleared = kernel.gwe.set_ime_candidate_list(
        himc,
        CANDIDATE_INDEX,
        crate::ce::gwe::ImeCandidateListState {
            style: crate::ce::gwe::IME_CAND_READ,
            selection: 0,
            page_start: 0,
            page_size: 0,
            candidates: Vec::new(),
        },
    );
    if cleared && had_candidates && hwnd != 0 {
        let _ = kernel.post_message_w_for_thread(
            thread_id,
            hwnd,
            crate::ce::gwe::WM_IME_NOTIFY,
            IMN_CLOSECANDIDATE,
            CANDIDATE_MASK,
        );
    }
}

fn imm_get_composition_window_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let Some(context) = kernel.gwe.ime_context(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let form = context.composition_form;
    if !write_guest_composition_form(kernel, memory, thread_id, raw_arg(args, 1), form) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_set_composition_window_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let Some(form) = read_guest_composition_form(kernel, memory, thread_id, raw_arg(args, 1))
    else {
        return false;
    };
    let Some(context) = kernel.gwe.ime_context_mut(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    context.composition_form = form;
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_get_candidate_list_count_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(context) = kernel.gwe.ime_context(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let mut list_count = 0u32;
    let mut byte_count = 0u32;
    for list in context.candidate_lists.iter().flatten() {
        if list.candidates.is_empty() {
            continue;
        }
        list_count = list_count.saturating_add(1);
        byte_count = byte_count.saturating_add(serialized_candidate_list_w(list).len() as u32);
    }
    let count_ptr = raw_arg(args, 1);
    if count_ptr != 0 && !write_guest_u32(kernel, memory, thread_id, count_ptr, list_count) {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    byte_count
}

fn imm_get_candidate_list_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let index = raw_arg(args, 1) as usize;
    let list_ptr = raw_arg(args, 2);
    let buffer_len = raw_arg(args, 3);
    let Some(context) = kernel.gwe.ime_context(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(slot) = context.candidate_lists.get(index) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(list) = slot.as_ref().filter(|list| !list.candidates.is_empty()) else {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    };
    let bytes = serialized_candidate_list_w(list);
    let required = bytes.len() as u32;
    if list_ptr == 0 || buffer_len < required {
        kernel.threads.set_last_error(thread_id, 0);
        return required;
    }
    if !write_guest_bytes(kernel, memory, thread_id, list_ptr, &bytes) {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    required
}

fn serialized_candidate_list_w(list: &crate::ce::gwe::ImeCandidateListState) -> Vec<u8> {
    let count = list.candidates.len();
    let string_base = 24usize + count * 4;
    let mut strings = Vec::new();
    let mut offsets = Vec::with_capacity(count);
    for candidate in &list.candidates {
        offsets.push((string_base + strings.len()) as u32);
        for unit in candidate.encode_utf16().chain(std::iter::once(0)) {
            strings.extend_from_slice(&unit.to_le_bytes());
        }
    }
    let total_size = string_base + strings.len();
    let mut bytes = Vec::with_capacity(total_size);
    bytes.extend_from_slice(&(total_size as u32).to_le_bytes());
    bytes.extend_from_slice(&list.style.to_le_bytes());
    bytes.extend_from_slice(&(count as u32).to_le_bytes());
    bytes.extend_from_slice(
        &list
            .selection
            .min(count.saturating_sub(1) as u32)
            .to_le_bytes(),
    );
    bytes.extend_from_slice(
        &list
            .page_start
            .min(count.saturating_sub(1) as u32)
            .to_le_bytes(),
    );
    bytes.extend_from_slice(&list.page_size.min(count as u32).to_le_bytes());
    for offset in offsets {
        bytes.extend_from_slice(&offset.to_le_bytes());
    }
    bytes.extend_from_slice(&strings);
    bytes
}

fn deserialize_ime_components<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    himc: u32,
    h_comp_str: u32,
    h_cand_info: u32,
) {
    if let Some(composition) =
        deserialize_composition_component(kernel, memory, thread_id, h_comp_str)
    {
        if let Some(context) = kernel.gwe.ime_context_mut(himc) {
            context.composition_string = composition;
        }
    }
    if let Some(candidate_lists) =
        deserialize_candidate_info_component(kernel, memory, thread_id, h_cand_info)
    {
        if let Some(context) = kernel.gwe.ime_context_mut(himc) {
            context.candidate_lists = candidate_lists;
        }
    }
}

fn deserialize_composition_component<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    handle: u32,
) -> Option<Vec<u16>> {
    if handle == 0 {
        return None;
    }
    let component = kernel.gwe.ime_component(handle).copied()?;
    if component.kind != crate::ce::gwe::ImeComponentKind::CompositionString
        || component.size < CE_COMPOSITIONSTRING_SIZE
    {
        return None;
    }
    let total_size = read_guest_u32(kernel, memory, thread_id, handle)?;
    if total_size < CE_COMPOSITIONSTRING_SIZE || total_size > component.size {
        return None;
    }
    let byte_len = read_guest_u32(kernel, memory, thread_id, handle.wrapping_add(44))? & !1;
    let offset = read_guest_u32(kernel, memory, thread_id, handle.wrapping_add(48))?;
    if byte_len == 0 {
        return Some(Vec::new());
    }
    if offset > total_size || byte_len > total_size.saturating_sub(offset) {
        return None;
    }
    let mut composition = Vec::with_capacity((byte_len / 2) as usize);
    for index in 0..(byte_len / 2) {
        composition.push(read_guest_u16(
            kernel,
            memory,
            thread_id,
            handle.wrapping_add(offset).wrapping_add(index * 2),
        )?);
    }
    Some(composition)
}

fn deserialize_candidate_info_component<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    handle: u32,
) -> Option<[Option<crate::ce::gwe::ImeCandidateListState>; 4]> {
    if handle == 0 {
        return None;
    }
    let component = kernel.gwe.ime_component(handle).copied()?;
    if component.kind != crate::ce::gwe::ImeComponentKind::CandidateInfo
        || component.size < CE_CANDIDATEINFO_SIZE
    {
        return None;
    }
    let total_size = read_guest_u32(kernel, memory, thread_id, handle)?;
    if total_size < CE_CANDIDATEINFO_SIZE || total_size > component.size {
        return None;
    }
    let list_count = read_guest_u32(kernel, memory, thread_id, handle.wrapping_add(4))?.min(32);
    let mut lists: [Option<crate::ce::gwe::ImeCandidateListState>; 4] =
        std::array::from_fn(|_| None);
    for index in 0..list_count.min(4) {
        let offset = read_guest_u32(
            kernel,
            memory,
            thread_id,
            handle.wrapping_add(8).wrapping_add(index * 4),
        )?;
        if offset == 0 {
            continue;
        }
        if offset < CE_CANDIDATEINFO_SIZE || offset >= total_size {
            return None;
        }
        let list = deserialize_candidate_list_w(
            kernel,
            memory,
            thread_id,
            handle.wrapping_add(offset),
            total_size - offset,
        )?;
        if !list.candidates.is_empty() {
            lists[index as usize] = Some(list);
        }
    }
    Some(lists)
}

fn deserialize_candidate_list_w<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    base: u32,
    max_size: u32,
) -> Option<crate::ce::gwe::ImeCandidateListState> {
    let size = read_guest_u32(kernel, memory, thread_id, base)?;
    if size < 24 || size > max_size {
        return None;
    }
    let style = read_guest_u32(kernel, memory, thread_id, base.wrapping_add(4))?;
    let count = read_guest_u32(kernel, memory, thread_id, base.wrapping_add(8))?;
    let header_size = 24u32.checked_add(count.checked_mul(4)?)?;
    if header_size > size {
        return None;
    }
    let mut candidates = Vec::with_capacity(count as usize);
    for index in 0..count {
        let offset = read_guest_u32(
            kernel,
            memory,
            thread_id,
            base.wrapping_add(24).wrapping_add(index * 4),
        )?;
        if offset < header_size || offset >= size {
            return None;
        }
        candidates.push(read_guest_wide_z_bounded(
            kernel,
            memory,
            thread_id,
            base.wrapping_add(offset),
            (size - offset) / 2,
        )?);
    }
    let candidate_count = candidates.len() as u32;
    let mut selection = read_guest_u32(kernel, memory, thread_id, base.wrapping_add(12))?;
    let mut page_start = read_guest_u32(kernel, memory, thread_id, base.wrapping_add(16))?;
    let mut page_size = read_guest_u32(kernel, memory, thread_id, base.wrapping_add(20))?;
    if candidate_count != 0 {
        selection = selection.min(candidate_count - 1);
        page_start = page_start.min(candidate_count - 1);
        page_size = page_size.min(candidate_count - page_start);
        if page_size == 0 {
            page_size = 1;
        }
    }
    Some(crate::ce::gwe::ImeCandidateListState {
        style,
        selection,
        page_start,
        page_size,
        candidates,
    })
}

fn read_guest_wide_z_bounded<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    ptr: u32,
    max_units: u32,
) -> Option<String> {
    let mut units = Vec::new();
    for index in 0..max_units {
        let unit = read_guest_u16(kernel, memory, thread_id, ptr.wrapping_add(index * 2))?;
        if unit == 0 {
            break;
        }
        units.push(unit);
    }
    Some(String::from_utf16_lossy(&units))
}

fn imm_get_guide_line_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    const GGL_LEVEL: u32 = 0x0000_0001;
    const GGL_INDEX: u32 = 0x0000_0002;
    const GGL_STRING: u32 = 0x0000_0003;
    const GGL_PRIVATE: u32 = 0x0000_0004;
    const GUIDELINE_SIZE: u32 = 28;
    const GUIDELINE_LEVEL_OFFSET: u32 = 4;
    const GUIDELINE_INDEX_OFFSET: u32 = 8;
    const GUIDELINE_STR_LEN_OFFSET: u32 = 12;
    const GUIDELINE_STR_OFFSET_OFFSET: u32 = 16;
    const GUIDELINE_PRIVATE_SIZE_OFFSET: u32 = 20;
    const GUIDELINE_PRIVATE_OFFSET_OFFSET: u32 = 24;

    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(hguide_line) = kernel
        .gwe
        .ime_context(himc)
        .map(|context| context.h_guide_line)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };

    let index = raw_arg(args, 1);
    let buffer = raw_arg(args, 2);
    let buffer_len = raw_arg(args, 3);
    if hguide_line != 0 {
        let Some(component) = kernel.gwe.ime_component(hguide_line).copied() else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        };
        if component.kind != crate::ce::gwe::ImeComponentKind::GuideLine
            || component.size < GUIDELINE_SIZE
        {
            kernel.threads.set_last_error(thread_id, 0);
            return 0;
        }
        let Some(total_size) = read_guest_u32(kernel, memory, thread_id, hguide_line) else {
            return 0;
        };
        if total_size < GUIDELINE_SIZE || total_size > component.size {
            kernel.threads.set_last_error(thread_id, 0);
            return 0;
        }
        return match index {
            GGL_LEVEL => match read_guest_u32(
                kernel,
                memory,
                thread_id,
                hguide_line.wrapping_add(GUIDELINE_LEVEL_OFFSET),
            ) {
                Some(level) => {
                    kernel.threads.set_last_error(thread_id, 0);
                    level
                }
                None => 0,
            },
            GGL_INDEX => match read_guest_u32(
                kernel,
                memory,
                thread_id,
                hguide_line.wrapping_add(GUIDELINE_INDEX_OFFSET),
            ) {
                Some(guideline_index) => {
                    kernel.threads.set_last_error(thread_id, 0);
                    guideline_index
                }
                None => 0,
            },
            GGL_STRING => {
                let Some(len_chars) = read_guest_u32(
                    kernel,
                    memory,
                    thread_id,
                    hguide_line.wrapping_add(GUIDELINE_STR_LEN_OFFSET),
                ) else {
                    return 0;
                };
                let Some(offset) = read_guest_u32(
                    kernel,
                    memory,
                    thread_id,
                    hguide_line.wrapping_add(GUIDELINE_STR_OFFSET_OFFSET),
                ) else {
                    return 0;
                };
                copy_guideline_wide_payload(
                    kernel,
                    memory,
                    thread_id,
                    hguide_line,
                    total_size,
                    offset,
                    len_chars.saturating_mul(2),
                    buffer,
                    buffer_len,
                )
            }
            GGL_PRIVATE => {
                let Some(size) = read_guest_u32(
                    kernel,
                    memory,
                    thread_id,
                    hguide_line.wrapping_add(GUIDELINE_PRIVATE_SIZE_OFFSET),
                ) else {
                    return 0;
                };
                let Some(offset) = read_guest_u32(
                    kernel,
                    memory,
                    thread_id,
                    hguide_line.wrapping_add(GUIDELINE_PRIVATE_OFFSET_OFFSET),
                ) else {
                    return 0;
                };
                copy_guideline_payload(
                    kernel,
                    memory,
                    thread_id,
                    hguide_line,
                    total_size,
                    offset,
                    size,
                    buffer,
                    buffer_len,
                )
            }
            _ => {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                0
            }
        };
    }

    match index {
        GGL_LEVEL | GGL_INDEX => {
            kernel.threads.set_last_error(thread_id, 0);
            0
        }
        GGL_STRING | GGL_PRIVATE => {
            if buffer != 0
                && buffer_len > 0
                && !write_guest_u16(kernel, memory, thread_id, buffer, 0)
            {
                return 0;
            }
            kernel.threads.set_last_error(thread_id, 0);
            0
        }
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            0
        }
    }
}

fn copy_guideline_payload<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    base: u32,
    total_size: u32,
    offset: u32,
    byte_len: u32,
    buffer: u32,
    buffer_len: u32,
) -> u32 {
    if byte_len == 0 {
        if buffer != 0 && buffer_len > 0 && !write_guest_u16(kernel, memory, thread_id, buffer, 0) {
            return 0;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    if offset > total_size || byte_len > total_size.saturating_sub(offset) {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    if buffer != 0 && buffer_len != 0 {
        let copy_len = byte_len.min(buffer_len);
        let Some(bytes) = read_guest_bytes(
            kernel,
            memory,
            thread_id,
            base.wrapping_add(offset),
            copy_len,
        ) else {
            return 0;
        };
        if !write_guest_bytes(kernel, memory, thread_id, buffer, &bytes) {
            return 0;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    byte_len
}

fn copy_guideline_wide_payload<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    base: u32,
    total_size: u32,
    offset: u32,
    byte_len: u32,
    buffer: u32,
    buffer_len: u32,
) -> u32 {
    if byte_len == 0 {
        if buffer != 0 && buffer_len > 0 && !write_guest_u16(kernel, memory, thread_id, buffer, 0) {
            return 0;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    if offset > total_size || byte_len > total_size.saturating_sub(offset) {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    if buffer != 0 && buffer_len != 0 {
        let copy_units = byte_len.min(buffer_len) / 2;
        for index in 0..copy_units {
            let src = base.wrapping_add(offset).wrapping_add(index * 2);
            let dst = buffer.wrapping_add(index * 2);
            let Some(unit) = read_guest_u16(kernel, memory, thread_id, src) else {
                return 0;
            };
            if !write_guest_u16(kernel, memory, thread_id, dst, unit) {
                return 0;
            }
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    byte_len
}

fn imm_get_candidate_window_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let index = raw_arg(args, 1) as usize;
    let Some(context) = kernel.gwe.ime_context(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let Some(form) = context.candidate_forms.get(index).copied() else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    if !write_guest_candidate_form(kernel, memory, thread_id, raw_arg(args, 2), form) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn imm_set_candidate_window_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let Some(himc) = resolve_imm_status_context(kernel, raw_arg(args, 0)) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let Some(form) = read_guest_candidate_form(kernel, memory, thread_id, raw_arg(args, 1)) else {
        return false;
    };
    let Some(context) = kernel.gwe.ime_context_mut(himc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let Some(slot) = context.candidate_forms.get_mut(form.index as usize) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    };
    *slot = form;
    kernel.threads.set_last_error(thread_id, 0);
    true
}

