fn map_window_points<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hwnd_from: u32,
    hwnd_to: u32,
    points_ptr: u32,
    point_count: u32,
) -> u32 {
    let mut points = Vec::new();
    for index in 0..point_count {
        let point_ptr = points_ptr.wrapping_add(index.wrapping_mul(8));
        let Some(point) = read_guest_point(kernel, memory, thread_id, point_ptr) else {
            return 0;
        };
        points.push(point);
    }
    let first_before = points.first().copied();
    let from = (hwnd_from != 0).then_some(hwnd_from);
    let to = (hwnd_to != 0).then_some(hwnd_to);
    if !kernel.gwe.map_window_points(from, to, &mut points) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    let packed_delta = first_before
        .zip(points.first().copied())
        .map(|(before, after)| {
            let dx = after.x.saturating_sub(before.x) as i16 as u16;
            let dy = after.y.saturating_sub(before.y) as i16 as u16;
            u32::from(dx) | (u32::from(dy) << 16)
        })
        .unwrap_or(0);
    for (index, point) in points.into_iter().enumerate() {
        let point_ptr = points_ptr.wrapping_add((index as u32).wrapping_mul(8));
        if !write_guest_point(kernel, memory, thread_id, point_ptr, point) {
            return 0;
        }
    }
    packed_delta
}

fn invalidate_rect_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hwnd = raw_arg(args, 0);
    let rect_ptr = raw_arg(args, 1);
    let erase = raw_arg(args, 2) != 0;
    let rect = if rect_ptr == 0 {
        None
    } else {
        match read_guest_rect(kernel, memory, thread_id, rect_ptr) {
            Some(rect) => Some(rect),
            None => return false,
        }
    };
    if !kernel.gwe.invalidate_window(hwnd, rect, erase) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn redraw_window_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hwnd = raw_arg(args, 0);
    let rect_ptr = raw_arg(args, 1);
    let region_handle = raw_arg(args, 2);
    let flags = raw_arg(args, 3);

    if !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }

    let rect = if region_handle != 0 {
        match kernel.resources.region(region_handle) {
            Some(region) => Some(region.rect),
            None => {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                return false;
            }
        }
    } else if rect_ptr != 0 {
        match read_guest_rect(kernel, memory, thread_id, rect_ptr) {
            Some(rect) => Some(rect),
            None => return false,
        }
    } else {
        None
    };

    let include_children = flags & RDW_ALLCHILDREN != 0 && flags & RDW_NOCHILDREN == 0;
    let targets = if include_children {
        match kernel.gwe.window_and_descendants(hwnd) {
            Some(targets) => targets,
            None => {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
                return false;
            }
        }
    } else {
        vec![hwnd]
    };

    let should_validate = flags & (RDW_VALIDATE | RDW_NOINTERNALPAINT) != 0;
    let should_invalidate = flags & (RDW_INVALIDATE | RDW_INTERNALPAINT) != 0;
    let erase = flags & RDW_NOERASE == 0 && flags & (RDW_ERASE | RDW_ERASENOW) != 0;

    for target in targets.iter().copied() {
        if should_validate && !kernel.gwe.validate_window_rect(target, rect) {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
            return false;
        }
        if should_invalidate && !kernel.gwe.invalidate_window(target, rect, erase) {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
            return false;
        }
    }

    if flags & (RDW_UPDATENOW | RDW_ERASENOW) != 0 {
        for target in targets {
            if !kernel.update_window(target) {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
                return false;
            }
        }
    }

    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn validate_rect_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hwnd = raw_arg(args, 0);
    let rect_ptr = raw_arg(args, 1);
    let rect = if rect_ptr == 0 {
        None
    } else {
        match read_guest_rect(kernel, memory, thread_id, rect_ptr) {
            Some(rect) => Some(rect),
            None => return false,
        }
    };
    if !kernel.gwe.validate_window_rect(hwnd, rect) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_update_rect_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hwnd: u32,
    rect_ptr: u32,
    erase: bool,
) -> bool {
    if !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    let Some(update) = kernel.gwe.update_rect(hwnd) else {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    };
    if rect_ptr != 0 && !write_guest_rect(kernel, memory, thread_id, rect_ptr, update.rect) {
        return false;
    }
    if erase && update.erase {
        let hdc = paint_hdc_for_hwnd(hwnd);
        if !kernel.erase_window_background(hwnd, hdc) {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
            return false;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_update_rgn_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    region: u32,
    erase: bool,
) -> u32 {
    if region == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    if !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return ERROR_REGION;
    }
    let update = kernel.gwe.update_rect(hwnd);
    let update_rects: Vec<crate::ce::gwe::Rect> = kernel
        .gwe
        .window(hwnd)
        .filter(|_| update.is_some())
        .map(|w| w.update_rects.clone())
        .unwrap_or_default();
    if !kernel.resources.set_region_rects(region, update_rects) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    if erase && update.is_some_and(|update| update.erase) {
        let hdc = paint_hdc_for_hwnd(hwnd);
        if !kernel.erase_window_background(hwnd, hdc) {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
            return ERROR_REGION;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .region(region)
        .map(region_status_object)
        .unwrap_or(NULLREGION)
}

fn get_window_thread_process_id_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hwnd = raw_arg(args, 0);
    let process_id_ptr = raw_arg(args, 1);
    let Some((owner_thread_id, owner_process_id)) = kernel.gwe.window_thread_process_id(hwnd)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    };
    if process_id_ptr != 0
        && !write_guest_u32(kernel, memory, thread_id, process_id_ptr, owner_process_id)
    {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    owner_thread_id
}

fn begin_paint_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hwnd: u32,
    paint_ptr: u32,
) -> u32 {
    let Some(update) = kernel.gwe.begin_paint(hwnd) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    };
    let hdc = paint_hdc_for_hwnd(hwnd);
    if paint_ptr != 0 && !write_paint_struct(kernel, memory, thread_id, paint_ptr, hdc, update) {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    hdc
}

fn end_paint_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32) -> bool {
    if !kernel.gwe.validate_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_dc_raw(kernel: &CeKernel, hwnd: u32) -> u32 {
    let target = if hwnd == 0 {
        kernel.gwe.get_desktop_window()
    } else {
        hwnd
    };
    if kernel.gwe.is_window(target) {
        paint_hdc_for_hwnd(target)
    } else {
        0
    }
}

// SCROLLINFO fMask flags
const SIF_RANGE: u32 = 0x0001;
const SIF_PAGE: u32 = 0x0002;
const SIF_POS: u32 = 0x0004;
const SIF_TRACKPOS: u32 = 0x0010;
const SB_HORZ: u32 = 0;
const SB_VERT: u32 = 1;
const SB_BOTH: u32 = 3;

fn get_scroll_info_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hwnd = raw_arg(args, 0);
    let n_bar = raw_arg(args, 1);
    let lpsi = raw_arg(args, 2);
    if !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    if lpsi == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    // cbSize must be 28
    let Some(cb_size) = read_guest_u32(kernel, memory, thread_id, lpsi) else {
        return false;
    };
    if cb_size < 28 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let fmask = read_guest_u32(kernel, memory, thread_id, lpsi + 4).unwrap_or(0);
    let bar = if n_bar == SB_BOTH { SB_VERT } else { n_bar };
    let state = match kernel.gwe.get_scroll_state(hwnd, bar).cloned() {
        Some(s) => s,
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return false;
        }
    };
    let mut ok = true;
    if fmask & SIF_RANGE != 0 {
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 8, state.min as u32);
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 12, state.max as u32);
    }
    if fmask & SIF_PAGE != 0 {
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 16, state.page);
    }
    if fmask & SIF_POS != 0 {
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 20, state.pos as u32);
    }
    if fmask & SIF_TRACKPOS != 0 {
        // tracking position same as current position
        ok = ok && write_guest_u32(kernel, memory, thread_id, lpsi + 24, state.pos as u32);
    }
    if ok {
        kernel.threads.set_last_error(thread_id, 0);
    }
    ok
}

fn set_scroll_info_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> i32 {
    let hwnd = raw_arg(args, 0);
    let n_bar = raw_arg(args, 1);
    let lpsi = raw_arg(args, 2);
    // arg 3: bRedraw (ignored — we have no actual rendering to trigger)
    if !kernel.gwe.is_window(hwnd) || lpsi == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    // Read all values from guest memory before touching the mutable borrow.
    let fmask = read_guest_u32(kernel, memory, thread_id, lpsi + 4).unwrap_or(0);
    let nmin = read_guest_u32(kernel, memory, thread_id, lpsi + 8).unwrap_or(0) as i32;
    let nmax = read_guest_u32(kernel, memory, thread_id, lpsi + 12).unwrap_or(0) as i32;
    let npage = read_guest_u32(kernel, memory, thread_id, lpsi + 16).unwrap_or(0);
    let npos = read_guest_u32(kernel, memory, thread_id, lpsi + 20).unwrap_or(0) as i32;
    let bars: &[u32] = match n_bar {
        SB_BOTH => &[SB_HORZ, SB_VERT],
        b => &[b],
    };
    let mut new_pos = 0i32;
    for &bar in bars {
        let Some(state) = kernel.gwe.get_scroll_state_mut(hwnd, bar) else {
            continue;
        };
        if fmask & SIF_RANGE != 0 {
            state.min = nmin;
            state.max = nmax;
        }
        if fmask & SIF_PAGE != 0 {
            state.page = npage;
        }
        if fmask & SIF_POS != 0 {
            let page_size = state.page as i32;
            let max_pos = (state.max - page_size.max(0) + 1).max(state.min);
            state.pos = npos.clamp(state.min, max_pos);
            new_pos = state.pos;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    new_pos
}

fn set_scroll_pos_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> i32 {
    let hwnd = raw_arg(args, 0);
    let n_bar = raw_arg(args, 1);
    let n_pos = raw_arg(args, 2) as i32;
    // arg 3: bRedraw (ignored)
    if !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    let bar = if n_bar == SB_BOTH { SB_VERT } else { n_bar };
    let (prev_pos, new_pos) = {
        let Some(state) = kernel.gwe.get_scroll_state_mut(hwnd, bar) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        let prev = state.pos;
        let page_size = state.page as i32;
        let max_pos = (state.max - page_size.max(0) + 1).max(state.min);
        state.pos = n_pos.clamp(state.min, max_pos);
        (prev, state.pos)
    };
    let _ = new_pos;
    kernel.threads.set_last_error(thread_id, 0);
    prev_pos
}

fn set_scroll_range_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let hwnd = raw_arg(args, 0);
    let n_bar = raw_arg(args, 1);
    let n_min = raw_arg(args, 2) as i32;
    let n_max = raw_arg(args, 3) as i32;
    // arg 4: bRedraw (ignored)
    if !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    let bars: &[u32] = match n_bar {
        SB_BOTH => &[SB_HORZ, SB_VERT],
        b => &[b],
    };
    for &bar in bars {
        if let Some(state) = kernel.gwe.get_scroll_state_mut(hwnd, bar) {
            state.min = n_min;
            state.max = n_max;
            state.pos = state.pos.clamp(n_min, n_max);
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn scroll_window_ex_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> i32 {
    // ScrollWindowEx(hWnd, dx, dy, prcScroll, prcClip, hrgnUpdate, prcUpdate, fuScroll)
    let hwnd = raw_arg(args, 0);
    let dx = raw_i32_arg(args, 1);
    let dy = raw_i32_arg(args, 2);
    let prc_scroll = raw_arg(args, 3);
    let prc_clip = raw_arg(args, 4);
    // args[5] = hrgnUpdate — region update not supported
    let prc_update = raw_arg(args, 6);
    let fu_scroll = raw_arg(args, 7);

    const SW_INVALIDATE: u32 = 0x0002;
    const SW_ERASE: u32 = 0x0004;

    if !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }

    // Client rect in client coords (zero-origin) and screen-space origin of client area
    let Some(client_rect) = kernel.gwe.get_client_rect(hwnd) else {
        return 0;
    };
    let Some(origin) = kernel.gwe.client_to_screen(hwnd, Point { x: 0, y: 0 }) else {
        return 0;
    };

    // Effective scroll rect in client coords, starting from full client area
    let mut eff = client_rect;
    if prc_scroll != 0 {
        if let Some(r) = read_guest_rect(kernel, memory, thread_id, prc_scroll) {
            match eff.intersect(r) {
                Some(i) => eff = i,
                None => {
                    if prc_update != 0 {
                        let _ =
                            write_guest_bytes(kernel, memory, thread_id, prc_update, &[0u8; 16]);
                    }
                    kernel.threads.set_last_error(thread_id, 0);
                    return NULLREGION as i32;
                }
            }
        }
    }
    if prc_clip != 0 {
        if let Some(r) = read_guest_rect(kernel, memory, thread_id, prc_clip) {
            match eff.intersect(r) {
                Some(i) => eff = i,
                None => {
                    if prc_update != 0 {
                        let _ =
                            write_guest_bytes(kernel, memory, thread_id, prc_update, &[0u8; 16]);
                    }
                    kernel.threads.set_last_error(thread_id, 0);
                    return NULLREGION as i32;
                }
            }
        }
    }

    if eff.is_empty() || (dx == 0 && dy == 0) {
        if prc_update != 0 {
            let _ = write_guest_bytes(kernel, memory, thread_id, prc_update, &[0u8; 16]);
        }
        kernel.threads.set_last_error(thread_id, 0);
        return NULLREGION as i32;
    }

    // Shift pixels on framebuffer
    if let Some(fb) = framebuffer {
        scroll_framebuffer_rect(fb, eff.offset(origin.x, origin.y), dx, dy);
    }

    // Compute exposed rect (client coords) — the strip newly revealed by the scroll
    let exposed = scroll_exposed_rect(eff, dx, dy);

    if prc_update != 0 {
        let _ = write_guest_rect(kernel, memory, thread_id, prc_update, exposed);
    }

    if fu_scroll & SW_INVALIDATE != 0 && !exposed.is_empty() {
        let erase = fu_scroll & SW_ERASE != 0;
        kernel.gwe.invalidate_window(hwnd, Some(exposed), erase);
    }

    kernel.threads.set_last_error(thread_id, 0);
    if exposed.is_empty() {
        NULLREGION as i32
    } else {
        SIMPLEREGION as i32
    }
}

// Shift framebuffer pixels within `screen_rect` by `(dx, dy)`, clearing the exposed strip.
fn scroll_framebuffer_rect(fb: &mut dyn Framebuffer, screen_rect: Rect, dx: i32, dy: i32) {
    let info = fb.info();
    let stride = info.stride;
    let bpp = info.format.bytes_per_pixel();
    let fb_w = info.width as i32;
    let fb_h = info.height as i32;

    let l = screen_rect.left.max(0).min(fb_w) as usize;
    let t = screen_rect.top.max(0).min(fb_h) as usize;
    let r = screen_rect.right.max(0).min(fb_w) as usize;
    let b = screen_rect.bottom.max(0).min(fb_h) as usize;
    if l >= r || t >= b {
        return;
    }
    let row_len = (r - l) * bpp;

    let pixels = fb.pixels_mut();

    // Phase 1: vertical shift — move each row to its destination row.
    // For dy > 0 (content moves down): iterate dst_y bottom-to-top to avoid src overwrite.
    // For dy < 0 (content moves up): iterate dst_y top-to-bottom.
    if dy != 0 {
        let (start, end, step) = if dy > 0 {
            (b as isize - 1, t as isize - 1, -1isize)
        } else {
            (t as isize, b as isize, 1isize)
        };
        let mut dst_y = start;
        loop {
            if step > 0 && dst_y >= end {
                break;
            }
            if step < 0 && dst_y <= end {
                break;
            }
            let src_y = dst_y - dy as isize;
            let dst_off = dst_y as usize * stride + l * bpp;
            if src_y >= t as isize && src_y < b as isize {
                let src_off = src_y as usize * stride + l * bpp;
                // Different rows — no overlap within [l*bpp, r*bpp] segment
                pixels.copy_within(src_off..src_off + row_len, dst_off);
            } else {
                pixels[dst_off..dst_off + row_len].fill(0);
            }
            dst_y += step;
        }
    }

    // Phase 2: horizontal shift — shift pixels within each row by dx.
    // After phase 1, each row holds the vertically-shifted content.
    // Now shift columns, exposing the vertical strip (left if dx>0, right if dx<0).
    if dx != 0 {
        for y in t..b {
            if dx > 0 {
                // Content moves right: iterate dst_x right-to-left
                for dst_x in (l..r).rev() {
                    let src_x = dst_x as isize - dx as isize;
                    let dst_off = y * stride + dst_x * bpp;
                    if src_x >= l as isize && src_x < r as isize {
                        let src_off = y * stride + src_x as usize * bpp;
                        pixels.copy_within(src_off..src_off + bpp, dst_off);
                    } else {
                        pixels[dst_off..dst_off + bpp].fill(0);
                    }
                }
            } else {
                // Content moves left: iterate dst_x left-to-right
                for dst_x in l..r {
                    let src_x = dst_x as isize - dx as isize;
                    let dst_off = y * stride + dst_x * bpp;
                    if src_x >= l as isize && src_x < r as isize {
                        let src_off = y * stride + src_x as usize * bpp;
                        pixels.copy_within(src_off..src_off + bpp, dst_off);
                    } else {
                        pixels[dst_off..dst_off + bpp].fill(0);
                    }
                }
            }
        }
    }

    fb.mark_dirty(FramebufferRect::new(
        l as u32,
        t as u32,
        (r - l) as u32,
        (b - t) as u32,
    ));
}

// Compute the exposed rect in client coords after scrolling `rect` by (dx, dy).
// The exposed area is the union of the horizontal and vertical strips newly revealed.
fn scroll_exposed_rect(rect: Rect, dx: i32, dy: i32) -> Rect {
    let horiz = if dx > 0 {
        Some(Rect {
            left: rect.left,
            top: rect.top,
            right: (rect.left + dx).min(rect.right),
            bottom: rect.bottom,
        })
    } else if dx < 0 {
        Some(Rect {
            left: (rect.right + dx).max(rect.left),
            top: rect.top,
            right: rect.right,
            bottom: rect.bottom,
        })
    } else {
        None
    };
    let vert = if dy > 0 {
        Some(Rect {
            left: rect.left,
            top: rect.top,
            right: rect.right,
            bottom: (rect.top + dy).min(rect.bottom),
        })
    } else if dy < 0 {
        Some(Rect {
            left: rect.left,
            top: (rect.bottom + dy).max(rect.top),
            right: rect.right,
            bottom: rect.bottom,
        })
    } else {
        None
    };
    match (horiz, vert) {
        (Some(h), Some(v)) => h.union(v),
        (Some(h), None) => h,
        (None, Some(v)) => v,
        (None, None) => Rect {
            left: 0,
            top: 0,
            right: 0,
            bottom: 0,
        },
    }
}

fn release_dc_raw(kernel: &CeKernel, hwnd: u32, hdc: u32) -> u32 {
    if hdc == 0 {
        return 0;
    }
    if hwnd == 0 || kernel.gwe.is_window(hwnd) {
        1
    } else {
        0
    }
}

fn get_device_caps_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32, index: u32) -> u32 {
    if hdc != 0 && !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    if index == u32::MAX {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let cx = kernel.gwe.system_metric(crate::ce::gwe::SM_CXSCREEN) as u32;
    let cy = kernel.gwe.system_metric(crate::ce::gwe::SM_CYSCREEN) as u32;
    let value = match index {
        DRIVERVERSION => 0x0001_0000,
        TECHNOLOGY => 1, // DT_RASDISPLAY
        // Physical display size in mm; approximate for a typical car-nav screen at 96 DPI.
        HORZSIZE => cx * 254 / 960,
        VERTSIZE => cy * 254 / 960,
        HORZRES => cx,
        VERTRES => cy,
        BITSPIXEL => 16,
        PLANES => 1,
        NUMBRUSHES | NUMPENS | NUMMARKERS | NUMFONTS => u32::MAX,
        NUMCOLORS => u32::MAX, // -1 cast to u32: true-color / hi-color device
        // CE GWES raster display capability flags.
        // RC_BITBLT | RC_BITMAP64 | RC_GDI20_OUTPUT | RC_DI_BITMAP | RC_DIBTODEV | RC_STRETCHBLT | RC_STRETCHDIB
        RASTERCAPS => 0x0000_2A99,
        // CE displays support the standard GDI polygon/curve/line/text primitives.
        CURVECAPS => 0x01FF, // CC_CIRCLES | CC_PIE | CC_CHORD | CC_ELLIPSES | CC_WIDE | CC_STYLED | CC_WIDESTYLED | CC_INTERIORS | CC_ROUNDRECT
        LINECAPS => 0x00FE, // LC_POLYLINE | LC_MARKER | LC_POLYMARKER | LC_WIDE | LC_STYLED | LC_WIDESTYLED | LC_INTERIORS
        POLYGONALCAPS => 0x00FF, // PC_POLYGON | PC_RECTANGLE | PC_WINDPOLYGON | PC_SCANLINE | PC_WIDE | PC_STYLED | PC_WIDESTYLED | PC_INTERIORS
        // TC_OP_CHARACTER | TC_OP_STROKE | TC_CR_ANY | TC_SF_X_YINDEP | TC_SA_DOUBLE | TC_SA_INTEGER | TC_SA_CONTIN | TC_UA_ABLE | TC_SO_ABLE | TC_RA_ABLE | TC_VA_ABLE
        TEXTCAPS => 0x0000_7FF7,
        CLIPCAPS => 1, // CP_RECTANGLE
        ASPECTX | ASPECTY => 36,
        ASPECTXY => 51,
        LOGPIXELSX | LOGPIXELSY => 96,
        // The local display is RGB565/non-paletted, but CE's DEFAULT_PALETTE remains readable.
        SIZEPALETTE | NUMRESERVED => 0,
        COLORRES => 16, // 16-bit RGB565 color resolution
        // SB_CONST_ALPHA | SB_PIXEL_ALPHA | SB_PREMULT_ALPHA | SB_GRAD_RECT
        SHADEBLENDCAPS => 0x0000_0017,
        _ => 0,
    };
    kernel.threads.set_last_error(thread_id, 0);
    value
}

const EXTESC_NOTSUPPORTED: u32 = 0;
const EXTESC_SUPPORTED: u32 = 1;
const EXTESC_ERROR: u32 = u32::MAX;
const QUERYESCSUPPORT: u32 = 8;
const DRVESC_SETGAMMAVALUE: u32 = 6201;
const DRVESC_GETGAMMAVALUE: u32 = 6202;
const DRVESC_SETSCREENROTATION: u32 = 6301;
const DRVESC_GETSCREENROTATION: u32 = 6302;
const DRVESC_SETVIDEOPROTECTION: u32 = 6401;
const DRVESC_GETVIDEOPROTECTION: u32 = 6402;
const DRVESC_SAVEVIDEOMEM: u32 = 6501;
const DRVESC_RESTOREVIDEOMEM: u32 = 6502;
const DRVESC_GETRAWFRAMEBUFFER: u32 = 0x0002_0001;
const CONTRASTCOMMAND: u32 = 6149;
const CONTRAST_CMD_GET: u32 = 0;
const CONTRAST_CMD_SET: u32 = 1;
const CONTRAST_CMD_INCREASE: u32 = 2;
const CONTRAST_CMD_DECREASE: u32 = 3;
const CONTRAST_CMD_DEFAULT: u32 = 4;
const CONTRAST_CMD_MAX: u32 = 5;
const SETBACKLIGHT: u32 = 100_000;
const GETBACKLIGHT: u32 = 100_001;
const DMDO_0: u32 = 0;
const DMDO_90: u32 = 1;
const DMDO_180: u32 = 2;
const DMDO_270: u32 = 4;
const DISP_CHANGE_BADMODE_RAW: u32 = (-2i32) as u32;
const DISPPERF_EXTESC_GETSIZE: u32 = 0xfefefff0;
const DISPPERF_EXTESC_GETTIMING: u32 = 0xfefefff1;
const DISPPERF_EXTESC_CLEARTIMING: u32 = 0xfefefff2;
const DISPPERF_EXTESC_GETUNHANDLED: u32 = 0xfefefff3;
const DISPPERF_TIMING_SIZE: u32 = 64;
const DISPPERF_NUM_ROP_TIMES: u32 = 32;
const DISPPERF_TIMING_TABLE_SIZE: u32 = DISPPERF_TIMING_SIZE * DISPPERF_NUM_ROP_TIMES;
const DISPPERF_ROP_LINE: u32 = 0xfefefff1;
const DISPPERF_ROP_TRANSPARENT_BLT: u32 = 0x0000_cccc;
const DISPPERF_ROP_ALPHA_BLEND: u32 = 0x0000_cccc;
const RAW_FRAMEBUFFER_INFO_SIZE: u32 = 28;
const RAW_FRAMEBUFFER_FORMAT_565: u16 = 1;
const RAW_FRAMEBUFFER_FORMAT_OTHER: u16 = 3;
const DEVICEEMULATOR_FRAMEBUFFER_UA_BASE: u32 = 0xa3f0_0000;
const DEVICEEMULATOR_FRAMEBUFFER_WIDTH: u32 = 240;
const DEVICEEMULATOR_FRAMEBUFFER_HEIGHT: u32 = 320;
const DEVICEEMULATOR_FRAMEBUFFER_STRIDE: usize = 480;

fn ext_escape_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hdc = raw_arg(args, 0);
    let escape = raw_arg(args, 1);
    let input_len = raw_arg(args, 2);
    let input_ptr = raw_arg(args, 3);
    let output_len = raw_arg(args, 4);
    let output_ptr = raw_arg(args, 5);
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return EXTESC_NOTSUPPORTED;
    }
    if escape == QUERYESCSUPPORT {
        if input_len < 4 || input_ptr == 0 {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return EXTESC_ERROR;
        }
        let Some(requested_escape) = read_guest_u32(kernel, memory, thread_id, input_ptr) else {
            return EXTESC_ERROR;
        };
        if is_queryable_display_escape(requested_escape) {
            kernel.threads.set_last_error(thread_id, 0);
            EXTESC_SUPPORTED
        } else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_NOT_SUPPORTED);
            EXTESC_NOTSUPPORTED
        }
    } else if is_dispperf_escape(escape) {
        dispperf_ext_escape_raw(kernel, memory, thread_id, escape, output_len, output_ptr)
    } else if escape == DRVESC_GETGAMMAVALUE {
        drvesc_get_gamma_value_raw(kernel, memory, thread_id, output_len, output_ptr)
    } else if escape == DRVESC_SETGAMMAVALUE {
        drvesc_set_gamma_value_raw(kernel, memory, thread_id, input_len, input_ptr)
    } else if escape == DRVESC_GETSCREENROTATION {
        drvesc_get_screen_rotation_raw(kernel, memory, thread_id, output_len, output_ptr)
    } else if escape == DRVESC_SETSCREENROTATION {
        drvesc_set_screen_rotation_raw(kernel, memory, thread_id, input_len, input_ptr)
    } else if escape == CONTRASTCOMMAND {
        contrast_command_raw(
            kernel, memory, thread_id, input_len, input_ptr, output_len, output_ptr,
        )
    } else if escape == DRVESC_GETRAWFRAMEBUFFER {
        get_raw_framebuffer_raw(
            kernel,
            memory,
            framebuffer,
            thread_id,
            output_len,
            output_ptr,
        )
    } else if escape == SETBACKLIGHT {
        set_backlight_raw(kernel, memory, thread_id, input_len, input_ptr)
    } else if escape == GETBACKLIGHT {
        get_backlight_raw(kernel, memory, thread_id, output_len, output_ptr)
    } else if is_privileged_display_escape(escape) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_ACCESS);
        EXTESC_ERROR
    } else {
        let _ = (output_len, output_ptr);
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_SUPPORTED);
        EXTESC_NOTSUPPORTED
    }
}

fn contrast_command_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    input_len: u32,
    input_ptr: u32,
    output_len: u32,
    output_ptr: u32,
) -> u32 {
    if input_len != 8 || input_ptr == 0 || (output_ptr != 0 && output_len != 4) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return EXTESC_ERROR;
    }
    let Some(command) = read_guest_u32(kernel, memory, thread_id, input_ptr) else {
        return EXTESC_ERROR;
    };
    let Some(parm) = read_guest_u32(kernel, memory, thread_id, input_ptr.wrapping_add(4)) else {
        return EXTESC_ERROR;
    };

    let out_value = match command {
        CONTRAST_CMD_GET => kernel.display_contrast_value(),
        CONTRAST_CMD_SET => kernel.set_display_contrast_value(parm as i32),
        CONTRAST_CMD_INCREASE => kernel.increase_display_contrast(),
        CONTRAST_CMD_DECREASE => kernel.decrease_display_contrast(),
        CONTRAST_CMD_DEFAULT => kernel.reset_display_contrast(),
        CONTRAST_CMD_MAX => 15,
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return EXTESC_ERROR;
        }
    };

    if output_ptr != 0 && !write_guest_u32(kernel, memory, thread_id, output_ptr, out_value) {
        return EXTESC_ERROR;
    }
    kernel.threads.set_last_error(thread_id, 0);
    EXTESC_SUPPORTED
}

fn get_raw_framebuffer_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    output_len: u32,
    output_ptr: u32,
) -> u32 {
    if output_len < RAW_FRAMEBUFFER_INFO_SIZE || output_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return EXTESC_ERROR;
    }

    let info = framebuffer
        .as_deref()
        .map(Framebuffer::info)
        .unwrap_or(FramebufferInfo {
            width: DEVICEEMULATOR_FRAMEBUFFER_WIDTH,
            height: DEVICEEMULATOR_FRAMEBUFFER_HEIGHT,
            stride: DEVICEEMULATOR_FRAMEBUFFER_STRIDE,
            format: PixelFormat::Rgb565,
        });
    let format = match info.format {
        PixelFormat::Rgb565 => RAW_FRAMEBUFFER_FORMAT_565,
        _ => RAW_FRAMEBUFFER_FORMAT_OTHER,
    };
    let mut bytes = Vec::with_capacity(RAW_FRAMEBUFFER_INFO_SIZE as usize);
    bytes.extend_from_slice(&format.to_le_bytes());
    bytes.extend_from_slice(&(info.format.bits_per_pixel() as u16).to_le_bytes());
    bytes.extend_from_slice(&DEVICEEMULATOR_FRAMEBUFFER_UA_BASE.to_le_bytes());
    bytes.extend_from_slice(&(info.format.bytes_per_pixel() as i32).to_le_bytes());
    bytes.extend_from_slice(&(info.stride as i32).to_le_bytes());
    bytes.extend_from_slice(&(info.width as i32).to_le_bytes());
    bytes.extend_from_slice(&(info.height as i32).to_le_bytes());

    if !write_guest_bytes(kernel, memory, thread_id, output_ptr, &bytes) {
        return EXTESC_ERROR;
    }
    kernel.threads.set_last_error(thread_id, 0);
    EXTESC_SUPPORTED
}

fn set_backlight_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    input_len: u32,
    input_ptr: u32,
) -> u32 {
    if input_len != 4 || input_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return EXTESC_ERROR;
    }
    let Some(enabled) = read_guest_u32(kernel, memory, thread_id, input_ptr) else {
        return EXTESC_ERROR;
    };
    kernel.set_display_backlight_enabled(enabled != 0);
    kernel.threads.set_last_error(thread_id, 0);
    EXTESC_SUPPORTED
}

fn get_backlight_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    output_len: u32,
    output_ptr: u32,
) -> u32 {
    if output_len != 4 || output_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return EXTESC_ERROR;
    }
    if !write_guest_u32(
        kernel,
        memory,
        thread_id,
        output_ptr,
        u32::from(kernel.display_backlight_enabled()),
    ) {
        return EXTESC_ERROR;
    }
    kernel.threads.set_last_error(thread_id, 0);
    EXTESC_SUPPORTED
}

fn drvesc_get_gamma_value_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    output_len: u32,
    output_ptr: u32,
) -> u32 {
    if output_len < 4 || output_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_ACCESS);
        return EXTESC_ERROR;
    }
    if !write_guest_u32(
        kernel,
        memory,
        thread_id,
        output_ptr,
        kernel.display_gamma_value(),
    ) {
        return EXTESC_ERROR;
    }
    kernel.threads.set_last_error(thread_id, 0);
    EXTESC_SUPPORTED
}

fn drvesc_set_gamma_value_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    input_len: u32,
    input_ptr: u32,
) -> u32 {
    if input_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_ACCESS);
        return EXTESC_ERROR;
    }
    if read_guest_u32(kernel, memory, thread_id, input_ptr).is_none() {
        return EXTESC_ERROR;
    }
    kernel.set_display_gamma_value(input_len);
    kernel.threads.set_last_error(thread_id, 0);
    EXTESC_SUPPORTED
}

fn drvesc_get_screen_rotation_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    output_len: u32,
    output_ptr: u32,
) -> u32 {
    if output_len < 4 || output_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_ACCESS);
        return EXTESC_ERROR;
    }
    let supported = (DMDO_0 | DMDO_90 | DMDO_180 | DMDO_270) << 8;
    let packed = supported | (kernel.display_rotation() & 0xff);
    if !write_guest_u32(kernel, memory, thread_id, output_ptr, packed) {
        return EXTESC_ERROR;
    }
    kernel.threads.set_last_error(thread_id, 0);
    DISP_CHANGE_SUCCESSFUL
}

fn drvesc_set_screen_rotation_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    input_len: u32,
    input_ptr: u32,
) -> u32 {
    if input_len == DMDO_0 && input_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_ACCESS);
        return EXTESC_ERROR;
    }
    if input_ptr != 0 && read_guest_u32(kernel, memory, thread_id, input_ptr).is_none() {
        return EXTESC_ERROR;
    }
    if matches!(input_len, DMDO_0 | DMDO_90 | DMDO_180 | DMDO_270) {
        kernel.set_display_rotation(input_len);
        kernel.threads.set_last_error(thread_id, 0);
        DISP_CHANGE_SUCCESSFUL
    } else {
        kernel.threads.set_last_error(thread_id, 0);
        DISP_CHANGE_BADMODE_RAW
    }
}

fn dispperf_ext_escape_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    escape: u32,
    output_len: u32,
    output_ptr: u32,
) -> u32 {
    match escape {
        DISPPERF_EXTESC_GETSIZE => {
            if output_len < 4 || output_ptr == 0 {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                return EXTESC_ERROR;
            }
            if !write_guest_u32(
                kernel,
                memory,
                thread_id,
                output_ptr,
                DISPPERF_TIMING_TABLE_SIZE,
            ) {
                return EXTESC_ERROR;
            }
            kernel.threads.set_last_error(thread_id, 0);
            EXTESC_SUPPORTED
        }
        DISPPERF_EXTESC_GETTIMING => {
            if output_len < DISPPERF_TIMING_TABLE_SIZE || output_ptr == 0 {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                return EXTESC_ERROR;
            }
            let timing = kernel.display_perf_timing_bytes();
            if !write_guest_bytes(kernel, memory, thread_id, output_ptr, &timing) {
                return EXTESC_ERROR;
            }
            kernel.threads.set_last_error(thread_id, 0);
            EXTESC_SUPPORTED
        }
        DISPPERF_EXTESC_CLEARTIMING => {
            kernel.clear_display_perf_timings();
            kernel.threads.set_last_error(thread_id, 0);
            EXTESC_SUPPORTED
        }
        DISPPERF_EXTESC_GETUNHANDLED => {
            if output_len < 4 || output_ptr == 0 {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                return EXTESC_ERROR;
            }
            if !write_guest_u32(
                kernel,
                memory,
                thread_id,
                output_ptr,
                kernel.display_perf_unhandled(),
            ) {
                return EXTESC_ERROR;
            }
            kernel.threads.set_last_error(thread_id, 0);
            EXTESC_SUPPORTED
        }
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            EXTESC_ERROR
        }
    }
}

fn is_queryable_display_escape(escape: u32) -> bool {
    matches!(
        escape,
        DRVESC_SETGAMMAVALUE
            | DRVESC_GETGAMMAVALUE
            | DRVESC_SETSCREENROTATION
            | DRVESC_GETSCREENROTATION
            | CONTRASTCOMMAND
            | DRVESC_GETRAWFRAMEBUFFER
            | DISPPERF_EXTESC_GETSIZE
            | DISPPERF_EXTESC_GETTIMING
            | DISPPERF_EXTESC_CLEARTIMING
            | DISPPERF_EXTESC_GETUNHANDLED
    )
}

fn is_dispperf_escape(escape: u32) -> bool {
    matches!(
        escape,
        DISPPERF_EXTESC_GETSIZE
            | DISPPERF_EXTESC_GETTIMING
            | DISPPERF_EXTESC_CLEARTIMING
            | DISPPERF_EXTESC_GETUNHANDLED
    )
}

fn is_privileged_display_escape(escape: u32) -> bool {
    matches!(
        escape,
        DRVESC_SETGAMMAVALUE
            | DRVESC_GETGAMMAVALUE
            | DRVESC_SETSCREENROTATION
            | DRVESC_GETSCREENROTATION
            | DRVESC_SETVIDEOPROTECTION
            | DRVESC_GETVIDEOPROTECTION
            | DRVESC_SAVEVIDEOMEM
            | DRVESC_RESTOREVIDEOMEM
    )
}

fn create_compatible_dc_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32) -> u32 {
    let _ = hdc;
    kernel.threads.set_last_error(thread_id, 0);
    kernel.resources.create_compatible_dc()
}

fn delete_dc_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32) -> bool {
    if hdc == 0 || !kernel.resources.delete_dc(hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn create_compatible_bitmap_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    hdc: u32,
    width: i32,
    height: i32,
) -> u32 {
    if hdc == 0 || width <= 0 || height <= 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(byte_count) = bitmap_byte_count(width, height, 32) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .create_owned_bitmap(width, height, 1, 32, bits_ptr)
}

fn create_dib_section_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hdc = raw_arg(args, 0);
    let info_ptr = raw_arg(args, 1);
    let color_usage = raw_arg(args, 2);
    let bits_out = raw_arg(args, 3);
    let section = raw_arg(args, 4);
    let offset = raw_arg(args, 5);
    if info_ptr == 0
        || !matches!(color_usage, DIB_RGB_COLORS | DIB_PAL_COLORS)
        || (section == 0 && offset != 0)
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(header_size) = read_guest_u32(kernel, memory, thread_id, info_ptr) else {
        return 0;
    };
    if header_size != 12 && !(40..=124).contains(&header_size) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(header_bytes) = read_guest_bytes(kernel, memory, thread_id, info_ptr, header_size)
    else {
        return 0;
    };
    let Some(header) = parse_dib_header(&header_bytes) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let compression = if header_size >= 40 {
        let Some(compression) = read_le_u32(&header_bytes, 16) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        compression
    } else {
        BI_RGB
    };
    let color_used = if header_size >= 40 {
        read_le_u32(&header_bytes, 32).unwrap_or(0)
    } else {
        0
    };
    if !is_supported_dib_bit_depth(header.bits_pixel) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    if header.bits_pixel < 16
        && color_used > 256
        && !(compression == BI_RGB && color_usage == DIB_PAL_COLORS)
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    if color_usage == DIB_PAL_COLORS && !matches!(header.bits_pixel, 1 | 2 | 4 | 8) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    if hdc != 0 && !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    if color_usage == DIB_PAL_COLORS && !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    let rgb_masks = match dib_rgb_masks(
        kernel,
        memory,
        thread_id,
        info_ptr,
        header_size,
        compression,
        header.bits_pixel,
    ) {
        Some(masks) => masks,
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        }
    };
    let alpha_mask = match dib_alpha_mask(
        kernel,
        memory,
        thread_id,
        info_ptr,
        header_size,
        compression,
        header.bits_pixel,
    ) {
        Some(mask) => mask,
        None => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        }
    };
    let color_table = read_dib_color_table(
        memory,
        info_ptr,
        header_size,
        compression,
        header.bits_pixel,
        color_usage,
    );
    if header.width == 0 || header.height == 0 || header.planes != 1 || header.bits_pixel == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(byte_count) = bitmap_byte_count(header.width, header.height, header.bits_pixel) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let section_bytes = if section != 0 {
        let (mapping_size, mapping_file_id, mapping_data) = {
            let Ok(mapping) = kernel.handles.file_mapping(section) else {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                return 0;
            };
            (mapping.size, mapping.file_id, mapping.data.clone())
        };
        let Some(section_end) = offset.checked_add(byte_count) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        if section_end > mapping_size {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return 0;
        };
        let start = offset as usize;
        let end = section_end as usize;
        let mut bytes = if let Some(file_id) = mapping_file_id {
            match kernel.read_file_at(file_id, start, byte_count as usize) {
                Ok(mut bytes) => {
                    bytes.resize(byte_count as usize, 0);
                    bytes
                }
                Err(_) => {
                    kernel
                        .threads
                        .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                    return 0;
                }
            }
        } else if start < mapping_data.len() {
            mapping_data[start..end.min(mapping_data.len())].to_vec()
        } else {
            Vec::new()
        };
        bytes.resize(byte_count as usize, 0);
        if start < mapping_data.len() {
            let overlay_end = end.min(mapping_data.len());
            bytes[..overlay_end - start].copy_from_slice(&mapping_data[start..overlay_end]);
        }
        Some(bytes)
    } else {
        None
    };
    let Some(bits_ptr) =
        kernel
            .memory
            .heap_alloc(PROCESS_HEAP_HANDLE, HEAP_ZERO_MEMORY, byte_count)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_NOT_ENOUGH_MEMORY);
        return 0;
    };
    if bits_out != 0 && !write_guest_u32(kernel, memory, thread_id, bits_out, bits_ptr) {
        let _ = kernel.memory.heap_free(PROCESS_HEAP_HANDLE, 0, bits_ptr);
        return 0;
    }
    if let Some(bytes) = section_bytes.as_ref() {
        try_seed_guest_bytes(memory, bits_ptr, bytes);
        let process_id = kernel.current_process_id();
        if let Ok(mapping) = kernel.handles.file_mapping_mut(section) {
            let start = offset as usize;
            let end = start.saturating_add(bytes.len());
            if end > mapping.data.len() {
                mapping.data.resize(end, 0);
            }
            mapping.data[start..end].copy_from_slice(bytes);
            mapping.views.push(FileMappingView {
                base: bits_ptr,
                size: byte_count,
                offset,
                process_id,
            });
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    let bitmap = kernel.resources.create_owned_bitmap_with_masks(
        header.width,
        header.height,
        header.planes,
        header.bits_pixel,
        bits_ptr,
        rgb_masks,
    );
    if !color_table.is_empty() {
        if let Some(object) = kernel.resources.bitmap_mut(bitmap) {
            object.color_table = color_table;
        }
    }
    if let Some(object) = kernel.resources.bitmap_mut(bitmap) {
        object.dib_section = true;
        object.section_handle = section;
        object.section_offset = offset;
        object.alpha_mask = alpha_mask;
    }
    bitmap
}

fn create_font_indirect_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    logfont_ptr: u32,
) -> u32 {
    const LOGFONTW_SIZE: u32 = 92;
    const LF_FACESIZE: usize = 32;
    if logfont_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, logfont_ptr, LOGFONTW_SIZE)
    else {
        return 0;
    };
    let Some(height) = read_le_i32(&bytes, 0) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(width) = read_le_i32(&bytes, 4) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(escapement) = read_le_i32(&bytes, 8) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(orientation) = read_le_i32(&bytes, 12) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(weight) = read_le_i32(&bytes, 16) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let face_units = (0..LF_FACESIZE)
        .filter_map(|index| read_le_u16(&bytes, 28 + index * 2))
        .take_while(|unit| *unit != 0)
        .collect::<Vec<_>>();
    let face_name = String::from_utf16_lossy(&face_units);
    kernel.threads.set_last_error(thread_id, 0);
    kernel.resources.create_font(
        logfont_ptr,
        height,
        width,
        escapement,
        orientation,
        weight,
        bytes.get(20).copied().unwrap_or(0) != 0,
        bytes.get(21).copied().unwrap_or(0) != 0,
        bytes.get(22).copied().unwrap_or(0) != 0,
        bytes.get(23).copied().unwrap_or(1),
        bytes.get(24).copied().unwrap_or(0),
        bytes.get(25).copied().unwrap_or(0),
        bytes.get(26).copied().unwrap_or(0),
        bytes.get(27).copied().unwrap_or(0),
        face_name,
    )
}

fn add_font_resource_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    path_ptr: u32,
) -> u32 {
    if path_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(path) = read_guest_wide_arg(memory, path_ptr) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    match kernel.read_guest_file(&path) {
        Ok(_) => {
            kernel.threads.set_last_error(thread_id, 0);
            kernel.send_notify_message_w(
                thread_id,
                crate::ce::gwe::HWND_BROADCAST,
                crate::ce::gwe::WM_FONTCHANGE,
                0,
                0,
            );
            1
        }
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_FILE_NOT_FOUND);
            0
        }
    }
}

