fn create_palette_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    log_palette_ptr: u32,
) -> u32 {
    if log_palette_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(header) = read_guest_bytes(kernel, memory, thread_id, log_palette_ptr, 4) else {
        return 0;
    };
    let Some(entry_count) = read_le_u16(&header, 2).map(u32::from) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if entry_count > MAX_LOG_PALETTE_ENTRIES {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(byte_count) = entry_count.checked_mul(PALETTE_ENTRY_SIZE_U32) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(bytes) = read_guest_bytes(
        kernel,
        memory,
        thread_id,
        log_palette_ptr.wrapping_add(4),
        byte_count,
    ) else {
        return 0;
    };
    let entries = bytes
        .chunks_exact(PALETTE_ENTRY_SIZE)
        .map(|entry| [entry[0], entry[1], entry[2], entry[3]])
        .collect();
    kernel.threads.set_last_error(thread_id, 0);
    kernel.resources.create_palette(entries)
}

fn get_palette_entries_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    palette: u32,
    start: u32,
    count: u32,
    entries_ptr: u32,
) -> u32 {
    let Some(entries) = palette_entries_for_read(kernel, palette) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Some(bytes) = palette_entry_bytes(&entries, start, count) else {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    };
    if entries_ptr == 0 || bytes.is_empty() {
        kernel.threads.set_last_error(thread_id, 0);
        return (bytes.len() / PALETTE_ENTRY_SIZE) as u32;
    }
    if !write_guest_bytes(kernel, memory, thread_id, entries_ptr, &bytes) {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    (bytes.len() / PALETTE_ENTRY_SIZE) as u32
}

fn set_palette_entries_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    palette: u32,
    start: u32,
    count: u32,
    entries_ptr: u32,
) -> u32 {
    let Some(entries_len) = kernel
        .resources
        .palette(palette)
        .map(|palette| palette.entries.len())
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let Ok(start_index) = usize::try_from(start) else {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    };
    if count == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    if start_index >= entries_len {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    if entries_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let copy_count = usize::try_from(count)
        .ok()
        .unwrap_or(usize::MAX)
        .min(entries_len - start_index);
    let Some(byte_count) = (copy_count as u32).checked_mul(PALETTE_ENTRY_SIZE_U32) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    let Some(bytes) = read_guest_bytes(kernel, memory, thread_id, entries_ptr, byte_count) else {
        return 0;
    };
    if let Some(palette) = kernel.resources.palette_mut(palette) {
        for (index, entry) in bytes.chunks_exact(PALETTE_ENTRY_SIZE).enumerate() {
            palette.entries[start_index + index] = [entry[0], entry[1], entry[2], entry[3]];
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    copy_count as u32
}

fn get_system_palette_entries_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdc: u32,
    start: u32,
    count: u32,
    entries_ptr: u32,
) -> u32 {
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    // CE GDIAPI's palette tests only expect system palette entries on 8bpp
    // primary surfaces with RC_PALETTE. The local display is RGB565.
    let _ = (memory, start, count, entries_ptr);
    kernel.threads.set_last_error(thread_id, 0);
    0
}

fn get_nearest_color_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32, colorref: u32) -> u32 {
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return CLR_INVALID;
    }
    // The local display is true-color/RGB565, so CE returns the input RGB color.
    kernel.threads.set_last_error(thread_id, 0);
    colorref & 0x00ff_ffff
}

fn get_current_object_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32, obj_type: u32) -> u32 {
    const OBJ_PEN: u32 = 1;
    const OBJ_BRUSH: u32 = 2;
    const OBJ_PAL: u32 = 5;
    const OBJ_FONT: u32 = 6;
    const OBJ_BITMAP: u32 = 7;

    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    if !matches!(
        obj_type,
        OBJ_PEN | OBJ_BRUSH | OBJ_PAL | OBJ_FONT | OBJ_BITMAP
    ) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel.resources.get_current_object(hdc, obj_type)
}

fn get_object_type_raw(kernel: &mut CeKernel, thread_id: u32, handle: u32) -> u32 {
    let type_code = match kernel.resources.gdi_object_kind(handle) {
        "pen" => 1,                             // OBJ_PEN
        "brush" => 2,                           // OBJ_BRUSH
        "memory_dc" => 10,                      // OBJ_MEMDC
        "palette" => 5,                         // OBJ_PAL
        "font" => 6,                            // OBJ_FONT
        "bitmap" => 7,                          // OBJ_BITMAP
        "region" => 8,                          // OBJ_REGION
        _ if is_valid_hdc(kernel, handle) => 3, // OBJ_DC
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        }
    };
    kernel.threads.set_last_error(thread_id, 0);
    type_code
}

fn get_nearest_palette_index_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    palette: u32,
    colorref: u32,
) -> u32 {
    let Some(entries) = palette_entries_for_read(kernel, palette) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return u32::MAX;
    };
    let red = (colorref & 0xff) as i32;
    let green = ((colorref >> 8) & 0xff) as i32;
    let blue = ((colorref >> 16) & 0xff) as i32;
    let Some((index, _distance)) = entries
        .iter()
        .enumerate()
        .map(|(index, entry)| {
            let dr = i32::from(entry[0]) - red;
            let dg = i32::from(entry[1]) - green;
            let db = i32::from(entry[2]) - blue;
            (index, dr * dr + dg * dg + db * db)
        })
        .min_by_key(|(_, distance)| *distance)
    else {
        kernel.threads.set_last_error(thread_id, 0);
        return u32::MAX;
    };
    kernel.threads.set_last_error(thread_id, 0);
    index as u32
}

fn palette_entry_count(kernel: &CeKernel, palette: u32) -> Option<u16> {
    if let Some(palette) = kernel.resources.palette(palette) {
        return u16::try_from(palette.entries.len()).ok();
    }
    is_default_palette_handle(palette).then_some(DEFAULT_PALETTE_ENTRIES.len() as u16)
}

fn palette_entries_for_read(kernel: &CeKernel, palette: u32) -> Option<Vec<[u8; 4]>> {
    kernel
        .resources
        .palette(palette)
        .map(|palette| palette.entries.clone())
        .or_else(|| is_default_palette_handle(palette).then(|| DEFAULT_PALETTE_ENTRIES.to_vec()))
}

fn is_default_palette_handle(handle: u32) -> bool {
    stock_object_handle(15) == Some(handle)
}

const DEFAULT_PALETTE_ENTRIES: [[u8; 4]; 20] = [
    [0x00, 0x00, 0x00, 0x00],
    [0x80, 0x00, 0x00, 0x00],
    [0x00, 0x80, 0x00, 0x00],
    [0x80, 0x80, 0x00, 0x00],
    [0x00, 0x00, 0x80, 0x00],
    [0x80, 0x00, 0x80, 0x00],
    [0x00, 0x80, 0x80, 0x00],
    [0xc0, 0xc0, 0xc0, 0x00],
    [0xc0, 0xdc, 0xc0, 0x00],
    [0xa6, 0xca, 0xf0, 0x00],
    [0xff, 0xfb, 0xf0, 0x00],
    [0xa0, 0xa0, 0xa4, 0x00],
    [0x80, 0x80, 0x80, 0x00],
    [0xff, 0x00, 0x00, 0x00],
    [0x00, 0xff, 0x00, 0x00],
    [0xff, 0xff, 0x00, 0x00],
    [0x00, 0x00, 0xff, 0x00],
    [0xff, 0x00, 0xff, 0x00],
    [0x00, 0xff, 0xff, 0x00],
    [0xff, 0xff, 0xff, 0x00],
];

fn select_palette_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32, palette: u32) -> u32 {
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    let Some(previous) = kernel.resources.select_palette(hdc, palette) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    previous
}

fn realize_palette_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32) -> u32 {
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    let Some(mapped) = kernel.resources.realize_palette(hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    kernel.threads.set_last_error(thread_id, 0);
    mapped
}

fn palette_entry_bytes(entries: &[[u8; 4]], start: u32, count: u32) -> Option<Vec<u8>> {
    let start = usize::try_from(start).ok()?;
    if start >= entries.len() || count == 0 {
        return Some(Vec::new());
    }
    let count = usize::try_from(count).ok().unwrap_or(usize::MAX);
    let end = start.saturating_add(count).min(entries.len());
    Some(entries[start..end].iter().flatten().copied().collect())
}

