impl TextMetricsModel {
    fn from_font(font: Option<&FontObject>) -> Self {
        let raw_height = font.map(|font| font.height).unwrap_or(0);
        let mut height = if raw_height == 0 {
            16
        } else {
            raw_height.saturating_abs().max(1)
        };
        if let Some(known_height) = font.and_then(known_pass_odd_text_height) {
            height = known_height;
        }
        let ave_width = font
            .and_then(|font| (font.width > 0).then_some(font.width))
            .unwrap_or_else(|| ((height + 1) / 2).max(1));
        let descent = (height / 4).max(1).min(height);
        let ascent = height.saturating_sub(descent).max(1);
        let face_name = font
            .map(|font| font.face_name.as_str())
            .filter(|name| !name.is_empty())
            .unwrap_or(DEFAULT_TEXT_FACE_NAME)
            .to_string();

        let mut metrics = Self {
            selected_font: font.is_some(),
            escapement: font.map(|font| font.escapement).unwrap_or(0),
            height,
            requested_width: font.map(|font| font.width).unwrap_or(0),
            ascent,
            descent,
            internal_leading: 0,
            external_leading: 0,
            ave_width,
            max_width: ave_width.saturating_mul(2).max(ave_width),
            weight: font.map(|font| font.weight).unwrap_or(400),
            overhang: 0,
            first_char: 0x20,
            last_char: 0xffff,
            default_char: '?' as u16,
            break_char: ' ' as u16,
            italic: font.map(|font| font.italic).unwrap_or(false),
            underline: font.map(|font| font.underline).unwrap_or(false),
            strikeout: font.map(|font| font.strikeout).unwrap_or(false),
            pitch_and_family: font
                .map(|font| font.pitch_and_family)
                .unwrap_or(DEFAULT_TEXT_PITCH_AND_FAMILY),
            charset: font
                .map(|font| font.charset)
                .unwrap_or(DEFAULT_TEXT_CHARSET),
            face_name,
        };

        if let Some(profile) = font.and_then(known_20px_text_metrics_profile) {
            metrics.apply_profile(profile);
        }

        metrics
    }

    fn apply_profile(&mut self, profile: &KnownTextMetricsProfile) {
        self.height = profile.height;
        self.ascent = profile.ascent;
        self.descent = profile.descent;
        self.internal_leading = profile.internal_leading;
        self.external_leading = profile.external_leading;
        self.ave_width = profile.ave_width;
        self.max_width = profile.max_width;
        self.weight = profile.weight;
        self.overhang = profile.overhang;
        self.first_char = profile.first_char;
        self.last_char = profile.last_char;
        self.default_char = profile.default_char;
        self.break_char = profile.break_char;
        self.italic = profile.italic;
        self.underline = profile.underline;
        self.strikeout = profile.strikeout;
        self.pitch_and_family = profile.pitch_and_family;
        self.charset = profile.charset;
    }

    fn char_width(&self, unit: u16) -> i32 {
        known_16px_extent_widths(self)
            .and_then(|widths| {
                (CE_EXTENT_FIRST_CHAR..=CE_EXTENT_LAST_CHAR)
                    .contains(&unit)
                    .then_some(widths[(unit - CE_EXTENT_FIRST_CHAR) as usize])
            })
            .unwrap_or_else(|| self.ave_width.max(1))
    }

    fn abc_width(&self, unit: u16) -> (i32, u32, i32) {
        known_16px_abc_widths(self)
            .and_then(|widths| {
                (CE_EXTENT_FIRST_CHAR..=CE_EXTENT_LAST_CHAR)
                    .contains(&unit)
                    .then_some(widths[(unit - CE_EXTENT_FIRST_CHAR) as usize])
            })
            .unwrap_or((0, self.ave_width.max(1) as u32, 0))
    }
}

fn known_20px_text_metrics_profile(font: &FontObject) -> Option<&'static KnownTextMetricsProfile> {
    let plain_known_font = font.height.saturating_abs() == 20
        && font.width == 0
        && font.weight == 400
        && !font.italic
        && !font.underline
        && !font.strikeout;
    if !plain_known_font {
        return None;
    }
    CE_20PX_TEXT_METRICS_PROFILES
        .iter()
        .find(|profile| font.face_name.eq_ignore_ascii_case(profile.face_name))
}

fn known_pass_odd_text_height(font: &FontObject) -> Option<i32> {
    let plain_known_font =
        font.width == 0 && font.weight == 400 && !font.italic && !font.underline && !font.strikeout;
    if !plain_known_font {
        return None;
    }
    let row = match font.height {
        0 => [
            ("Tahoma", 19),
            ("Courier New", 18),
            ("Symbol", 20),
            ("Times New Roman", 19),
            ("Wingdings", 17),
        ],
        -24 => [
            ("Tahoma", 29),
            ("Courier New", 27),
            ("Symbol", 30),
            ("Times New Roman", 27),
            ("Wingdings", 26),
        ],
        _ => return None,
    };
    row.iter()
        .find_map(|(face, height)| font.face_name.eq_ignore_ascii_case(face).then_some(*height))
}

fn known_16px_extent_widths(metrics: &TextMetricsModel) -> Option<&'static [i32; 90]> {
    let plain_known_font = metrics.height == 16
        && metrics.selected_font
        && metrics.requested_width == 0
        && metrics.weight == 400
        && !metrics.italic
        && !metrics.underline
        && !metrics.strikeout;
    if !plain_known_font {
        return None;
    }
    if metrics.face_name.eq_ignore_ascii_case("Tahoma") {
        Some(&CE_EXTENT_TAHOMA_16PX)
    } else if metrics.face_name.eq_ignore_ascii_case("Courier New") {
        Some(&CE_EXTENT_COURIER_NEW_16PX)
    } else if metrics.face_name.eq_ignore_ascii_case("Times New Roman") {
        Some(&CE_EXTENT_TIMES_NEW_ROMAN_16PX)
    } else if metrics.face_name.eq_ignore_ascii_case("Wingdings") {
        Some(&CE_EXTENT_WINGDINGS_16PX)
    } else if metrics.face_name.eq_ignore_ascii_case("Verdana") {
        Some(&CE_EXTENT_VERDANA_16PX)
    } else if metrics.face_name.eq_ignore_ascii_case("Arial") {
        Some(&CE_EXTENT_ARIAL_RASTER_16PX)
    } else {
        None
    }
}

fn known_16px_abc_widths(metrics: &TextMetricsModel) -> Option<&'static [(i32, u32, i32); 90]> {
    let plain_known_font = metrics.height == 16
        && metrics.selected_font
        && metrics.requested_width == 0
        && metrics.weight == 400
        && !metrics.italic
        && !metrics.underline
        && !metrics.strikeout;
    if plain_known_font && metrics.face_name.eq_ignore_ascii_case("Tahoma") {
        Some(&CE_ABC_TAHOMA_16PX)
    } else {
        None
    }
}

fn selected_text_metrics(kernel: &CeKernel, hdc: u32) -> Option<TextMetricsModel> {
    let state = kernel.resources.dc_state(hdc)?;
    Some(TextMetricsModel::from_font(
        kernel.resources.font(state.selected_font),
    ))
}

fn text_advance_with_extra(char_width: i32, previous_char_width: i32, extra: i32) -> i32 {
    if extra >= 0 {
        char_width.saturating_add(extra)
    } else if previous_char_width.saturating_add(extra) > 0 {
        char_width.saturating_add(extra).max(0)
    } else {
        char_width
    }
}

fn text_run_advances(char_width: i32, extra: i32, count: usize) -> Vec<i32> {
    let mut previous_char_width = 0;
    let mut advances = Vec::with_capacity(count);
    for _ in 0..count {
        advances.push(text_advance_with_extra(
            char_width,
            previous_char_width,
            extra,
        ));
        previous_char_width = char_width;
    }
    advances
}

fn text_run_advances_for_units(metrics: &TextMetricsModel, units: &[u16], extra: i32) -> Vec<i32> {
    let mut previous_char_width = 0;
    let mut advances = Vec::with_capacity(units.len());
    for unit in units {
        let char_width = metrics.char_width(*unit);
        advances.push(text_advance_with_extra(
            char_width,
            previous_char_width,
            extra,
        ));
        previous_char_width = char_width;
    }
    advances
}

fn read_text_extent_units<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    text_ptr: u32,
    count: i32,
) -> Option<Vec<u16>> {
    if count < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    if count == 0 {
        return Some(Vec::new());
    }
    if text_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    let mut units = Vec::with_capacity(count as usize);
    for index in 0..count as u32 {
        let Ok(unit) = memory.read_u16(text_ptr.wrapping_add(index.saturating_mul(2))) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return None;
        };
        units.push(unit);
    }
    Some(units)
}

fn write_size<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    size_ptr: u32,
    cx: i32,
    cy: i32,
) -> bool {
    write_guest_i32(kernel, memory, thread_id, size_ptr, cx)
        && write_guest_i32(kernel, memory, thread_id, size_ptr.wrapping_add(4), cy)
}

fn write_textmetric_w<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    out_ptr: u32,
    metrics: &TextMetricsModel,
) -> bool {
    const TEXTMETRICW_SIZE: usize = 60;
    let mut bytes = [0u8; TEXTMETRICW_SIZE];
    let mut write_i32 = |offset: usize, value: i32| {
        bytes[offset..offset + 4].copy_from_slice(&value.to_le_bytes());
    };
    write_i32(0, metrics.height);
    write_i32(4, metrics.ascent);
    write_i32(8, metrics.descent);
    write_i32(12, metrics.internal_leading);
    write_i32(16, metrics.external_leading);
    write_i32(20, metrics.ave_width);
    write_i32(24, metrics.max_width);
    write_i32(28, metrics.weight);
    write_i32(32, metrics.overhang);
    write_i32(36, 96);
    write_i32(40, 96);
    bytes[44..46].copy_from_slice(&metrics.first_char.to_le_bytes());
    bytes[46..48].copy_from_slice(&metrics.last_char.to_le_bytes());
    bytes[48..50].copy_from_slice(&metrics.default_char.to_le_bytes());
    bytes[50..52].copy_from_slice(&metrics.break_char.to_le_bytes());
    bytes[52] = u8::from(metrics.italic);
    bytes[53] = u8::from(metrics.underline);
    bytes[54] = u8::from(metrics.strikeout);
    bytes[55] = metrics.pitch_and_family;
    bytes[56] = metrics.charset;
    write_guest_bytes(kernel, memory, thread_id, out_ptr, &bytes)
}

// DT_* flags used by DrawTextW
const DT_LEFT: u32 = 0x0000;
const DT_CENTER: u32 = 0x0001;
const DT_RIGHT: u32 = 0x0002;
const DT_TOP: u32 = 0x0000;
const DT_VCENTER: u32 = 0x0004;
const DT_BOTTOM: u32 = 0x0008;
const DT_WORDBREAK: u32 = 0x0010;
const DT_SINGLELINE: u32 = 0x0020;
const DT_NOCLIP: u32 = 0x0100;
const DT_CALCRECT: u32 = 0x0400;
const DT_NOPREFIX: u32 = 0x0800;

fn draw_text_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    mut framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    hdc: u32,
    text_ptr: u32,
    count: i32,
    rect_ptr: u32,
    format: u32,
) -> u32 {
    if hdc == 0 || text_ptr == 0 || rect_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(rect) = read_guest_rect(kernel, memory, thread_id, rect_ptr) else {
        return 0;
    };
    let char_count = if count < 0 {
        read_guest_wide_arg(memory, text_ptr).map(|text| text.encode_utf16().count())
    } else {
        Some(count as usize)
    };
    let Some(char_count) = char_count else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    };
    if char_count == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    if hdc_has_readonly_selected_bitmap(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }

    let metrics = selected_text_metrics(kernel, hdc);
    let cell_h = metrics.as_ref().map(|m| m.height).unwrap_or(16).max(1);

    if format & DT_CALCRECT == 0 {
        let clip = if format & DT_NOCLIP == 0 {
            Some(rect)
        } else {
            None
        };

        // Horizontal alignment within the rect
        let text_w = measure_text_width(kernel, memory, hdc, text_ptr, char_count as u32, 0);
        let rect_w = (rect.right - rect.left).max(0);
        let x = match format & (DT_CENTER | DT_RIGHT) {
            DT_RIGHT => rect.right - text_w,
            DT_CENTER => rect.left + (rect_w - text_w) / 2,
            _ => rect.left,
        };
        // Vertical alignment: DT_VCENTER/DT_BOTTOM only apply with DT_SINGLELINE
        let y = if format & DT_SINGLELINE != 0 {
            let rect_h = (rect.bottom - rect.top).max(0);
            if format & DT_BOTTOM != 0 {
                rect.bottom - cell_h
            } else if format & DT_VCENTER != 0 {
                rect.top + (rect_h - cell_h) / 2
            } else {
                rect.top
            }
        } else {
            rect.top
        };

        if let Some(fb) = framebuffer.as_deref_mut() {
            draw_ext_text_glyphs_to_framebuffer(
                kernel,
                memory,
                fb,
                hdc,
                x,
                y,
                text_ptr,
                char_count as u32,
                0,
                clip,
            );
        } else if kernel.resources.is_memory_dc(hdc) {
            draw_ext_text_glyphs_to_bitmap(
                kernel,
                memory,
                hdc,
                x,
                y,
                text_ptr,
                char_count as u32,
                0,
                clip,
            );
        }
    }

    kernel.threads.set_last_error(thread_id, 0);
    cell_h as u32
}

// Render FONT_8X8 glyphs into the selected bitmap of a memory DC.
// Analogous to draw_ext_text_glyphs_to_framebuffer but writes via write_bitmap_pixel_rgb.
fn draw_ext_text_glyphs_to_bitmap<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &mut M,
    hdc: u32,
    x: i32,
    y: i32,
    text_ptr: u32,
    count: u32,
    dx_ptr: u32,
    clip: Option<Rect>,
) {
    if !kernel.resources.is_memory_dc(hdc) {
        return;
    }
    let Some(bitmap) = selected_bitmap_object(kernel, hdc) else {
        return;
    };

    let Some(state) = kernel.resources.dc_state(hdc) else {
        return;
    };
    let text_color = state.text_color;
    let bk_mode = state.bk_mode;
    let bk_color = state.bk_color;
    let font = kernel.resources.font(state.selected_font).cloned();
    let metrics = TextMetricsModel::from_font(font.as_ref());
    let cell_h = metrics.height.max(1) as usize;
    let cell_w = metrics.ave_width.max(1);
    let text_char_extra = state.text_char_extra;
    let total_w = measure_text_width(kernel, memory, hdc, text_ptr, count, dx_ptr);
    let text_bounds = Rect {
        left: x,
        top: y,
        right: x.saturating_add(total_w),
        bottom: y.saturating_add(cell_h as i32),
    };
    let requested = if let Some(clip) = clip {
        let Some(rect) = intersect_rect_value(normalize_rect(text_bounds), normalize_rect(clip))
        else {
            return;
        };
        rect
    } else {
        normalize_rect(text_bounds)
    };
    let clips = hdc_clip_rects(kernel, hdc, requested, bitmap.width, bitmap.height);
    if clips.is_empty() {
        return;
    }
    let rgb = colorref_rgb(text_color);
    let bk_rgb = colorref_rgb(bk_color);

    let bm_w = bitmap.width;
    let bm_h = bitmap.height;

    let mut cursor_x = x;

    for char_idx in 0..count as usize {
        let unit = memory
            .read_u16(text_ptr.wrapping_add((char_idx as u32) * 2))
            .unwrap_or(0);

        let advance = if dx_ptr != 0 {
            (memory
                .read_u32(dx_ptr.wrapping_add((char_idx as u32) * 4))
                .unwrap_or(cell_w as u32) as i32)
                .saturating_add(text_char_extra)
        } else {
            let char_width = metrics.char_width(unit);
            let previous_char_width = if char_idx == 0 {
                0
            } else {
                let previous_unit = memory
                    .read_u16(text_ptr.wrapping_add(((char_idx - 1) as u32) * 2))
                    .unwrap_or(0);
                metrics.char_width(previous_unit)
            };
            text_advance_with_extra(char_width, previous_char_width, text_char_extra)
        };

        if bk_mode == BKMODE_OPAQUE && advance > 0 {
            let bg_left = cursor_x;
            let bg_right = cursor_x.saturating_add(advance);
            let bg_top = y;
            let bg_bottom = y.saturating_add(cell_h as i32);
            for sy in bg_top.max(0)..bg_bottom.min(bm_h) {
                for sx in bg_left.max(0)..bg_right.min(bm_w) {
                    if !clip_rects_contain_point(&clips, sx, sy) {
                        continue;
                    }
                    let _ = write_bitmap_pixel_rgb(memory, &bitmap, sx, sy, bk_rgb);
                }
            }
        }

        if unit >= 32 && unit < 128 {
            let glyph = FONT_8X8[(unit - 32) as usize];
            for glyph_row in 0..8usize {
                let row_byte = glyph[glyph_row];
                if row_byte == 0 {
                    continue;
                }
                let sy0 = y + (glyph_row * cell_h / 8) as i32;
                let sy1 = y + ((glyph_row + 1) * cell_h / 8) as i32;
                for sy in sy0..sy1 {
                    if sy < 0 || sy >= bm_h {
                        continue;
                    }
                    for glyph_col in 0..8usize {
                        if row_byte & (0x80u8 >> glyph_col) == 0 {
                            continue;
                        }
                        let sx0 = cursor_x + (glyph_col as i32 * cell_w) / 8;
                        let sx1 = cursor_x + ((glyph_col as i32 + 1) * cell_w) / 8;
                        let sx1 = sx1.max(sx0 + 1);
                        for sx in sx0..sx1 {
                            if sx < 0 || sx >= bm_w {
                                continue;
                            }
                            if !clip_rects_contain_point(&clips, sx, sy) {
                                continue;
                            }
                            let _ = write_bitmap_pixel_rgb(memory, &bitmap, sx, sy, rgb);
                        }
                    }
                }
            }
        }

        cursor_x += advance;
    }
}

fn clip_rects_contain_point(clips: &[Rect], x: i32, y: i32) -> bool {
    clips
        .iter()
        .any(|clip| x >= clip.left && x < clip.right && y >= clip.top && y < clip.bottom)
}

fn get_text_extent_ex_point_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let text_ptr = raw_arg(args, 1);
    let count = raw_i32_arg(args, 2);
    let max_extent = raw_i32_arg(args, 3);
    let fit_ptr = raw_arg(args, 4);
    let dx_ptr = raw_arg(args, 5);
    let size_ptr = raw_arg(args, 6);
    if size_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let Some(units) = read_text_extent_units(kernel, memory, thread_id, text_ptr, count) else {
        return false;
    };
    let advances = text_run_advances(
        metrics.ave_width.max(1),
        kernel.resources.text_char_extra(hdc),
        units.len().min(i32::MAX as usize),
    );
    let advances = if known_16px_extent_widths(&metrics).is_some() {
        text_run_advances_for_units(&metrics, &units, kernel.resources.text_char_extra(hdc))
    } else {
        advances
    };
    let total_width = advances
        .iter()
        .fold(0i32, |sum, advance| sum.saturating_add(*advance));
    if fit_ptr != 0 {
        let fit = if max_extent > 0 {
            let mut width = 0i32;
            let mut fit = 0u32;
            for advance in advances.iter().copied() {
                let next = width.saturating_add(advance);
                if next > max_extent {
                    break;
                }
                width = next;
                fit = fit.saturating_add(1);
            }
            fit
        } else {
            units.len().min(u32::MAX as usize) as u32
        };
        if !write_guest_u32(kernel, memory, thread_id, fit_ptr, fit) {
            return false;
        }
    }
    if dx_ptr != 0 {
        let mut advance = 0i32;
        for (index, char_advance) in advances.iter().copied().enumerate() {
            advance = advance.saturating_add(char_advance);
            if !write_guest_i32(
                kernel,
                memory,
                thread_id,
                dx_ptr.wrapping_add((index as u32).saturating_mul(4)),
                advance,
            ) {
                return false;
            }
        }
    }
    if !write_size(
        kernel,
        memory,
        thread_id,
        size_ptr,
        total_width,
        metrics.height,
    ) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_text_metrics_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdc: u32,
    out_ptr: u32,
) -> bool {
    if out_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    if !write_textmetric_w(kernel, memory, thread_id, out_ptr, &metrics) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_char_width32_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let first = raw_arg(args, 1);
    let last = raw_arg(args, 2);
    let out_ptr = raw_arg(args, 3);
    if out_ptr == 0 || last < first {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let count = (last - first + 1) as usize;
    for i in 0..count {
        let width = metrics.char_width((first + i as u32).min(u16::MAX as u32) as u16) as u32;
        if !write_guest_u32(kernel, memory, thread_id, out_ptr + i as u32 * 4, width) {
            return false;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

// GetCharABCWidths — fills ABC structs (abcA: i32, abcB: u32, abcC: i32).
fn get_char_abcwidths_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let first = raw_arg(args, 1);
    let last = raw_arg(args, 2);
    let out_ptr = raw_arg(args, 3);
    if out_ptr == 0 || last < first {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    if metrics.escapement != 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let count = (last - first + 1) as usize;
    let units = (0..count).map(|index| (first + index as u32).min(u16::MAX as u32) as u16);
    if !write_abc_widths(kernel, memory, thread_id, out_ptr, units, &metrics) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn get_char_abcwidths_i_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let first = raw_arg(args, 1);
    let count = raw_arg(args, 2) as usize;
    let glyph_indices_ptr = raw_arg(args, 3);
    let out_ptr = raw_arg(args, 4);
    if out_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    if glyph_indices_ptr != 0 {
        for index in 0..count {
            if memory
                .read_u16(glyph_indices_ptr.wrapping_add((index as u32).saturating_mul(2)))
                .is_err()
            {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                return false;
            }
        }
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    };
    let mut units = Vec::with_capacity(count);
    if glyph_indices_ptr != 0 {
        for index in 0..count {
            match memory.read_u16(glyph_indices_ptr.wrapping_add((index as u32).saturating_mul(2)))
            {
                Ok(unit) => units.push(unit),
                Err(_) => {
                    kernel
                        .threads
                        .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                    return false;
                }
            }
        }
    } else {
        units.extend((0..count).map(|index| (first + index as u32).min(u16::MAX as u32) as u16));
    }
    if !write_abc_widths(
        kernel,
        memory,
        thread_id,
        out_ptr,
        units.into_iter(),
        &metrics,
    ) {
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn write_abc_widths<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    out_ptr: u32,
    units: impl Iterator<Item = u16>,
    metrics: &TextMetricsModel,
) -> bool {
    for (i, unit) in units.enumerate() {
        let base = out_ptr + i as u32 * 12;
        let (abc_a, abc_b, abc_c) = metrics.abc_width(unit);
        if !write_guest_i32(kernel, memory, thread_id, base, abc_a)
            || !write_guest_u32(kernel, memory, thread_id, base + 4, abc_b)
            || !write_guest_i32(kernel, memory, thread_id, base + 8, abc_c)
        {
            return false;
        }
    }
    true
}

fn get_text_face_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdc: u32,
    capacity_chars: i32,
    out_ptr: u32,
) -> u32 {
    if capacity_chars < 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0;
    }
    let Some(metrics) = selected_text_metrics(kernel, hdc) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let face_len = metrics.face_name.encode_utf16().count() as u32;
    if out_ptr == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return face_len.saturating_add(1);
    }
    if out_ptr != 0 && capacity_chars > 0 {
        if !write_guest_wide_fixed(
            kernel,
            memory,
            thread_id,
            out_ptr,
            &metrics.face_name,
            capacity_chars as usize,
        ) {
            return 0;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return face_len.min(capacity_chars.saturating_sub(1) as u32);
    }
    kernel.threads.set_last_error(thread_id, 0);
    face_len
}

fn ext_text_out_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    mut framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hdc = raw_arg(args, 0);
    let x = raw_i32_arg(args, 1);
    let y = raw_i32_arg(args, 2);
    let options = raw_arg(args, 3);
    let rect_ptr = raw_arg(args, 4);
    let text_ptr = raw_arg(args, 5);
    let count = raw_arg(args, 6);
    let dx_ptr = raw_arg(args, 7);
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    if count != 0 && text_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    let rect = if rect_ptr != 0 {
        let Some(rect) = read_guest_rect(kernel, memory, thread_id, rect_ptr) else {
            return false;
        };
        Some(rect)
    } else {
        None
    };
    if hdc_has_readonly_selected_bitmap(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    if options & ETO_OPAQUE != 0
        && let Some(rect) = rect
    {
        let color = kernel
            .resources
            .dc_state(hdc)
            .map(|state| state.bk_color)
            .unwrap_or(rgb(0xff, 0xff, 0xff));
        if !fill_bitmap_rect_for_hdc(kernel, memory, hdc, rect, BrushPaint::Solid(color))
            && let Some(fb) = framebuffer.as_deref_mut()
        {
            fill_framebuffer_rect_for_hdc(kernel, fb, hdc, rect, color);
        }
    }
    // Draw glyphs: window DCs → framebuffer; memory DCs → backing bitmap.
    if count > 0 && text_ptr != 0 {
        let clip = if options & ETO_CLIPPED != 0 {
            rect
        } else {
            None
        };

        // Apply SetTextAlign alignment to the drawing origin.
        let (draw_x, draw_y) =
            text_align_origin(kernel, memory, hdc, x, y, text_ptr, count, dx_ptr);

        if let Some(fb) = framebuffer.as_deref_mut() {
            draw_ext_text_glyphs_to_framebuffer(
                kernel, memory, fb, hdc, draw_x, draw_y, text_ptr, count, dx_ptr, clip,
            );
        } else if kernel.resources.is_memory_dc(hdc) {
            draw_ext_text_glyphs_to_bitmap(
                kernel, memory, hdc, draw_x, draw_y, text_ptr, count, dx_ptr, clip,
            );
        }

        // TA_UPDATECP: advance the DC's current position to the end of text.
        if let Some(state) = kernel.resources.dc_state(hdc) {
            if state.text_align & TA_UPDATECP != 0 {
                let total_w = measure_text_width(kernel, memory, hdc, text_ptr, count, dx_ptr);
                kernel.resources.move_to(
                    hdc,
                    crate::ce::gwe::Point {
                        x: draw_x + total_w,
                        y: draw_y,
                    },
                );
            }
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

// Compute the total pixel width of a text run using DC font metrics + optional dx array.
fn measure_text_width<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &M,
    hdc: u32,
    text_ptr: u32,
    count: u32,
    dx_ptr: u32,
) -> i32 {
    let state = kernel.resources.dc_state(hdc);
    let font = state
        .as_ref()
        .and_then(|state| kernel.resources.font(state.selected_font).cloned());
    let metrics = TextMetricsModel::from_font(font.as_ref());
    let cell_w = metrics.ave_width.max(1);
    let text_char_extra = state.map(|state| state.text_char_extra).unwrap_or(0);
    if dx_ptr != 0 {
        (0..count as usize)
            .map(|i| {
                (memory
                    .read_u32(dx_ptr.wrapping_add((i as u32) * 4))
                    .unwrap_or(cell_w as u32) as i32)
                    .saturating_add(text_char_extra)
            })
            .fold(0i32, |sum, advance| sum.saturating_add(advance))
    } else {
        let mut previous_char_width = 0;
        let mut total = 0i32;
        for index in 0..count {
            let unit = memory
                .read_u16(text_ptr.wrapping_add(index.saturating_mul(2)))
                .unwrap_or(0);
            let char_width = metrics.char_width(unit);
            total = total.saturating_add(text_advance_with_extra(
                char_width,
                previous_char_width,
                text_char_extra,
            ));
            previous_char_width = char_width;
        }
        total
    }
}

// Adjust the (x, y) drawing origin for the DC's current SetTextAlign flags.
// Handles TA_UPDATECP (use current pos), TA_CENTER/TA_RIGHT (shift x),
// TA_BASELINE/TA_BOTTOM (shift y).
fn text_align_origin<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &M,
    hdc: u32,
    x: i32,
    y: i32,
    text_ptr: u32,
    count: u32,
    dx_ptr: u32,
) -> (i32, i32) {
    let Some(state) = kernel.resources.dc_state(hdc) else {
        return (x, y);
    };
    let align = state.text_align;

    // Horizontal: TA_UPDATECP uses current pos; then TA_CENTER/TA_RIGHT shifts
    let (mut ox, mut oy) = if align & TA_UPDATECP != 0 {
        (state.current_pos.x, state.current_pos.y)
    } else {
        (x, y)
    };

    let horiz = align & TA_HORIZMASK;
    if horiz == TA_RIGHT || horiz == TA_CENTER {
        let total_w = measure_text_width(kernel, memory, hdc, text_ptr, count, dx_ptr);
        if horiz == TA_RIGHT {
            ox -= total_w;
        } else {
            ox -= total_w / 2;
        }
    }

    let font = kernel.resources.font(state.selected_font).cloned();
    let metrics = TextMetricsModel::from_font(font.as_ref());
    let vert = align & TA_VERTMASK;
    if vert == TA_BOTTOM {
        oy -= metrics.height;
    } else if vert == TA_BASELINE {
        oy -= metrics.ascent;
    }

    (ox, oy)
}

// Render ExtTextOutW glyphs to the framebuffer using the embedded 8×8 bitmap font.
// Handles window DCs only; memory DCs are skipped (no backing bitmap write yet).
fn draw_ext_text_glyphs_to_framebuffer<M: CoredllGuestMemory>(
    kernel: &CeKernel,
    memory: &M,
    fb: &mut dyn Framebuffer,
    hdc: u32,
    x: i32,
    y: i32,
    text_ptr: u32,
    count: u32,
    dx_ptr: u32,
    clip: Option<Rect>,
) {
    let state = kernel.resources.dc_state(hdc).unwrap_or_default();
    let text_color = state.text_color;
    let bk_mode = state.bk_mode;
    let bk_color = state.bk_color;
    let font = kernel.resources.font(state.selected_font).cloned();
    let metrics = TextMetricsModel::from_font(font.as_ref());
    let cell_h = metrics.height.max(1) as usize;
    let cell_w = metrics.ave_width.max(1);
    let text_char_extra = state.text_char_extra;
    let total_w = measure_text_width(kernel, memory, hdc, text_ptr, count, dx_ptr);
    let text_bounds = Rect {
        left: x,
        top: y,
        right: x.saturating_add(total_w),
        bottom: y.saturating_add(cell_h as i32),
    };
    let requested = if let Some(clip) = clip {
        let Some(rect) = intersect_rect_value(normalize_rect(text_bounds), normalize_rect(clip))
        else {
            return;
        };
        rect
    } else {
        normalize_rect(text_bounds)
    };
    let Some((origin, client_clips)) = hdc_framebuffer_client_clip_rects(kernel, hdc, requested)
    else {
        return;
    };
    let screen_clips: Vec<Rect> = client_clips
        .into_iter()
        .map(|clip| clip.offset(origin.x, origin.y))
        .collect();

    let info = fb.info();
    let stride = info.stride;
    let bpp = info.format.bytes_per_pixel();
    let pixel = pixel_bytes_for_colorref(info.format, text_color);
    let bk_pixel = pixel_bytes_for_colorref(info.format, bk_color);
    let fb_w = info.width as i32;
    let fb_h = info.height as i32;

    let screen_x0 = x + origin.x;
    let screen_y0 = y + origin.y;
    let mut cursor_x = screen_x0;
    let mut any_pixel = false;

    for char_idx in 0..count as usize {
        let unit = memory
            .read_u16(text_ptr.wrapping_add((char_idx as u32) * 2))
            .unwrap_or(0);

        let advance = if dx_ptr != 0 {
            (memory
                .read_u32(dx_ptr.wrapping_add((char_idx as u32) * 4))
                .unwrap_or(cell_w as u32) as i32)
                .saturating_add(text_char_extra)
        } else {
            let char_width = metrics.char_width(unit);
            let previous_char_width = if char_idx == 0 {
                0
            } else {
                let previous_unit = memory
                    .read_u16(text_ptr.wrapping_add(((char_idx - 1) as u32) * 2))
                    .unwrap_or(0);
                metrics.char_width(previous_unit)
            };
            text_advance_with_extra(char_width, previous_char_width, text_char_extra)
        };

        if bk_mode == BKMODE_OPAQUE && advance > 0 {
            let bg_left = cursor_x;
            let bg_right = cursor_x.saturating_add(advance);
            let bg_top = screen_y0;
            let bg_bottom = screen_y0.saturating_add(cell_h as i32);
            for sy in bg_top.max(0)..bg_bottom.min(fb_h) {
                for sx in bg_left.max(0)..bg_right.min(fb_w) {
                    if !clip_rects_contain_point(&screen_clips, sx, sy) {
                        continue;
                    }
                    let off = sy as usize * stride + sx as usize * bpp;
                    fb.pixels_mut()[off..off + bpp].copy_from_slice(&bk_pixel[..bpp]);
                    any_pixel = true;
                }
            }
        }

        // Look up 8×8 glyph; non-ASCII → blank (no glyph drawn)
        if unit >= 32 && unit < 128 {
            let glyph = FONT_8X8[(unit - 32) as usize];
            for glyph_row in 0..8usize {
                let row_byte = glyph[glyph_row];
                if row_byte == 0 {
                    continue;
                }
                // Map glyph row to screen rows via cell_h/8 scale
                let sy0 = screen_y0 + (glyph_row * cell_h / 8) as i32;
                let sy1 = screen_y0 + ((glyph_row + 1) * cell_h / 8) as i32;
                for sy in sy0..sy1 {
                    if sy < 0 || sy >= fb_h {
                        continue;
                    }
                    for glyph_col in 0..8usize {
                        if row_byte & (0x80u8 >> glyph_col) == 0 {
                            continue;
                        }
                        // Map glyph col to screen cols via cell_w/8 scale
                        let sx0 = cursor_x + (glyph_col as i32 * cell_w) / 8;
                        let sx1 = cursor_x + ((glyph_col as i32 + 1) * cell_w) / 8;
                        let sx1 = sx1.max(sx0 + 1); // always draw at least 1px
                        for sx in sx0..sx1 {
                            if sx < 0 || sx >= fb_w {
                                continue;
                            }
                            if !clip_rects_contain_point(&screen_clips, sx, sy) {
                                continue;
                            }
                            let off = sy as usize * stride + sx as usize * bpp;
                            fb.pixels_mut()[off..off + bpp].copy_from_slice(&pixel[..bpp]);
                            any_pixel = true;
                        }
                    }
                }
            }
        }

        cursor_x += advance;
    }

    if any_pixel {
        let sx = screen_x0.max(0).min(fb_w) as u32;
        let sy = screen_y0.max(0).min(fb_h) as u32;
        let ex = cursor_x.max(0).min(fb_w) as u32;
        let ey = (screen_y0 + cell_h as i32).max(0).min(fb_h) as u32;
        if ex > sx && ey > sy {
            fb.mark_dirty(FramebufferRect::new(sx, sy, ex - sx, ey - sy));
        }
    }
}

fn create_rect_rgn_raw(kernel: &mut CeKernel, left: i32, top: i32, right: i32, bottom: i32) -> u32 {
    kernel.resources.create_region(normalize_rect(Rect {
        left,
        top,
        right,
        bottom,
    }))
}

fn create_rect_rgn_indirect_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    rect_ptr: u32,
) -> u32 {
    let Some(rect) = read_guest_rect(kernel, memory, thread_id, rect_ptr) else {
        return 0;
    };
    kernel.resources.create_region(normalize_rect(rect))
}

fn set_rect_rgn_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    region: u32,
    left: i32,
    top: i32,
    right: i32,
    bottom: i32,
) -> bool {
    if !kernel.resources.set_region(
        region,
        normalize_rect(Rect {
            left,
            top,
            right,
            bottom,
        }),
    ) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return false;
    }
    kernel.threads.set_last_error(thread_id, 0);
    true
}

fn combine_rgn_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    dest: u32,
    src1: u32,
    src2: u32,
    mode: u32,
) -> u32 {
    if mode == RGN_OR && dest == src1 {
        let Some(rhs_rect) = kernel
            .resources
            .region(src2)
            .and_then(|region| (region.rects.len() == 1).then_some(region.rects[0]))
        else {
            if kernel.resources.region(src1).is_none() || kernel.resources.region(src2).is_none() {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_HANDLE);
                return 0;
            }
            return combine_rgn_raw_slow(kernel, thread_id, dest, src1, src2, mode);
        };
        if !kernel.resources.union_region_with_rect(dest, rhs_rect) {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return kernel
            .resources
            .region(dest)
            .map(region_status_object)
            .unwrap_or(ERROR_REGION);
    }
    combine_rgn_raw_slow(kernel, thread_id, dest, src1, src2, mode)
}

fn combine_rgn_raw_slow(
    kernel: &mut CeKernel,
    thread_id: u32,
    dest: u32,
    src1: u32,
    src2: u32,
    mode: u32,
) -> u32 {
    let Some(lhs) = kernel
        .resources
        .region(src1)
        .map(|region| region.rects.clone())
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let rhs = if mode == RGN_COPY {
        Vec::new()
    } else {
        let Some(rhs) = kernel
            .resources
            .region(src2)
            .map(|region| region.rects.clone())
        else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        };
        rhs
    };
    let combined = match mode {
        RGN_AND => intersect_region_rects(&lhs, &rhs),
        RGN_OR => union_region_rects(&lhs, &rhs),
        RGN_XOR => xor_region_rects(&lhs, &rhs),
        RGN_DIFF => diff_region_rects(&lhs, &rhs),
        RGN_COPY => lhs,
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_NOT_SUPPORTED);
            return ERROR_REGION;
        }
    };
    if !kernel.resources.set_region_rects(dest, combined) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .region(dest)
        .map(region_status_object)
        .unwrap_or(ERROR_REGION)
}

fn get_rgn_box_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    region: u32,
    rect_ptr: u32,
) -> u32 {
    let Some(rect) = kernel.resources.region(region).map(|region| region.rect) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    };
    if rect_ptr != 0 && !write_guest_rect(kernel, memory, thread_id, rect_ptr, rect) {
        return ERROR_REGION;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .region(region)
        .map(region_status_object)
        .unwrap_or(ERROR_REGION)
}

fn select_clip_rgn_raw(kernel: &mut CeKernel, thread_id: u32, hdc: u32, region: u32) -> u32 {
    if !is_valid_hdc(kernel, hdc) || (region != 0 && kernel.resources.region(region).is_none()) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    }
    kernel
        .resources
        .select_clip_region(hdc, (region != 0).then_some(region));
    kernel.threads.set_last_error(thread_id, 0);
    if region == 0 {
        SIMPLEREGION
    } else {
        region_status_object(kernel.resources.region(region).unwrap())
    }
}

fn intersect_clip_rect_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    hdc: u32,
    left: i32,
    top: i32,
    right: i32,
    bottom: i32,
) -> u32 {
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    let new_rect = Rect {
        left,
        top,
        right,
        bottom,
    };
    let new_rects = if is_rect_empty_value(new_rect) {
        Vec::new()
    } else {
        let existing = kernel
            .resources
            .clip_region(hdc)
            .map(|r| r.rects.clone())
            .unwrap_or_else(|| vec![hdc_base_clip_rect(kernel, hdc)]);
        intersect_region_rects(&existing, &[new_rect])
    };
    let status = region_status_from_rects(&new_rects);
    kernel.resources.select_clip_region_rects(hdc, new_rects);
    kernel.threads.set_last_error(thread_id, 0);
    status
}

fn exclude_clip_rect_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    hdc: u32,
    left: i32,
    top: i32,
    right: i32,
    bottom: i32,
) -> u32 {
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    let cut_rect = Rect {
        left,
        top,
        right,
        bottom,
    };
    let existing = kernel
        .resources
        .clip_region(hdc)
        .map(|region| region.rects.clone())
        .unwrap_or_else(|| vec![hdc_base_clip_rect(kernel, hdc)]);
    let new_rects = if is_rect_empty_value(cut_rect) {
        existing
    } else {
        diff_region_rects(&existing, &[cut_rect])
    };
    let status = region_status_from_rects(&new_rects);
    kernel.resources.select_clip_region_rects(hdc, new_rects);
    kernel.threads.set_last_error(thread_id, 0);
    status
}

fn hdc_base_clip_rect(kernel: &CeKernel, hdc: u32) -> Rect {
    if let Some(bitmap) = selected_bitmap_object(kernel, hdc) {
        return Rect::from_origin_size(0, 0, bitmap.width.max(0), bitmap.height.max(0));
    }
    hdc_to_hwnd(hdc)
        .and_then(|hwnd| kernel.gwe.get_client_rect(hwnd))
        .unwrap_or_else(|| Rect::from_origin_size(0, 0, 800, 480))
}

fn region_status_from_rects(rects: &[Rect]) -> u32 {
    match rects.len() {
        0 => NULLREGION,
        1 => SIMPLEREGION,
        _ => COMPLEXREGION,
    }
}

fn get_clip_box_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    hdc: u32,
    rect_ptr: u32,
) -> u32 {
    if !is_valid_hdc(kernel, hdc) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    if rect_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return ERROR_REGION;
    }
    let (rect, status) = if let Some(region) = kernel.resources.clip_region(hdc) {
        (region.rect, region_status_object(region))
    } else {
        let rect = hdc_to_hwnd(hdc)
            .and_then(|hwnd| kernel.gwe.get_client_rect(hwnd))
            .unwrap_or_else(|| Rect::from_origin_size(0, 0, 800, 480));
        (rect, region_status(rect))
    };
    if !write_guest_rect(kernel, memory, thread_id, rect_ptr, rect) {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    status
}

// GetRegionData(hrgn, dwCount, lpRgnData) — serialise region into RGNDATA buffer.
// RGNDATAHEADER (32 bytes): dwSize(4)+iType(4)+nCount(4)+nRgnSize(4)+rcBound(16)
// followed by nCount RECT structs (each 16 bytes).
fn get_region_data_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hrgn = raw_arg(args, 0);
    let buf_size = raw_arg(args, 1);
    let buf_ptr = raw_arg(args, 2);
    let Some(rgn) = kernel.resources.region(hrgn) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return 0;
    };
    let rects = rgn.rects.clone();
    let bound = rgn.rect;
    let n = rects.len() as u32;
    let rgn_size = n * 16;
    let total = 32 + rgn_size; // RGNDATAHEADER(32) + rects
    if buf_ptr == 0 || buf_size < total {
        kernel.threads.set_last_error(thread_id, 0);
        return total;
    }
    // Write RGNDATAHEADER.
    let _ = write_guest_u32(kernel, memory, thread_id, buf_ptr, 32); // dwSize
    let _ = write_guest_u32(kernel, memory, thread_id, buf_ptr + 4, 1); // iType = RDH_RECTANGLES
    let _ = write_guest_u32(kernel, memory, thread_id, buf_ptr + 8, n); // nCount
    let _ = write_guest_u32(kernel, memory, thread_id, buf_ptr + 12, rgn_size); // nRgnSize
    // rcBound
    let _ = write_guest_i32(kernel, memory, thread_id, buf_ptr + 16, bound.left);
    let _ = write_guest_i32(kernel, memory, thread_id, buf_ptr + 20, bound.top);
    let _ = write_guest_i32(kernel, memory, thread_id, buf_ptr + 24, bound.right);
    let _ = write_guest_i32(kernel, memory, thread_id, buf_ptr + 28, bound.bottom);
    // Write each RECT.
    for (i, r) in rects.iter().enumerate() {
        let base = buf_ptr + 32 + i as u32 * 16;
        let _ = write_guest_i32(kernel, memory, thread_id, base, r.left);
        let _ = write_guest_i32(kernel, memory, thread_id, base + 4, r.top);
        let _ = write_guest_i32(kernel, memory, thread_id, base + 8, r.right);
        let _ = write_guest_i32(kernel, memory, thread_id, base + 12, r.bottom);
    }
    kernel.threads.set_last_error(thread_id, 0);
    total
}

fn pt_in_region_raw(kernel: &CeKernel, region: u32, x: i32, y: i32) -> bool {
    kernel
        .resources
        .region(region)
        .is_some_and(|region| region.rects.iter().any(|rect| point_in_rect(*rect, x, y)))
}

fn rect_in_region_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    region: u32,
    rect_ptr: u32,
) -> bool {
    let Some(rect) = read_guest_rect(kernel, memory, thread_id, rect_ptr) else {
        return false;
    };
    kernel.resources.region(region).is_some_and(|region| {
        region
            .rects
            .iter()
            .any(|region_rect| rects_intersect(*region_rect, rect))
    })
}

fn set_window_rgn_raw(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    region: u32,
    redraw: bool,
) -> u32 {
    let rects = if region == 0 {
        None
    } else {
        let Some(region) = kernel.resources.region(region) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_HANDLE);
            return 0;
        };
        Some(region.rects.clone())
    };
    if !kernel.gwe.set_window_region_rects(hwnd, rects) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    if redraw && !kernel.gwe.invalidate_window(hwnd, None, true) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    1
}

fn get_window_rgn_raw(kernel: &mut CeKernel, thread_id: u32, hwnd: u32, region: u32) -> u32 {
    if region == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    let Some(rects) = kernel
        .gwe
        .window_region_rects(hwnd)
        .map(|rects| rects.to_vec())
    else {
        if kernel.gwe.is_window(hwnd) {
            kernel.threads.set_last_error(thread_id, 0);
            return NULLREGION;
        }
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return ERROR_REGION;
    };
    if !kernel.resources.set_region_rects(region, rects) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_HANDLE);
        return ERROR_REGION;
    }
    kernel.threads.set_last_error(thread_id, 0);
    kernel
        .resources
        .region(region)
        .map(region_status_object)
        .unwrap_or(ERROR_REGION)
}

fn paint_hdc_for_hwnd(hwnd: u32) -> u32 {
    0x0200_0000 | (hwnd & 0x00ff_ffff)
}

fn hdc_to_hwnd(hdc: u32) -> Option<u32> {
    (hdc & 0xff00_0000 == 0x0200_0000).then_some(hdc & 0x00ff_ffff)
}

fn is_valid_hdc(kernel: &CeKernel, hdc: u32) -> bool {
    if kernel.resources.is_memory_dc(hdc) {
        return true;
    }
    let Some(hwnd) = hdc_to_hwnd(hdc) else {
        return false;
    };
    hwnd == kernel.gwe.get_desktop_window() || kernel.gwe.is_window(hwnd)
}

fn normalize_rect(rect: Rect) -> Rect {
    Rect {
        left: rect.left.min(rect.right),
        top: rect.top.min(rect.bottom),
        right: rect.left.max(rect.right),
        bottom: rect.top.max(rect.bottom),
    }
}

fn union_rect_value(lhs: Rect, rhs: Rect) -> Rect {
    match (is_rect_empty_value(lhs), is_rect_empty_value(rhs)) {
        (true, true) => Rect::default(),
        (true, false) => rhs,
        (false, true) => lhs,
        (false, false) => Rect {
            left: lhs.left.min(rhs.left),
            top: lhs.top.min(rhs.top),
            right: lhs.right.max(rhs.right),
            bottom: lhs.bottom.max(rhs.bottom),
        },
    }
}

fn intersect_rect_value(lhs: Rect, rhs: Rect) -> Option<Rect> {
    let rect = Rect {
        left: lhs.left.max(rhs.left),
        top: lhs.top.max(rhs.top),
        right: lhs.right.min(rhs.right),
        bottom: lhs.bottom.min(rhs.bottom),
    };
    (!is_rect_empty_value(rect)).then_some(rect)
}

fn intersect_region_rects(lhs: &[Rect], rhs: &[Rect]) -> Vec<Rect> {
    let mut rects = Vec::new();
    for lhs_rect in lhs {
        for rhs_rect in rhs {
            if let Some(rect) = intersect_rect_value(*lhs_rect, *rhs_rect) {
                rects.push(rect);
            }
        }
    }
    rects
}

fn union_region_rects(lhs: &[Rect], rhs: &[Rect]) -> Vec<Rect> {
    lhs.iter()
        .chain(rhs.iter())
        .copied()
        .filter(|rect| !is_rect_empty_value(*rect))
        .collect()
}

fn diff_region_rects(lhs: &[Rect], rhs: &[Rect]) -> Vec<Rect> {
    let mut remaining: Vec<Rect> = lhs
        .iter()
        .copied()
        .filter(|rect| !is_rect_empty_value(*rect))
        .collect();
    for rhs_rect in rhs {
        let mut next = Vec::new();
        for rect in remaining {
            next.extend(subtract_rect(rect, *rhs_rect));
        }
        remaining = next;
        if remaining.is_empty() {
            break;
        }
    }
    remaining
}

fn xor_region_rects(lhs: &[Rect], rhs: &[Rect]) -> Vec<Rect> {
    let mut rects = diff_region_rects(lhs, rhs);
    rects.extend(diff_region_rects(rhs, lhs));
    rects
}

fn subtract_rect(rect: Rect, cut: Rect) -> Vec<Rect> {
    let Some(overlap) = intersect_rect_value(rect, cut) else {
        return vec![rect];
    };
    let candidates = [
        Rect {
            left: rect.left,
            top: rect.top,
            right: rect.right,
            bottom: overlap.top,
        },
        Rect {
            left: rect.left,
            top: overlap.bottom,
            right: rect.right,
            bottom: rect.bottom,
        },
        Rect {
            left: rect.left,
            top: overlap.top,
            right: overlap.left,
            bottom: overlap.bottom,
        },
        Rect {
            left: overlap.right,
            top: overlap.top,
            right: rect.right,
            bottom: overlap.bottom,
        },
    ];
    candidates
        .into_iter()
        .filter(|rect| !is_rect_empty_value(*rect))
        .collect()
}

fn region_status(rect: Rect) -> u32 {
    if is_rect_empty_value(rect) {
        NULLREGION
    } else {
        SIMPLEREGION
    }
}

fn region_status_object(region: &RegionObject) -> u32 {
    match region.rects.len() {
        0 => NULLREGION,
        1 => SIMPLEREGION,
        _ => COMPLEXREGION,
    }
}

fn point_in_rect(rect: Rect, x: i32, y: i32) -> bool {
    x >= rect.left && x < rect.right && y >= rect.top && y < rect.bottom
}

fn rects_intersect(lhs: Rect, rhs: Rect) -> bool {
    !is_rect_empty_value(lhs)
        && !is_rect_empty_value(rhs)
        && lhs.left < rhs.right
        && rhs.left < lhs.right
        && lhs.top < rhs.bottom
        && rhs.top < lhs.bottom
}

fn write_paint_struct<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    hdc: u32,
    update: crate::ce::gwe::PaintUpdate,
) -> bool {
    write_guest_u32(kernel, memory, thread_id, addr, hdc)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(4),
            u32::from(update.erase),
        )
        && write_guest_rect(kernel, memory, thread_id, addr.wrapping_add(8), update.rect)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(24), 0)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(28), 0)
        && (0..32).all(|offset| {
            write_guest_u8(kernel, memory, thread_id, addr.wrapping_add(32 + offset), 0)
        })
}

fn get_message_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let msg_ptr = raw_arg(args, 0);
    let hwnd = parse_get_message_hwnd_filter(raw_arg(args, 1));
    let min_msg = raw_arg(args, 2);
    let max_msg = raw_arg(args, 3);
    let Some(message) = kernel.get_message_w_filtered(thread_id, hwnd, min_msg, max_msg) else {
        return false;
    };
    if !write_guest_message(kernel, memory, thread_id, msg_ptr, &message) {
        return false;
    }
    message.msg != crate::ce::gwe::WM_QUIT
}

fn peek_message_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let msg_ptr = raw_arg(args, 0);
    let hwnd = parse_get_message_hwnd_filter(raw_arg(args, 1));
    let min_msg = raw_arg(args, 2);
    let max_msg = raw_arg(args, 3);
    let flags = PeekFlags::from_bits_truncate(raw_arg(args, 4));
    let Some(message) = kernel.peek_message_w_filtered(thread_id, hwnd, min_msg, max_msg, flags)
    else {
        return false;
    };
    write_guest_message(kernel, memory, thread_id, msg_ptr, &message)
}

/// Convert a GetMessageW/PeekMessageW hWnd argument to an hwnd filter:
/// - 0x0000_0000 (NULL): None → all messages for the calling thread
/// - 0xFFFF_FFFF (-1):   Some(0) → thread messages only (PostThreadMessage, hwnd==0)
/// - other non-zero:     Some(hwnd) → messages for that specific window
fn parse_get_message_hwnd_filter(hwnd_raw: u32) -> Option<u32> {
    match hwnd_raw {
        0 => None,
        0xFFFF_FFFF => Some(0),
        hwnd => Some(hwnd),
    }
}

fn dispatch_message_w_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    msg_ptr: u32,
) -> u32 {
    let Some(message) = read_guest_message(kernel, memory, thread_id, msg_ptr) else {
        return 0;
    };
    let (class_name, wndproc) = kernel
        .gwe
        .window(message.hwnd)
        .map(|window| (window.class_name.clone(), window.wndproc))
        .unwrap_or_default();
    tracing::debug!(
        target: "ce.gwe",
        thread_id,
        msg_ptr = format_args!("0x{msg_ptr:08x}"),
        hwnd = format_args!("0x{:08x}", message.hwnd),
        msg = format_args!("0x{:08x}", message.msg),
        wparam = format_args!("0x{:08x}", message.wparam),
        lparam = format_args!("0x{:08x}", message.lparam),
        class = class_name.as_str(),
        wndproc = format_args!("0x{wndproc:08x}"),
        "DispatchMessageW"
    );
    let send_id = kernel.gwe.active_sent_message_id(thread_id);
    let result = kernel.dispatch_message_w_for_thread(thread_id, message);
    if let Some(send_id) = send_id {
        write_completed_send_message_timeout_result(kernel, memory, thread_id, send_id);
    }
    result
}

fn destroy_window_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    framebuffer: Option<&mut dyn Framebuffer>,
    thread_id: u32,
    hwnd: u32,
) -> bool {
    // CE: post WM_PARENTNOTIFY(WM_DESTROY) to parent before destroying.
    let notify = kernel.gwe.window(hwnd).and_then(|w| {
        w.parent
            .filter(|_| w.ex_style & crate::ce::gwe::WS_EX_NOPARENTNOTIFY == 0)
            .map(|p| (p, w.id))
    });
    if let Some((parent_hwnd, child_id)) = notify {
        let wparam = (child_id << 16) | crate::ce::gwe::WM_DESTROY;
        kernel.post_message_w(parent_hwnd, crate::ce::gwe::WM_PARENTNOTIFY, wparam, hwnd);
    }
    let destroyed = kernel.destroy_window_with_framebuffer(hwnd, "DestroyWindow", framebuffer);
    if destroyed {
        write_completed_send_message_timeout_results(kernel, memory, thread_id);
    }
    destroyed
}

fn write_completed_send_message_timeout_results<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
) -> bool {
    let writes = kernel.gwe.completed_sent_message_result_writes();
    let mut ok = true;
    for (_, result_ptr, result) in writes {
        ok &= write_guest_u32(kernel, memory, thread_id, result_ptr, result);
    }
    ok
}

fn write_completed_send_message_timeout_result<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    send_id: u64,
) -> bool {
    let Some((result_ptr, result)) = kernel.gwe.sent_message(send_id).and_then(|sent| {
        sent.result_ptr
            .zip(sent.result)
            .filter(|_| sent.flags & crate::ce::gwe::SMF_RESULT_READY != 0)
    }) else {
        return true;
    };
    write_guest_u32(kernel, memory, thread_id, result_ptr, result)
}

fn send_message_timeout_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let hwnd = raw_arg(args, 0);
    let msg = raw_arg(args, 1);
    let wparam = raw_arg(args, 2);
    let lparam = raw_arg(args, 3);
    let flags = raw_arg(args, 4);
    let timeout_ms = raw_arg(args, 5);
    let result_ptr = raw_arg(args, 6);
    if flags & !SMTO_SUPPORTED_CE_FLAGS != 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_FLAGS_LOCAL);
        return 0;
    }
    let Some(target_thread) = kernel
        .gwe
        .window(hwnd)
        .filter(|window| !window.destroyed)
        .map(|window| window.thread_id)
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    };
    if target_thread != thread_id {
        const CE_HUNG_THRESHOLD_MS: u32 = 5000;
        if flags & SMTO_ABORTIFHUNG != 0
            && kernel.gwe.is_thread_hung(
                target_thread,
                kernel.timers.tick_count(),
                CE_HUNG_THRESHOLD_MS,
            )
        {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_TIMEOUT_LOCAL);
            return 0;
        }
        let Some(send_id) = kernel.begin_cross_thread_send_message_w(
            thread_id,
            hwnd,
            msg,
            wparam,
            lparam,
            Some(timeout_ms),
        ) else {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
            return 0;
        };
        kernel.gwe.set_sent_message_result_ptr(send_id, result_ptr);
        kernel.gwe.set_sent_message_timeout_flags(send_id, flags);
        if timeout_ms == 0 {
            let expired = kernel.expire_timed_out_send_messages();
            if expired.contains(&send_id) {
                let _ = kernel.take_completed_send_message_result(send_id);
            }
        }
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }
    let Some(result) = kernel.send_message_w(hwnd, msg, wparam, lparam) else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return 0;
    };
    if result_ptr != 0 && !write_guest_u32(kernel, memory, thread_id, result_ptr, result) {
        return 0;
    }
    kernel.threads.set_last_error(thread_id, 0);
    result
}

#[derive(Debug, Clone)]
#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
pub(crate) struct SendMessageTimeoutBlockState {
    pub send_id: u64,
    pub result_ptr: u32,
    pub timeout_ms: u32,
    pub start_ms: u32,
}

/// Called by Unicorn to set up a cross-thread SendMessageTimeout send and
/// return the tracking state.  Returns `None` if the call doesn't meet the
/// blocking criteria (same-thread, invalid flags, hung-abort, zero timeout).
/// Covers both SMTO_BLOCK and SMTO_NORMAL cross-thread sends — the caller parks the
/// Unicorn thread and polls
/// `kernel.gwe.sent_message_result_ready(state.send_id)` on each re-entry.
#[cfg_attr(not(feature = "unicorn"), allow(dead_code))]
pub(crate) fn send_message_timeout_block_prepare(
    kernel: &mut CeKernel,
    thread_id: u32,
    args: &[u32],
) -> Option<SendMessageTimeoutBlockState> {
    let hwnd = raw_arg(args, 0);
    let msg = raw_arg(args, 1);
    let wparam = raw_arg(args, 2);
    let lparam = raw_arg(args, 3);
    let flags = raw_arg(args, 4);
    let timeout_ms = raw_arg(args, 5);
    let result_ptr = raw_arg(args, 6);
    if timeout_ms == 0 {
        return None;
    }
    if flags & !SMTO_SUPPORTED_CE_FLAGS != 0 {
        return None;
    }
    let target_thread = kernel
        .gwe
        .window(hwnd)
        .filter(|w| !w.destroyed)
        .map(|w| w.thread_id)?;
    if target_thread == thread_id {
        return None;
    }
    const CE_HUNG_THRESHOLD_MS: u32 = 5000;
    if flags & SMTO_ABORTIFHUNG != 0
        && kernel.gwe.is_thread_hung(
            target_thread,
            kernel.timers.tick_count(),
            CE_HUNG_THRESHOLD_MS,
        )
    {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_TIMEOUT_LOCAL);
        return None;
    }
    let send_id = kernel.begin_cross_thread_send_message_w(
        thread_id,
        hwnd,
        msg,
        wparam,
        lparam,
        Some(timeout_ms),
    )?;
    kernel.gwe.set_sent_message_result_ptr(send_id, result_ptr);
    kernel.gwe.set_sent_message_timeout_flags(send_id, flags);
    let start_ms = kernel.timers.tick_count();
    Some(SendMessageTimeoutBlockState {
        send_id,
        result_ptr,
        timeout_ms,
        start_ms,
    })
}

fn translate_message_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    msg_ptr: u32,
) -> bool {
    let Some(message) = read_guest_message(kernel, memory, thread_id, msg_ptr) else {
        return false;
    };
    if !matches!(
        message.msg,
        crate::ce::gwe::WM_KEYDOWN | crate::ce::gwe::WM_SYSKEYDOWN
    ) || message.hwnd == 0
    {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }
    // VK_HANGUL (0x15): toggle IME open status, commit any pending composition,
    // and post IMN_SETOPENSTATUS.
    if message.wparam == crate::ce::gwe::VK_HANGUL && message.msg == crate::ce::gwe::WM_KEYDOWN {
        if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
            // Commit any active composition before toggling.
            if kernel.gwe.hangul_composition_active(himc) {
                if let Some((hwnd, actions)) = kernel.gwe.commit_hangul_ime(himc) {
                    deliver_hangul_ime_actions(kernel, thread_id, hwnd, message.lparam, &actions);
                }
            }
            let currently_open = kernel.gwe.ime_context(himc).is_some_and(|c| c.open);
            kernel.gwe.set_ime_open_status(himc, !currently_open);
            let hwnd = kernel
                .gwe
                .ime_context(himc)
                .and_then(|c| c.hwnd)
                .unwrap_or(0);
            if hwnd != 0 {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_NOTIFY,
                    crate::ce::gwe::IMN_SETOPENSTATUS,
                    0,
                );
            }
        }
        kernel.threads.set_last_error(thread_id, 0);
        return true;
    }

    // Korean IME composition path: WM_KEYDOWN when the Korean keyboard layout
    // (0x0412) is active and the window's IME context is open.
    if message.msg == crate::ce::gwe::WM_KEYDOWN
        && kernel.gwe.keyboard_layout() == 0x0412
        && kernel.gwe.is_ime_open_for_window(message.hwnd)
    {
        let shift = kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0;
        let vk = message.wparam;

        // VK_BACK (0x08): undo the last Jamo in the composition.
        if vk == 0x08 {
            if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
                if kernel.gwe.hangul_composition_active(himc) {
                    if let Some((hwnd, actions)) = kernel.gwe.backspace_hangul_ime(himc) {
                        deliver_hangul_ime_actions(
                            kernel,
                            thread_id,
                            hwnd,
                            message.lparam,
                            &actions,
                        );
                    }
                    kernel.threads.set_last_error(thread_id, 0);
                    return true;
                }
            }
            // No active composition — fall through to post WM_CHAR(BS) normally.
        }

        // Commit-and-pass-through keys: Tab, Return, Escape.
        if matches!(vk, 0x09 | 0x0d | 0x1b) {
            if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
                if kernel.gwe.hangul_composition_active(himc) {
                    if let Some((hwnd, actions)) = kernel.gwe.commit_hangul_ime(himc) {
                        deliver_hangul_ime_actions(
                            kernel,
                            thread_id,
                            hwnd,
                            message.lparam,
                            &actions,
                        );
                    }
                }
            }
            // Fall through: still post WM_CHAR for the key.
        }

        // Try to map the VK to a Hangul Jamo.
        if let Some(jamo) = crate::ce::hangul::vk_to_hangul_jamo(vk, shift) {
            if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
                if let Some((hwnd, actions)) = kernel.gwe.process_hangul_ime_jamo(himc, jamo) {
                    deliver_hangul_ime_actions(kernel, thread_id, hwnd, message.lparam, &actions);
                }
            }
            kernel.threads.set_last_error(thread_id, 0);
            return true; // key consumed by IME
        }

        // Non-Jamo key while IME is open: commit any pending composition, then
        // fall through to normal WM_CHAR translation for non-Hangul characters.
        if let Some(himc) = kernel.gwe.get_ime_context(message.hwnd) {
            if kernel.gwe.hangul_composition_active(himc) {
                if let Some((hwnd, actions)) = kernel.gwe.commit_hangul_ime(himc) {
                    deliver_hangul_ime_actions(kernel, thread_id, hwnd, message.lparam, &actions);
                }
            }
        }
        // Fall through to normal character translation below.
    }

    // Western European layout dead-key state machine.
    // Active for layouts 0x040C (French), 0x0407 (German), 0x040A/0x0C0A (Spanish).
    let layout = kernel.gwe.keyboard_layout();
    let layout_lang = layout & 0xFFFF;
    let is_western_layout = matches!(layout_lang, 0x040C | 0x0407 | 0x040A | 0x0C0A);

    if is_western_layout && message.msg == crate::ce::gwe::WM_KEYDOWN {
        let ctrl = kernel.gwe.get_key_state(crate::ce::gwe::VK_CONTROL) & 0x8000_0000 != 0;
        let alt = kernel.gwe.get_key_state(crate::ce::gwe::VK_MENU) & 0x8000_0000 != 0;
        // Pure Ctrl (without Alt): bypass Western layout; fall through to control-key translation.
        if ctrl && !alt {
            // intentional fall-through to translate_virtual_key_to_char below
        } else {
            let shift = kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0;
            let caps = kernel.gwe.get_key_state(crate::ce::gwe::VK_CAPITAL) & 0x0001 != 0;
            // AltGr (Ctrl+Alt): use the AltGr variant of the layout table, falling back
            // to the normal layout table if there is no AltGr mapping for this VK.
            let (ch, is_dead) = if ctrl && alt {
                translate_vk_for_western_layout_altgr(layout, message.wparam).map_or_else(
                    || translate_vk_for_western_layout(layout, message.wparam, shift, caps),
                    |c| (c, false),
                )
            } else {
                translate_vk_for_western_layout(layout, message.wparam, shift, caps)
            };

            if let Some(pending_dead) = kernel.gwe.take_dead_key() {
                if ch != 0 {
                    // Attempt to compose dead + base. If current key is a dead key itself,
                    // first emit the pending dead char literally, then record the new dead key.
                    if is_dead {
                        // Pending dead + new dead key: emit pending dead as literal WM_CHAR,
                        // then store the new dead key.
                        let _ = kernel.post_message_w_for_thread(
                            thread_id,
                            message.hwnd,
                            crate::ce::gwe::WM_CHAR,
                            pending_dead,
                            message.lparam,
                        );
                        kernel.gwe.set_dead_key(ch);
                        let _ = kernel.post_message_w_for_thread(
                            thread_id,
                            message.hwnd,
                            crate::ce::gwe::WM_DEADCHAR,
                            ch,
                            message.lparam,
                        );
                    } else if let Some(composed) = compose_dead_key(pending_dead, ch) {
                        // Composed form: emit single WM_CHAR with the combined character.
                        let _ = kernel.post_message_w_for_thread(
                            thread_id,
                            message.hwnd,
                            crate::ce::gwe::WM_CHAR,
                            composed,
                            message.lparam,
                        );
                    } else {
                        // No composed form: emit dead char literally, then the base char.
                        let _ = kernel.post_message_w_for_thread(
                            thread_id,
                            message.hwnd,
                            crate::ce::gwe::WM_CHAR,
                            pending_dead,
                            message.lparam,
                        );
                        let _ = kernel.post_message_w_for_thread(
                            thread_id,
                            message.hwnd,
                            crate::ce::gwe::WM_CHAR,
                            ch,
                            message.lparam,
                        );
                    }
                    kernel.threads.set_last_error(thread_id, 0);
                    return true;
                }
                // ch == 0 (non-character key): restore the pending dead key untouched.
                kernel.gwe.set_dead_key(pending_dead);
            } else if is_dead && ch != 0 {
                // No pending dead key, current key is a dead key: store it and post WM_DEADCHAR.
                kernel.gwe.set_dead_key(ch);
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    message.hwnd,
                    crate::ce::gwe::WM_DEADCHAR,
                    ch,
                    message.lparam,
                );
                kernel.threads.set_last_error(thread_id, 0);
                return true;
            } else if ch != 0 {
                // Normal character in a Western layout — emit it and we're done.
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    message.hwnd,
                    crate::ce::gwe::WM_CHAR,
                    ch,
                    message.lparam,
                );
                kernel.threads.set_last_error(thread_id, 0);
                return true;
            }
            // ch == 0 from western table: fall through to standard US translation.
        } // end `else` for non-pure-Ctrl branch
    }

    // WM_SYSKEYDOWN on a Western layout: translate VK→char using the layout table
    // (no dead-key state machine for Alt+key sequences) and post WM_SYSCHAR.
    if is_western_layout && message.msg == crate::ce::gwe::WM_SYSKEYDOWN {
        let shift = kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0;
        let caps = kernel.gwe.get_key_state(crate::ce::gwe::VK_CAPITAL) & 0x0001 != 0;
        let (ch, _is_dead) = translate_vk_for_western_layout(layout, message.wparam, shift, caps);
        if ch != 0 {
            let _ = kernel.post_message_w_for_thread(
                thread_id,
                message.hwnd,
                crate::ce::gwe::WM_SYSCHAR,
                ch,
                message.lparam,
            );
            kernel.threads.set_last_error(thread_id, 0);
            return true;
        }
        // ch == 0 from western table: fall through to standard US translation.
    }

    let char_code = translate_virtual_key_to_char(kernel, message.wparam);
    if char_code == 0 {
        kernel.threads.set_last_error(thread_id, 0);
        return false;
    }
    let translated_msg = if message.msg == crate::ce::gwe::WM_SYSKEYDOWN {
        crate::ce::gwe::WM_SYSCHAR
    } else {
        crate::ce::gwe::WM_CHAR
    };
    let posted = kernel.post_message_w_for_thread(
        thread_id,
        message.hwnd,
        translated_msg,
        char_code,
        message.lparam,
    );
    kernel.threads.set_last_error(thread_id, 0);
    posted
}

/// Post WM_IME_* messages corresponding to a slice of Hangul IME actions.
fn deliver_hangul_ime_actions(
    kernel: &mut CeKernel,
    thread_id: u32,
    hwnd: u32,
    key_lparam: u32,
    actions: &[crate::ce::hangul::HangulImeAction],
) {
    use crate::ce::hangul::HangulImeAction;
    for action in actions {
        match *action {
            HangulImeAction::StartComposition => {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_STARTCOMPOSITION,
                    0,
                    0,
                );
            }
            HangulImeAction::UpdateComposition(ch) => {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_COMPOSITION,
                    u32::from(ch),
                    crate::ce::gwe::GCS_COMPSTR,
                );
            }
            HangulImeAction::CommitChar(ch) => {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_CHAR,
                    u32::from(ch),
                    key_lparam,
                );
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_ENDCOMPOSITION,
                    0,
                    0,
                );
            }
            HangulImeAction::EndCompositionOnly => {
                let _ = kernel.post_message_w_for_thread(
                    thread_id,
                    hwnd,
                    crate::ce::gwe::WM_IME_ENDCOMPOSITION,
                    0,
                    0,
                );
            }
        }
    }
}

fn keybd_vkey_to_unicode_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let vk = raw_arg(args, 0) & 0xff;
    // arg 1: scan code (unused for translation)
    let key_state_ptr = raw_arg(args, 2); // 256-byte key state array
    let buf_ptr = raw_arg(args, 3);
    let buf_size = raw_arg(args, 4) as usize; // in WCHARs
    let flags_ptr = raw_arg(args, 5);

    if buf_ptr == 0 || buf_size == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return 0_u32.wrapping_neg();
    }

    // Read key state from the provided pKeyState buffer if available,
    // otherwise fall back to the emulator's current key state.
    let (shift, control, caps) = if key_state_ptr != 0 {
        let shift = read_guest_bytes(
            kernel,
            memory,
            thread_id,
            key_state_ptr + crate::ce::gwe::VK_SHIFT,
            1,
        )
        .and_then(|b| b.into_iter().next())
        .map(|b| b & 0x80 != 0)
        .unwrap_or(false);
        let ctrl = read_guest_bytes(
            kernel,
            memory,
            thread_id,
            key_state_ptr + crate::ce::gwe::VK_CONTROL,
            1,
        )
        .and_then(|b| b.into_iter().next())
        .map(|b| b & 0x80 != 0)
        .unwrap_or(false);
        let caps = read_guest_bytes(
            kernel,
            memory,
            thread_id,
            key_state_ptr + crate::ce::gwe::VK_CAPITAL,
            1,
        )
        .and_then(|b| b.into_iter().next())
        .map(|b| b & 0x01 != 0)
        .unwrap_or(false);
        (shift, ctrl, caps)
    } else {
        (
            kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0,
            kernel.gwe.get_key_state(crate::ce::gwe::VK_CONTROL) & 0x8000_0000 != 0,
            kernel.gwe.get_key_state(crate::ce::gwe::VK_CAPITAL) & 0x0001 != 0,
        )
    };

    // For Western European layouts, use the layout-specific table so OEM keys
    // produce the correct characters (e.g. VK_OEM_4 → '^' on AZERTY, '[' on US).
    let layout = kernel.gwe.keyboard_layout();
    let layout_lang = layout & 0xFFFF;
    let is_western_layout = matches!(layout_lang, 0x040C | 0x0407 | 0x040A | 0x0C0A);

    let (char_code, is_dead) = if control {
        (translate_control_key(vk), false)
    } else if is_western_layout {
        let (ch, dead) = translate_vk_for_western_layout(layout, vk, shift, caps);
        if ch != 0 {
            (ch, dead)
        } else {
            // Fall back to US table for any VK not covered by the western table.
            (
                translate_virtual_key_to_char_with_state(vk, shift, caps),
                false,
            )
        }
    } else {
        (
            translate_virtual_key_to_char_with_state(vk, shift, caps),
            false,
        )
    };

    if char_code == 0 {
        // Key produces no character.
        if flags_ptr != 0 {
            let _ = write_guest_u32(kernel, memory, thread_id, flags_ptr, 0);
        }
        kernel.threads.set_last_error(thread_id, 0);
        return 0;
    }

    // Write the Unicode character (WCHAR) to the output buffer.
    // Dead-key chars are returned as a single WCHAR; callers that need to
    // distinguish can inspect the flags word (non-zero → dead key).
    let wchar = char_code as u16;
    if !write_guest_u16(kernel, memory, thread_id, buf_ptr, wchar) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INSUFFICIENT_BUFFER);
        return 0_u32.wrapping_neg();
    }
    if flags_ptr != 0 {
        // Bit 0 set → dead key character (CE keyboard PDD convention).
        let flags_val: u32 = if is_dead { 1 } else { 0 };
        let _ = write_guest_u32(kernel, memory, thread_id, flags_ptr, flags_val);
    }
    kernel.threads.set_last_error(thread_id, 0);
    1 // one character written
}

fn translate_virtual_key_to_char_with_state(vkey: u32, shift: bool, caps: bool) -> u32 {
    match vkey {
        0x08 | 0x09 | 0x0d | 0x1b => vkey,
        0x30..=0x39 => translate_digit_key(vkey, shift),
        0x41..=0x5a => {
            if shift ^ caps {
                vkey
            } else {
                vkey + 0x20
            }
        }
        0x60..=0x69 => vkey - 0x60 + u32::from(b'0'),
        0x6a => u32::from(b'*'),
        0x6b => u32::from(b'+'),
        0x6d => u32::from(b'-'),
        0x6e => u32::from(b'.'),
        0x6f => u32::from(b'/'),
        0x6c | 0x70..=0x87 => 0,
        0x20 => 0x20,
        0xba => translate_pair_key(b';', b':', shift),
        0xbb => translate_pair_key(b'=', b'+', shift),
        0xbc => translate_pair_key(b',', b'<', shift),
        0xbd => translate_pair_key(b'-', b'_', shift),
        0xbe => translate_pair_key(b'.', b'>', shift),
        0xbf => translate_pair_key(b'/', b'?', shift),
        0xc0 => translate_pair_key(b'`', b'~', shift),
        0xdb => translate_pair_key(b'[', b'{', shift),
        0xdc => translate_pair_key(b'\\', b'|', shift),
        0xdd => translate_pair_key(b']', b'}', shift),
        0xde => translate_pair_key(b'\'', b'"', shift),
        0xe2 => translate_pair_key(b'\\', b'|', shift),
        _ => 0,
    }
}

fn map_virtual_key_w_raw(kernel: &CeKernel, code: u32, map_type: u32) -> u32 {
    const MAPVK_VK_TO_VSC: u32 = 0;
    const MAPVK_VSC_TO_VK: u32 = 1;
    const MAPVK_VK_TO_CHAR: u32 = 2;
    const MAPVK_VSC_TO_VK_EX: u32 = 3;
    match map_type {
        MAPVK_VK_TO_CHAR => vkey_to_unshifted_char_for_layout(kernel, code),
        MAPVK_VK_TO_VSC => vkey_to_scan_code(code),
        MAPVK_VSC_TO_VK | MAPVK_VSC_TO_VK_EX => {
            scan_code_to_vkey(code, map_type == MAPVK_VSC_TO_VK_EX)
        }
        _ => 0,
    }
}

fn vkey_to_unshifted_char_for_layout(kernel: &CeKernel, vkey: u32) -> u32 {
    let layout = kernel.gwe.keyboard_layout();
    let layout_lang = layout & 0xFFFF;
    if matches!(layout_lang, 0x040C | 0x0407 | 0x040A | 0x0C0A) {
        let (ch, is_dead) = translate_vk_for_western_layout(layout, vkey, false, false);
        if ch != 0 {
            // Bit 31 set when the key is a dead-key character (CE/Windows convention).
            return if is_dead { ch | 0x8000_0000 } else { ch };
        }
    }
    vkey_to_unshifted_char(vkey)
}

fn vkey_to_unshifted_char(vkey: u32) -> u32 {
    match vkey {
        0x08 | 0x09 | 0x0d | 0x1b => vkey,
        0x20 => 0x20,
        0x30..=0x39 => vkey,                          // digits '0'..'9'
        0x41..=0x5a => vkey | 0x20,                   // lowercase letters 'a'..'z'
        0x60..=0x69 => vkey - 0x60 + u32::from(b'0'), // numpad 0-9
        0x6a => u32::from(b'*'),
        0x6b => u32::from(b'+'),
        0x6d => u32::from(b'-'),
        0x6e => u32::from(b'.'),
        0x6f => u32::from(b'/'),
        0xba => u32::from(b';'),
        0xbb => u32::from(b'='),
        0xbc => u32::from(b','),
        0xbd => u32::from(b'-'),
        0xbe => u32::from(b'.'),
        0xbf => u32::from(b'/'),
        0xc0 => u32::from(b'`'),
        0xdb => u32::from(b'['),
        0xdc => u32::from(b'\\'),
        0xdd => u32::from(b']'),
        0xde => u32::from(b'\''),
        0xe2 => u32::from(b'\\'),
        _ => 0,
    }
}

fn vkey_to_scan_code(vkey: u32) -> u32 {
    match vkey {
        0x08 => 0x0e, // Backspace
        0x09 => 0x0f, // Tab
        0x0d => 0x1c, // Return
        0x1b => 0x01, // Escape
        0x20 => 0x39, // Space
        0x21 => 0x49, // Page Up (extended)
        0x22 => 0x51, // Page Down (extended)
        0x23 => 0x4f, // End (extended)
        0x24 => 0x47, // Home (extended)
        0x25 => 0x4b, // Left (extended)
        0x26 => 0x48, // Up (extended)
        0x27 => 0x4d, // Right (extended)
        0x28 => 0x50, // Down (extended)
        0x2d => 0x52, // Insert (extended)
        0x2e => 0x53, // Delete (extended)
        0x30 => 0x0b, // '0'
        0x31 => 0x02, // '1'
        0x32 => 0x03, // '2'
        0x33 => 0x04, // '3'
        0x34 => 0x05, // '4'
        0x35 => 0x06, // '5'
        0x36 => 0x07, // '6'
        0x37 => 0x08, // '7'
        0x38 => 0x09, // '8'
        0x39 => 0x0a, // '9'
        0x41 => 0x1e, // A
        0x42 => 0x30, // B
        0x43 => 0x2e, // C
        0x44 => 0x20, // D
        0x45 => 0x12, // E
        0x46 => 0x21, // F
        0x47 => 0x22, // G
        0x48 => 0x23, // H
        0x49 => 0x17, // I
        0x4a => 0x24, // J
        0x4b => 0x25, // K
        0x4c => 0x26, // L
        0x4d => 0x32, // M
        0x4e => 0x31, // N
        0x4f => 0x18, // O
        0x50 => 0x19, // P
        0x51 => 0x10, // Q
        0x52 => 0x13, // R
        0x53 => 0x1f, // S
        0x54 => 0x14, // T
        0x55 => 0x16, // U
        0x56 => 0x2f, // V
        0x57 => 0x11, // W
        0x58 => 0x2d, // X
        0x59 => 0x15, // Y
        0x5a => 0x2c, // Z
        0x60 => 0x52, // Numpad 0
        0x61 => 0x4f, // Numpad 1
        0x62 => 0x50, // Numpad 2
        0x63 => 0x51, // Numpad 3
        0x64 => 0x4b, // Numpad 4
        0x65 => 0x4c, // Numpad 5
        0x66 => 0x4d, // Numpad 6
        0x67 => 0x47, // Numpad 7
        0x68 => 0x48, // Numpad 8
        0x69 => 0x49, // Numpad 9
        0x6a => 0x37, // Numpad *
        0x6b => 0x4e, // Numpad +
        0x6d => 0x4a, // Numpad -
        0x6e => 0x53, // Numpad .
        0x70 => 0x3b, // F1
        0x71 => 0x3c, // F2
        0x72 => 0x3d, // F3
        0x73 => 0x3e, // F4
        0x74 => 0x3f, // F5
        0x75 => 0x40, // F6
        0x76 => 0x41, // F7
        0x77 => 0x42, // F8
        0x78 => 0x43, // F9
        0x79 => 0x44, // F10
        0x7a => 0x57, // F11
        0x7b => 0x58, // F12
        0x90 => 0x45, // NumLock
        0x91 => 0x46, // ScrollLock
        0xa0 => 0x2a, // LShift
        0xa1 => 0x36, // RShift
        0xa2 => 0x1d, // LControl
        0xa3 => 0x1d, // RControl (same scan as LControl without extended)
        0xa4 => 0x38, // LAlt
        0xa5 => 0x38, // RAlt (same scan as LAlt without extended)
        0xba => 0x27, // ;
        0xbb => 0x0d, // =
        0xbc => 0x33, // ,
        0xbd => 0x0c, // -
        0xbe => 0x34, // .
        0xbf => 0x35, // /
        0xc0 => 0x29, // `
        0xdb => 0x1a, // [
        0xdc => 0x2b, // backslash
        0xdd => 0x1b, // ]
        0xde => 0x28, // '
        _ => 0,
    }
}

fn scan_code_to_vkey(scan: u32, extended: bool) -> u32 {
    // Standard PC AT scan code set 1 to VK mapping.
    // Extended prefix (0xe0) distinguishes some keys when extended=true.
    match (scan & 0x7f, extended) {
        (0x01, _) => 0x1b,     // Escape
        (0x02, _) => 0x31,     // '1'
        (0x03, _) => 0x32,     // '2'
        (0x04, _) => 0x33,     // '3'
        (0x05, _) => 0x34,     // '4'
        (0x06, _) => 0x35,     // '5'
        (0x07, _) => 0x36,     // '6'
        (0x08, _) => 0x37,     // '7'
        (0x09, _) => 0x38,     // '8'
        (0x0a, _) => 0x39,     // '9'
        (0x0b, _) => 0x30,     // '0'
        (0x0c, _) => 0xbd,     // -
        (0x0d, _) => 0xbb,     // =
        (0x0e, _) => 0x08,     // Backspace
        (0x0f, _) => 0x09,     // Tab
        (0x10, _) => 0x51,     // Q
        (0x11, _) => 0x57,     // W
        (0x12, _) => 0x45,     // E
        (0x13, _) => 0x52,     // R
        (0x14, _) => 0x54,     // T
        (0x15, _) => 0x59,     // Y
        (0x16, _) => 0x55,     // U
        (0x17, _) => 0x49,     // I
        (0x18, _) => 0x4f,     // O
        (0x19, _) => 0x50,     // P
        (0x1a, _) => 0xdb,     // [
        (0x1b, _) => 0xdd,     // ]
        (0x1c, false) => 0x0d, // Return
        (0x1c, true) => 0x0d,  // Numpad Enter (same VK)
        (0x1d, false) => 0xa2, // LControl
        (0x1d, true) => 0xa3,  // RControl
        (0x1e, _) => 0x41,     // A
        (0x1f, _) => 0x53,     // S
        (0x20, _) => 0x44,     // D
        (0x21, _) => 0x46,     // F
        (0x22, _) => 0x47,     // G
        (0x23, _) => 0x48,     // H
        (0x24, _) => 0x4a,     // J
        (0x25, _) => 0x4b,     // K
        (0x26, _) => 0x4c,     // L
        (0x27, _) => 0xba,     // ;
        (0x28, _) => 0xde,     // '
        (0x29, _) => 0xc0,     // `
        (0x2a, _) => 0xa0,     // LShift
        (0x2b, _) => 0xdc,     // backslash
        (0x2c, _) => 0x5a,     // Z
        (0x2d, _) => 0x58,     // X
        (0x2e, _) => 0x43,     // C
        (0x2f, _) => 0x56,     // V
        (0x30, _) => 0x42,     // B
        (0x31, _) => 0x4e,     // N
        (0x32, _) => 0x4d,     // M
        (0x33, _) => 0xbc,     // ,
        (0x34, _) => 0xbe,     // .
        (0x35, false) => 0xbf, // /
        (0x35, true) => 0x6f,  // Numpad /
        (0x36, _) => 0xa1,     // RShift
        (0x37, _) => 0x6a,     // Numpad *
        (0x38, false) => 0xa4, // LAlt
        (0x38, true) => 0xa5,  // RAlt
        (0x39, _) => 0x20,     // Space
        (0x3b, _) => 0x70,     // F1
        (0x3c, _) => 0x71,     // F2
        (0x3d, _) => 0x72,     // F3
        (0x3e, _) => 0x73,     // F4
        (0x3f, _) => 0x74,     // F5
        (0x40, _) => 0x75,     // F6
        (0x41, _) => 0x76,     // F7
        (0x42, _) => 0x77,     // F8
        (0x43, _) => 0x78,     // F9
        (0x44, _) => 0x79,     // F10
        (0x45, _) => 0x90,     // NumLock
        (0x46, _) => 0x91,     // ScrollLock
        (0x47, false) => 0x67, // Numpad 7
        (0x47, true) => 0x24,  // Home
        (0x48, false) => 0x68, // Numpad 8
        (0x48, true) => 0x26,  // Up
        (0x49, false) => 0x69, // Numpad 9
        (0x49, true) => 0x21,  // PageUp
        (0x4a, _) => 0x6d,     // Numpad -
        (0x4b, false) => 0x64, // Numpad 4
        (0x4b, true) => 0x25,  // Left
        (0x4c, _) => 0x65,     // Numpad 5
        (0x4d, false) => 0x66, // Numpad 6
        (0x4d, true) => 0x27,  // Right
        (0x4e, _) => 0x6b,     // Numpad +
        (0x4f, false) => 0x61, // Numpad 1
        (0x4f, true) => 0x23,  // End
        (0x50, false) => 0x62, // Numpad 2
        (0x50, true) => 0x28,  // Down
        (0x51, false) => 0x63, // Numpad 3
        (0x51, true) => 0x22,  // PageDown
        (0x52, false) => 0x60, // Numpad 0
        (0x52, true) => 0x2d,  // Insert
        (0x53, false) => 0x6e, // Numpad .
        (0x53, true) => 0x2e,  // Delete
        (0x57, _) => 0x7a,     // F11
        (0x58, _) => 0x7b,     // F12
        _ => 0,
    }
}

fn translate_virtual_key_to_char(kernel: &CeKernel, vkey: u32) -> u32 {
    let shift = kernel.gwe.get_key_state(crate::ce::gwe::VK_SHIFT) & 0x8000_0000 != 0;
    let control = kernel.gwe.get_key_state(crate::ce::gwe::VK_CONTROL) & 0x8000_0000 != 0;
    let caps = kernel.gwe.get_key_state(crate::ce::gwe::VK_CAPITAL) & 0x0001 != 0;
    if control {
        return translate_control_key(vkey);
    }
    match vkey {
        0x08 | 0x09 | 0x0d | 0x1b => vkey,
        0x30..=0x39 => translate_digit_key(vkey, shift),
        0x41..=0x5a => {
            if shift ^ caps {
                vkey
            } else {
                vkey + 0x20
            }
        }
        0x60..=0x69 => vkey - 0x60 + u32::from(b'0'),
        0x6a => u32::from(b'*'),
        0x6b => u32::from(b'+'),
        0x6d => u32::from(b'-'),
        0x6e => u32::from(b'.'),
        0x6f => u32::from(b'/'),
        0x6c => 0,        // VK_SEPARATOR: produces no character
        0x70..=0x87 => 0, // VK_F1..VK_F24: function keys produce no character
        0x20 => 0x20,
        0xba => translate_pair_key(b';', b':', shift),
        0xbb => translate_pair_key(b'=', b'+', shift),
        0xbc => translate_pair_key(b',', b'<', shift),
        0xbd => translate_pair_key(b'-', b'_', shift),
        0xbe => translate_pair_key(b'.', b'>', shift),
        0xbf => translate_pair_key(b'/', b'?', shift),
        0xc0 => translate_pair_key(b'`', b'~', shift),
        0xdb => translate_pair_key(b'[', b'{', shift),
        0xdc => translate_pair_key(b'\\', b'|', shift),
        0xdd => translate_pair_key(b']', b'}', shift),
        0xde => translate_pair_key(b'\'', b'"', shift),
        // VK_OEM_102 / VK_EXTEND_BSLASH (0xE2): ISO extra key, same `\`/`|` mapping
        // as VK_OEM_5 on both US (il_0409.cpp) and Korean (il_0412.cpp) layouts.
        0xe2 => translate_pair_key(b'\\', b'|', shift),
        _ => 0,
    }
}

fn translate_control_key(vkey: u32) -> u32 {
    match vkey {
        0x41..=0x5a => vkey - 0x40,
        0x61..=0x7a => vkey - 0x60,
        0xdb => 0x1b,
        0xdc => 0x1c,
        0xdd => 0x1d,
        0xde => 0x1e,
        0xbd => 0x1f,
        0xe2 => 0x1c,
        0x08 | 0x09 | 0x0d | 0x1b => vkey,
        _ => 0,
    }
}

fn translate_pair_key(base: u8, shifted: u8, shift: bool) -> u32 {
    if shift {
        u32::from(shifted)
    } else {
        u32::from(base)
    }
}

fn translate_digit_key(vkey: u32, shift: bool) -> u32 {
    if !shift {
        return vkey;
    }
    match vkey {
        0x30 => b')' as u32,
        0x31 => b'!' as u32,
        0x32 => b'@' as u32,
        0x33 => b'#' as u32,
        0x34 => b'$' as u32,
        0x35 => b'%' as u32,
        0x36 => b'^' as u32,
        0x37 => b'&' as u32,
        0x38 => b'*' as u32,
        0x39 => b'(' as u32,
        _ => 0,
    }
}

/// Translate a VK code with AltGr (Ctrl+Alt) held for a Western European layout.
/// Returns `Some(char_code)` when AltGr produces a character, `None` to fall back
/// to the normal layout table. Only covers the most common AltGr mappings.
fn translate_vk_for_western_layout_altgr(layout: u32, vkey: u32) -> Option<u32> {
    let lang = layout & 0xFFFF;
    match lang {
        // French AZERTY AltGr (kbdfr.dll)
        0x040C => match vkey {
            0x30 => Some(0x40),   // AltGr+0 = @
            0x32 => Some(0x7e),   // AltGr+2 = ~
            0x33 => Some(0x23),   // AltGr+3 = #
            0x34 => Some(0x7b),   // AltGr+4 = {
            0x35 => Some(0x5b),   // AltGr+5 = [
            0x36 => Some(0x7c),   // AltGr+6 = |
            0x37 => Some(0x60),   // AltGr+7 = `
            0x38 => Some(0x5c),   // AltGr+8 = backslash
            0x39 => Some(0x5e),   // AltGr+9 = ^
            0x45 => Some(0x20ac), // AltGr+E = €
            0xbd => Some(0x5d),   // AltGr+) = ]
            0xbb => Some(0x7d),   // AltGr+= = }
            _ => None,
        },
        // German QWERTZ AltGr (kbdgr.dll)
        0x0407 => match vkey {
            0x32 => Some(0x00b2), // AltGr+2 = ²
            0x33 => Some(0x00b3), // AltGr+3 = ³
            0x37 => Some(0x7b),   // AltGr+7 = {
            0x38 => Some(0x5b),   // AltGr+8 = [
            0x39 => Some(0x5d),   // AltGr+9 = ]
            0x30 => Some(0x7d),   // AltGr+0 = }
            0x51 => Some(0x40),   // AltGr+Q = @
            0x45 => Some(0x20ac), // AltGr+E = €
            0xbd => Some(0x5c),   // AltGr+ß = backslash
            0xbb => Some(0x7e),   // AltGr+acute = ~
            0xe2 => Some(0x7c),   // AltGr+< = |
            _ => None,
        },
        // Spanish AltGr (kbdsp.dll)
        0x040A | 0x0C0A => match vkey {
            0x31 => Some(0x7c),   // AltGr+1 = |
            0x32 => Some(0x40),   // AltGr+2 = @
            0x33 => Some(0x23),   // AltGr+3 = #
            0x34 => Some(0x7e),   // AltGr+4 = ~
            0x35 => Some(0x00bd), // AltGr+5 = ½
            0x36 => Some(0x00ac), // AltGr+6 = ¬
            0x45 => Some(0x20ac), // AltGr+E = €
            0xdb => Some(0x5b),   // AltGr+[ = [
            0xdd => Some(0x5d),   // AltGr+] = ]
            0xe2 => Some(0x7c),   // AltGr+< = |
            _ => None,
        },
        _ => None,
    }
}

/// Translate a VK code for a Western European keyboard layout.
/// Returns `(char_code, is_dead)`. `char_code == 0` means no character.
/// `is_dead == true` means the char is a dead-key diacritic.
/// Used for layouts 0x040C (French AZERTY), 0x0407 (German QWERTZ),
/// 0x040A / 0x0C0A (Spanish).
fn translate_vk_for_western_layout(layout: u32, vkey: u32, shift: bool, caps: bool) -> (u32, bool) {
    let lang = layout & 0xFFFF;
    match lang {
        // French AZERTY (040C)
        0x040C => translate_vk_azerty(vkey, shift, caps),
        // German QWERTZ (0407)
        0x0407 => translate_vk_qwertz(vkey, shift, caps),
        // Spanish (040A, 0C0A)
        0x040A | 0x0C0A => translate_vk_spanish(vkey, shift, caps),
        _ => (0, false),
    }
}

fn translate_vk_azerty(vkey: u32, shift: bool, caps: bool) -> (u32, bool) {
    // French AZERTY layout VK→char table (VK codes are physical QWERTY positions).
    // Dead keys: VK_OEM_4 (0xDB) unshifted → dead circumflex '^',
    //            VK_OEM_4 (0xDB) shifted   → dead diaeresis '¨'.
    // Reference: standard Windows AZERTY (kbdfr.dll) layout.
    let letter = |lower: u8, upper: u8| -> (u32, bool) {
        let ch = if shift ^ caps { upper } else { lower };
        (u32::from(ch), false)
    };
    match vkey {
        // Letter row remapping (AZERTY vs QWERTY)
        0x41 => letter(b'q', b'Q'), // A key → q/Q
        0x5a => letter(b'w', b'W'), // Z key → w/W
        0x57 => letter(b'z', b'Z'), // W key → z/Z
        0x51 => letter(b'a', b'A'), // Q key → a/A
        // Remaining letters same physical position as QWERTY
        // Excludes: A=0x41, Q=0x51, W=0x57, Z=0x5A (remapped above),
        //           M=0x4D (at AZERTY ',' position, handled below).
        0x42..=0x4c | 0x4e..=0x50 | 0x52..=0x56 | 0x58..=0x59 => {
            let base = if shift ^ caps { vkey } else { vkey + 0x20 };
            (base, false)
        }
        0x4d => (if shift { 0x3f } else { 0x2c }, false), // M key → ,/?
        // Digit row: unshifted produce special chars; shifted produce digit
        0x31 => (if shift { 0x31 } else { 0x26 }, false), // 1 / &
        0x32 => (if shift { 0x32 } else { 0x00e9 }, false), // 2 / é
        0x33 => (if shift { 0x33 } else { 0x22 }, false), // 3 / "
        0x34 => (if shift { 0x34 } else { 0x27 }, false), // 4 / '
        0x35 => (if shift { 0x35 } else { 0x28 }, false), // 5 / (
        0x36 => (if shift { 0x36 } else { 0x2d }, false), // 6 / -
        0x37 => (if shift { 0x37 } else { 0x00e8 }, false), // 7 / è
        0x38 => (if shift { 0x38 } else { 0x5f }, false), // 8 / _
        0x39 => (if shift { 0x39 } else { 0x00e7 }, false), // 9 / ç
        0x30 => (if shift { 0x30 } else { 0x00e0 }, false), // 0 / à
        // OEM keys
        0xbd => (if shift { 0x00b0 } else { 0x29 }, false), // ° / )
        0xbb => (if shift { 0x2b } else { 0x3d }, false),   // + / =
        0xdb => {
            // VK_OEM_4: dead circumflex (unshifted) / dead diaeresis (shifted)
            if shift {
                (0x00a8, true) // dead diaeresis ¨
            } else {
                (0x5e, true) // dead circumflex ^
            }
        }
        0xdd => (if shift { 0x00a3 } else { 0x24 }, false), // £ / $
        0xba => letter(b'm', b'M'),                         // VK_OEM_1 (;) → m/M on AZERTY
        0xde => (if shift { 0x25 } else { 0x00f9 }, false), // % / ù
        0xdc => (if shift { 0x00b5 } else { 0x2a }, false), // µ / *
        0xe2 => (if shift { 0x3e } else { 0x3c }, false),   // > / <
        0xbc => (if shift { 0x2e } else { 0x3b }, false),   // . / ;
        0xbe => (if shift { 0x2f } else { 0x3a }, false),   // / / :
        0xbf => (if shift { 0x00a7 } else { 0x21 }, false), // § / !
        0xc0 => (if shift { 0x7e } else { 0x60 }, false),   // ~ / `
        // Special keys
        0x08 | 0x09 | 0x0d | 0x1b | 0x20 => (vkey, false),
        0x60..=0x69 => (vkey - 0x60 + 0x30, false),
        0x6a => (0x2a, false), // *
        0x6b => (0x2b, false), // +
        0x6d => (0x2d, false), // -
        0x6e => (0x2e, false), // .
        0x6f => (0x2f, false), // /
        _ => (0, false),
    }
}

fn translate_vk_qwertz(vkey: u32, shift: bool, caps: bool) -> (u32, bool) {
    // German QWERTZ layout.
    // Dead keys:
    //   VK_OEM_3 (0xC0, backtick position) unshifted → dead circumflex '^'
    //   VK_OEM_PLUS (0xBB, = position)    unshifted → dead acute '´'
    //   VK_OEM_PLUS (0xBB)                shifted   → dead grave '`'
    // Reference: standard Windows QWERTZ (kbdgr.dll) layout.
    let letter = |lower: u8, upper: u8| -> (u32, bool) {
        let ch = if shift ^ caps { upper } else { lower };
        (u32::from(ch), false)
    };
    match vkey {
        // Y↔Z swap
        0x59 => letter(b'z', b'Z'),
        0x5a => letter(b'y', b'Y'),
        // Other letters (A..X) — same as QWERTY (Y=0x59 and Z=0x5A are swapped above)
        0x41..=0x58 => {
            let base = if shift ^ caps { vkey } else { vkey + 0x20 };
            (base, false)
        }
        // Digit row
        0x31 => (if shift { 0x21 } else { 0x31 }, false), // ! / 1
        0x32 => (if shift { 0x22 } else { 0x32 }, false), // " / 2
        0x33 => (if shift { 0x00a7 } else { 0x33 }, false), // § / 3
        0x34 => (if shift { 0x24 } else { 0x34 }, false), // $ / 4
        0x35 => (if shift { 0x25 } else { 0x35 }, false), // % / 5
        0x36 => (if shift { 0x26 } else { 0x36 }, false), // & / 6
        0x37 => (if shift { 0x2f } else { 0x37 }, false), // / / 7
        0x38 => (if shift { 0x28 } else { 0x38 }, false), // ( / 8
        0x39 => (if shift { 0x29 } else { 0x39 }, false), // ) / 9
        0x30 => (if shift { 0x3d } else { 0x30 }, false), // = / 0
        // OEM keys
        0xbd => (if shift { 0x3f } else { 0x00df }, false), // ß / ?
        0xbb => {
            // VK_OEM_PLUS: dead acute (unshifted) / dead grave (shifted)
            if shift {
                (0x60, true) // dead grave `
            } else {
                (0x00b4, true) // dead acute ´
            }
        }
        0xdb => (if shift { 0x00dc } else { 0x00fc }, false), // ü/Ü
        0xdd => (if shift { 0x2a } else { 0x2b }, false),     // * / +
        0xba => (if shift { 0x00d6 } else { 0x00f6 }, false), // ö/Ö
        0xde => (if shift { 0x00c4 } else { 0x00e4 }, false), // ä/Ä
        0xdc => (if shift { 0x27 } else { 0x23 }, false),     // ' / #
        0xc0 => (0x5e, true),                                 // dead circumflex ^
        0xe2 => (if shift { 0x3e } else { 0x3c }, false),     // > / <
        0xbc => (if shift { 0x3b } else { 0x2c }, false),     // ; / ,
        0xbe => (if shift { 0x3a } else { 0x2e }, false),     // : / .
        0xbf => (if shift { 0x5f } else { 0x2d }, false),     // _ / -
        // Special keys
        0x08 | 0x09 | 0x0d | 0x1b | 0x20 => (vkey, false),
        0x60..=0x69 => (vkey - 0x60 + 0x30, false),
        0x6a => (0x2a, false), // *
        0x6b => (0x2b, false), // +
        0x6d => (0x2d, false), // -
        0x6e => (0x2e, false), // .
        0x6f => (0x2f, false), // /
        _ => (0, false),
    }
}

fn translate_vk_spanish(vkey: u32, shift: bool, caps: bool) -> (u32, bool) {
    // Spanish (Spain) keyboard layout.
    // Dead keys:
    //   VK_OEM_4 (0xDB) unshifted → dead grave '`'
    //   VK_OEM_4 (0xDB) shifted   → dead circumflex '^'
    //   VK_OEM_PLUS (0xBB, = position) unshifted → dead acute '´'
    // Reference: standard Windows Spanish layout (kbdsp.dll).
    let _ = caps; // Spanish letters follow caps-lock the same as QWERTY
    match vkey {
        // Letters same as US
        0x41..=0x5a => {
            let base = if shift ^ caps { vkey } else { vkey + 0x20 };
            (base, false)
        }
        // Digit row: shifted produces Spanish special characters
        0x30 => (if shift { 0x3d } else { 0x30 }, false), // = / 0
        0x31 => (if shift { 0x21 } else { 0x31 }, false), // ! / 1
        0x32 => (if shift { 0x22 } else { 0x32 }, false), // " / 2
        0x33 => (if shift { 0x00b7 } else { 0x33 }, false), // · / 3
        0x34 => (if shift { 0x24 } else { 0x34 }, false), // $ / 4
        0x35 => (if shift { 0x25 } else { 0x35 }, false), // % / 5
        0x36 => (if shift { 0x26 } else { 0x36 }, false), // & / 6
        0x37 => (if shift { 0x2f } else { 0x37 }, false), // / / 7
        0x38 => (if shift { 0x28 } else { 0x38 }, false), // ( / 8
        0x39 => (if shift { 0x29 } else { 0x39 }, false), // ) / 9
        // OEM keys
        0xbd => (if shift { 0x3f } else { 0x27 }, false), // ? / '
        0xbb => (0x00b4, true),                           // dead acute ´ (both shift states)
        0xdb => {
            if shift {
                (0x5e, true) // dead circumflex ^
            } else {
                (0x60, true) // dead grave `
            }
        }
        0xdd => (if shift { 0x2a } else { 0x2b }, false), // * / +
        0xba => (if shift { 0x3a } else { 0x3b }, false), // : / ;
        0xde => (if shift { 0x22 } else { 0x00ba }, false), // " / º
        0xdc => (if shift { 0x00aa } else { 0x00ba }, false),
        0xc0 => (if shift { 0x00d1 } else { 0x00f1 }, false), // Ñ / ñ
        0xe2 => (if shift { 0x3e } else { 0x3c }, false),     // > / <
        0xbc => (if shift { 0x3b } else { 0x2c }, false),     // ; / ,
        0xbe => (if shift { 0x3a } else { 0x2e }, false),     // : / .
        0xbf => (if shift { 0x5f } else { 0x2d }, false),     // _ / -
        // Special keys
        0x08 | 0x09 | 0x0d | 0x1b | 0x20 => (vkey, false),
        0x60..=0x69 => (vkey - 0x60 + 0x30, false),
        0x6a => (0x2a, false), // *
        0x6b => (0x2b, false), // +
        0x6d => (0x2d, false), // -
        0x6e => (0x2e, false), // .
        0x6f => (0x2f, false), // /
        _ => (0, false),
    }
}

/// Look up the composed character for a dead-key + base-character pair.
/// Returns `Some(composed)` if a Unicode precomposed form exists,
/// `None` if there is no composed form (caller should emit dead+base separately).
fn compose_dead_key(dead: u32, base: u32) -> Option<u32> {
    // Standard Unicode precomposed forms for the five common diacritics.
    match dead {
        // Dead circumflex ^ (0x5E)
        0x5e => match base {
            0x61 => Some(0x00e2), // a → â
            0x65 => Some(0x00ea), // e → ê
            0x69 => Some(0x00ee), // i → î
            0x6f => Some(0x00f4), // o → ô
            0x75 => Some(0x00fb), // u → û
            0x41 => Some(0x00c2), // A → Â
            0x45 => Some(0x00ca), // E → Ê
            0x49 => Some(0x00ce), // I → Î
            0x4f => Some(0x00d4), // O → Ô
            0x55 => Some(0x00db), // U → Û
            0x20 => Some(0x005e), // space → literal ^
            _ => None,
        },
        // Dead grave ` (0x60)
        0x60 => match base {
            0x61 => Some(0x00e0), // a → à
            0x65 => Some(0x00e8), // e → è
            0x69 => Some(0x00ec), // i → ì
            0x6f => Some(0x00f2), // o → ò
            0x75 => Some(0x00f9), // u → ù
            0x41 => Some(0x00c0), // A → À
            0x45 => Some(0x00c8), // E → È
            0x49 => Some(0x00cc), // I → Ì
            0x4f => Some(0x00d2), // O → Ò
            0x55 => Some(0x00d9), // U → Ù
            0x20 => Some(0x0060), // space → literal `
            _ => None,
        },
        // Dead acute ´ (U+00B4)
        0x00b4 => match base {
            0x61 => Some(0x00e1), // a → á
            0x65 => Some(0x00e9), // e → é
            0x69 => Some(0x00ed), // i → í
            0x6f => Some(0x00f3), // o → ó
            0x75 => Some(0x00fa), // u → ú
            0x79 => Some(0x00fd), // y → ý
            0x41 => Some(0x00c1), // A → Á
            0x45 => Some(0x00c9), // E → É
            0x49 => Some(0x00cd), // I → Í
            0x4f => Some(0x00d3), // O → Ó
            0x55 => Some(0x00da), // U → Ú
            0x59 => Some(0x00dd), // Y → Ý
            0x20 => Some(0x00b4), // space → literal ´
            _ => None,
        },
        // Dead tilde ~ (0x7E)
        0x7e => match base {
            0x61 => Some(0x00e3), // a → ã
            0x6f => Some(0x00f5), // o → õ
            0x6e => Some(0x00f1), // n → ñ
            0x41 => Some(0x00c3), // A → Ã
            0x4f => Some(0x00d5), // O → Õ
            0x4e => Some(0x00d1), // N → Ñ
            0x20 => Some(0x007e), // space → literal ~
            _ => None,
        },
        // Dead diaeresis ¨ (U+00A8)
        0x00a8 => match base {
            0x61 => Some(0x00e4), // a → ä
            0x65 => Some(0x00eb), // e → ë
            0x69 => Some(0x00ef), // i → ï
            0x6f => Some(0x00f6), // o → ö
            0x75 => Some(0x00fc), // u → ü
            0x79 => Some(0x00ff), // y → ÿ
            0x41 => Some(0x00c4), // A → Ä
            0x45 => Some(0x00cb), // E → Ë
            0x49 => Some(0x00cf), // I → Ï
            0x4f => Some(0x00d6), // O → Ö
            0x55 => Some(0x00dc), // U → Ü
            0x20 => Some(0x00a8), // space → literal ¨
            _ => None,
        },
        _ => None,
    }
}

fn post_keybd_message_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let hwnd = raw_arg(args, 0);
    if hwnd != 0 && !kernel.gwe.is_window(hwnd) {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_WINDOW_HANDLE);
        return false;
    }
    let virtual_key = raw_arg(args, 1);
    let key_state_flags = raw_arg(args, 2);
    let requested_characters = raw_arg(args, 3);
    let (character_ptr, character_capacity) = if args.len() >= 8 {
        (raw_arg(args, 6), raw_arg(args, 7))
    } else {
        (raw_arg(args, 5), requested_characters)
    };
    let character_count = requested_characters.min(character_capacity) as usize;
    let characters = match read_keyboard_character_buffer(
        kernel,
        memory,
        thread_id,
        character_ptr,
        character_count,
    ) {
        Some(characters) => characters,
        None => return false,
    };
    let key_down = key_state_flags & crate::ce::gwe::KEY_STATE_DOWN_FLAG != 0;
    let lparam = keyboard_message_lparam(
        0,
        key_state_flags & crate::ce::gwe::KEY_STATE_PREV_DOWN_FLAG != 0,
        !key_down,
        false,
    );
    let posted = kernel.post_keybd_message_for_thread(
        thread_id,
        (hwnd != 0).then_some(hwnd),
        virtual_key,
        key_down,
        lparam,
        &characters,
    );
    kernel.threads.set_last_error(
        thread_id,
        if posted {
            0
        } else {
            ERROR_INVALID_WINDOW_HANDLE
        },
    );
    posted
}

fn keybd_event_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) {
    let virtual_key = raw_arg(args, 0) & 0xff;
    let scan_code = raw_arg(args, 1) & 0xff;
    let flags = raw_arg(args, 2);
    let key_up = flags & KEYEVENTF_KEYUP != 0;
    let lparam = keyboard_message_lparam(
        scan_code,
        key_up,
        key_up,
        flags & KEYEVENTF_EXTENDEDKEY != 0,
    );
    let _ =
        kernel.post_keybd_message_for_thread(thread_id, None, virtual_key, !key_up, lparam, &[]);
    kernel.threads.set_last_error(thread_id, 0);
}

fn read_keyboard_character_buffer<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    character_ptr: u32,
    character_count: usize,
) -> Option<Vec<u32>> {
    if character_count == 0 {
        return Some(Vec::new());
    }
    if character_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    let mut characters = Vec::with_capacity(character_count);
    for index in 0..character_count {
        let addr = character_ptr.wrapping_add((index as u32) * 4);
        characters.push(read_guest_u32(kernel, memory, thread_id, addr)?);
    }
    Some(characters)
}

fn keyboard_message_lparam(
    scan_code: u32,
    previous_down: bool,
    key_up: bool,
    extended: bool,
) -> u32 {
    let mut lparam = 1 | ((scan_code & 0xff) << 16);
    if extended {
        lparam |= KF_EXTENDED_LPARAM;
    }
    if previous_down {
        lparam |= KF_REPEAT_LPARAM;
    }
    if key_up {
        lparam |= KF_UP_LPARAM;
    }
    lparam
}

const CS_LOCK_COUNT: u32 = 0;
const CS_OWNER_THREAD: u32 = 4;
const CS_HANDLE: u32 = 8;
const CS_NEED_TRAP: u32 = 12;
const CS_CONTENTIONS: u32 = 16;
const CS_SIZE_WORDS: u32 = 5;

fn initialize_critical_section<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
) {
    if addr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return;
    }
    for offset in [
        CS_LOCK_COUNT,
        CS_OWNER_THREAD,
        CS_HANDLE,
        CS_NEED_TRAP,
        CS_CONTENTIONS,
    ] {
        if !write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(offset), 0) {
            return;
        }
    }
    let handle = kernel
        .handles
        .insert(KernelObject::CriticalSection(CriticalSectionObject {
            guest_ptr: addr,
        }));
    write_guest_u32(
        kernel,
        memory,
        thread_id,
        addr.wrapping_add(CS_HANDLE),
        handle,
    );
}

fn delete_critical_section<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
) {
    if let Some(handle) = read_guest_u32(kernel, memory, thread_id, addr.wrapping_add(CS_HANDLE)) {
        let _ = kernel.close_handle(handle);
    }
    for word in 0..CS_SIZE_WORDS {
        write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(word * 4), 0);
    }
}

fn enter_critical_section<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    try_only: bool,
) -> bool {
    let owner_addr = addr.wrapping_add(CS_OWNER_THREAD);
    let lock_addr = addr.wrapping_add(CS_LOCK_COUNT);
    let contentions_addr = addr.wrapping_add(CS_CONTENTIONS);
    let Some(owner) = read_guest_u32(kernel, memory, thread_id, owner_addr) else {
        return false;
    };

    if owner == thread_id {
        let Some(lock_count) = read_guest_u32(kernel, memory, thread_id, lock_addr) else {
            return false;
        };
        return write_guest_u32(
            kernel,
            memory,
            thread_id,
            lock_addr,
            lock_count.wrapping_add(1),
        );
    }

    if owner == 0 {
        return write_guest_u32(kernel, memory, thread_id, owner_addr, thread_id)
            && write_guest_u32(kernel, memory, thread_id, lock_addr, 1);
    }

    if !try_only {
        interlocked_update(
            kernel,
            memory,
            thread_id,
            contentions_addr,
            |value| value.wrapping_add(1),
            InterlockedReturn::NewValue,
        );
    }
    false
}

fn leave_critical_section<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
) {
    let owner_addr = addr.wrapping_add(CS_OWNER_THREAD);
    let lock_addr = addr.wrapping_add(CS_LOCK_COUNT);
    let Some(owner) = read_guest_u32(kernel, memory, thread_id, owner_addr) else {
        return;
    };
    if owner != thread_id {
        return;
    }
    let Some(lock_count) = read_guest_u32(kernel, memory, thread_id, lock_addr) else {
        return;
    };
    if lock_count > 1 {
        write_guest_u32(
            kernel,
            memory,
            thread_id,
            lock_addr,
            lock_count.wrapping_sub(1),
        );
    } else {
        write_guest_u32(kernel, memory, thread_id, owner_addr, thread_id | 1);
        interlocked_compare_store(kernel, memory, thread_id, owner_addr, 0, thread_id | 1);
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum InterlockedReturn {
    OldValue,
    NewValue,
}

fn interlocked_update<M, F>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    update: F,
    return_mode: InterlockedReturn,
) -> u32
where
    M: CoredllGuestMemory,
    F: FnOnce(u32) -> u32,
{
    let Some(old_value) = read_guest_u32(kernel, memory, thread_id, addr) else {
        return 0;
    };
    let new_value = update(old_value);
    if !write_guest_u32(kernel, memory, thread_id, addr, new_value) {
        return 0;
    }
    match return_mode {
        InterlockedReturn::OldValue => old_value,
        InterlockedReturn::NewValue => new_value,
    }
}

fn interlocked_compare_store<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    exchange: u32,
    comparand: u32,
) -> u32 {
    let Some(old_value) = read_guest_u32(kernel, memory, thread_id, addr) else {
        return 0;
    };
    if old_value == comparand {
        write_guest_u32(kernel, memory, thread_id, addr, exchange);
    }
    old_value
}

const CECOMPRESS_ALLZEROS: u32 = 0;
const CECOMPRESS_FAILED: u32 = u32::MAX;
const CEDECOMPRESS_FAILED: u32 = u32::MAX;
const STRING_COMPRESS_SIZE_MASK: u16 = 0x3fff;
const STRING_COMPRESS_PART1_RAW: u16 = 0x8000;
const STRING_COMPRESS_PART2_RAW: u16 = 0x4000;
const STRING_COMPRESS_ENGINE_MAGIC: [u8; 2] = [0xce, 0x53];
const STRING_COMPRESS_RUN_TOKEN: u8 = 0x80;
const STRING_COMPRESS_TOKEN_LEN_MASK: u8 = 0x7f;
const STRING_COMPRESS_MAX_TOKEN_LEN: usize = 128;

fn string_compress_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let input_ptr = raw_arg(args, 0);
    let input_len = raw_arg(args, 1);
    let output_ptr = raw_arg(args, 2);
    let output_len = raw_arg(args, 3);
    if input_len == 0 {
        if output_ptr != 0 && !write_guest_u16(kernel, memory, thread_id, output_ptr, 0) {
            return CECOMPRESS_FAILED;
        }
        kernel.threads.set_last_error(thread_id, 0);
        return CECOMPRESS_ALLZEROS;
    }
    let Some(input) = read_guest_bytes(kernel, memory, thread_id, input_ptr, input_len) else {
        return CECOMPRESS_FAILED;
    };
    if input.iter().all(|&byte| byte == 0) {
        if output_ptr != 0 {
            if output_len < 2 {
                kernel
                    .threads
                    .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
                return CECOMPRESS_FAILED;
            }
            if !write_guest_u16(kernel, memory, thread_id, output_ptr, 0) {
                return CECOMPRESS_FAILED;
            }
        }
        kernel.threads.set_last_error(thread_id, 0);
        return CECOMPRESS_ALLZEROS;
    }

    let even_stream: Vec<u8> = input.iter().step_by(2).copied().collect();
    let odd_stream: Vec<u8> = input.iter().skip(1).step_by(2).copied().collect();
    if even_stream.len() > usize::from(STRING_COMPRESS_SIZE_MASK) {
        kernel.threads.set_last_error(thread_id, 0);
        return CECOMPRESS_FAILED;
    }

    let even_part = string_compress_stream_part(&even_stream);
    let odd_part = string_compress_stream_part(&odd_stream);
    if even_part.payload_len() > usize::from(STRING_COMPRESS_SIZE_MASK) {
        kernel.threads.set_last_error(thread_id, 0);
        return CECOMPRESS_FAILED;
    }
    let packet_len = 2usize
        .saturating_add(even_part.payload_len())
        .saturating_add(odd_part.payload_len());
    if packet_len >= input_len as usize {
        kernel.threads.set_last_error(thread_id, 0);
        return CECOMPRESS_FAILED;
    }
    let mut header = even_part.header_bits(true);
    header |= odd_part.header_bits(false);
    if output_ptr != 0 {
        if packet_len > output_len as usize {
            kernel.threads.set_last_error(thread_id, 0);
            return CECOMPRESS_FAILED;
        }
        if !write_guest_u16(kernel, memory, thread_id, output_ptr, header) {
            return CECOMPRESS_FAILED;
        }
        let mut cursor = output_ptr.wrapping_add(2);
        if let Some(bytes) = even_part.payload() {
            if !write_guest_bytes(kernel, memory, thread_id, cursor, bytes) {
                return CECOMPRESS_FAILED;
            }
            cursor = cursor.wrapping_add(bytes.len() as u32);
        }
        if let Some(bytes) = odd_part.payload()
            && !write_guest_bytes(kernel, memory, thread_id, cursor, bytes)
        {
            return CECOMPRESS_FAILED;
        }
    }
    kernel.threads.set_last_error(thread_id, 0);
    packet_len as u32
}

enum StringCompressPart {
    Zero,
    Raw(Vec<u8>),
    Compressed(Vec<u8>),
}

impl StringCompressPart {
    fn payload(&self) -> Option<&[u8]> {
        match self {
            Self::Zero => None,
            Self::Raw(bytes) | Self::Compressed(bytes) => Some(bytes),
        }
    }

    fn payload_len(&self) -> usize {
        self.payload().map_or(0, <[u8]>::len)
    }

    fn header_bits(&self, first_part: bool) -> u16 {
        match self {
            Self::Zero => 0,
            Self::Raw(bytes) => {
                let raw_bit = if first_part {
                    STRING_COMPRESS_PART1_RAW
                } else {
                    STRING_COMPRESS_PART2_RAW
                };
                raw_bit | if first_part { bytes.len() as u16 } else { 0 }
            }
            Self::Compressed(bytes) => {
                if first_part {
                    bytes.len() as u16
                } else {
                    0
                }
            }
        }
    }
}

fn string_compress_stream_part(bytes: &[u8]) -> StringCompressPart {
    if bytes.is_empty() || bytes.iter().all(|&byte| byte == 0) {
        return StringCompressPart::Zero;
    }
    if let Some(compressed) = string_engine_compress_stream(bytes)
        && compressed.len() < bytes.len()
    {
        return StringCompressPart::Compressed(compressed);
    }
    StringCompressPart::Raw(bytes.to_vec())
}

fn string_engine_compress_stream(bytes: &[u8]) -> Option<Vec<u8>> {
    let mut encoded = Vec::with_capacity(bytes.len());
    encoded.extend_from_slice(&STRING_COMPRESS_ENGINE_MAGIC);
    let mut cursor = 0usize;
    while cursor < bytes.len() {
        let value = bytes[cursor];
        let mut run_len = 1usize;
        while cursor + run_len < bytes.len()
            && bytes[cursor + run_len] == value
            && run_len < STRING_COMPRESS_MAX_TOKEN_LEN
        {
            run_len += 1;
        }
        if run_len >= 4 {
            encoded.push(STRING_COMPRESS_RUN_TOKEN | (run_len as u8 - 1));
            encoded.push(value);
            cursor += run_len;
            continue;
        }

        let literal_start = cursor;
        let mut literal_len = 0usize;
        while cursor < bytes.len() && literal_len < STRING_COMPRESS_MAX_TOKEN_LEN {
            let literal_value = bytes[cursor];
            let mut next_run_len = 1usize;
            while cursor + next_run_len < bytes.len()
                && bytes[cursor + next_run_len] == literal_value
                && next_run_len < STRING_COMPRESS_MAX_TOKEN_LEN
            {
                next_run_len += 1;
            }
            if next_run_len >= 4 && literal_len != 0 {
                break;
            }
            cursor += 1;
            literal_len += 1;
            if next_run_len >= 4 {
                break;
            }
        }
        if literal_len == 0 {
            return None;
        }
        encoded.push(literal_len as u8 - 1);
        encoded.extend_from_slice(&bytes[literal_start..literal_start + literal_len]);
    }
    Some(encoded)
}

fn string_engine_decompress_stream(
    bytes: &[u8],
    output_len: usize,
) -> std::result::Result<Vec<u8>, u32> {
    if !bytes.starts_with(&STRING_COMPRESS_ENGINE_MAGIC) {
        return Err(ERROR_NOT_SUPPORTED);
    }
    let mut decoded = Vec::with_capacity(output_len);
    let mut cursor = STRING_COMPRESS_ENGINE_MAGIC.len();
    while cursor < bytes.len() {
        let token = bytes[cursor];
        cursor += 1;
        let count = usize::from(token & STRING_COMPRESS_TOKEN_LEN_MASK) + 1;
        if token & STRING_COMPRESS_RUN_TOKEN != 0 {
            let Some(&value) = bytes.get(cursor) else {
                return Err(ERROR_INVALID_PARAMETER);
            };
            cursor += 1;
            decoded.resize(decoded.len().saturating_add(count), value);
        } else {
            let end = cursor.saturating_add(count);
            if end > bytes.len() {
                return Err(ERROR_INVALID_PARAMETER);
            }
            decoded.extend_from_slice(&bytes[cursor..end]);
            cursor = end;
        }
        if decoded.len() > output_len {
            return Err(ERROR_INVALID_PARAMETER);
        }
    }
    Ok(decoded)
}

fn string_decompress_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> u32 {
    let input_ptr = raw_arg(args, 0);
    let input_len = raw_arg(args, 1);
    let output_ptr = raw_arg(args, 2);
    let output_len = raw_arg(args, 3);
    if input_len < 2 || output_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return CEDECOMPRESS_FAILED;
    }
    let Some(header) = read_guest_u16(kernel, memory, thread_id, input_ptr) else {
        return CEDECOMPRESS_FAILED;
    };
    let part1_size = usize::from(header & STRING_COMPRESS_SIZE_MASK);
    let Some(part2_size) = (input_len as usize)
        .checked_sub(2)
        .and_then(|payload| payload.checked_sub(part1_size))
    else {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return CEDECOMPRESS_FAILED;
    };

    let newsize1;
    if part1_size == 0 {
        for offset in (0..output_len).step_by(2) {
            if !write_guest_u8(
                kernel,
                memory,
                thread_id,
                output_ptr.wrapping_add(offset),
                0,
            ) {
                return CEDECOMPRESS_FAILED;
            }
        }
        newsize1 = 0;
    } else if header & STRING_COMPRESS_PART1_RAW != 0 {
        if part1_size.saturating_mul(2) > output_len as usize {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return CEDECOMPRESS_FAILED;
        }
        let Some(bytes) = read_guest_bytes(
            kernel,
            memory,
            thread_id,
            input_ptr.wrapping_add(2),
            part1_size as u32,
        ) else {
            return CEDECOMPRESS_FAILED;
        };
        for (index, byte) in bytes.iter().copied().enumerate() {
            if !write_guest_u8(
                kernel,
                memory,
                thread_id,
                output_ptr.wrapping_add((index * 2) as u32),
                byte,
            ) {
                return CEDECOMPRESS_FAILED;
            }
        }
        newsize1 = part1_size;
    } else {
        let Some(bytes) = read_guest_bytes(
            kernel,
            memory,
            thread_id,
            input_ptr.wrapping_add(2),
            part1_size as u32,
        ) else {
            return CEDECOMPRESS_FAILED;
        };
        let decompressed =
            match string_engine_decompress_stream(&bytes, (output_len as usize).div_ceil(2)) {
                Ok(bytes) => bytes,
                Err(error) => {
                    kernel.threads.set_last_error(thread_id, error);
                    return CEDECOMPRESS_FAILED;
                }
            };
        newsize1 = decompressed.len();
        for (index, byte) in decompressed.iter().copied().enumerate() {
            if !write_guest_u8(
                kernel,
                memory,
                thread_id,
                output_ptr.wrapping_add((index * 2) as u32),
                byte,
            ) {
                return CEDECOMPRESS_FAILED;
            }
        }
    }

    let newsize2;
    if part2_size == 0 {
        for offset in (1..output_len).step_by(2) {
            if !write_guest_u8(
                kernel,
                memory,
                thread_id,
                output_ptr.wrapping_add(offset),
                0,
            ) {
                return CEDECOMPRESS_FAILED;
            }
        }
        newsize2 = 0;
    } else if header & STRING_COMPRESS_PART2_RAW != 0 {
        if part2_size.saturating_mul(2) > output_len as usize {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            return CEDECOMPRESS_FAILED;
        }
        let Some(bytes) = read_guest_bytes(
            kernel,
            memory,
            thread_id,
            input_ptr.wrapping_add(2 + part1_size as u32),
            part2_size as u32,
        ) else {
            return CEDECOMPRESS_FAILED;
        };
        for (index, byte) in bytes.iter().copied().enumerate() {
            if !write_guest_u8(
                kernel,
                memory,
                thread_id,
                output_ptr.wrapping_add((index * 2 + 1) as u32),
                byte,
            ) {
                return CEDECOMPRESS_FAILED;
            }
        }
        newsize2 = part2_size;
    } else {
        let Some(bytes) = read_guest_bytes(
            kernel,
            memory,
            thread_id,
            input_ptr.wrapping_add(2 + part1_size as u32),
            part2_size as u32,
        ) else {
            return CEDECOMPRESS_FAILED;
        };
        let decompressed = match string_engine_decompress_stream(&bytes, output_len as usize / 2) {
            Ok(bytes) => bytes,
            Err(error) => {
                kernel.threads.set_last_error(thread_id, error);
                return CEDECOMPRESS_FAILED;
            }
        };
        newsize2 = decompressed.len();
        for (index, byte) in decompressed.iter().copied().enumerate() {
            if !write_guest_u8(
                kernel,
                memory,
                thread_id,
                output_ptr.wrapping_add((index * 2 + 1) as u32),
                byte,
            ) {
                return CEDECOMPRESS_FAILED;
            }
        }
    }

    let out_size = newsize1.max(newsize2).saturating_mul(2);
    kernel.threads.set_last_error(thread_id, 0);
    out_size as u32
}

pub(crate) fn read_guest_bytes<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
    len: u32,
) -> Option<Vec<u8>> {
    let mut bytes = vec![0; len as usize];
    if memory.read_bytes(addr, &mut bytes).is_err() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    Some(bytes)
}

fn read_guest_narrow_preview<M: CoredllGuestMemory>(
    memory: &M,
    ptr: u32,
    max_len: usize,
) -> Option<String> {
    if ptr == 0 {
        return None;
    }
    let mut preview = String::new();
    for offset in 0..max_len {
        let byte = memory.read_u8(ptr.wrapping_add(offset as u32)).ok()?;
        if byte == 0 {
            break;
        }
        match byte {
            b'\r' => preview.push_str("\\r"),
            b'\n' => preview.push_str("\\n"),
            b'\t' => preview.push_str("\\t"),
            0x20..=0x7e => preview.push(byte as char),
            _ => preview.push_str(&format!("\\x{byte:02x}")),
        }
    }
    Some(preview)
}

pub(crate) fn write_guest_bytes<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    bytes: &[u8],
) -> bool {
    if memory.write_bytes(addr, bytes).is_err() {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    true
}

fn write_optional_count<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u32,
) -> bool {
    addr == 0 || write_guest_u32(kernel, memory, thread_id, addr, value)
}

fn write_optional_u32<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u32,
) -> bool {
    write_optional_count(kernel, memory, thread_id, addr, value)
}

fn write_optional_u64<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u64,
) -> bool {
    addr == 0
        || (write_guest_u32(kernel, memory, thread_id, addr, value as u32)
            && write_guest_u32(
                kernel,
                memory,
                thread_id,
                addr.wrapping_add(4),
                (value >> 32) as u32,
            ))
}

fn read_guest_u32<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<u32> {
    match memory.read_u32(addr) {
        Ok(value) => Some(value),
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            None
        }
    }
}

fn read_guest_u16<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<u16> {
    match memory.read_u16(addr) {
        Ok(value) => Some(value),
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            None
        }
    }
}

fn read_guest_i16<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<i16> {
    read_guest_u16(kernel, memory, thread_id, addr).map(|value| value as i16)
}

fn write_guest_u32<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u32,
) -> bool {
    match memory.write_u32(addr, value) {
        Ok(()) => true,
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
    }
}

fn write_guest_u8<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u8,
) -> bool {
    match memory.write_u8(addr, value) {
        Ok(()) => true,
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
    }
}

pub(crate) fn write_guest_u16<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: u16,
) -> bool {
    match memory.write_u16(addr, value) {
        Ok(()) => true,
        Err(_) => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
            false
        }
    }
}

fn read_guest_wide_z<M: CoredllGuestMemory>(
    memory: &M,
    addr: u32,
    max_chars: usize,
) -> Result<String> {
    let mut units = Vec::new();
    for index in 0..max_chars {
        let unit = memory.read_u16(addr.wrapping_add((index as u32) * 2))?;
        if unit == 0 {
            break;
        }
        units.push(unit);
    }
    Ok(String::from_utf16_lossy(&units))
}

fn read_guest_i32<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<i32> {
    read_guest_u32(kernel, memory, thread_id, addr).map(|value| value as i32)
}

fn write_guest_i32<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    value: i32,
) -> bool {
    write_guest_u32(kernel, memory, thread_id, addr, value as u32)
}

fn read_guest_point<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<Point> {
    Some(Point {
        x: read_guest_i32(kernel, memory, thread_id, addr)?,
        y: read_guest_i32(kernel, memory, thread_id, addr.wrapping_add(4))?,
    })
}

fn write_guest_point<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    point: Point,
) -> bool {
    write_guest_i32(kernel, memory, thread_id, addr, point.x)
        && write_guest_i32(kernel, memory, thread_id, addr.wrapping_add(4), point.y)
}

fn read_guest_rect<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<Rect> {
    Some(Rect {
        left: read_guest_i32(kernel, memory, thread_id, addr)?,
        top: read_guest_i32(kernel, memory, thread_id, addr.wrapping_add(4))?,
        right: read_guest_i32(kernel, memory, thread_id, addr.wrapping_add(8))?,
        bottom: read_guest_i32(kernel, memory, thread_id, addr.wrapping_add(12))?,
    })
}

fn write_guest_rect<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    rect: Rect,
) -> bool {
    write_guest_i32(kernel, memory, thread_id, addr, rect.left)
        && write_guest_i32(kernel, memory, thread_id, addr.wrapping_add(4), rect.top)
        && write_guest_i32(kernel, memory, thread_id, addr.wrapping_add(8), rect.right)
        && write_guest_i32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(12),
            rect.bottom,
        )
}

fn read_guest_composition_form<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<crate::ce::gwe::ImeCompositionForm> {
    if addr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    Some(crate::ce::gwe::ImeCompositionForm {
        style: read_guest_u32(kernel, memory, thread_id, addr)?,
        current_pos: read_guest_point(kernel, memory, thread_id, addr.wrapping_add(4))?,
        area: read_guest_rect(kernel, memory, thread_id, addr.wrapping_add(12))?,
    })
}

fn write_guest_composition_form<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    form: crate::ce::gwe::ImeCompositionForm,
) -> bool {
    if addr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    write_guest_u32(kernel, memory, thread_id, addr, form.style)
        && write_guest_point(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(4),
            form.current_pos,
        )
        && write_guest_rect(kernel, memory, thread_id, addr.wrapping_add(12), form.area)
}

fn read_guest_candidate_form<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<crate::ce::gwe::ImeCandidateForm> {
    if addr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return None;
    }
    Some(crate::ce::gwe::ImeCandidateForm {
        index: read_guest_u32(kernel, memory, thread_id, addr)?,
        style: read_guest_u32(kernel, memory, thread_id, addr.wrapping_add(4))?,
        current_pos: read_guest_point(kernel, memory, thread_id, addr.wrapping_add(8))?,
        area: read_guest_rect(kernel, memory, thread_id, addr.wrapping_add(16))?,
    })
}

fn write_guest_candidate_form<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    form: crate::ce::gwe::ImeCandidateForm,
) -> bool {
    if addr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }
    write_guest_u32(kernel, memory, thread_id, addr, form.index)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(4), form.style)
        && write_guest_point(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(8),
            form.current_pos,
        )
        && write_guest_rect(kernel, memory, thread_id, addr.wrapping_add(16), form.area)
}

fn read_guest_message<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &M,
    thread_id: u32,
    addr: u32,
) -> Option<Message> {
    Some(Message {
        hwnd: read_guest_u32(kernel, memory, thread_id, addr)?,
        msg: read_guest_u32(kernel, memory, thread_id, addr.wrapping_add(4))?,
        wparam: read_guest_u32(kernel, memory, thread_id, addr.wrapping_add(8))?,
        lparam: read_guest_u32(kernel, memory, thread_id, addr.wrapping_add(12))?,
        time_ms: read_guest_u32(kernel, memory, thread_id, addr.wrapping_add(16))?,
        source: crate::ce::gwe::MSGSRC_UNKNOWN,
        mouse_pos_at_post: None,
    })
}

fn write_guest_message<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    message: &Message,
) -> bool {
    if !write_message_pointer_payload(kernel, memory, thread_id, message) {
        return false;
    }
    write_guest_u32(kernel, memory, thread_id, addr, message.hwnd)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(4), message.msg)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(8),
            message.wparam,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(12),
            message.lparam,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(16),
            message.time_ms,
        )
        && write_guest_i32(kernel, memory, thread_id, addr.wrapping_add(20), 0)
        && write_guest_i32(kernel, memory, thread_id, addr.wrapping_add(24), 0)
}

fn write_message_pointer_payload<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    message: &Message,
) -> bool {
    if message.lparam == 0 {
        return true;
    }
    match kernel.message_pointer_payload(message.lparam) {
        Some(MessagePointerPayload::WindowPos(window_pos))
            if message.msg == crate::ce::gwe::WM_WINDOWPOSCHANGED =>
        {
            write_guest_window_pos(kernel, memory, thread_id, message.lparam, window_pos)
        }
        Some(MessagePointerPayload::ShellNotification(notification))
            if message.msg == crate::ce::gwe::WM_NOTIFY =>
        {
            write_guest_shell_notification(kernel, memory, thread_id, message.lparam, notification)
        }
        Some(MessagePointerPayload::FileChangeNotification(notification))
            if message.msg == WM_FILECHANGEINFO =>
        {
            write_guest_file_change_notification(
                kernel,
                memory,
                thread_id,
                message.lparam,
                notification,
            )
        }
        Some(MessagePointerPayload::NotifyIcon(notification))
            if message.msg == crate::ce::gwe::WM_USER + 0x0bad =>
        {
            write_guest_notify_icon(kernel, memory, thread_id, message.lparam, notification)
        }
        Some(_) | None => true,
    }
}

fn write_guest_window_pos<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    window_pos: WindowPos,
) -> bool {
    write_guest_u32(kernel, memory, thread_id, addr, window_pos.hwnd)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(4),
            window_pos.insert_after,
        )
        && write_guest_i32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(8),
            window_pos.x,
        )
        && write_guest_i32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(12),
            window_pos.y,
        )
        && write_guest_i32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(16),
            window_pos.width,
        )
        && write_guest_i32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(20),
            window_pos.height,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(24),
            window_pos.flags,
        )
}

fn write_guest_shell_notification<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    notification: crate::ce::gwe::ShellNotificationMessage,
) -> bool {
    let (data0, data1) = if notification.link.is_some() {
        (addr.wrapping_add(28), 0)
    } else {
        (notification.data0, notification.data1)
    };
    let header_written = write_guest_u32(kernel, memory, thread_id, addr, notification.hwnd_from)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(4),
            notification.id_from,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(8),
            notification.code,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(12),
            notification.lparam,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(16),
            notification.return_value,
        )
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(20), data0)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(24), data1);
    if !header_written {
        return false;
    }
    if let Some(link) = notification.link.as_deref() {
        let capacity = link.encode_utf16().count() + 1;
        write_guest_wide_fixed(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(28),
            link,
            capacity,
        )
    } else {
        true
    }
}

fn write_guest_file_change_notification<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    notification: crate::ce::gwe::FileChangeNotificationMessage,
) -> bool {
    let item1 = notification_item_bytes(&notification, true);
    let item2 = notification_item_bytes(&notification, false);
    let item1_ptr = item1
        .as_ref()
        .map(|_| addr.wrapping_add(FILECHANGENOTIFY_SIZE))
        .unwrap_or(0);
    let item1_len = item1.as_ref().map(|bytes| bytes.len() as u32).unwrap_or(0);
    let item2_ptr = item2
        .as_ref()
        .map(|_| addr.wrapping_add(FILECHANGENOTIFY_SIZE + item1_len))
        .unwrap_or(0);
    let fixed_written = write_guest_u32(kernel, memory, thread_id, addr, 1)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(4),
            FILECHANGEINFO_SIZE,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(8),
            notification.event_id,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(12),
            notification.flags,
        )
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(16), item1_ptr)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(20), item2_ptr)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(24),
            notification.attributes,
        )
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(28), 0)
        && write_guest_u32(kernel, memory, thread_id, addr.wrapping_add(32), 0)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(36),
            notification.file_size,
        );
    if !fixed_written {
        return false;
    }
    if item1.is_some()
        && !write_notification_item(kernel, memory, thread_id, item1_ptr, &notification, true)
    {
        return false;
    }
    if item2.is_some()
        && !write_notification_item(kernel, memory, thread_id, item2_ptr, &notification, false)
    {
        return false;
    }
    true
}

fn write_guest_notify_icon<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    notification: crate::ce::gwe::NotifyIconMessage,
) -> bool {
    write_guest_u32(kernel, memory, thread_id, addr, NOTIFYICONDATA_FIXED_SIZE_W)
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(4),
            notification.hwnd,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(8),
            notification.id,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(12),
            notification.flags,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(16),
            notification.callback_message,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(20),
            notification.icon,
        )
        && write_guest_wide_fixed(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(NOTIFYICONDATA_TIP_OFFSET),
            &notification.tip,
            NOTIFYICONDATA_TIP_CHARS,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(NOTIFYICONDATA_STATE_OFFSET),
            notification.state,
        )
        && write_guest_u32(
            kernel,
            memory,
            thread_id,
            addr.wrapping_add(NOTIFYICONDATA_STATE_MASK_OFFSET),
            notification.state_mask,
        )
}

fn write_notification_item<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    addr: u32,
    notification: &crate::ce::gwe::FileChangeNotificationMessage,
    first: bool,
) -> bool {
    if notification.flags == SHCNF_IDLIST {
        return if let Some(bytes) = notification_item_bytes(notification, first) {
            write_guest_bytes(kernel, memory, thread_id, addr, &bytes)
        } else {
            true
        };
    } else {
        let Some(path) = (if first {
            notification.path1.as_deref()
        } else {
            notification.path2.as_deref()
        }) else {
            return true;
        };
        for (index, unit) in path.encode_utf16().chain(std::iter::once(0)).enumerate() {
            if !write_guest_u16(
                kernel,
                memory,
                thread_id,
                addr.wrapping_add((index as u32) * 2),
                unit,
            ) {
                return false;
            }
        }
    }
    true
}

fn notification_item_bytes(
    notification: &crate::ce::gwe::FileChangeNotificationMessage,
    first: bool,
) -> Option<Vec<u8>> {
    if notification.flags == SHCNF_IDLIST {
        if first {
            notification.pidl1.clone()
        } else {
            notification.pidl2.clone()
        }
    } else {
        let path = if first {
            notification.path1.as_deref()
        } else {
            notification.path2.as_deref()
        }?;
        let mut bytes = Vec::with_capacity((path.encode_utf16().count() + 1) * 2);
        for unit in path.encode_utf16().chain(std::iter::once(0)) {
            bytes.extend_from_slice(&unit.to_le_bytes());
        }
        Some(bytes)
    }
}

fn get_sys_color(index: u32) -> u32 {
    match sys_color_index(index) {
        0 => rgb(0xc0, 0xc0, 0xc0),
        1 => rgb(0x00, 0x80, 0x80),
        2 | 27 => rgb(0x00, 0x00, 0x80),
        3 | 28 => rgb(0x80, 0x80, 0x80),
        4 | 15 | 25 => rgb(0xc0, 0xc0, 0xc0),
        5 => rgb(0xff, 0xff, 0xff),
        6 => rgb(0x00, 0x00, 0x00),
        7 | 8 | 9 | 18 | 23 | 26 => rgb(0x00, 0x00, 0x00),
        10 | 11 | 12 | 16 | 17 | 19 | 21 => rgb(0x80, 0x80, 0x80),
        13 => rgb(0x00, 0x00, 0x80),
        14 => rgb(0xff, 0xff, 0xff),
        20 | 22 => rgb(0xff, 0xff, 0xff),
        24 => rgb(0xff, 0xff, 0xe1),
        _ => rgb(0x00, 0x00, 0x00),
    }
}

fn get_sys_color_brush(index: u32) -> u32 {
    0x000b_4000 | sys_color_index(index)
}

fn sys_color_index(index: u32) -> u32 {
    index & !SYS_COLOR_INDEX_FLAG
}

const fn rgb(red: u32, green: u32, blue: u32) -> u32 {
    red | (green << 8) | (blue << 16)
}

fn raw_arg(args: &[u32], index: usize) -> u32 {
    args.get(index).copied().unwrap_or(0)
}

fn raw_i32_arg(args: &[u32], index: usize) -> i32 {
    raw_arg(args, index) as i32
}

fn raw_f32_arg(args: &[u32], index: usize) -> f32 {
    f32::from_bits(raw_arg(args, index))
}

fn raw_u64_pair(args: &[u32], low_index: usize, high_index: usize) -> u64 {
    u64::from(raw_arg(args, low_index)) | (u64::from(raw_arg(args, high_index)) << 32)
}

fn raw_i64_pair(args: &[u32], low_index: usize, high_index: usize) -> i64 {
    raw_u64_pair(args, low_index, high_index) as i64
}

fn raw_f64_pair(args: &[u32], low_index: usize, high_index: usize) -> f64 {
    f64::from_bits(raw_u64_pair(args, low_index, high_index))
}

fn sh_sip_preference_i_raw(kernel: &mut CeKernel, thread_id: u32, args: &[u32]) -> bool {
    let hwnd = raw_arg(args, 0);
    let state = raw_arg(args, 1);
    if hwnd == 0 || state > SIP_DOWN_NOVALIDATE {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }

    let ok = kernel.gwe.sh_sip_preference(hwnd, state);
    kernel.threads.set_last_error(thread_id, 0);
    ok
}

fn imm_sipanel_state_raw<M: CoredllGuestMemory>(
    kernel: &mut CeKernel,
    memory: &mut M,
    thread_id: u32,
    args: &[u32],
) -> bool {
    let command = raw_arg(args, 0);
    let value_ptr = raw_arg(args, 1);
    if value_ptr == 0 {
        kernel
            .threads
            .set_last_error(thread_id, ERROR_INVALID_PARAMETER);
        return false;
    }

    match command {
        SIP_QUERY_LOCATION => {
            let rect = kernel.gwe.sip_panel_rect();
            let ok = write_guest_rect(kernel, memory, thread_id, value_ptr, rect);
            if ok {
                kernel.threads.set_last_error(thread_id, 0);
            }
            ok
        }
        SIP_SET_LOCATION => {
            let Some(rect) = read_guest_rect(kernel, memory, thread_id, value_ptr) else {
                return false;
            };
            kernel.gwe.set_sip_panel_rect(rect);
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        SIP_INPUT_ATTRIBUTES => {
            let Some(attributes) = read_guest_u32(kernel, memory, thread_id, value_ptr) else {
                return false;
            };
            kernel.gwe.set_sip_input_attributes(attributes);
            kernel.threads.set_last_error(thread_id, 0);
            true
        }
        _ => {
            kernel
                .threads
                .set_last_error(thread_id, ERROR_NOT_SUPPORTED);
            false
        }
    }
}

fn security_gen_cookie_raw(kernel: &CeKernel, thread_id: u32) -> u32 {
    let mut cookie = 0xa5a5_5a5a_u32
        ^ kernel.current_process_id().rotate_left(5)
        ^ thread_id.rotate_left(13)
        ^ kernel.timers.tick_count().rotate_left(17);
    cookie ^= cookie >> 16;
    cookie = cookie.wrapping_mul(0x045d_9f3b);
    if cookie == 0 || cookie == 0xbb40_e64e {
        cookie ^= 0x4711_2010;
    }
    if cookie == 0 { 0x4711_2010 } else { cookie }
}

fn raw_unary_f64(kernel: &CeKernel, args: &[u32], op: CeMathUnaryF64) -> CoredllValue {
    CoredllValue::CeMath(kernel.math.eval(CeMathCall::UnaryF64 {
        op,
        value: raw_f64_pair(args, 0, 1),
    }))
}

fn raw_binary_f64(kernel: &CeKernel, args: &[u32], op: CeMathBinaryF64) -> CoredllValue {
    CoredllValue::CeMath(kernel.math.eval(CeMathCall::BinaryF64 {
        op,
        lhs: raw_f64_pair(args, 0, 1),
        rhs: raw_f64_pair(args, 2, 3),
    }))
}

fn raw_binary_f32(kernel: &CeKernel, args: &[u32], op: CeMathBinaryF32) -> CoredllValue {
    CoredllValue::CeMath(kernel.math.eval(CeMathCall::BinaryF32 {
        op,
        lhs: raw_f32_arg(args, 0),
        rhs: raw_f32_arg(args, 1),
    }))
}

fn normalize_name(name: &str) -> String {
    name.to_ascii_lowercase()
}

fn has_any_prefix(name: &str, prefixes: &[&str]) -> bool {
    prefixes
        .iter()
        .any(|prefix| name.starts_with(&normalize_name(prefix)))
}

fn is_sdk_crt_export(export: &CoredllExport) -> bool {
    SDK_ORDINALS
        .iter()
        .any(|sdk| sdk.name == export.name && sdk.ordinal == export.ordinal)
}

